window.AUTHOR_CLOCK_QUOTES_KO = {"precise":{"00:00":[{"t":"열두시","q":"중로에서 그렇듯 많이 충그리고 길이 터지고 했어도, 회장에 당도했을 때에는 부민관 꼭대기의 큰 시계가 열두시밖에는 더 되지 않았습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"자정","q":"렌이 말했다. \"핼러윈 자정에 축구장에 가서 그 이름을 세 번 부르면, 그의 유령이 나타난다고 해.\"","title":"코퍼 리버","author":"윌리엄 켄트 크루거","ampm":"am","kind":"역"}],"01:00":[{"t":"한 시","q":"열 한 시가 좀 지났구나, 여기도 결코 내 안주의 곳은 아니구나, 어디 가서 자정을 넘길까?","title":"날개","author":"이상","ampm":"unknown","kind":"원문"},{"t":"한 시","q":"하기야 아무리 흠잡을 데 없이 얌전스럽고 덕이 있고 한 며느리라도, 야속한 시어머니한테 걸리고 보면 반찬 먹은 개요, 고양이 앞에 쥐요 하지 별수가 없는 것이지만, 고씨로 말하면 사람이 몸집 생김새와 같이 둥실둥실한 게 후덕하기는 하나, 대단히 이퉁이 세어 한번 코를 휘어 붙이면 지렛대로 떠곤질러도 꿈쩍을 않고, 또 몹시 거만진 성품까지 없지 않습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"새벽 한 시","q":"새벽 한 시에 자잘한 주머니가 잔뜩 달린 검정 정장 차림으로 은행 금고에서 붙잡히면 누가 봐도 수상하지 않겠는가, 그런데도 왜 그런 짓을 할까?","title":"고잉 포스탈","author":"테리 프래쳇","ampm":"am","kind":"역"}],"02:00":[{"t":"두시","q":"다른 중국인들은 새벽 두시쯤 하여 돌아가는 것을 보면서 복녀는 왕 서방의 집 안에 들어갔다.","title":"감자","author":"김동인","ampm":"am","kind":"원문"},{"t":"두시","q":"새로 두시―--- 세시―---","title":"상록수","author":"심훈","ampm":"unknown","kind":"원문"},{"t":"두시","q":"하고 떨리는 붓으로, ‘歲次丙辰六月二十九日午前二時에 죄인 朴英采는 泣血百拜(세차병진 유월 이십구일 오전 두시에 죄인 박영채 읍혈백배)’라 하였다.","title":"무정","author":"이광수","ampm":"am","kind":"원문"},{"t":"두 시","q":"대성당 종이 두 시를 알리자, 장 발장은 잠에서 깨어났다.","title":"레 미제라블","author":"빅토르 위고","ampm":"am","kind":"역"}],"03:00":[{"t":"세시","q":"“세시부터 개인교수가 있어.","title":"무정","author":"이광수","ampm":"unknown","kind":"원문"},{"t":"세시","q":"고씨는 새벽 세시가 지나 술이 얼큰해 들어오더니 여태 태평몽이고…….","title":"태평천하","author":"채만식","ampm":"am","kind":"원문"},{"t":"새벽 세 시","q":"\"프레드, 야경대의 가장 훌륭한 전통은 새벽 세 시에 바람 없는 곳에서 조용히 담배 한 대 피우는 거야. 너무 흥분하지 말자고, 응?\"","title":"징고","author":"테리 프래쳇","ampm":"am","kind":"역"}],"04:00":[{"t":"네시","q":"종수가 도로 여관으로 돌아와서 네시까지 기다리다가 그만 질증이 나서, 다 작파하고 조부 윤직원 영감한테 급한 돈 천 원이나 옭아 내어 가지고 내려가 버릴까, 내일 하루 더 기다려 볼까 망설이는 판에, 키다리 병호가 터덜터덜 달려들었습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"네 시","q":"캐럿 하사는 새벽 네 시경 잠에서 깼다, 범죄자와 경찰관 같은 밤의 사람들만이 아는 그 은밀한 시각이었다. 그는 좁은 침대의 절반을 차지한 채 누워 벽을 바라보았다.","title":"무장한 남자들","author":"테리 프래쳇","ampm":"am","kind":"역"}],"05:00":[{"t":"다섯시","q":"시계의 짧은 침은 벌써 다섯시를 가리켰으나 하늘이 흐려 아직도 정거장의 등불이 반작반작한다.","title":"무정","author":"이광수","ampm":"unknown","kind":"원문"},{"t":"다섯 시","q":"그가 마침내 잿빛 새벽 속으로 비틀거리며 나섰을 때 비는 두꺼운 커튼처럼 쏟아지고 있었다. 배수로는 넘쳐흘렀다. 지붕 위에서는 흉측한 가고일들이 지나가는 이들 머리 위로 능숙하게 토악질을 해댔지만, 이제 다섯 시라 인파는 조금 줄어 있었다.","title":"움직이는 그림들","author":"테리 프래쳇","ampm":"am","kind":"역"}],"07:30":[{"t":"일곱시 반","q":"한 시간 안에 다녀오마고 나간 병호는, 두시간 세시간 눈이 빠지게 기다려 놓고서 일곱시 반에야 휘적휘적, 그나마 맨손으로 돌아왔습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"일곱 시 반","q":"이튿날 아침 일곱 시 반, 그는 블레넘 애비뉴 21번지의 초인종을 눌렀다.","title":"비 온 뒤","author":"윌리엄 트레버","ampm":"am","kind":"역"}],"08:00":[{"t":"여덟시","q":"그럭저럭 여덟시가 되자, 윤직원 영감은 안으로 들어가서 조반을 자시고 나와, 다시 그럭저럭 아홉시가 되었습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"여덟 시","q":"아이들의 요란한 웃음소리는 이내 신음으로 바뀌었다. 그날 오후는 평소처럼 여덟 시부터 열한 시 반까지가 아니라 하루 종일 수업이라는 그의 냉담한 통보 때문이었다.","title":"사랑의 빛나는 골짜기","author":"에드나 홍","ampm":"am","kind":"역"}],"09:00":[{"t":"아홉시","q":"다른 교사들은 각각 앞에다가 분필통과 교과서를 놓고 벌써 아홉시에 십여 분이 지났건마는 교실에 들어갈 생각도 아니한다.","title":"무정","author":"이광수","ampm":"unknown","kind":"원문"},{"t":"아홉시","q":"형식은 석점이나 지나서야 잠이 들어 아침 아홉시가 되도록 잤다.","title":"무정","author":"이광수","ampm":"am","kind":"원문"},{"t":"아홉시","q":"구두를 신노라니까 등뒤에서 마루의 괘종이 아홉시를 칩니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"아홉시","q":"아홉시면 지금 가더라도 '모로코'밖에 못 볼 텐데 어쩔까 싶어 작정을 못 한 대로 나가기는 나갑니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"아홉시","q":"종수가 시계를 꺼내어 마침 아홉시 이십분이 된 것을 보고 있노라니까, 샛문을 배깃이 열고 노파가 담뱃대 문 곰보딱지 얼굴을 들이밉니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"아홉시","q":"또, 제 아범이 앓는다고 불려갔으니 혹시 못 오기나 하면 어찌하노 해서, 바야흐로 등이 단 참인데, 웬걸 아홉시 치는 소리가 때앵땡 나자 고년이 씨근버근 해뜩반뜩 달려들지를 않는다구요!","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"아홉 시","q":"그날 밤 잉게의 흔적은 낮에도 밤에도 발견되지 않았다. 몇몇은 밤새 수색을 이어갔다. 그러다 이튿날 아침 아홉 시 무렵, 시온 교회 종탑의 종이 미친 듯이 울리기 시작했다.","title":"사랑의 빛나는 골짜기","author":"에드나 홍","ampm":"am","kind":"역"}],"10:00":[{"t":"열시","q":"내일 온대도 정각인 아침 열시까지는 도저히 대어 들어올 수가 없지 않은가.","title":"상록수","author":"심훈","ampm":"am","kind":"원문"},{"t":"열 시","q":"빌라 보르게세에서 새로운 삶이 펼쳐지고 있다. 겨우 열 시인데 우리는 벌써 아침을 먹고 산책까지 다녀왔다.","title":"북회귀선","author":"헨리 밀러","ampm":"am","kind":"역"}],"11:00":[{"t":"열한 시","q":"열한 시쯤 해서 하는 아내의 첫 번 세수는 좀 간단하다.","title":"날개","author":"이상","ampm":"unknown","kind":"원문"},{"t":"열한시","q":"열한시가 넘어서 영채는 집에 돌아왔다.","title":"무정","author":"이광수","ampm":"unknown","kind":"원문"},{"t":"열한시","q":"마구 싸우다시피 구 원 십 전에 그 반지를 뺏어 가지고 가게를 나오니까 열한시가 훨씬 넘었습니다.","title":"태평천하","author":"채만식","ampm":"unknown","kind":"원문"},{"t":"열한 시","q":"\"인구 경찰이 열한 시에 마을 광장에서 열리는 집회에 출석할 것을 요구합니다. 새 신분증이 발급될 것이며, 이 카드가 발급된 뒤로는 다른 카드나 서류는 모두 무효가 됩니다.\" 루크가 다급히 말했다.","title":"자유인들 사이에서","author":"마거릿 피터슨 해딕스","ampm":"am","kind":"역"}],"12:00":[{"t":"열두시","q":"낮에는 배워 가지고 와서는 밤이면 똑 열두시, 새로 한시까지 앉아서 배운 것을 보고 그대로 그리고 모두 치수를 적고 했어요.","title":"경희","author":"나혜석","ampm":"pm","kind":"원문"},{"t":"정오","q":"안나 수녀가 정오에 그를 파트모스로 데려왔을 때, 군터는 들리는 모든 이에게 외쳤다, \"나 읽을 줄 알아요!\"","title":"사랑의 빛나는 골짜기","author":"에드나 홍","ampm":"pm","kind":"역"}],"13:00":[{"t":"한시","q":"오후 한시에 시작한 것이 넉점이 지나도록 끝이 나지 못하였다.","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"한시","q":"저럴까 하고 마음을 정치 못하면서 오후 한시에 안동 김장로의 집에 선형과 순애의 영어를 가르치러 갔다.","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"한시","q":"윤주사 창식 그는 아무튼 그러한 사람으로서, 밤이고 낮이고 하는 일이라고는 쌍스럽지 않은 친구 사귀어 두고 술 먹으러 다니기, 활 쏘기, 제철 따라 승지(勝地)로 유람 다니기, 옛 한서(漢書) 모아 놓고 뒤지기, 한시(漢詩) 지어서 신문사에 투고하기, 이 첩의 집에서 술 먹다가 심심하면 저 첩의 집으로 가서 마작하기, 도무지 유유자적한 게 어떻게 보면 신선인 것처럼이나 탈속이 되어 보입니다.","title":"태평천하","author":"채만식","ampm":"pm","kind":"원문"},{"t":"한 시","q":"내일 한 시에 안데르스가 썰매를 끌고 올 것이니, 그때 목록에 따라 집집마다 돌며 바구니를 놓고 오도록 해라.","title":"하나님의 망치","author":"보 기에르츠","ampm":"pm","kind":"역"},{"t":"한시","q":"아무튼 그만큼이나 좋아하는 명창대회요, 그래 오늘만 하더라도 낮에는 한시부터 시작을 한다는 걸 윤직원 영감이 춘심이를 앞세우고 댁에서 나선 것이 열한시 반이 채 못 되어섭니다.","title":"태평천하","author":"채만식","ampm":"pm","kind":"원문"}],"14:00":[{"t":"두시","q":"그날 밤도 (아마 두시는 지났을걸요) 그 예배당에서 혼자서 눈을 감고 조용한 맛을 즐기고 있노라는데, 갑자기 저편 아래에서 재재 하는 소리가 납디다.","title":"광염 소나타","author":"김동인","ampm":"pm","kind":"원문"},{"t":"두 시","q":"마침 오후 두 시에 S읍으로 가는 자동차가 있었다.","title":"상록수","author":"심훈","ampm":"pm","kind":"원문"},{"t":"두시","q":"경성학교 영어 교사 이형식은 오후 두시 사년급 영어 시간을 마치고 내려쪼이는 유월 볕에 땀을 흘리면서 안동 김장로의 집으로 간다.","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"두 시쯤","q":"\"정확히 어디서? 그리고 언제? 우리도 가야 해.\" \"광장. 옛 도서관 계단에서.\" 그녀는 술집 위의 시계를 흘긋 보았다. \"정오에서 두 시간 지난, 두 시쯤일 거야.\"","title":"이 어두운 심연으로부터","author":"바네사 라사넨","ampm":"pm","kind":"역"}],"15:00":[{"t":"세 시","q":"나는 밤중 세 시나 네 시쯤 해서 변소에 갔다.","title":"날개","author":"이상","ampm":"pm","kind":"원문"},{"t":"세시","q":"김장로의 딸 선형(善馨)이가 명년 미국 유학을 가기 위하여 영어를 준비할 차로 이형식을 매일 한 시간씩 가정교사로 고빙하여 오늘 오후 세시부터 수업을 시작하게 되었음이라.","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"세 시","q":"마들렌 씨는 보통 세 시에 왔고, 시간을 지키는 것도 친절의 한 형태였기에 그는 늘 정확했다.","title":"레 미제라블","author":"빅토르 위고","ampm":"pm","kind":"역"}],"19:00":[{"t":"일곱 시","q":"그러나 저녁 일곱 시쯤 해서 하는 두 번째 세수는 손이 많이 간다.","title":"날개","author":"이상","ampm":"pm","kind":"원문"},{"t":"저녁 일곱 시","q":"저녁 일곱 시, 수학 연습을 할 것.","title":"한밤중에 개에게 일어난 기이한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"20:00":[{"t":"여덟시","q":"이튿날 형식은 어젯밤 늦게야 잠이 들었던 탓으로 여덟시가 지나서야 일어났다.","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"여덟시","q":"더구나 밤이 여덟시나 지났는데!’","title":"무정","author":"이광수","ampm":"pm","kind":"원문"},{"t":"여덟 시","q":"아직 여덟 시였다. \"마님!\" 그가 외쳤다. \"오늘 밤 집에 갈 수 있어요! 크리스마스는 집에서 보내는 거예요!\" \"그래요, 퐁고,\" 미시스가 명랑하게 대답했지만, 목소리만큼 마음이 밝지는 않았다.","title":"101마리 달마시안","author":"도디 스미스","ampm":"pm","kind":"역"}],"21:00":[{"t":"아홉시","q":"역시 같은 날 밤이요, 아홉시가 한 오 분 가량 지나섭니다.","title":"태평천하","author":"채만식","ampm":"pm","kind":"원문"},{"t":"아홉시","q":"동대문 밖 창식이 윤주사의 큰첩네 집 사랑, 여기도 역시 같은 그날 밤 같은 시각, 아홉시 가량 해섭니다.","title":"태평천하","author":"채만식","ampm":"pm","kind":"원문"},{"t":"아홉 시","q":"아홉 시, 텔레비전이나 비디오를 본다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"22:00":[{"t":"열시","q":"초저녁부터 몇 번 붙잡아 앉힌 것은 물론이고, 마침내 열시가 되자 할 수 없이 놓아 보내는데, 윤직원 영감은 크게 생색을 내어 인력거를 불러다가 선금을 주어서 태워 보내는 외에, 일 원 한 장을 따로 손에 쥐어 주기까지 했습니다.","title":"태평천하","author":"채만식","ampm":"pm","kind":"원문"},{"t":"열 시","q":"열 시에 그는 신주쿠에 가서 신용카드로 후지쓰 워드프로세서를 샀다. 최신 모델로, 이전 버전들보다 훨씬 가벼웠다.","title":"1Q84 BOOK 1","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"00:01":[{"t":"자정 1분","q":"\"어쩌면요. 하지만 미리 경고해두는 게 좋을 겁니다. 브리스톨에 당신이 있다는 걸 세무 당국에 알리는 게 제 의무라 여겼으니, 자정 1분에 경찰이 요트에 올라 압류해도 놀라지 마시길.\"","title":"그는 그런 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"00:02":[{"t":"0시 2분","q":"역에 도착했을 때는 열두 시 십오 분 전이었고, 0시 2분에 기차가 있어 다음 날 오후 두 시 반쯤 파리에 도착할 예정이었다.","title":"서배스천 나이트의 진짜 인생","author":"블라디미르 나보코프","ampm":"am","kind":"역"}],"00:03":[{"t":"자정 3분","q":"내가 마지막으로 아처 해리슨을 살아있는 모습으로 본 것은 자정 3분이었다. 기억하는 이유는 내가 2분이라 말하자 그가 시계를 보고 3분이라 정정했기 때문이다.","title":"입센 이후로","author":"조지 진 네이선","ampm":"am","kind":"역"}],"00:04":[{"t":"자정 4분","q":"1월 22일 자정 4분, 로리 제독의 함대 250여 척이 안치오 앞바다 상륙 지점에 도달했다. 바다는 잔잔했고 밤은 칠흑 같았다.","title":"안치오: 용기의 서사시","author":"프레드 시핸","ampm":"am","kind":"역"}],"00:05":[{"t":"자정 5분","q":"자정 5분. 내일이 오늘이 되었다.","title":"명예를 건 결투","author":"블라디미르 나보코프","ampm":"am","kind":"역"}],"00:06":[{"t":"자정 6분","q":"자정 6분, 죽음이 고통받던 이를 놓아주었다.","title":"헬스 프린지 서쪽","author":"글렌 셜리","ampm":"am","kind":"역"}],"00:07":[{"t":"자정 7분","q":"자정 7분이었다. 개는 시어스 부인 집 앞 잔디밭 한가운데 누워 있었다. 눈은 감겨 있었다. 꿈속에서 고양이를 쫓듯 옆으로 누워 달리는 자세였다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"00:08":[{"t":"자정 8분","q":"\"밤중이라니!\" 사제가 외쳤다. \"지금은 밤이 아니라 낮이오, 자정 8분이란 말이오!\"","title":"브리간틴 호","author":"제임스 패스코","ampm":"am","kind":"역"}],"00:09":[{"t":"자정 9분","q":"10월 18일 자정 9분, 행렬은 목적지에서 아직 10킬로미터 떨어진 카르사즈 다리에 이르렀다.","title":"부토 살해 재판: 와지리스탄에서 총사령부까지","author":"아미르 미르","ampm":"am","kind":"역"}],"00:10":[{"t":"자정 10분","q":"\"먼스터 말로는 어젯밤 문을 잠글 때 그것이 진열장 안에 있었다더군요. 그때가 자정 10분이었습니다. 오늘 아침 6시 조금 지나 문을 열었지만 진열장은 보지 않았답니다, 팔이 없어졌다면 눈치챘을지도 모른다고는 하지만 확신은 못한다는군요.\"","title":"피부 아래의 해골","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:11":[{"t":"자정 11분","q":"그녀는 가능한 한 빨리 리셉션을 빠져나와 방으로 돌아가 옷을 갈아입기로 했다. 자정 11분에 다시 한 번 정전이 일어날 것이고, 그 틈에 외부 계단을 통해 1층으로 내려가 출구에서 브로드무어의 케이터링 밴을 기다릴 참이었다.","title":"인클레이브","author":"캐런 핸콕","ampm":"am","kind":"역"}],"00:12":[{"t":"자정 12분","q":"모녀가 첫 번째 번개를 본 것은 자정 12분이었다. 그것은 헛간 본채를 강타해 발밑의 땅이 흔들릴 정도였다.","title":"켄터키의 열기","author":"펀 미카엘스","ampm":"am","kind":"역"}],"00:13":[{"t":"자정 13분","q":"지금은 자정 13분. 우리는 또 다른 비행기 안에 있다, 이번엔 시카고를 거쳐 샌디에이고에서 보스턴으로 가는 편이다. 주위 사람들은 모두 잠들어 있다.","title":"매드랜드","author":"애나 로즈","ampm":"am","kind":"역"}],"00:14":[{"t":"자정 14분","q":"그가 마지막 통화를 마친 것은 정확히 자정 14분이었다. 그가 연락한 이들 중에는 명예로운 사람들이 있었다. 그들의 목소리는 대통령의 귀에 닿을 것이었다.","title":"마타레제 서클","author":"로버트 러들럼","ampm":"am","kind":"역"}],"00:15":[{"t":"자정 십오 분","q":"파티는 저녁 식사 후 자정 십오 분경에 끝났다. 손님들을 배웅하며 올가 미하일로브나는 문가에 서서 말했다. \"숄을 꼭 챙기세요! 날이 좀 쌀쌀해졌어요. 부디 감기 걸리지 마시고요!\"","title":"파티 외 단편집","author":"안톤 파블로비치 체호프","ampm":"am","kind":"역"}],"00:16":[{"t":"자정 16분","q":"자정 16분, 4번 구역이 피격되어 지붕에 불이 붙었다.","title":"가장 긴 밤","author":"개빈 모티머","ampm":"am","kind":"역"}],"00:17":[{"t":"자정 17분","q":"\"그러니 당신은 내가 쓰러진 나무에 자정 17분보다 늦게 도착했다고 추리하는군요. 그럴 수도 있죠. 알리바이를 꾸미던 게 아니었으니 2분마다 시간을 확인하지는 않았습니다.\"","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:18":[{"t":"자정 18분","q":"순식간에 직사각형이 정사각형으로 바뀌더니, 그마저 꺼져버렸다. 토인턴 그레인지는 어둠 속 고요한 곶 위에 희미하게 새겨진 형상으로 남아 있었다. 문득 궁금해져 그는 시계를 보았다. 자정 18분이었다.","title":"검은 탑","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:19":[{"t":"자정 19분","q":"나는 침대에서 뛰쳐나와 계단을 뛰어 내려가, 날카롭게 쏟아지는 불빛을 뚫고 부엌으로 들어갔다. 벽시계는 자정 19분을 가리키고 있었다. 뒷문 옆 고리에서 검은 우비를 낚아채고, 한쪽은 발이 잘 들어가지 않는 장화를 억지로 신은 뒤 밖으로 뛰쳐나갔다.","title":"화재 이후","author":"헤닝 망켈","ampm":"am","kind":"역"}],"00:20":[{"t":"자정 20분","q":"사촌이 돌아온 것은 자정 20분이었다.","title":"눈먼 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"am","kind":"역"}],"00:21":[{"t":"자정 21분","q":"자정 21분. 아이코. 밴스는 갑자기 선로가 떨리는 것을 느꼈다. 이윽고 금속이 금속을 갈아내는 듯한 고통스러운 소리와 함께 갠트리가 다시 움직이기 시작했다. 그들이 안전 차단 장치를 무시하기로 한 것이다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"00:22":[{"t":"자정 22분","q":"노바디는 마이크로프트 워드의 가장 중요한 요원 중 하나로, 매일 자정 21분에서 자정 22분 사이 단 60초 동안 그의 노트북은 마이크로프트 워드의 정신 그 자체인 거대한 온라인 자아 데이터베이스에 직접 접속하도록 허락되었다.","title":"로 샤크 텍스트","author":"스티븐 홀","ampm":"am","kind":"역"}],"00:23":[{"t":"자정 23분","q":"오스카는 손목시계를 손에 들고 무게를 가늠하다가, 자정 23분을 가리키는 야광 문자반이 달린 제법 근사한 그 물건을 꼬마 핀치콜에게 건넸다. 그는 궁금한 듯 두목을 올려다보았다. 슈퇴르테베커가 동의의 뜻으로 고개를 끄덕였다. 오스카는 귀갓길에 맞춰 드럼을 단단히 고쳐 메며 말했다. \"예수님이 길을 인도하시리라. 나를 따르라!\"","title":"양철북","author":"귄터 그라스","ampm":"am","kind":"역"}],"00:24":[{"t":"자정 24분","q":"서턴을 사수로 태운 샌더스는 자정 24분에 순찰을 시작해 고도 만 피트로 비치 헤드를 향해 남쪽으로 기수를 돌렸다.","title":"가장 긴 밤","author":"개빈 모티머","ampm":"am","kind":"역"}],"00:25":[{"t":"자정 25분","q":"잠시 후 현실감이 되돌아왔고, 그녀는 환각이 아니라 꿈을 꾸었던 것임을 깨달았다. 책상 위 시계는 12시 55분을 가리켰다. 그들은 자정 25분에 십 분짜리 세션을 시작했으니, 스무 분의 공백이 있는 셈이었다.","title":"인클레이브","author":"캐런 핸콕","ampm":"am","kind":"역"}],"00:26":[{"t":"자정 26분","q":"\"킹스크로스에서 두타 씨가 전화해 당신이 오고 있다고 알려주더군요. 어제 자정 26분 도착 열차 영상을 보고 싶다 하셨다면서요. 화면을 준비하는 데 몇 분 걸릴 겁니다. 오늘은 우리 경비원이 안 계세요, 대건던 걸스 파이퍼스 본부 앞에서 저지른 풍기문란죄로 해링게이 치안판사 법정에 출두 중이거든요.\"","title":"브라이언트와 메이, 탈선하다","author":"크리스토퍼 파울러","ampm":"am","kind":"역"}],"00:27":[{"t":"자정 27분","q":"블레이크는 잠든 아기를 안은 통통한 여자 뒤를 따라 버스에서 내렸다. 버스 기사는 화려하게 차려입은 여자애와 이야기하느라 그 여자와 아기를 쳐다보지도 않았다. 블레이크는 비틀거리는 그녀를 붙잡아주었다. 그녀는 돌아서서 피곤한 미소를 지었다. 블레이크는 고개를 끄덕이고 터미널 시계를 올려다보았다. 그때가 자정 27분이었다.","title":"교수형 집행인을 애도하며","author":"해리 위팅턴","ampm":"am","kind":"역"}],"00:28":[{"t":"자정 28분","q":"'드링크 치어업 커피' 벽시계는 자정 28분을 가리키고 있었다.","title":"11/22/63","author":"스티븐 킹","ampm":"am","kind":"역"}],"00:29":[{"t":"자정 29분","q":"\"몇 시야?\" 티니비츠가 물었다. 역무원은 커다란 은시계를 꺼내 유심히 살펴보더니 말했다. \"자정 29분이야.\" \"자정이라고!\" 티니비츠가 되뇌었다. \"그럴 리가.\"","title":"칼자국","author":"클레이턴 H. 어니스트","ampm":"am","kind":"역"}],"00:30":[{"t":"열두 시 반","q":"\"당신을 얼마나 사랑하는지 당신은 모를 거예요.\"<br>\"나도 사랑해.\" 나는 미소 짓고, 그의 입술이 내 뺨에 머문다. 그가 복도를 걸어갈 때 나는 시간을 확인한다. 열두 시 반.","title":"배스 하우스","author":"P.J. 버넌","ampm":"am","kind":"역"}],"00:31":[{"t":"자정 삼십일 분","q":"세 번째 인물이 눈치채지 못하게, 경계도 없이 다가온다. 손이 닿을 거리에 이르자 대상들을 향해 손을 뻗는다. 녹화 종료, 타임코드 자정 삼십일 분 이초.","title":"좀비 아포칼립스! 반격","author":"스티븐 존스","ampm":"am","kind":"역"}],"00:32":[{"t":"열두 시 삼십이 분","q":"그는 벽난로 위 시계를 꼼꼼히 확인하고 수첩에 기록했다. \"열두 시 삼십이 분, 코트니-브릭스 씨가 윈체스터 로드에 쓰러진 나무를 신고함.\"","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:33":[{"t":"열두 시 삼십삼 분","q":"스티븐 맥시는 그의 눈을 똑바로 보며 거의 태연하게 말했다. \"제 시계로는 열두 시 삼십삼 분이었습니다.\"","title":"그녀의 얼굴을 덮어라","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:34":[{"t":"자정 삼십사 분","q":"자정 삼십사 분. \"십 분 후엔 여기로 돌아와 있어야 해.\" LT는 반박하지 않았다. 스쿨보이는 예전 수법을 잘 알았다. LT의 눈길이 박물관을 훑었다. \"설마 아직도 경비 걱정하는 건 아니지? 경비 따위 없는데.\"","title":"킬러 튠","author":"드레다 세이 미첼","ampm":"am","kind":"역"}],"00:35":[{"t":"자정 삼십오 분","q":"시계는 자정 삼십오 분을 가리키고 있었다. 나는 깊은 잠에서 막 깨어나 멍한 상태였다. 이 시간에 누가 전화를 건 걸까?","title":"최첨단의 고양이","author":"리디아 애덤슨","ampm":"am","kind":"역"}],"00:36":[{"t":"자정 삼십육 분","q":"검사는 금빛 손목시계를 들여다보았다. 자정 삼십육 분.","title":"얼어붙은 죽음","author":"베르나르 미니에","ampm":"am","kind":"역"}],"00:37":[{"t":"열두 시 삼십칠 분","q":"스티븐은 침대맡 시계를 보았다. 열두 시 삼십칠 분. 그는 부엌으로 가 냉장고에서 바닐라 콜라를 꺼냈다. 거실에서는 DVD장을 열어 수백 개의 제목을 훑어보았다.","title":"전사 수도승","author":"레이 키팅","ampm":"am","kind":"역"}],"00:38":[{"t":"열두 시 삼십팔 분","q":"\"자정쯤 본관을 나가셨죠. 열두 시 삼십팔 분에는 정문 수위와 이야기를 나누셨고요. 그 사이엔 어디 계셨습니까?\"","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:39":[{"t":"열두 시 삼십구 분","q":"열두 시 삼십구 분, 나는 달이 사나운 먹구름 떼에 잡아먹히는 광경을 바라보았다.","title":"수도원의 악몽","author":"로스 H. 스펜서","ampm":"am","kind":"역"}],"00:40":[{"t":"열두 시 사십 분","q":"열두 시 사십 분에 시신을 살펴본 법의학자의 소견으로는, 오키프 부인이 귀가한 직후 곧바로 사망했다는 것이었다.","title":"어떤 정의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"00:41":[{"t":"열두 시 사십일 분","q":"그가 차로 돌아왔을 때는 열두 시 사십일 분이었다. 나는 내 차 밖에 서서 그저 기다리고 있었고, 그가 나를 알아보았다.","title":"혈연","author":"헤랄도 크루즈","ampm":"am","kind":"역"}],"00:42":[{"t":"한 시 십팔 분 전","q":"담배꽁초가 손가락 사이에서 점점 뜨거워지더니, 타들어가는 끝이 이제 피부를 찔러왔다. 그녀는 담배를 비벼 끄고 일어나 검은 치마에서 재를 털어냈다. 한 시 십팔 분 전이었다. 그녀는 내선 전화로 가서 그의 방에 걸었다. 전화벨이 계속 울렸지만 아무도 받지 않았다.","title":"마조리 모닝스타","author":"허먼 워크","ampm":"am","kind":"역"}],"00:43":[{"t":"열두 시 사십삼 분","q":"\"5분 전에 죽었다고요?\" 그가 물었다. 그의 눈이 손목시계로 향했다. 그는 압지에 \"열두 시 사십삼 분\"이라고 적었다.","title":"호주머니 속의 죽음","author":"애거사 크리스티","ampm":"am","kind":"역"}],"00:44":[{"t":"열두 시 사십사 분","q":"그녀가 브륄레 가게 모퉁이를 돌아 스테이트라인 로드로 접어든 것은 열두 시 사십사 분이었다. 그녀는 다가오는 열차를 기다렸다.","title":"타오르는 잉걸불","author":"웨인 피어슨","ampm":"am","kind":"역"}],"00:45":[{"t":"열두 시 사십오 분","q":"열두 시 사십오 분, 잠시 소강상태가 찾아왔을 때 요쇼기 씨는 전쟁 때문에 지금 영국에는 남자보다 여자가 훨씬 많아졌다고 내게 말했다.","title":"돼지와 후추: 청춘의 희극","author":"데이비드 풋맨","ampm":"am","kind":"역"}],"00:46":[{"t":"열두 시 사십육 분","q":"테디는 통화 기록이 러튼 양의 이야기를 뒷받침한다고 적었다. 그녀가 전화를 건 시각은 열두 시 사십육 분이었다.","title":"장난을 위한 다이얼 M","author":"케이시 마이클스","ampm":"am","kind":"역"}],"00:47":[{"t":"열두 시 사십칠 분","q":"열두 시 사십칠 분, 호 아저씨는 우리 곁을 영영 떠났다.","title":"지난밤 나는 평화를 꿈꿨다","author":"앤드루 X. 팜","ampm":"am","kind":"역"}],"00:48":[{"t":"열두 시 사십팔 분","q":"스탠튼은 불을 끄며 시계의 붉은 숫자를 힐끗 보았다. 열두 시 사십팔 분이었다. 그녀는 오늘이 무슨 요일인지 떠올려보려 했다.","title":"모리아 루스","author":"마빈 위베너","ampm":"am","kind":"역"}],"00:49":[{"t":"열두 시 사십구 분","q":"그때 그들은 도움을 청하며 소리치기 시작했다. 인근 고층건물의 경비원이 그 외침을 듣고 경찰에 신고했다. 열두 시 사십구 분이었다. 메트로데이드 경찰관 바트 코언과 그의 파트너가 1분 뒤 도착했다.","title":"우는 모습을 보이지 마라","author":"에드나 뷰캐넌","ampm":"am","kind":"역"}],"00:50":[{"t":"열두 시 오십 분","q":"짐 싸기는 열두 시 오십 분에 끝났다. 해리스는 커다란 바구니 위에 앉아 아무것도 깨지지 않았기를 바란다고 말했다. 조지는 뭔가 깨졌다면 이미 깨진 것이라고 말했고, 그 생각이 그를 위로하는 듯했다. 그는 이제 자러 갈 준비가 됐다고도 말했다.","title":"보트 위의 세 남자","author":"제롬 K. 제롬","ampm":"am","kind":"역"}],"00:51":[{"t":"열두 시 오십일 분","q":"시간을 깨닫고 나는 웃음을 지우고 말았다. 열두 시 오십일 분이었고, 새벽 한 시가 되면 늘 우리를 확인하러 왔다. 나는 엘리베이터에 닿을 때까지 있는 힘껏 달리려 했다.","title":"우리 위의 모든 별","author":"지에르무","ampm":"am","kind":"역"}],"00:52":[{"t":"열두 시 오십이 분","q":"새해 전야, 아니 정확히는 1998년 새해 아침의 이른 시각. 정확히 말하자면 열두 시 오십이 분이었다. 나는 내가 원하는 것을 깨달았다. 관심이었다.","title":"사랑과 눈물의 해","author":"케네스 로빈슨","ampm":"am","kind":"역"}],"00:53":[{"t":"열두 시 오십삼 분","q":"하지만 이번엔 그가 너무 천천히 깨어나서, 재클린은 그가 완전히 정신을 차리기도 전에 이미 수화기를 들고 여보세요라고 말한 뒤였다. 시계는 열두 시 오십삼 분을 가리키고 있었다. 미드가 전화하기엔 조금 이른 시간인데, 그럼 대체 누구일까?","title":"충동","author":"마이클 위버","ampm":"am","kind":"역"}],"00:54":[{"t":"한 시 육 분 전","q":"모두가 즐거웠고 모두가 서로를 칭찬했다. 어색함은 금세 사라졌고, 노래와 일화와 술잔이 이어지며 무르익은 시간이 쏜살같이 흘렀다. 한 시 육 분 전, 흥이 절정에 달했을 때 쾅! 하는 소리와 함께 사방이 순식간에 조용해졌다.","title":"쌍발총 탐정 이야기","author":"마크 트웨인","ampm":"am","kind":"역"}],"00:55":[{"t":"열두 시 오십오 분","q":"잠시 후 현실감이 돌아왔고, 그녀는 자신이 환각을 본 게 아니라 꿈을 꾼 것임을 깨달았다. 책상 위 시계는 열두 시 오십오 분을 가리키고 있었다. 십 분짜리 세션을 열두 시 이십오 분에 시작했으니, 이십 분의 공백을 설명해야 했다.","title":"인클레이브","author":"캐런 핸콕","ampm":"am","kind":"역"}],"00:56":[{"t":"열두 시 오십육 분","q":"열두 시 오십육 분, 조 오코너는 결국 잠들기를 포기했다. 몇 시간째 그녀는 루이스와 스토미, 사라 투 나이브스를 걱정하며 깨어 있었다. 그리고 코크도.","title":"바운더리 워터스","author":"윌리엄 켄트 크루거","ampm":"am","kind":"역"}],"00:57":[{"t":"열두 시 오십칠 분","q":"일 분이 지나자 롤러가 새 잎을 떨어뜨렸다. 열두 시 오십칠 분. 12 더하기 57은 69, 6 더하기 9는 15, 1 더하기 5는 6이었다.","title":"본질의 교훈","author":"데이나 스탠드리지","ampm":"am","kind":"역"}],"00:58":[{"t":"자정 오십팔 분","q":"자정 오십팔 분, 중앙유럽 표준시. \"다 준비됐어. 이제 우리가 할 일은…\" 윌리엄은 그 목소리가 사라질 때까지 미동도 하지 않았다. 더 많은 말이 이어졌지만 바람에 흩어졌다. 그는 방수포를 조금 들어올렸고, 그의 시선은 구명보트에서 몇 야드 떨어진 곳에 선 네 남자에게 멈췄다.","title":"낫싱 벤처드","author":"제프리 아처","ampm":"am","kind":"역"}],"00:59":[{"t":"한 시 일 분 전","q":"뒤늦게 지나가는 자동차 소리만이 희미하게 정적을 깨뜨렸다. 나는 손목시계를 보았다. 한 시 일 분 전이었다. 고개를 들자, 어디선가 조급한 시계가 그 사실을 확인시켜주었다. 나는 하품을 하며 테리어에게 이제 자라 이르고는 스위치로 손을 뻗었다. 그 순간 녀석이 다시 으르렁댔다.","title":"베리 앤 코","author":"돈포드 예이츠","ampm":"am","kind":"역"}],"01:01":[{"t":"한 시 일 분","q":"한 시 일 분, 유난히 자존심 강한 포터가 더 볼일이 없음을 무심히 확인하고 물러가자, 소녀는 사치스러운 침대 가장자리에 주저앉아 흥분으로 발갛게 상기된 채 거울 속에서 자신을 마주 보는 낯선 여인을 바라보았다.","title":"노바디","author":"루이스 조지프 밴스","ampm":"am","kind":"역"}],"01:02":[{"t":"한 시 이 분","q":"팰런은 한 시 이 분에 정문 앞에 다다랐고, 그 우쭐한 걸음걸이가 사태의 전개에 대한 만족을 드러내고 있었다.","title":"해뜨기 전의 피","author":"아만다 보닐라","ampm":"am","kind":"역"}],"01:03":[{"t":"한 시 삼 분","q":"클리블랜드가 토론토 쪽에 그 사실을 넘긴 건 한 시 삼 분, 그러니까 칠 분 전이었다.","title":"에어포트","author":"아서 헤일리","ampm":"am","kind":"역"}],"01:04":[{"t":"한 시 사 분","q":"지붕 위 전광시계는 그들이 덜컹거리며 지나갈 때 한 시 사 분을 가리키고 있었다.","title":"모트메인","author":"아서 체니 트레인","ampm":"am","kind":"역"}],"01:05":[{"t":"한 시 오 분","q":"확실합니다, 나리. 우리 마구간으로 들어선 게 정확히 한 시 오 분이었습니다.","title":"헤라파스가의 재산","author":"J.S. 플레처","ampm":"am","kind":"역"}],"01:06":[{"t":"한 시 육 분","q":"저택으로 걸려 온 그의 전화는 한 시 육 분에 있었다.","title":"산타클로스 살인 사건","author":"P.D. 제임스","ampm":"am","kind":"역"}],"01:07":[{"t":"한 시 칠 분","q":"한 시 칠 분, 라몬트는 뒤에서 다가오는 자동차 소리를 들었다.","title":"모험 없이는","author":"제프리 아처","ampm":"am","kind":"역"}],"01:08":[{"t":"한 시 팔 분","q":"라디오 알람 시계가 한 시 팔 분을 밝히고 있을 때, 계단에서 발소리가 들리더니 잠시 멈췄다가 겁먹은 듯한 노크 소리가 들려왔다.","title":"본 클락스","author":"데이비드 미첼","ampm":"am","kind":"역"}],"01:09":[{"t":"한 시 구 분","q":"수요일 새벽 한 시 구 분, '자기, 저들이 이게 속임수였다는 걸 알아챌 것 같아?'","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"01:10":[{"t":"한 시 십 분","q":"뒷문은 잠겨 있지 않았습니다, 나리. 콜드웰과 메이크피스 양이 조명을 점검하던, 대략 한 시 십 분쯤의 일이었죠.","title":"산타클로스 살인 사건","author":"P.D. 제임스","ampm":"am","kind":"역"}],"01:11":[{"t":"한 시 십일 분","q":"나는 문을 살짝 열어 두었고, 한 시 십일 분에 하비가 거실을 가로질러 걷는 소리를 들었다.","title":"빌리언 달러 브레인","author":"렌 데이턴","ampm":"am","kind":"역"}],"01:12":[{"t":"한 시 십이 분","q":"그는 시계를 보았다. 새벽 한 시 십이 분을 가리키고 있었다.","title":"바티칸의 그림자","author":"레이 키팅","ampm":"am","kind":"역"}],"01:13":[{"t":"한 시 십삼 분","q":"그는 수첩을 꺼내 그 수수께끼 같은 초 상인이 했던 말을 소리 내어 읽었다. '내가 마지막 숨을 거둔 건 정확히 일월 이십사일 한 시 십삼 분이었소.'","title":"아틀란티스","author":"게르하르트 하웁트만","ampm":"am","kind":"역"}],"01:14":[{"t":"한 시 십사 분","q":"'지금이,' 그는 시계를 보며 말했다, '정확히 한 시 십사 분이야.'","title":"길 위에서","author":"잭 케루악","ampm":"am","kind":"역"}],"01:15":[{"t":"한 시 십오 분","q":"새벽 한 시 십오 분에 로빈이 낼 수 있는 최선치고는 좀 약했지만, 그로서는 그게 다였다.","title":"한 푼도 더도 덜도 말고","author":"제프리 아처","ampm":"am","kind":"역"}],"01:16":[{"t":"한 시 십육 분","q":"한 시 십육 분, 그들은 취조실로 들어갔다.","title":"황금빛은 오래가지 않는다","author":"데이나 스타베노우","ampm":"am","kind":"역"}],"01:17":[{"t":"한 시 십칠 분","q":"헤이즐이 시계를 확인했다. 한 시 십칠 분이었다.","title":"구두닦이 소년","author":"제프리 아처","ampm":"am","kind":"역"}],"01:18":[{"t":"한 시 십팔 분","q":"토요일 밤, 아니 정확히는 일요일 새벽, 한 시 십팔 분이었다.","title":"서머랜드","author":"엘린 힐더브랜드","ampm":"am","kind":"역"}],"01:19":[{"t":"한 시 십구 분","q":"분침은 어느새 한 시 십구 분을 가리키고 있었고, 그녀의 신경은 점점 더 곤두섰다.","title":"유령 같은 남편","author":"엘리자베스 오거스트","ampm":"am","kind":"역"}],"01:20":[{"t":"한 시 이십 분","q":"잠에서 깨어 침대맡 시계를 보니 한 시 이십 분이었다. 심장이 사납게 뛰고 있었다.","title":"장님 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"am","kind":"역"}],"01:21":[{"t":"한 시 이십일 분","q":"금요일 새벽 한 시 이십일 분, '이름이 밴스인가?' 서투른 영어의 러시아어 억양은 그가 전혀 예상치 못한 것이었다.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"01:22":[{"t":"한 시 이십이 분","q":"아버지의 무덤을 찾아낸 건 한 시 이십이 분이었다.","title":"엄청나게 시끄럽고 믿을 수 없게 가까운","author":"조너선 사프란 포어","ampm":"am","kind":"역"}],"01:23":[{"t":"한 시 이십삼 분","q":"크로이던 센트럴의 개표는 새벽 한 시 이십삼 분에 발표되었고, 보수당 쪽으로 1.8퍼센트의 표심 이동이 있었다.","title":"이것이 한 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"01:24":[{"t":"한 시 이십사 분","q":"라킨은 새벽 한 시 이십사 분에 숨을 거두었다. 곁을 지키던 간호사에게 고개를 돌려 손을 꼭 쥐고는, 힘없는 목소리로 '나는 이제 피할 수 없는 곳으로 간다'고 말했다.","title":"몸의 조각들: 삶을 쓰는 것에 관한 에세이","author":"허마이오니 리","ampm":"am","kind":"역"}],"01:25":[{"t":"한 시 이십오 분","q":"그가 마지막 힘을 다해 일어나려다 다시 주저앉았다. 고개는 소파 쿠션 위로 떨어졌다. 그때가 한 시 이십오 분이었다.","title":"월장석","author":"윌키 콜린스","ampm":"am","kind":"역"}],"01:26":[{"t":"한 시 이십육 분","q":"정류장에 도착해 내렸을 때는 버스 자체 시계로도 이미 새벽 한 시 이십육 분이었다.","title":"실버 메탈 러버","author":"타니스 리","ampm":"am","kind":"역"}],"01:27":[{"t":"한 시 이십칠 분","q":"그 영수증은 일월 일일 새벽 한 시 이십칠 분, 그 주유소에서 발급된 것이었다.","title":"블러드 할로우","author":"윌리엄 켄트 크루거","ampm":"am","kind":"역"}],"01:29":[{"t":"한 시 이십구 분","q":"그가 남자 화장실을 나선 건 새벽 한 시 이십구 분이었다.","title":"마약 수사관","author":"윌리엄 에드먼드 버터워스","ampm":"am","kind":"역"}],"01:30":[{"t":"한 시 반","q":"'한 시 반,' 가로등이 지직거렸다. 가로등이 중얼거렸다. 가로등이 말했다, '저 여자를 보라...'","title":"바람 부는 밤의 광시곡","author":"T.S. 엘리엇","ampm":"am","kind":"역"}],"01:31":[{"t":"한 시 삼십일 분","q":"새벽 한 시 삼십일 분이었다. 그는 크라운을 한 잔 더 따랐다. 그것을 비우고 같은 과정을 두 번 더 반복했다.","title":"웨스털리","author":"마이클 E. 뉴얼","ampm":"am","kind":"역"}],"01:32":[{"t":"한 시 삼십이 분","q":"그녀는 커다란 각진 이를 드러내며 짓궂은 웃음을 지어 보이고는 계단을 향해 달렸다. 한 시 삼십이 분. 호루라기 소리가 들린 것 같아 마지막 세 계단을 단숨에 뛰어내렸다.","title":"이스탄불행 열차","author":"그레이엄 그린","ampm":"am","kind":"역"}],"01:33":[{"t":"한 시 삼십삼 분","q":"그는 손목시계를 들여다보았다. 새벽 한 시 삼십삼 분. 한 시간 반 넘게 이 벤치에서 잠들어 있었던 것이다.","title":"스켈레톤스","author":"캣 폭스","ampm":"am","kind":"역"}],"01:34":[{"t":"한 시 삼십사 분","q":"머틀은 잠을 이룰 수 없었다. 디지털시계의 빛나는 숫자는 새벽 한 시 삼십사 분을 가리켰다, 평생 이렇게 늦도록 깨어 있어 본 적이 없었다. 하지만 의문들이 너무 많고 집요해서 그녀를 놓아주지 않았다.","title":"가라앉은 희망","author":"도널드 E. 웨스트레이크","ampm":"am","kind":"역"}],"01:35":[{"t":"한 시 삼십오 분","q":"이틀 후, 한밤중에 다이어리의 차임벨 소리가 메랄을 깨웠다. 그는 몸을 일으켜 화면의 시계를 들여다보았다. 한 시 삼십오 분. 메시지가 오기엔 이상한 시각이었다, 배가 발견된 것일까?","title":"어둠의 토대","author":"크리스 월리","ampm":"am","kind":"역"}],"01:36":[{"t":"한 시 삼십육 분","q":"그날 새벽, 아버지의 시계로 한 시 삼십육 분이라는 고요하고 엄숙한 시각에, 나는 통상적인 격식과 의례를 갖추어 허리 가문의 아홉째이자 막내로 이 세상에 태어났다.","title":"허리케인 허리","author":"W.H.G. 킹스턴","ampm":"am","kind":"역"}],"01:37":[{"t":"한 시 삼십칠 분","q":"\"오늘 새벽 한 시 삼십칠 분, 기지 내부에서 암호화된 메시지가 발신됐습니다.\"","title":"아웃캐스츠","author":"게일 딜레이니","ampm":"am","kind":"역"}],"01:38":[{"t":"한 시 삼십팔 분","q":"새벽 한 시 삼십팔 분, 용의자는 드라이브인을 나서 월넛 북로 723번지로 차를 몰아 저택 뒤편에 주차했다.","title":"더 나크","author":"윌리엄 에드먼드 버터워스","ampm":"am","kind":"역"}],"01:39":[{"t":"한 시 삼십구 분","q":"블루아이드보이의 웹저널이다, 게시 시각은 금요일 2월 22일 새벽 한 시 삼십구 분, 기분은 험악함, 듣던 곡은 글로리아 게이너의 'I Will Survive'.","title":"블루아이드보이","author":"조앤 해리스","ampm":"am","kind":"역"}],"01:40":[{"t":"한 시 사십 분","q":"3월 12일 새벽 한 시 사십 분, 그녀는 술친구들과 헤어져 집으로 가는 버스를 타러 나섰다. 하지만 끝내 도착하지 못했다.","title":"뼛속의 재","author":"캐시 라이크스","ampm":"am","kind":"역"}],"01:42":[{"t":"한 시 사십이 분","q":"새벽 한 시 사십이 분 이십육 초, 비행기는 니미츠 언덕 사면에 시속 백 마일의 속도로 충돌했다, 육천만 달러와 이십일만 이천 킬로그램의 강철이 바위투성이 땅에 처박혔다.","title":"아웃라이어","author":"맬컴 글래드웰","ampm":"am","kind":"역"}],"01:43":[{"t":"한 시 사십삼 분","q":"새벽 한 시 사십삼 분, 보수당이 바질던을 차지하면서 환호는 더욱 커졌다, 엠마의 차트로는 보수당이 삼십 석가량 과반을 넘길 듯했다.","title":"디스 워즈 어 맨","author":"제프리 아처","ampm":"am","kind":"역"}],"01:44":[{"t":"두 시 십육 분 전","q":"이틀간 이어진 스트레스 탓임을 그녀는 알았다, 시계를 보니 두 시 십육 분 전이었고, 그녀는 놀라 펄쩍 뛸 뻔했다, 대체 시간이 어디로 가버린 걸까.","title":"트래커스","author":"데온 마이어","ampm":"am","kind":"역"}],"01:45":[{"t":"한 시 사십오 분","q":"결국 나는 클라레 한 잔을 받아들였다. 마차시계가 한 시 사십오 분을 알릴 때에야 그는 정신을 차리고 말했다, 미안하네 사촌, 취했나 보군, 자네 어깨 좀 빌리세.","title":"미슬토 살인 사건","author":"P.D. 제임스","ampm":"am","kind":"역"}],"01:47":[{"t":"한 시 사십칠 분","q":"그날 밤 코크는 잠에서 깨어 침대 옆 탁자의 시계를 보았다, 새벽 한 시 사십칠 분, 그리고 자신이 혼자라는 것을 깨달았다.","title":"머시 폴스","author":"윌리엄 켄트 크루거","ampm":"am","kind":"역"}],"01:48":[{"t":"한 시 사십팔 분","q":"\"페리파트 씨, 당신은 사이공 정부의 특별 허가를 받아 즉시 출발했다가 현지 시각 새벽 한 시 사십팔 분에 이곳으로 돌아왔습니다.\"","title":"피니티","author":"존 반스","ampm":"am","kind":"역"}],"01:49":[{"t":"한 시 사십구 분","q":"전화벨이 두 번째로 울렸을 때 팜플무스 씨는 잠긴 눈을 겨우 뜨고서야 침대 머리맡 디지털시계의 숫자, 한 시 사십구 분을 알아볼 수 있었다.","title":"팜플무스 씨와 투사 산파들","author":"마이클 본드","ampm":"am","kind":"역"}],"01:50":[{"t":"두 시 십 분 전","q":"독신인 법률비서든 바텐더든 치과교정의든 다들 고양이 한두 마리는 키우지 않던가, 그녀는 생각했다, 새벽 두 시 십 분 전이라 해도 단 한 순간조차 그런 상투적인 존재가 되는 것만은 견딜 수 없었다.","title":"도그","author":"미셸 허먼","ampm":"am","kind":"역"}],"01:51":[{"t":"두 시 구 분 전","q":"두 시 구 분 전, 다른 차량이 도착했다. 처음에 밀라는 자기 눈을 믿을 수 없었다, 저 형체와 저 문양을.","title":"트래커스","author":"데온 마이어","ampm":"am","kind":"역"}],"01:52":[{"t":"두 시 팔 분 전","q":"링크는 텔레파시로 지금이 새벽 두 시 팔 분 전임을 확인해 주었다. 변칙이 다시 나타나기까지 이제 딱 팔 분 남은 셈이었다, 26세기의 시간이 내게서 빠르게 새어나가고 있었다.","title":"타임리스 저니","author":"엘리엇 사키","ampm":"am","kind":"역"}],"01:53":[{"t":"두 시 칠 분 전","q":"보니는 노인에게 자라고 이르고 방을 나와 소리 없이 자기 방 창가로 돌아왔다. 방에 들어온 지 채 일 분도 안 되어 뷰익이 돌아오는 소리가 들렸다, 그때가 두 시 칠 분 전이었다.","title":"산이 감춘 비밀","author":"아서 업필드","ampm":"am","kind":"역"}],"01:54":[{"t":"두 시 육 분 전","q":"두 시 육 분 전. 야니나 멘츠는 화면을 지켜보았다, 자잘한 프로그램 창이 파일들을 너무 빠르게 훑어 내려 읽을 수도 없었다, 그 안에서 그녀는 키워드를 찾고 있었다.","title":"트래커스","author":"딘 쿤츠","ampm":"am","kind":"역"}],"01:55":[{"t":"한 시 오십오 분","q":"새벽 한 시 오십오 분, 베이사이드, 퀸스. 지하 아파트로 이어지는 계단은 두 갈래였다, 하나는 좁은 뒷마당에서, 다른 하나는 집 안에서 이어졌다.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"01:56":[{"t":"한 시 오십육 분","q":"\"페리파트 씨, 당신은 한 시 오십육 분에 제게 다시 종료 모드로 들어가라고 명령하셨습니다.\"","title":"피니티","author":"존 반스","ampm":"am","kind":"역"}],"01:57":[{"t":"한 시 오십칠 분","q":"그러고 나서 나는 눈을 뜨고 손목시계를 보았다. 한 시 오십칠 분이었다. 어딘가로 이십오 분이 사라져 있었다, 나쁘지 않다고 스스로에게 말했다, 시간을 깎아 없애는 무의미한 방식이었지만, 나쁘지 않았다.","title":"눈먼 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"am","kind":"역"}],"01:58":[{"t":"두 시 이 분 전","q":"두 시 이 분 전이었다. 나는 손전등과 봉투를 확인하고 재킷 너머로 권총집의 단단함을 팔 안쪽으로 느꼈다. 그것이 마음을 놓이게 했다.","title":"불릿 포 어 스타","author":"스튜어트 M. 카민스키","ampm":"am","kind":"역"}],"01:59":[{"t":"두 시가 되기 직전","q":"폰더는 깜빡 졸았던 모양이었다, 새벽 두 시가 되기 직전 비명소리에 잠에서 깼는데, 정신을 차려보니 저녁 접시 절반에 얼굴을 처박고 있었다.","title":"라스트 콘티넨트","author":"테리 프래쳇","ampm":"am","kind":"역"}],"02:01":[{"t":"두 시 일 분","q":"나는 시계를 확인했다. 새벽 두 시 일 분. 치즈버거 해피밀은 이미 아득한 추억이 되어 있었다, 아침용 샌드위치를 함께 주문해두지 않은 것이 후회스러웠다.","title":"T.S. 스파이벳의 발명 노트","author":"레이프 라르센","ampm":"am","kind":"역"}],"02:02":[{"t":"두 시쯤","q":"\"한밤중이었다니?\" 앨릭이 날카롭게 물었다, \"좀 더 정확히 말해줄 수 있어?\" \"두 시쯤. 막 지났을 때.\" 데이지는 그가 자신의 안전을 조금도 걱정하지 않았음을 알아챘다.","title":"죽음은 물속에서","author":"카롤라 던","ampm":"am","kind":"역"}],"02:03":[{"t":"두 시 삼 분","q":"두 시 삼 분, 모텔 복도의 불빛이 깜박이다 꺼지면서 긴 복도는 어둠에 잠겼고, 계단통에서 새어 나오는 빛만이 유일한 광원이었다.","title":"본 아이덴티티","author":"로버트 러들럼","ampm":"am","kind":"역"}],"02:04":[{"t":"두 시 사 분","q":"\"일어나.\" \"최악의 꿈을 꿨어.\" \"그랬을 만하네.\" \"끔찍했어. 끝없이 이어졌어.\" \"계속 흔들어 깨웠는데.\" \"몇 시야.\" \"거의, 두 시 사 분이야.\"","title":"오블리비언","author":"데이비드 포스터 월리스","ampm":"am","kind":"역"}],"02:05":[{"t":"새벽 두 시 오 분","q":"새벽 두 시 오 분, 퀸스 플러싱. 진동으로 맞춰둔 그녀의 휴대폰이 침대 옆 협탁 위에 놓여 있었다.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"02:06":[{"t":"두 시 육 분","q":"시각은 두 시 육 분이었다. 조나는 어떻게 됐을까? 그와 해리는 아마 오 분쯤 늦게 도착할 터였다.","title":"베리 앤 코","author":"돈퍼드 예이츠","ampm":"am","kind":"역"}],"02:07":[{"t":"새벽 두 시 칠 분","q":"잠이 오지 않았다. 나는 새벽 두 시 칠 분에 침대에서 일어났고, 시어스 아저씨가 무서워서 아래층으로 내려가 현관문을 나서 채플 로드로 갔다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"02:08":[{"t":"두 시 팔 분","q":"그녀는 재빨리 옷을 챙겨 입고 두 번째 운동화 끈을 마저 묶었다. 시계는 이제 두 시 팔 분을 가리키고 있었다.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"02:09":[{"t":"새벽 두 시 구 분","q":"새벽 두 시 구 분, 퀸스 자메이카. 알다울라의 집 밖에서 FBI 요원들이 자리를 잡았다. 지상뿐 아니라 이 층 침실 창밖의 일 층 지붕 위에도.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"02:10":[{"t":"두 시 십 분","q":"그녀는 침대맡 등을 켜고 안경을 더듬어 찾은 뒤 협탁 위에서 조용히 째깍거리는 회중시계를 들여다보았다. 겨우 두 시 십 분이었다. 아침까지 기다릴 여유는 없었다.","title":"죽음의 취향","author":"P.D. 제임스","ampm":"am","kind":"역"}],"02:11":[{"t":"두 시 십일 분","q":"잘 숨겨진 전화기들은 자비를 모르는 병사처럼 명령을 기다렸다. 그리고 그 명령은 정확히 미 동부시간 두 시 십일 분 십칠 초에 떨어졌다.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"02:12":[{"t":"새벽 두 시 십이 분","q":"새벽 두 시 십이 분이면 프랑스인이 다시 방송을 시작하리라는 걸 베르너는 알고 있었다. 그러면 수신기를 꺼야 하거나, 잡음만 들리는 척해야 했다.","title":"우리가 볼 수 없는 모든 빛","author":"앤서니 도어","ampm":"am","kind":"역"}],"02:13":[{"t":"새벽 두 시 십삼 분","q":"잘 들어. 네 목적지는 1944년 8월 4일 금요일이고, 그 창은 22시 30분에 열릴 거야. 넌 1918년 2월 20일 수요일 새벽 두 시 십삼 분, 그러니까 지금으로부터 이십육 년도 더 전에 갈라져 나온 차원으로 가는 거야. 어떤 곳일지는 아무도 몰라.","title":"두 번째 인터넷 카페, 1부: 차원 연구자","author":"크리스 제임스","ampm":"am","kind":"역"}],"02:14":[{"t":"두 시 십사 분","q":"그가 도착했을 때보다 불 켜진 창이 늘지도 않았다. 그것만으로도 다행이었다. 총성 이후 건물 안엔 별다른 소동이 없었다. 차 안에서 시계를 흘끗 보니 두 시 십사 분이었다.","title":"총잡이가 작별하는 법","author":"맬컴 매케이","ampm":"am","kind":"역"}],"02:15":[{"t":"새벽 두 시 십오 분","q":"그는 이메일을 훑으며 대부분을 대수롭지 않게 넘겼지만, 유독 하나가 그의 호기심을 자극했다. 새벽 두 시 십오 분에 아트 불록이 보낸 메일로, 제목은 '금요일 아침 긴급'이었다.","title":"야망","author":"리 스트로벨","ampm":"am","kind":"역"}],"02:16":[{"t":"두 시 십육 분","q":"\"비행기 안에서 내가 한 말 못 들었어? 스콧 장군의 비행기가 오늘 새벽 두 시 십육 분에 사막에서 추락해 탑승자 전원이 사망했다고.\"","title":"에코 오브 투모로우","author":"롭 벅먼","ampm":"am","kind":"역"}],"02:17":[{"t":"두 시 십칠 분","q":"'헬리콥터' 한 대가 멈추더니 방향을 돌려 내게로 돌아왔다. 조명탄이 지지직대다 사그라들었고, 이번엔 탐조등 불빛이 나를 눈멀게 했다. 나는 미동도 하지 않았다. 두 시 십칠 분이었다. 로터 소음 너머로 더 낮고 묵직한 소리가 차가운 밤공기를 갈랐다.","title":"입크레스 파일","author":"렌 데이턴","ampm":"am","kind":"역"}],"02:18":[{"t":"새벽 두 시 십팔 분","q":"새벽 두 시 십팔 분이었고, 도나가 보기에 이 시간까지 일하는 사람은 다른 어느 사무실에도 없는 듯했다.","title":"무","author":"제인 스마일리","ampm":"am","kind":"역"}],"02:19":[{"t":"두 시 십구 분","q":"보조 감속기어가 무용지물이 되어 페트로스 주피터호는 더 이상 나아갈 수 없었고, 두 시 십구 분에 선장은 랜즈엔드 해안경비대에 무선으로 상황을 알리고 예인선 지원 가능 여부를 문의했다.","title":"블랙 타이드","author":"해먼드 이니스","ampm":"am","kind":"역"}],"02:20":[{"t":"두 시 이십 분","q":"두 시 이십 분, 샌디에이고로 가는 길. 선율도 내용도 없는 기괴한 불협화음을 듣고 있었다.","title":"시간을 넘어서","author":"리처드 매드슨","ampm":"am","kind":"역"}],"02:21":[{"t":"새벽 두 시 이십일 분","q":"새벽 두 시 이십일 분, 하르트만 상병이 롱드르 가의 집에서 걸어 나왔다.","title":"장군들의 밤","author":"한스 헬무트 키르스트","ampm":"am","kind":"역"}],"02:22":[{"t":"두 시 이십이 분","q":"두 번의 왕진 끝에 가장 명망 높은 의사는 포파닐라에게 그의 병이 '틀림없이 신경성'이라며, 말을 너무 많이 해 스스로를 지나치게 흥분시킨 탓이니 앞으로는 말마다 다섯을 세고 질문은 절대 하지 말며 사교 모임을 피하라고, 즉 어떤 저녁 모임에서도 두 시 이십이 분을 넘겨 머물지 말고 하루에 두 번 이상 외식하지 말라고 일렀다.","title":"포파닐라 대령의 항해","author":"벤저민 디즈레일리","ampm":"am","kind":"역"}],"02:23":[{"t":"두 시 이십삼 분","q":"좁은 침대 사정이 허락하는 한 남편 곁에 바짝 붙어 누웠지만, 그것은 선택이기도 했다. 누군가 돼지 같다고 표현했던 이들처럼 굴지 않으려 밤새 얼마나 애써 체통을 지켰던가. 의사의 아내는 시계를 보았다. 두 시 이십삼 분이었다.","title":"눈먼 자들의 도시","author":"주제 사라마구","ampm":"am","kind":"역"}],"02:24":[{"t":"새벽 두 시 이십사 분","q":"새벽 두 시 이십사 분이었다. 그녀는 아까 벗어 던진 신발에 걸려 넘어질 뻔하며 침대에서 뛰쳐나와 스웨터를 걸쳤다.","title":"당신이 떠난 후","author":"매기 오패럴","ampm":"am","kind":"역"}],"02:25":[{"t":"새벽 두 시 이십오 분","q":"새벽 두 시 이십오 분, 션에게서 전화가 왔다. 스티븐은 조용히 침대를 빠져나와 침실을 나섰다. 션의 전화라면 집안일일 수도, 국가적 위협일 수도, 그 사이 무엇이든 될 수 있었다.","title":"배신자","author":"레이 키팅","ampm":"am","kind":"역"}],"02:26":[{"t":"새벽 두 시 이십육 분","q":"새벽 두 시 이십육 분에 클로드가 남긴 음성 메시지를 들었다.","title":"불 켜진 방들","author":"리처드 메이슨","ampm":"am","kind":"역"}],"02:27":[{"t":"두 시 이십칠 분","q":"요청은 받아들여졌지만, 또 다른 서류를 작성하고 서명한 뒤에야 가능했다. 덱스터 허친스는 그날 아침 두 시 이십칠 분에 CIA 국장에게 수신자 부담 전화를 걸었다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"02:28":[{"t":"새벽 두 시 이십팔 분","q":"새벽 두 시 이십팔 분, 양은 다 세고 이제 다른 농장 동물들을 세기 시작했다.","title":"커밋먼트 씨","author":"마이크 게일","ampm":"am","kind":"역"}],"02:29":[{"t":"두 시 반이 다 되어가는","q":"그는 두 시 반이 다 되어가는 새벽에 악명 높은 이탈리아 운전자들과 씨름할 필요가 없었고, 안전가옥은 콜로세움에서 몇 블록 떨어진 곳에 있었다. 콜로세움은 서기 80년 개장 이래 로마에 서 있는 건축물이었다.","title":"바티칸 섀도스","author":"레이 키팅","ampm":"am","kind":"역"}],"02:30":[{"t":"두 시 반","q":"두 시 반 무렵, 그녀는 계단에서 들려오는 삐걱이는 발소리에 잠에서 깼다. 처음엔 겁이 났다.","title":"리틀 스트레인저","author":"세라 워터스","ampm":"am","kind":"역"}],"02:31":[{"t":"새벽 두 시 삼십일 분","q":"아파트 안에서 사람들이 소리 지르는 통에 잠에서 깼는데, 새벽 두 시 삼십일 분이었다. 그중 한 명은 아버지였고, 나는 무서웠다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"02:32":[{"t":"새벽 두 시 삼십이 분","q":"마지막 손님들은 예정된 종료 시간에서 두 시간 이 분이 지난 새벽 두 시 삼십이 분에 떠났다.","title":"로지 프로젝트","author":"그레임 심시온","ampm":"am","kind":"역"}],"02:33":[{"t":"두 시 삼십삼 분","q":"계속 안 움직이고 있었다! 두 시 삼십사 분이라니, 좋아. 두 시 삼십삼 분인데 아무 일도 일어나지 않았다. 지금 방으로 전화가 오거나, 엘리베이터 야간벨이 울린다면 어떨까.","title":"그럴싸한 여자","author":"짐 톰슨","ampm":"am","kind":"역"}],"02:34":[{"t":"두 시 삼십사 분","q":"아직도 안 움직이고 있었다! 두 시 삼십사 분, 좋아. 두 시 삼십삼 분에서 아무 일도 없었다. 지금 방 전화가 오거나 엘리베이터 야간벨이 울린다면 어쩌지.","title":"그럴싸한 여자","author":"짐 톰슨","ampm":"am","kind":"역"}],"02:35":[{"t":"새벽 두 시 삼십오 분","q":"화면에는 발신자 정보가 뜨지 않았지만, 지금이 새벽 두 시 삼십오 분이라는 것만은 알 수 있었다.","title":"시프팅 샌즈","author":"레이 키팅","ampm":"am","kind":"역"}],"02:36":[{"t":"새벽 두 시 삼십육 분","q":"헌병 대령이 나를 체포하러 온 것은 새벽 두 시 삼십육 분 무렵이었다. 삼십 초 후 나는 그 커다란 절연 장갑을 떠올렸다. 하지만 진작 떠올렸다 한들 무엇을 할 수 있었을까.","title":"입크레스 파일","author":"렌 데이턴","ampm":"am","kind":"역"}],"02:37":[{"t":"두 시 삼십칠 분","q":"1990년 6월 13일. 새벽 두 시 삼십칠 분. 그리고 십육 초.","title":"스탠드","author":"스티븐 킹","ampm":"am","kind":"역"}],"02:38":[{"t":"세 시 이십이 분 전","q":"종 치는 장치는 오래전부터 시곗바늘과 어긋나 있었고, 시곗바늘 자체도 여러 해에 걸쳐 오차가 쌓여 더는 정확한 시각을 가리키지 않았다. 그래도 일곱 번 종이 울릴 때면 바늘은 언제나 열두 시 십오 분을 가리켰으니, 그때가 바로 세 시 이십이 분 전이었다.","title":"파라오의 중개인","author":"엘스워스 더글러스","ampm":"am","kind":"역"}],"02:39":[{"t":"두 시 삼십구 분","q":"핀훼리 역장에게서 보고가 들어왔는데예, 어떤 신사분이 핀훼리에서 두 시 삼십구 분 기차를 탔다 카데요.","title":"다섯 마리 붉은 청어","author":"도로시 L. 세이어즈","ampm":"am","kind":"역"}],"02:40":[{"t":"두 시 사십 분","q":"손목시계가 두 시 사십 분을 가리켰을 때, 그녀는 떠날 준비가 되어 있었다. 가장 짙은 색 코트를 걸치고, 성냥갑 하나를 주머니에 넣은 채, 머리에 스카프를 둘렀다.","title":"개인 환자","author":"P.D. 제임스","ampm":"am","kind":"역"}],"02:41":[{"t":"두 시 사십일 분","q":"보좌관들은 여러 장군을 향한 화려한 찬사로 가득한 장황한 발표문을 원했다. 아이젠하워는 그 초안을 옆으로 치우고 직접 이렇게 썼다. \"이 연합군의 임무는 1945년 5월 7일 현지 시각 두 시 사십일 분에 완수되었다.\"","title":"문워","author":"벤 보바","ampm":"am","kind":"역"}],"02:42":[{"t":"두 시 사십이 분","q":"이번에는 고글을 쓴 까마귀였다. 패터슨은 전보를 해독해 재빨리 읽어 내려갔다. 여신 4호는 천재가 줄루 시각 두 시 사십이 분에 살롱을 떠났다고 보고했다.","title":"나이트 헤론","author":"애덤 브룩스","ampm":"am","kind":"역"}],"02:43":[{"t":"두 시 사십삼 분","q":"맥스는 헐떡이며 악몽에서 깨어나 캄캄한 방에서 눈을 번쩍 떴다. 두 번 눈을 깜박이고, 시야에 떠오른 두 시 사십삼 분이라는 시각에 신음을 삼켰다. \"넌 진짜 곰은 본 적도 없잖아.\" 그녀가 중얼거렸다.","title":"어둠 속의 창백한 빛","author":"K.B. 웨이거스","ampm":"am","kind":"역"}],"02:44":[{"t":"세 시 십육 분 전","q":"\"당신, 세 시 십육 분 전에 여기 왔잖아요.\" 론이 손목시계를 들여다보았다.","title":"혐오스러운 남자","author":"마이 셰발","ampm":"am","kind":"역"}],"02:45":[{"t":"세 시 십오 분 전","q":"잠에서 깨니 이미 밤이었고, 달빛이 방 안을 비추고 있었다. 시계를 보니 세 시 십오 분 전이었다. 잠이 완전히 달아나 그는 침대에 걸터앉아 늙은 백작 부인의 장례식을 떠올렸다.","title":"스페이드 여왕","author":"알렉산드르 푸시킨","ampm":"am","kind":"역"}],"02:46":[{"t":"두 시 사십육 분","q":"비키는 안경을 밀어 올리고 시계를 노려보았다. 두 시 사십육 분. \"이럴 시간 없는데\" 그녀는 중얼거리며 베개에 다시 몸을 기댔다. 심장은 여전히 갈비뼈를 두드리고 있었다.","title":"블러드 라인스","author":"타냐 허프","ampm":"am","kind":"역"}],"02:47":[{"t":"두 시 사십칠 분","q":"두 시 사십칠 분, 소녀가 와 있는 것을 알아챈다. 어젯밤보다 조금 이르다. 오늘은 자리를 지키며 그녀가 나타나기를 기다린다. 가끔 눈을 깜박이는 것 말고는 한 번도 눈을 감지 않는다.","title":"해변의 카프카","author":"무라카미 하루키","ampm":"am","kind":"역"}],"02:48":[{"t":"세 시 십이 분 전","q":"\"조용히 해, 베티. 곤란해질 수 있어.\" 그는 그녀를 거의 밀어붙이듯 책상에서 맥스 쪽으로 보냈다. 잠시 후 그는 현관문 옆 스위치를 내려 방을 어둡게 했다. 문틈 너머로, 시계는 세 시 십이 분 전을 가리키고 있었다.","title":"눈먼 동맹","author":"베이너드 켄드릭","ampm":"am","kind":"역"}],"02:49":[{"t":"새벽 두 시 사십구 분","q":"새벽 두 시 사십구 분, 읍서기가 마이크 앞으로 돌아와 다시 한번 두드렸다. 잠깐의 정적은 탁자에서 떨어진 연필이 바닥을 구르는 소리에만 깨졌다.","title":"펜은 칼보다 강하다","author":"제프리 아처","ampm":"am","kind":"역"}],"02:50":[{"t":"두 시 오십 분","q":"두 시 오십 분이 되었는데도 은행마저 습격당하지 않았을 때, 오늘이 대규모 작전을 벌일 날이 아님은 분명해졌다.","title":"잠긴 방","author":"마이 셰발 & 페르 발뢰","ampm":"am","kind":"역"}],"02:52":[{"t":"새벽 세 시 팔 분 전","q":"그것은 외로움에서 비롯된 충동이었다. 때는 일요일 새벽 세 시 팔 분 전이었다.","title":"아침의 노래","author":"제럴드 세이무어","ampm":"am","kind":"역"}],"02:53":[{"t":"세 시 칠 분 전","q":"그들은 불라와요 외곽의 첫 검문소에 도착했고, 크레이그는 손목시계를 확인했다. 새벽 세 시 칠 분 전이었다.","title":"표범은 어둠 속을 사냥한다","author":"윌버 스미스","ampm":"am","kind":"역"}],"02:54":[{"t":"세 시 육 분 전","q":"시대가 바뀐 순간을 나는 정확히 말할 수 있다. 지난 금요일 아침 정확히 세 시 육 분 전에 시대는 바뀌었다.","title":"GB84","author":"데이비드 피스","ampm":"am","kind":"역"}],"02:55":[{"t":"세 시 오 분 전","q":"계기판 시계는 세 시 오 분 전을 가리켰다, 테오가 예상했던 것보다 늦은 시각이었다. 좁고 인적 없는 도로가 창백하게 앞으로 펼쳐지더니, 찢기고 얼룩진 리넨 조각처럼 바퀴 밑으로 미끄러져 들어갔다.","title":"사람의 아이들","author":"P.D. 제임스","ampm":"am","kind":"역"}],"02:56":[{"t":"두 시 오십육 분","q":"삽이 관에 닿은 것은 두 시 오십육 분이었다. 우리는 모두 그 소리를 듣고 서로를 쳐다보았다.","title":"엄청나게 시끄럽고 믿을 수 없게 가까운","author":"조너선 사프란 포어","ampm":"am","kind":"역"}],"02:57":[{"t":"두 시 오십칠 분","q":"그리니치 표준시로 두 시 오십칠 분이었다. 야하야는 은신처에서 빠져나와, 선박 병원에서 훔친 주사기를 오른손에 쥐었다.","title":"라이프 프로브","author":"마이클 매콜럼","ampm":"am","kind":"역"}],"02:58":[{"t":"세 시 이 분 전","q":"하지만 보통은 그 반대로, 천천히 흘러간다. 그녀가 다이얼을 완전히 멈춰 놓으면 화면 속 태양은 몇 주 동안 머리카락 한 올만큼도 움직이지 않고 얼어붙는다. 나무 잎사귀 하나, 목초지 풀잎 하나 흔들리지 않는다. 시곗바늘은 세 시 이 분 전에 멈춰 있고, 그녀 마음이라면 우리가 녹슬 때까지 그대로 둘 것이다.","title":"뻐꾸기 둥지 위로 날아간 새","author":"켄 키지","ampm":"am","kind":"역"}],"02:59":[{"t":"새벽 두 시 오십구 분","q":"그는 새벽 두 시 오십구 분에 침대에서 일어났다, 완전히 원기를 회복하고 정신이 또렷한 채로. 오두막 한가운데 놓인 커다란 궤짝으로 다가가 뚜껑을 들어 올렸다.","title":"소원할 때는 조심해야 한다","author":"제프리 아처","ampm":"am","kind":"역"}],"03:01":[{"t":"새벽 세 시쯤","q":"그것은 정확히 위스키도 아니고 정확히 진도 아니었지만, 정확히 도수 구십 도였고, 눈을 떠 자신이 누구인지 잊어버리는 새벽 세 시쯤 그 불안한 순간들에 큰 위안이 되어 주었다.","title":"귀족과 숙녀","author":"테리 프래쳇","ampm":"am","kind":"역"}],"03:02":[{"t":"세 시 이 분","q":"몇 달에 걸친 확인과 재확인 끝에, 1995년 10월 19일 서부 표준시로 세 시 이 분에 부에노스아이레스의 한 병원에서 사생아로 태어난 혼혈 조지프 리카르도는 마침내 공식적으로 인정받았다.","title":"사람의 아이들","author":"P.D. 제임스","ampm":"am","kind":"역"}],"03:03":[{"t":"세 시 삼 분","q":"세 시 삼 분, 그는 세계적인 유명 인사로서의 경력을 시작했다.","title":"지구를 뒤흔든 남자","author":"아서 C. 트레인, 로버트 W. 우드","ampm":"am","kind":"역"}],"03:04":[{"t":"세 시 사 분","q":"그는 침대맡 탁자 위 최전선 시계를 보았다. 세 시 사 분에 멈춰 있었다. 그러니 자명종도 믿을 게 못 됐다.","title":"춤추는 선생의 귀환","author":"헤닝 만켈","ampm":"am","kind":"역"}],"03:05":[{"t":"세 시 오 분","q":"\"오 분 전엔 세 시였어,\" 머피가 말했다. \"확신할 순 없지만, 지금쯤이면 세 시 오 분쯤 됐을 거야.\" 나는 팔짱을 꼈다. \"난 잠복근무는 잘 안 해.\"","title":"화이트 나이트","author":"짐 부처","ampm":"am","kind":"역"}],"03:06":[{"t":"새벽 세 시 육 분","q":"새벽 세 시 육 분, \"여기요,\" 페티그루 양이 가냘픈 목소리로 말했다. 조가 그녀 위로 우뚝 섰다. 그는 말없이 팔을 걸었고, 그 다정하고 소유욕 어린 남자다운 배려는 페티그루 양이 여태 겪어본 적 없는 것이었다. 그녀는 그저 힘없이 그에게 기대었다.","title":"페티그루 양의 어느 특별한 하루","author":"위니프레드 왓슨","ampm":"am","kind":"역"}],"03:07":[{"t":"세 시 칠 분","q":"그는 시계를 흘긋 보았다. 세 시 칠 분. 설마 피오나일까? 그는 억지로 침대에서 몸을 일으켜 가운을 걸치고 마지못해 문 쪽으로 걸어갔다.","title":"헤즈 유 윈","author":"제프리 아처","ampm":"am","kind":"역"}],"03:08":[{"t":"세 시 팔 분","q":"안개가 걷혀 가면서 저택의 윤곽이 드러났다, 창문마다 흐릿한 불빛이 새어 나오는 짙은 그림자였다. 손목시계는 세 시 팔 분을 가리켰다. 다들 지금쯤 각자의 방에서 홀로 묵상하며 네 시의 최종 투표 소집을 기다리고 있을 터였다.","title":"검은 탑","author":"P.D. 제임스","ampm":"am","kind":"역"}],"03:09":[{"t":"세 시 구 분","q":"홀은 롤렉스를 보았다. 세 시 구 분이었지만, 뻐꾸기시계는 단 한 번도 시각을 알리지 않았다. 대체 언제부터 이랬던 걸까, 아니면 언제부터 멈춰 있던 걸까.","title":"파멸로 가는 길","author":"도널드 E. 웨스트레이크","ampm":"am","kind":"역"}],"03:10":[{"t":"세 시 십 분","q":"그랜트 목사가 마침내 사택으로 돌아온 것은 새벽 세 시 십 분이었다.","title":"워리어 몽크","author":"레이 키팅","ampm":"am","kind":"역"}],"03:11":[{"t":"세 시 십일 분","q":"시계는 세 시 십일 분을 가리켰다. \"네, 여보세요?\" 감정 없는 낮은 목소리가 물었다. \"스티븐 그랜트 목사님 되십니까?\"","title":"만악의 근원인가","author":"레이 키팅","ampm":"am","kind":"역"}],"03:12":[{"t":"세 시 십이 분","q":"낚시 잡지와 재떨이가 놓인 탁자, 선반 위 책 몇 권, 병에 꽂힌 초, 의자들, 그리고 세 시 십이 분에 멈춰 선 벽난로 위 시계.","title":"다른 이들과 함께","author":"잰 캐론","ampm":"am","kind":"역"}],"03:13":[{"t":"세 시 십삼 분","q":"당신은 아마 날 기억 못 하겠지만, 나는 그리니치 표준시로 세 시 십삼 분에 인간의 몸속으로 순간이동해 들어온 운 좋은 영혼이다.","title":"컴 어게인","author":"조지 로이드, 엠린 리스","ampm":"am","kind":"역"}],"03:14":[{"t":"세 시 십사 분","q":"그녀에게 끝내자고 말한 뒤로 그는 매일 아침 세 시 십사 분이면 어김없이 눈을 떴다. 전자 자명종의 붉은 숫자는 늘 세 시 십사 분을 가리키고 있었다.","title":"슬랩","author":"크리스토스 치올카스","ampm":"am","kind":"역"}],"03:15":[{"t":"세 시 십오 분","q":"69호실 문 위 시계는 세 시 십오 분을 가리키며 째깍이고 있었다. 움직임은 점점 빨라졌다. 한때 체육관이었던 그곳은 이제 폭 이 미터 남짓한, 거의 완벽한 정육면체의 작은 방이 되어 있었다.","title":"맨홀 69","author":"J.G. 밸러드","ampm":"am","kind":"역"}],"03:16":[{"t":"세 시 십육 분","q":"레베카와 애비는 구급차로 병원에 실려 갔다. 애비는 몇 시간 뒤 가벼운 찰과상만 입고 퇴원했지만, 레베카 라우든은 오늘 새벽 세 시 십육 분에 경동맥 손상을 회복하지 못하고 사망 선고를 받았다.","title":"안전한 곳","author":"엠마 솔즈베리","ampm":"am","kind":"역"}],"03:17":[{"t":"세 시 십칠 분","q":"하산은 손목시계를 확인했다. 세 시 십칠 분. 갑판 위에서 아직 깨어 있을 사람은 그 젊은이뿐일 거라 확신했다. 룩이 비숍 네 칸으로. 그녀는 나이트 하나를 판에서 치웠다.","title":"넥스트 인 라인","author":"제프리 아처","ampm":"am","kind":"역"}],"03:18":[{"t":"세 시 십팔 분","q":"우리가 진실을 알 길은 영영 없을지도 모른다. 다만 확실한 건, 이월 십일 세 시 십팔 분에 서던크로스호가 얼음에 단단히 갇혀 SOS를 타전하고 있었다는 사실뿐이다.","title":"화이트 사우스","author":"해먼드 인스","ampm":"am","kind":"역"}],"03:19":[{"t":"세 시 십구 분","q":"나비드슨의 캠코더에 찍힌 시각은 정확히 새벽 세 시 십구 분을 가리키고 있었다.","title":"나뭇잎의 집","author":"마크 Z. 다니엘레프스키","ampm":"am","kind":"역"}],"03:20":[{"t":"세 시 이십 분","q":"프라바트 쿠마라, 16세. 1989년 11월 17일. 새벽 세 시 이십 분, 친구 집에서.","title":"아닐의 유령","author":"마이클 온다치","ampm":"am","kind":"역"}],"03:21":[{"t":"세 시 이십일 분","q":"그는 샤워도 면도도 하지 않고 전날 입었던 옷을 그대로 걸쳤다. 퀸스의 아파트를 세 시 이십일 분에 나서 맨해튼으로 차를 몰았고, 네 시가 되기 몇 분 전 경찰서 앞에 차를 세웠다.","title":"명예로운 도둑들","author":"제프리 아처","ampm":"am","kind":"역"}],"03:22":[{"t":"세 시 이십이 분","q":"\"신사 숙녀 여러분, 오늘 새벽 세 시 이십이 분, 뉴멕시코 소코로의 GEODSS 센서망이 달 궤도 바깥에서 정체불명 물체를 포착했습니다.\"","title":"더 기프트","author":"데이브 도노반","ampm":"am","kind":"역"}],"03:23":[{"t":"세 시 이십삼 분","q":"지금은 세 시 이십삼 분, 그의 비행기는 오전 여덟 시에 떠난다.","title":"캔디랜드","author":"에번 헌터, 에드 맥베인","ampm":"am","kind":"역"}],"03:24":[{"t":"세 시 이십사 분","q":"\"설마 그럴 리가!\" 그녀가 놀렸다. \"대륙 횡단 노선을 잇고, 세상을 팔십 일 만에, 아니 이젠 사십 일 만에 도는 거요? 여행객들에게 세 시 이십사 분 기차 시각을 알려주고 시간표를 나눠주는 그 고귀한 교육 수단 말이에요.\" \"난 여기가 좋아,\" 그가 고집스레 말했다.","title":"성공: 어느 소설","author":"새뮤얼 홉킨스 애덤스","ampm":"am","kind":"역"}],"03:25":[{"t":"세 시 이십오 분","q":"새벽 세 시 이십오 분이었다. 이 집에서 깨어 있는 멀베이니가 나 하나뿐이라는 사실에 묘한 전율이 일었다.","title":"우리는 멀베이니가였다","author":"조이스 캐럴 오츠","ampm":"am","kind":"역"}],"03:26":[{"t":"세 시 이십육 분","q":"샘은 헝클어진 침대 가장자리에 무겁게 주저앉아 머리카락을 쓸어 넘기다 협탁 위 디지털시계를 힐끗 보았다. 붉은 숫자는 세 시 이십육 분을 깜박이고 있었고, 그는 한숨을 내쉬었다.","title":"잉크","author":"토리 매클레인","ampm":"am","kind":"역"}],"03:27":[{"t":"세 시 이십칠 분","q":"레인저를 선두로 그들은 빠른 속도로 마을을 벗어났다. 누군가 지켜봤다면, 버드케이지 벽시계가 세 시 이십칠 분을 가리키는 걸 보았을 것이다.","title":"오, 유 텍스!","author":"윌리엄 매클라우드 레인","ampm":"am","kind":"역"}],"03:28":[{"t":"세 시 이십팔 분","q":"누군가 방 앞을 뛰어 지나갔다. 문이 쾅 닫혔다. 또 그 외국어. 대체 무슨 일이지? 그는 불을 켜고 손목시계를 들여다보았다. 세 시 이십팔 분. 그는 침대에서 일어났다.","title":"떠나는 꿈들","author":"루퍼트 톰슨","ampm":"am","kind":"역"}],"03:29":[{"t":"세 시 이십구 분","q":"\"CIU에서 온 메시지일 뿐이야. 디포드의 휴대폰 통화 내역을 확보했어. 마지막 통화는 일요일 새벽 세 시 이십구 분에 다른 휴대폰으로 걸렸어. 그 뒤로는 아무도 그 번호를 쓰지 않았고.\"","title":"빌린 빛","author":"그레이엄 헐리","ampm":"am","kind":"역"}],"03:30":[{"t":"세 시 반","q":"새벽 세 시 반, 그는 한 가지 환상을 잃었다. 정찰 나갔던 장교들이 적군이 아무 움직임도 보이지 않는다고 보고해 온 것이다.","title":"레 미제라블","author":"빅토르 위고","ampm":"am","kind":"역"}],"03:31":[{"t":"세 시 삼십일 분","q":"그는 잠시 망설이다 제독 호출 아이콘에 손을 뻗었다, 마치 핵폭탄 방아쇠라도 되는 양 조심스럽게. 아라샨은 근무일지에 정확한 시각을 기입했다. 세 시 삼십일 분.","title":"슈라우드 오브 에덴","author":"말린 데솔트","ampm":"am","kind":"역"}],"03:32":[{"t":"세 시 삼십이 분","q":"오늘 새벽 세 시 삼십이 분, 여기서 북쪽으로 삼십육 마일 떨어진 헤이즐브룩 마을 근처 버려진 차 밖에서 빈 냉동 보관 실린더가 발견되었다.","title":"스칼라티가의 아들들","author":"존 맥널리","ampm":"am","kind":"역"}],"03:33":[{"t":"세 시 삼십삼 분","q":"부엌 창틀 사이로 외풍이 휘파람 소리를 내며 스며들어 나는 몸을 떨었다. 퍼커스네 스토브 위 디지털시계는 세 시 삼십삼 분을 가리키고 있었다.","title":"크로닉 시티","author":"조너선 레덤","ampm":"am","kind":"역"}],"03:34":[{"t":"세 시 삼십사 분","q":"세 시 삼십사 분, 그는 말똥말똥 깨어 있었다. 전화벨 소리와 삼촌의 목소리가 들렸던 것이다.","title":"언제나 플로렌스","author":"뮤리엘 젠슨","ampm":"am","kind":"역"}],"03:35":[{"t":"세 시 삼십오 분","q":"세 시 삼십 분, 세 시 삼십오 분, 세 시 사십 분. 갑자기 육중한 충격이 그를 좌석 밖으로 튕겨낼 뻔했다. 이어 바퀴가 요란하게 끼익거리며 기차가 급격히 속도를 줄이더니 마침내 멈춰 섰다.","title":"소원을 빌 때 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"03:36":[{"t":"세 시 삼십육 분","q":"데드호스에 가까워질 무렵, 시각은 세 시 삼십육 분이고 기온은 영하 십칠 도다. 키 큰 나트륨등이 도로를 비추고 나무 한 그루 없이 오직 기계와 그 그림자뿐이다. 교회조차 없다. 그것이 모든 것을 말해준다.","title":"주프락시스","author":"리처드 C. 매드슨","ampm":"am","kind":"역"}],"03:37":[{"t":"세 시 삼십칠 분","q":"세 시 삼십칠 분, 모처럼 매기는 잠들어 있었다. 요 몇 달 새 제법 잘 자는 아이가 되었다. 클라이드는 그 어떤 것보다 이 사실을 자랑스러워했다.","title":"거미줄","author":"스티븐 버리","ampm":"am","kind":"역"}],"03:38":[{"t":"세 시 삼십팔 분","q":"세 시 삼십팔 분, 켄터키주 볼링그린에는 눈이 내리기 시작했다. 도시 위를 맴돌던 기러기들은 공원으로 돌아와 내려앉더니 호수 섬에 웅크리고 앉아 눈을 견뎠다.","title":"우리가 알던 그런 크리스마스처럼","author":"코니 윌리스","ampm":"am","kind":"역"}],"03:39":[{"t":"세 시 삼십구 분","q":"1893년 10월 23일, 세 시 삼십구 분. 다시 생각해보니 스승의 작업장으로 유배된 것이 그리 나쁜 운명은 아니라고 밝혀두어야겠다. 그곳은 자극이라곤 없는 삭막한 지하실이 결코 아니었다, 오히려 그 반대였다.","title":"태엽 장치 인간","author":"윌리엄 야블론스키","ampm":"am","kind":"역"}],"03:40":[{"t":"세 시 사십 분","q":"머리맡 시계가 세 시 사십 분을 가리켰다. 그는 왜 잠자리에서 일어나 있는지 스스로도 알 수 없었다. 볼일이 급한 것도, 꿈이나 지난 하루의 일 때문에 뒤숭숭한 것도, 세상 돌아가는 일 때문도 아니었다.","title":"토요일","author":"이언 매큐언","ampm":"am","kind":"역"}],"03:41":[{"t":"세 시 사십일 분","q":"자명종은 세 시 사십일 분을 가리켰다. 그는 몸을 일으켰다. 자명종이 왜 이렇게 느린 걸까? 그는 자명종을 집어 들어 손목시계와 같은 시각, 세 시 사십사 분에 맞춰 바늘을 돌렸다.","title":"리가의 개들","author":"헤닝 만켈","ampm":"am","kind":"역"}],"03:42":[{"t":"세 시 사십이 분","q":"전화벨이 세 시 사십이 분에 울렸다. 이 늦은, 아니 이른 시각에 누가 전화를 한단 말인가? 그들은 겨우 몇 시간밖에 못 잤다. 부활 성야 미사는 밤 열한 시쯤 끝났고, 그녀는 그 후 여섯 시경 시작될 부활절 새벽 예배 준비를 모두 마쳐둔 참이었다.","title":"피로 얼룩진","author":"게일 시걸","ampm":"am","kind":"역"}],"03:43":[{"t":"세 시 사십삼 분","q":"시계는 세 시 사십삼 분을 가리킨다. 온도계는 쌀쌀한 화씨 십사 도를 가리킨다. 기상캐스터는 이 한파가 목요일까지 이어질 테니 단단히 껴입으라 말한다. 박쥐 동굴 창문에는 고드름이 빗장처럼 걸려 있다.","title":"유령이 쓴 소설","author":"데이비드 미첼","ampm":"am","kind":"역"}],"03:44":[{"t":"세 시 사십사 분","q":"눈을 떴을 때 굴 껍데기 빛깔의 새벽이 창문으로 스며들고 있었다. 놋쇠 자명종의 바늘은 세 시 사십사 분을 가리키고 있었다.","title":"파이 바닥의 달콤함","author":"앨런 브래들리","ampm":"am","kind":"역"}],"03:45":[{"t":"세 시 사십오 분","q":"그는 시간을 확인하려 손목시계 겉면을 만졌다, 세 시 사십오 분. 그것은 바깥문을 열고 그의 또 다른 세계, 그 안전한 곳으로 내려가게 해줄 암호였다.","title":"내 시체를 넘어서","author":"제프리 아처","ampm":"am","kind":"역"}],"03:46":[{"t":"세 시 사십육 분","q":"이번에는 연도가 먼저였다, 88, 이어서 월인 09, 그리고 마지막으로 방금 세 시 사십육 분으로 바뀐 시각이 나왔다.","title":"내 시체를 넘어서","author":"제프리 아처","ampm":"am","kind":"역"}],"03:47":[{"t":"세 시 사십칠 분","q":"나는 세 시 사십칠 분까지 깨어 있었다. 그것이 잠들기 전 마지막으로 손목시계를 본 시각이었다. 문자판이 야광이라 버튼을 누르면 불이 들어와 어둠 속에서도 읽을 수 있었다. 춥고, 아버지가 나와서 나를 발견할까 두려웠다. 하지만 정원에 숨어 있으니 더 안전하게 느껴졌다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"03:48":[{"t":"세 시 사십팔 분","q":"그는 시간을 확인했다, 세 시 사십팔 분. 암호를 입력하려던 참에 콜린스가 연미복에 줄무늬 바지, 빳빳한 흰 칼라, 회색 실크 넥타이 차림으로 태연히 방에 들어섰다.","title":"내 시체를 넘어서","author":"제프리 아처","ampm":"am","kind":"역"}],"03:49":[{"t":"세 시 사십구 분","q":"세 시 사십구 분, 그가 나를 때린 것은 내가 모르겠어요라고 이백 번을 말했기 때문이었다. 그 후로도 그는 나를 여러 번 때렸다.","title":"입크레스 파일","author":"렌 데이턴","ampm":"am","kind":"역"}],"03:50":[{"t":"세 시 오십 분","q":"내 손목시계는 세 시 오십 분을 가리켰지만, 시계는 멈춰 있었다.","title":"밤의 파도","author":"스티븐 킹","ampm":"am","kind":"역"}],"03:51":[{"t":"세 시 오십일 분","q":"라디오 겸용 시계의 디지털 표시는 세 시 오십일 분이었다. 이런 순간엔 늘 홀수다. 그게 무슨 의미일까? 죽음도 홀수로 오는 걸까?","title":"화이트 노이즈","author":"돈 드릴로","ampm":"am","kind":"역"}],"03:52":[{"t":"세 시 오십이 분","q":"말끔했다, 지나치리만큼. 항해일지는 마지막 기록에 펼쳐져 있었다. 세 시 오십이 분, 브래디 필드 등대 방위 312도, 거리 약 팔 마일.","title":"지중해 함정","author":"클라이브 커슬러","ampm":"am","kind":"역"}],"03:53":[{"t":"네 시 칠 분 전","q":"엘스 할멈에게 들은 얘기는 있지만, 아직 자네 입으로는 못 들었네. 오늘 아침 네 시 칠 분 전쯤 호그 코트에서 대체 뭘 하고 있었나?","title":"소호","author":"키스 워터하우스","ampm":"am","kind":"역"}],"03:54":[{"t":"세 시 오십사 분","q":"플로리다발 전세기는 조금 전, 세 시 오십사 분에 앨더그로브에 착륙했다.","title":"더 가진 자가 더 원한다","author":"폴 멀둔","ampm":"am","kind":"역"}],"03:55":[{"t":"세 시 오십오 분","q":"동굴 같은 지하실, 세 시 오십오 분, 홀로 떨어진 불빛 웅덩이 속에 테오 페로운이 있다.","title":"토요일","author":"이언 매큐언","ampm":"am","kind":"역"}],"03:56":[{"t":"네 시 사 분 전","q":"이제 네 시 사 분 전, 새로운 하루가 시작되었다. 균열을 갈라 벌리고 멍을 피 흐르는 상처로 만들며, 그녀가 공들여 쌓아온 모든 것을 산산조각 낼 하루였다.","title":"카산드라 콤플렉스","author":"브라이언 스테이블포드","ampm":"am","kind":"역"}],"03:57":[{"t":"세 시 오십칠 분","q":"그는 머리맡 등을 켜고 손목시계를 집어 들었다. 세 시 오십칠 분이었다. 그는 몇 시간 전 있었던 일을 떠올리기 시작했다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"03:58":[{"t":"세 시 오십팔 분","q":"클럽하우스 꼭대기의 시계는 세 시 오십팔 분을 가리킨다.","title":"언더월드","author":"돈 드릴로","ampm":"am","kind":"역"}],"03:59":[{"t":"네 시 일 분 전","q":"그는 조르 알라를 돌아보았다. 자네가 믿을 만하다 여기는 식민지 내 다른 인간들과 접촉해 몇몇 무리를 조직하게. 정문 양쪽 방책 그늘에 소규모로 모여 있게 하고, 네 시 일 분 전까지는 반드시 준비를 마치게 하게. 구할 수 있는 무기는 뭐든 들려두게.","title":"크라의 타임테크","author":"맥스 셰리든","ampm":"am","kind":"역"}],"04:01":[{"t":"네 시 일 분","q":"잠시 후 나는 편집국과 야간 데스크를 연결해 신원을 밝히고 구술을 시작했다. 우리 시각으로 네 시 일 분, 파리 시각으로 몇 시인지 확인해 함께 적어두게, 모든 전쟁을 끝내겠다는 그 남자가 프랑스 전함 한 척을 격침했다. 승선자 중 살아남은 이는 아마 없을 것이다. 마지막 문장은 지난 경험에 비추어 짐작한 것이었다.","title":"전쟁을 끝낸 남자","author":"홀리스 갓프리","ampm":"am","kind":"역"}],"04:02":[{"t":"네 시 이 분","q":"줄을 따라 오르내렸다. 아무도 두 번 눈길을 주지 않았다. 마침내 한 남자 옆에 앉았다. 그는 신경도 쓰지 않았다. 내 손목시계는 네 시 이 분을 가리켰다. 그는 늦은 건지도 몰랐다.","title":"사랑의 역사","author":"니콜 크라우스","ampm":"am","kind":"역"}],"04:03":[{"t":"네 시 삼 분","q":"지독하게 추운 일월의 아침, 네 시 삼 분에 나는 이제야 집에 도착했다. 밤새 춤을 추러 나갔다 왔는데 반쯤 취했을 뿐 완전히 녹초가 되었다.","title":"시간 여행자의 아내","author":"오드리 니페네거","ampm":"am","kind":"역"}],"04:04":[{"t":"네 시 사 분","q":"네 시 사 분이라니, 아직 이르다. 천천히 걸어도 십오 분이면 충분할 텐데, 그녀는 다섯 시쯤 오라고 했으니 모퉁이에서 기다리는 편이 낫지 않을까.","title":"천사의 언덕","author":"시릴로 비야베르데","ampm":"am","kind":"역"}],"04:05":[{"t":"네 시 오 분","q":"나뭇잎이 창문에 부딪쳐 날렸다. 네 시 오 분, 달은 하늘 한쪽으로 옮겨가 뭉게뭉게 뭉친 구름 사이로 계란 속처럼 빛나고 있었다.","title":"우리는 멀베이니가 사람들이었다","author":"조이스 캐럴 오츠","ampm":"am","kind":"역"}],"04:06":[{"t":"네 시 육 분","q":"덱스터는 케이트의 쪽지를 보고, 그녀의 얼굴을 보고, 시계를 보았다. 네 시 육 분, 그들이 레스토랑에 가기 전날 밤이었다.","title":"익스팻","author":"크리스 파본","ampm":"am","kind":"역"}],"04:07":[{"t":"네 시 칠 분","q":"네 시 칠 분. 나는 왜 서 있는 걸까. 어깨가 서늘하고 몸이 떨린다. 정신을 차려보니 방 한가운데 서 있었다.","title":"한나를 지키다","author":"미하 마치니","ampm":"am","kind":"역"}],"04:08":[{"t":"네 시 팔 분","q":"정글짐의 차가운 금속 아래, 네 시 팔 분에 앤드류의 모든 꿈이 이루어졌다. 그는 진정한 사랑에게 입을 맞추고 영원을 맹세했다.","title":"여름의 황혼 속에 죽어가며","author":"세스 오코넬","ampm":"am","kind":"역"}],"04:09":[{"t":"네 시 구 분","q":"네 시 구 분이었다. \"그가 초음파 장 한가운데 앉아 있는데 나는 십 분이나 늦었어. 서둘러!\"","title":"마지막 사건: U.N.C.L.E.의 사나이","author":"데이비드 맥대니얼","ampm":"am","kind":"역"}],"04:10":[{"t":"네 시 십 분","q":"\"이렇게 기다리는 거 싫어.\" 그가 말했다. 그녀가 웃었다. \"넌 형편없는 사립탐정이 될 거야.\" \"지금 몇 시야?\" \"네 시 십 분. 아까 물어봤을 때보다 십오 분 늦었어.\"","title":"코퍼 리버","author":"윌리엄 켄트 크루거","ampm":"am","kind":"역"}],"04:11":[{"t":"네 시 십일 분","q":"다음 날 아침 나는 정확히 네 시 십일 분에 눈을 떴다. 평소 세 시에 찾아오던 불면의 각성을 건너뛴 채였다.","title":"삶이라는 것","author":"캐런 카보","ampm":"am","kind":"역"}],"04:12":[{"t":"네 시 십이 분","q":"캐런은 해리의 무게에 침대가 흔들리는 걸 느꼈다. 옆으로 누운 채 눈을 뜨니 어둠 속 초록빛 숫자가 네 시 십이 분을 가리키고 있었다.","title":"겟 쇼티","author":"엘모어 레너드","ampm":"am","kind":"역"}],"04:13":[{"t":"네 시 십삼 분","q":"캐런은 눈을 뜬 채 어둠 속 숫자를 바라보았다. 초록빛 숫자가 네 시 십삼 분으로 바뀌는 것을 그녀는 지켜보았다.","title":"겟 쇼티","author":"엘모어 레너드","ampm":"am","kind":"역"}],"04:14":[{"t":"네 시 십사 분","q":"네 시 십사 분, 두 남자가 지프로 돌아왔다. 조수석 남자가 통을 짐칸에 다시 싣자 운전자는 차를 몰고 동쪽으로 향했다.","title":"진짜 악몽","author":"데이비드 H. 스웬드슨","ampm":"am","kind":"역"}],"04:15":[{"t":"네 시 십오 분","q":"앨리스는 가족에게 대물림되는 결함이 있다고 경고하고 싶었다, 평발이나 당뇨처럼. 볼품없는 부엌 시계는 네 시 십오 분을 가리켰다.","title":"천국의 돼지들","author":"바버라 킹솔버","ampm":"am","kind":"역"}],"04:16":[{"t":"네 시 십육 분","q":"그들은 네 시 십육 분에 방문객용 주차장으로 들어섰다. 산부인과 입구 간판 아래 디지털시계가 있어 시각을 정확히 알 수 있었다.","title":"도시의 괴짜들: 프릭스 시리즈 2권","author":"마리 앤더슨","ampm":"am","kind":"역"}],"04:17":[{"t":"네 시 십칠 분","q":"빅 알은 기지개를 켜며 차 주변을 천천히 걸었다. 손목시계를 확인하니 네 시 십칠 분이었다. 그때 비행기 한 대가 머리 위로 지나갔다.","title":"타고난 죄수","author":"제프리 아처","ampm":"am","kind":"역"}],"04:18":[{"t":"네 시 십팔 분","q":"자명종을 집어 무릎에 던지고 빨간 버튼과 검은 버튼을 두 손으로 두드렸다. 울림은 멈추지 않았다. 전화였다. 시계는 네 시 십팔 분을 가리켰다. 창밖은 여전히 어두웠다.","title":"세계의 끝과 하드보일드 원더랜드","author":"무라카미 하루키","ampm":"am","kind":"역"}],"04:19":[{"t":"네 시 십구 분","q":"2040년 12월 27일 새벽 네 시 십구 분, 아즈텍의 제물 칼처럼 검은 그녀의 눈이 번쩍 뜨였다.","title":"오로라 퀘스트","author":"제임스 액슬러","ampm":"am","kind":"역"}],"04:20":[{"t":"네 시 이십 분","q":"깰 때마다 그는 불을 켜고 머리맡 시계를 들여다보며 새벽이 가까워지길 바랐다. 두 시 십 분, 세 시 사십 분, 네 시 이십 분.","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"04:21":[{"t":"네 시 이십일 분","q":"네 시 이십일 분, 초기 교전이 장치를 망가뜨리지 않았다는 걸 알 수 있었다. 시간은 여전히 흐르고 있었고, 그것이 좋은 징조인지 나쁜 징조인지 알 수 없었다.","title":"양철북","author":"귄터 그라스","ampm":"am","kind":"역"}],"04:22":[{"t":"네 시 이십이 분","q":"회장은 일곱 자리 번호를 눌러 당직 장교를 찾았다. 연결을 기다리며 손목시계를 보니 네 시 이십이 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"04:23":[{"t":"네 시 이십삼 분","q":"네 시 이십삼 분, 월요일 아침, 아이슬란드 광장. 비외른손가타 인근 사람들이 요란한 비명 소리에 잠에서 깼다.","title":"렛 미 인","author":"욘 아이비데 린드크비스트","ampm":"am","kind":"역"}],"04:24":[{"t":"네 시 이십사 분","q":"2025년 1월 5일 네 시 이십사 분, 하늘의 별들이 멈춘 듯했다. 캘리포니아에서는 낮게 웅웅거리는 진동과 함께 지진이 시작되었다.","title":"퍼펙트 서클","author":"카를로스 J. 코르테스","ampm":"am","kind":"역"}],"04:25":[{"t":"네 시 이십오 분","q":"옷을 입으며 시계를 힐끗 보았다. 아무도 깨어 있지 않은 게 당연했다, 네 시 이십오 분이었으니.","title":"셜록 홈즈의 모험","author":"아서 코난 도일 경","ampm":"am","kind":"역"}],"04:27":[{"t":"네 시 이십칠 분","q":"꿈속에서 학교 종소리가 들렸지만 진짜 종소리는 아니었다, 음이 가파르게 치솟더니 함정 문처럼 열려 나는 침대 위로 떨어졌다. 자명종은 네 시 이십칠 분을 가리켰다.","title":"죽은 아빠들의 클럽","author":"맷 헤이그","ampm":"am","kind":"역"}],"04:29":[{"t":"네 시 이십구 분","q":"\"실례합니다, 레빙 박사님, 급한 전화입니다. 유사 로봇 칼리반이 지금 당장 통화하고 싶다고 합니다.\" \"지금 몇 시지?\" 그녀가 물었다. \"현재 네 시 이십구 분입니다.\" 도널드가 답했다.","title":"유토피아","author":"로저 맥브라이드 앨런","ampm":"am","kind":"역"}],"04:30":[{"t":"네 시 반","q":"요나스는 뻣뻣하게 굳은 허리를 부여잡고 해먹에서 힘겹게 굴러 나왔다. 손목시계를 보니 네 시 반, 그런데 오전인지 오후인지 알 수 없었다.","title":"메그: 태고의 바다","author":"스티브 알텐","ampm":"am","kind":"역"}],"04:31":[{"t":"네 시 삼십일 분","q":"니콜 양은 복도를 걸으며 손목시계를 확인했다. 네 시 삼십일 분이었다. 그녀는 오 층으로 계단을 내려가 유아실로 향했다.","title":"행운의 아들들","author":"제프리 아처","ampm":"am","kind":"역"}],"04:32":[{"t":"네 시 삼십이 분","q":"유치원 첫 등교일, 피터 호턴은 네 시 삼십이 분에 눈을 떴다. 그는 부모님 방으로 종종걸음쳐 스쿨버스 탈 시간이냐고 물었다.","title":"19분","author":"조디 피코","ampm":"am","kind":"역"}],"04:33":[{"t":"네 시 삼십삼 분","q":"등 뒤에서 철문이 닫히는 희미한 소리를 듣자 그는 어둠 속에서 미소 지었다. 나왔다. 손목시계 버튼을 눌러 확인하니 네 시 삼십삼 분, 그의 미소는 이내 활짝 웃음으로 바뀌었다.","title":"잘못 걸린 남자","author":"제이슨 딘","ampm":"am","kind":"역"}],"04:34":[{"t":"네 시 삼십사 분","q":"꿈에서 끌려 나온 것이 마뜩잖았다. 시계는 조롱하듯 네 시 삼십사 분을 알렸다. 그는 수화기를 집어 들었다.","title":"전사 수도승","author":"레이 키팅","ampm":"am","kind":"역"}],"04:35":[{"t":"네 시 삼십오 분","q":"크리스마스 아침 여섯 시 전에는 어떤 피로도 아이를 잠재우지 못한다. 콜비는 네 시 삼십오 분에 눈을 떴다.","title":"꿈과 그림자","author":"C. 로버트 카길","ampm":"am","kind":"역"}],"04:36":[{"t":"네 시 삼십육 분","q":"그날 아침 네 시 삼십육 분, 호텔 방에 홀로 있을 때는 훨씬 나은 장면이었다. 스펜서는 내 비난의 논리를 피할 수 없어 새파랗게 질렸다. 윗입술에 땀방울이 맺히고, 관자놀이의 실핏줄이 파르르 떨리기 시작했다.","title":"놋쇠 중개자","author":"로스 토머스","ampm":"am","kind":"역"}],"04:37":[{"t":"네 시 삼십칠 분","q":"문을 두드리는 소리는 나직했지만 스티븐을 깨우기엔 충분했다. 그는 스마트폰 화면을 건드렸다. 네 시 삼십칠 분이었다.","title":"황금 돔 아래에서","author":"레이 키팅","ampm":"am","kind":"역"}],"04:38":[{"t":"네 시 삼십팔 분","q":"골리 숲 너머로 해가 떠오르던 네 시 삼십팔 분, 옆 풀숲에서 이상한 바스락 소리가 들렸다. 자세히 들여다봐도 아무것도 보이지 않았다.","title":"대기 행렬","author":"조너선 배로우","ampm":"am","kind":"역"}],"04:39":[{"t":"다섯 시 이십일 분 전","q":"영시 일 분 전, 다섯 시 이십일 분 전인 삼월 이십일일, 지피 트립은 참호 속에서 보병 장교 곁에 서서 무인지대를 바라보고 있었다. 아직 어두웠다. 영시 오 초 뒤 포탄이 터지며 무인지대에 마녀의 만화경 같은 빛을 던졌고, 그는 구조 신호탄을 향해 손을 뻗었다. 빨강, 초록, 빨강.","title":"신의 참새들","author":"필립 차일드","ampm":"am","kind":"역"}],"04:40":[{"t":"네 시 사십 분","q":"나는 하루 일과에 익숙해졌다. 네 시 사십 분에 일어나 샤워를 하고, 다섯 시 십 분 지나 북쪽으로 가는 기차를 탔다.","title":"보시팬츠","author":"티나 페이","ampm":"am","kind":"역"}],"04:41":[{"t":"네 시 사십일 분","q":"네 시 사십일 분, 크레인의 목소리가 워키토키를 타고 마치 그들의 반란 심리를 읽은 듯 갈라져 나왔다. '전부 엘리베이터로! 지금 당장!' 그 무전이 있기 바로 몇 분 전, 그와 C.J.는 성공적이길 바라는 양동작전을 막 끝낸 참이었다.","title":"흠집 난 상품","author":"롤런드 S. 제퍼슨","ampm":"am","kind":"역"}],"04:42":[{"t":"네 시 사십이 분","q":"책상 위 큰 시계는 네 시 사십이 분을 가리키고 있었다. 그는 걸음을 멈추고 귀를 기울였다. 무슨 일이 있었든 이미 끝난 듯했다.","title":"죽은 도시","author":"매튜 워릭","ampm":"am","kind":"역"}],"04:43":[{"t":"네 시 사십삼 분","q":"시각은 네 시 사십삼 분, 밖은 거의 밝아오고 있었다.","title":"사이코라그","author":"수하일 사디","ampm":"am","kind":"역"}],"04:45":[{"t":"네 시 사십오 분","q":"그는 총리에게 먼저 전화를 걸 필요를 느낀 적이 없었지만, 처칠 씨가 한 번 그에게 전화를 건 적이 있었다. 찰리가 책상 위 수화기를 든 것은 네 시 사십오 분이었다.","title":"까마귀는 똑바로 난다","author":"제프리 아처","ampm":"am","kind":"역"}],"04:46":[{"t":"네 시 사십육 분","q":"전화가 다시 울린 것은 네 시 사십육 분이었다. '여보세요,' 내가 말했다. '여보세요,' 여자의 목소리가 들려왔다. '아까는 죄송했어요. 음장에 교란이 있어서요. 가끔 소리가 사라지거든요.' '소리가 사라진다고요?' '네,' 그녀가 말했다. '음장이 미끄러지고 있어요. 제 목소리 들리세요?'","title":"세계의 끝과 하드보일드 원더랜드","author":"무라카미 하루키","ampm":"am","kind":"역"}],"04:47":[{"t":"네 시 사십칠 분","q":"온라인에서 그 글을 읽은 뒤로 잠을 설쳤다. 읽었던 문구들이 머릿속에서 계속 맴돌았다. 몇 번째인지 모를 만큼 다시 깼을 때, 침대 옆 스톰트루퍼 시계는 네 시 사십칠 분을 가리키고 있었다.","title":"그녀가 알고 있던 것","author":"길리 맥밀런","ampm":"am","kind":"역"}],"04:48":[{"t":"네 시 사십팔 분","q":"네 시 사십팔 분, 명료함이 따뜻한 어둠을 찾아와 내 눈을 적시는 행복한 시간, 나는 아무 죄도 알지 못한다.","title":"4.48 사이코시스","author":"사라 케인","ampm":"am","kind":"역"}],"04:49":[{"t":"다섯 시 십일 분 전","q":"코스테인이 함교를 떠났을 때 조타실의 놋쇠 크로노미터는 다섯 시 십일 분 전을 가리키고 있었다. 하크니스는 그것을 보며 간격이 여전히 너무 크다는 것을 어렴풋이 깨달았다.","title":"질풍","author":"엘레스턴 트레버","ampm":"am","kind":"역"}],"04:50":[{"t":"다섯 시 십 분 전","q":"그의 손목시계 바늘도, 열세 개의 시계 바늘도 모두 멈춰 있었다. 칠 년 전 눈 내리던 밤, 그것들은 일제히 멈추었고, 그 뒤로 성 안은 언제나 다섯 시 십 분 전이었다.","title":"열세 개의 시계","author":"제임스 서버","ampm":"am","kind":"역"}],"04:51":[{"t":"다섯 시 구 분 전","q":"'이른 시간이라고요? 지금은 다섯 시 구 분 전인데, 누가 이렇게 일찍 일어나 있겠어요?' '아, 우리는 다들 일찍 일어나는 편이에요.'","title":"동방박사들의 선물","author":"진 존슨","ampm":"am","kind":"역"}],"04:52":[{"t":"다섯 시 팔 분 전","q":"'상관있다면 말해두는데, 지금은 다섯 시 팔 분 전이야. 이 시간에 잠자리에서 끌려나온 게 즐겁다는 피해망상은 갖지 마. 우리를 안으로 들이는 편이 법적으로 더 수월할 거야.'","title":"제로를 지키다","author":"제럴드 시모어","ampm":"am","kind":"역"}],"04:53":[{"t":"다섯 시 칠 분 전","q":"우체국 안은 너무나 고요해서 트리니다드는 시계 초침이 움직일 때마다 나는 부드러운 소리를 들을 수 있었다. 이제 다섯 시 칠 분 전이었다.","title":"보나벤처 애로우의 침묵","author":"리타 레간스키","ampm":"am","kind":"역"}],"04:54":[{"t":"다섯 시 육 분 전","q":"마지막 뚜껑을 도로 덮은 뒤 그는 벽시계를 확인했다. 다섯 시 육 분 전이었다. 다른 상자를 들여다보고 같은 것을 또 기대할 수 있을지 볼 시간은 충분했다.","title":"명예의 문제","author":"제프리 아처","ampm":"am","kind":"역"}],"04:55":[{"t":"네 시 오십오 분","q":"메시지가 두 통 와 있었다. 네 시 오십오 분에 온 첫 번째 메시지는 캠퍼스 정비소에서 온 것이었다. '차를 확보했습니다,' 정비공의 목소리가 알려왔다. '안타깝게도 도랑에서 끌어내는 데 애를 먹어서, 손상이 조금 더 생겼습니다.'","title":"인클레이브","author":"캐런 핸콕","ampm":"am","kind":"역"}],"04:56":[{"t":"다섯 시가 되기 직전","q":"핵심 사실을 짚어내려던 이선은 문득 자신이 벽시계를 보고 있다는 걸 깨달았다. 일곱 시 삼십오 분이었다. '잠깐만. 그 소식은 언제 들었지?' 잠시 망설임이 흘렀다. '첫 소식은 다섯 시가 되기 직전에 들어왔어.'","title":"무한한 하루","author":"크리스 월리","ampm":"am","kind":"역"}],"04:57":[{"t":"다섯 시 삼 분 전","q":"엘크하트에서 기관차를 교체하느라 백삼십일 초가 지체되었고, 데이브 루스가 조종석에 앉은 거대한 599호가 밝아오는 하늘을 향해 코를 돌려 백삼십삼 마일 떨어진 톨레도로 출발한 것은 다섯 시 삼 분 전이었다.","title":"위험과 대담함의 삶들","author":"클리블랜드 모펫","ampm":"am","kind":"역"}],"04:58":[{"t":"다섯 시 이 분 전","q":"그는 죽음을 정면으로 마주하고 싶어 했다. 다섯 시 이 분 전. 나는 주머니에서 손수건을 꺼냈지만 존 도슨이 도로 넣으라고 명령했다. 영국인은 눈을 뜬 채 죽는다. 그는 죽음을 정면으로 마주하고 싶어 했다.","title":"새벽","author":"엘리 위젤","ampm":"am","kind":"역"}],"04:59":[{"t":"다섯 시 일 분 전","q":"선장과 세 명의 항해사가 이른 아침 안개 속에서 모습을 드러낸 것은 다섯 시 일 분 전이었다. 넷 다 전날 밤과 똑같은 옷차림이어서, 퍼시는 그들이 곧장 피셔맨스 암스에서 오는 길이 아닐까 생각했다.","title":"서투른 외교관","author":"제프리 아처","ampm":"am","kind":"역"}],"05:01":[{"t":"다섯 시를 막 넘긴 시각","q":"쌀쌀한 구월 아침, 다섯 시를 막 넘긴 시각에 키르스텐과 에밀리아를 태우고 그동안 챙길 수 있었던 짐을 실은 생선 장수의 수레가 로젠보르 성문을 빠져나간다.","title":"음악과 침묵","author":"로즈 트레메인","ampm":"am","kind":"역"}],"05:02":[{"t":"다섯 시 이 분","q":"다섯 시 이 분, 십이월 십사일이었다. 오십팔 분만 지나면 그는 미국으로 떠날 참이었다. 그는 신부를 떠나고 싶지 않았고, 가고 싶지도 않았다.","title":"그 상","author":"브렌다 조이스","ampm":"am","kind":"역"}],"05:03":[{"t":"다섯 시 삼 분","q":"다섯 시 삼 분이었다. 그런 건 중요하지 않았다. 그녀는 다시 잠들 생각이 없었다. 이불을 걷어차고, 자기 자신과 케일럽과 그리핀 씨를 욕하며 샤워실로 향했다.","title":"저주받은 땅","author":"헤더 그레이엄","ampm":"am","kind":"역"}],"05:04":[{"t":"다섯 시 사 분","q":"허름한 라디오시계는 다섯 시 사 분을 가리켰다. 사람들은 왜 늘 하루가 지금 시작된다고 말하는 걸까. 실은 자정을 지난 찰나의 순간, 한밤중에 시작되는데.","title":"우연한 손님","author":"앨리 스미스","ampm":"am","kind":"역"}],"05:05":[{"t":"다섯 시 오 분","q":"아기, 아들이 다섯 시 오 분에 태어났다.","title":"이름 뒤에 숨은 사랑","author":"줌파 라히리","ampm":"am","kind":"역"}],"05:06":[{"t":"다섯 시 육 분","q":"다섯 시 육 분, 이상하게 힘이 솟은 채로 깨어나니 배에서 꼬르륵 소리가 났다. 위층에서는 잔뜩 쌓인 냉장고가 위로의 음식들을 잔뜩 내놓는다.","title":"여기가 내가 널 떠나는 곳","author":"조나단 트로퍼","ampm":"am","kind":"역"}],"05:07":[{"t":"다섯 시 칠 분","q":"그는 눈을 깜박이다 몸을 뒤척이며 침대맡 시계의 형광 초록빛 숫자를 바라보았다. 다섯 시 칠 분. 일어나기 전 첫 문장을 되뇌어볼 시간은 충분했다.","title":"그는 사나이였다","author":"제프리 아처","ampm":"am","kind":"역"}],"05:08":[{"t":"다섯 시 팔 분","q":"앰브로즈와 나는 이번 토요일, 로쉬 하샤나에 맥헨리 요새에서 동부표준시로 다섯 시 팔 분에 결혼할 거예요!","title":"편지들","author":"존 바스","ampm":"am","kind":"역"}],"05:09":[{"t":"다섯 시 구 분","q":"몇 년만 지나면 침대맡에 하나쯤 두게 될 테니 사무실까지 갈 필요도 없을 거예요, 라고 수 링이 말하며 침대맡 시계에 다섯 시 구 분이 떠오르는 것을 보고는 베개에 고개를 떨구었다.","title":"운명의 아들들","author":"제프리 아처","ampm":"am","kind":"역"}],"05:10":[{"t":"다섯 시 십 분","q":"나는 규칙적인 일과에 자리를 잡았다. 새벽 네 시 사십 분에 일어나 샤워를 하고, 다섯 시 십 분에 북쪽으로 가는 기차에 올랐다.","title":"보시팬츠","author":"티나 페이","ampm":"am","kind":"역"}],"05:11":[{"t":"다섯 시 십일 분","q":"오늘은 팔월 십오일 화요일이었다. 해는 오늘 아침 다섯 시 십일 분에 떠서 저녁 일곱 시 이 분 전에 질 예정이었다.","title":"핫 록","author":"도널드 E. 웨스트레이크","ampm":"am","kind":"역"}],"05:12":[{"t":"다섯 시 십이 분 육 초","q":"1906년 4월 18일 아침 다섯 시 십이 분 육 초, 샌프란시스코 반도는 지진의 손아귀 속에서 진동하기 시작했다. 그 궁극적 결과를 고려하면 북아메리카 대륙 기록 역사상 가장 참혹한 지진이었다.","title":"슬러머의 낙원","author":"허버트 애스베리","ampm":"am","kind":"역"}],"05:13":[{"t":"다섯 시 십삼 분","q":"우가 말했다. \"오늘 아침 다섯 시 십삼 분에 정지했다가, 다시 시작했을 때는 보조 전력으로 가동했더군요.\"","title":"쥬라기 공원","author":"마이클 크라이튼","ampm":"am","kind":"역"}],"05:14":[{"t":"다섯 시 십사 분","q":"시각은 다섯 시 십사 분, 보안관이 이른 아침 순찰 중 목격했다고 주장한 것을 보기에는 참으로 기이한 시간이었다. 그는 킹덤 시티의 인적 없는 눈 덮인 거리를 오가며 순찰하다 경계를 카운티 로드 북쪽으로 넓혀가던 참이었다.","title":"거미줄 속으로","author":"토머스 H. 쿡","ampm":"am","kind":"역"}],"05:15":[{"t":"다섯 시 십오 분","q":"브라운과의 기이한 대화. 다섯 시 십오 분에 침대에서 끌려 나온 지치고 혼란스러운 노인이었다.","title":"공포와 혐오, 1972년 대선 유세","author":"헌터 S. 톰슨","ampm":"am","kind":"역"}],"05:16":[{"t":"다섯 시 십육 분","q":"다섯 시 십육 분, 맹크가 국무장관 브라운과 통화 중이다. \"브라운 씨, 21구역 상황이 심히 우려됩니다. 그곳에서는 결과라는 게 하나도 안 나오는군요.\"","title":"공포와 혐오, 1972년 대선 유세","author":"헌터 S. 톰슨","ampm":"am","kind":"역"}],"05:17":[{"t":"다섯 시 십칠 분","q":"세 시간 남짓 자고 난 뒤 그랜트는 휴대폰으로 시각을 확인했다. 다섯 시 십칠 분. 더 자기는 어려울 듯했다. 아침 달리기를 할 시간이었다.","title":"라이온하츠","author":"레이 키팅","ampm":"am","kind":"역"}],"05:18":[{"t":"다섯 시 십팔 분","q":"윌리엄은 불을 켜지 않은 채 수화기를 집어 들었고, 침대맡 디지털시계는 다섯 시 십칠 분에서 다섯 시 십팔 분으로 바뀌었다. 전화선 저편에 있을 사람은 오직 한 명뿐임을 그는 알고 있었다.","title":"다음 차례","author":"제프리 아처","ampm":"am","kind":"역"}],"05:19":[{"t":"다섯 시 십구 분","q":"스콧은 손목시계의 작은 인광 점을 다시 확인한 뒤 구석으로 몸을 밀어 넣었다. 다섯 시 십구 분이었다. 그와 한나는 한 시간 십칠 분째 금고 안에 갇혀 있었다.","title":"도둑들의 의리","author":"제프리 아처","ampm":"am","kind":"역"}],"05:20":[{"t":"다섯 시 이십 분","q":"시속 칠십을 유지한 채 미드타운에서 유료도로를 빠져나가고 대부분의 신호를 잘 탄다면, 다섯 시 이십 분까지는 건물에 도착할 수 있으리라 그녀는 어림했다.","title":"만약 그것이 피를 흘린다면","author":"스티븐 킹","ampm":"am","kind":"역"}],"05:21":[{"t":"다섯 시 이십일 분","q":"어제, 그러니까 이번 달 구일 아침 다섯 시 이십일 분, 휘트스터블 순경은 여느 때처럼 순찰을 돌다 클라지스 가와 피커딜리가 만나는 모퉁이에 이르렀는데, 그린 파크에서 이어지는 오솔길 쪽에서 고함 소리가 들려왔다.","title":"문던 수선화 살인 사건의 기묘한 전말","author":"가스 닉스","ampm":"am","kind":"역"}],"05:22":[{"t":"다섯 시 이십이 분","q":"\"네,\" 그녀가 고개를 끄덕였다. \"어둠을 틈타 이륙해서 해 뜰 무렵엔 투티 비행장 상공에 있을 거예요. 다섯 시 이십이 분이죠.\"","title":"표범은 어둠 속에서 사냥한다","author":"윌버 스미스","ampm":"am","kind":"역"}],"05:23":[{"t":"다섯 시 이십삼 분","q":"톡은 자랑스레 꼬리를 흔들었지만 마일로는 한마디도 하지 않았고, 그 이상하기 짝이 없는 아침 다섯 시 이십삼 분에 깨어 있었던 몇몇 사람들 말고는 오늘날까지 그 잃어버린 한 주를 아는 이가 없다.","title":"팬텀 톨부스","author":"노튼 저스터","ampm":"am","kind":"역"}],"05:24":[{"t":"다섯 시 이십사 분","q":"다섯 시 이십삼 분에서 시작해 그녀의 디지털시계가 다섯 시 이십사 분으로 녹아들 때까지, 지나가는 주황빛 숫자 사이를 정확히 육십까지 셀 수 있다면, 그녀가 깨어났을 때 나를 사랑하며 이것이 끔찍한 실수였다고 말하지 않을 것 같았다.","title":"아서의 비극","author":"아서 필립스","ampm":"am","kind":"역"}],"05:25":[{"t":"다섯 시 이십오 분","q":"조지가 뉴 스트리트에서 집으로 가는 기차는 다섯 시 이십오 분에 출발한다. 돌아오는 길에는 남학생들이 좀처럼 없다.","title":"아서와 조지","author":"줄리언 반스","ampm":"am","kind":"역"}],"05:26":[{"t":"다섯 시 이십육 분","q":"아마 이번이 천구백칠십 번째 부딪힘일 거야. 그런데도 그 소년은 같은 속도로 계속해서 애쓰고 있다. 소리 하나 들리지 않는다. 신음 하나 없다. 불쌍한 그들. 불쌍한 나. 시계를 본다. 다섯 시 이십육 분.","title":"101 레이캬비크","author":"하들그리무르 헬가손","ampm":"am","kind":"역"}],"05:27":[{"t":"다섯 시 이십칠 분","q":"그녀는 손목시계를 보았다. 다섯 시 이십칠 분이었다. 가웨인이 벌써 와 있어야 하지 않을까? 안으로 들어갈 뾰족한 방법도 없는데, 그가 그녀를 살피고 있지 않을까?","title":"뉴욕 발렌타인","author":"카먼 리드","ampm":"am","kind":"역"}],"05:28":[{"t":"다섯 시 이십팔 분","q":"나는 다섯 시 이십팔 분에 아오야마 슈퍼마켓 주차장으로 들어섰다. 동쪽 하늘이 밝아오고 있었다. 가방을 든 채 매장으로 들어갔다. 가게 안에는 사람이 거의 없었다.","title":"세계의 끝과 하드보일드 원더랜드","author":"무라카미 하루키","ampm":"am","kind":"역"}],"05:29":[{"t":"다섯 시 반이 되기 직전","q":"다섯 시 반이 되기 직전, 마틴 신부는 공포에 질린 비명과 함께 잠에서 깼다. 그는 침대에서 벌떡 일어나 인형처럼 뻣뻣하게 앉은 채 눈을 크게 뜨고 어둠 속을 응시했다.","title":"성직 안의 죽음","author":"P.D. 제임스","ampm":"am","kind":"역"}],"05:30":[{"t":"다섯 시 반","q":"해리는 이튿날 아침 다섯 시 반에, 마치 누군가 귓가에 고함이라도 지른 것처럼 갑작스럽고 완전하게 눈을 떴다.","title":"해리 포터와 불사조 기사단","author":"J.K. 롤링","ampm":"am","kind":"역"}],"05:32":[{"t":"다섯 시 삼십이 분","q":"다섯 시 삼십이 분 무렵 운전사는 모퉁이 가게에서 콜라 여섯 캔, 잭 다니엘 한 병, 아침용 우유 봉지 몇 개, 눅눅한 케이크 한 아름과 중난하이 담배 한 보루를 사 들고 돌아왔다. 문이 쾅 닫히고 승합차가 움직이기 시작했다.","title":"희토류","author":"폴 메이슨","ampm":"am","kind":"역"}],"05:33":[{"t":"다섯 시 삼십삼 분","q":"우리가 떠난 건 다섯 시 삼십삼 분이었다. 지금은 여섯 시나 됐을까? 여섯 시 반? 마크는 아직 우리에 갇혀 있고 나는 너무 빨리 몰기가 무서운데... 제시간에 도착하지 못하면 어쩌지?","title":"용감한 자들 사이에서","author":"마거릿 피터슨 해딕스","ampm":"am","kind":"역"}],"05:34":[{"t":"다섯 시 삼십사 분","q":"나는 물었다. \"일출이 몇 시지?\" 잠시 침묵이 흐르는 사이 풀 죽은 부시가 질책을 곱씹었고, 이내 다른 목소리가 답했다. \"다섯 시 삼십사 분입니다, 각하.\"","title":"코모도어","author":"C.S. 포레스터","ampm":"am","kind":"역"}],"05:35":[{"t":"다섯 시 삼십오 분","q":"상원의원은 식은땀을 흘리며 다섯 시 삼십오 분에 깨어났다. 사실 그날 밤은 어느 순간에도 몇 분 이상 제대로 잠들지 못했다. 천둥과 번개와 사이렌이 뒤섞인 사악한 밤이었다.","title":"대통령에게 알릴까요?","author":"제프리 아처","ampm":"am","kind":"역"}],"05:36":[{"t":"다섯 시 삼십육 분","q":"그녀는 잭 다니엘 한 병을 다 마셨다. 다섯 시 삼십육 분에 깨어났을 때 그녀는 전날 밤의 기억을 지워버린 뒤였다.","title":"파울러 가족 사업","author":"조너선 미즈","ampm":"am","kind":"역"}],"05:37":[{"t":"다섯 시 삼십칠 분","q":"리처드는 전자레인지 시계를 힐끗 보았다. 다섯 시 삼십칠 분. 911에 신고한 지 거의 열두 시간, 거의 반나절이 지나 있었다.","title":"이 책이 당신의 인생을 구할 것이다","author":"A.M. 홈스","ampm":"am","kind":"역"}],"05:38":[{"t":"다섯 시 삼십팔 분","q":"\"좋은 아침이야, 조니.\" 배가 말했다. \"지금은 다섯 시 삼십팔 분이야.\"\n\"뭐라고?\" 조니가 말했다. \"오늘 토요일이잖아.\"","title":"조니 매킨토시: 지구를 위한 전투","author":"키스 맨스필드","ampm":"am","kind":"역"}],"05:39":[{"t":"여섯 시 이십일 분 전","q":"조지는 화장대에서 휴대폰을 집어 들었다. \"악몽이 알람보다 한 시간이나 빨랐네.\" 그가 말했다. \"지금은 여섯 시 이십일 분 전이야.\"","title":"이 유토피아 프로젝트","author":"쿠다크와셰 무지라","ampm":"am","kind":"역"}],"05:40":[{"t":"다섯 시 사십 분","q":"다섯 시 사십 분, 그는 이불을 걷어차고 침대에서 다리를 내려 카펫 위에 두 발을 딱 붙였다.","title":"그는 그런 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"05:41":[{"t":"다섯 시 사십일 분","q":"이니고가 마침내 백작을 궁지로 몰아넣은 것은 다섯 시 사십일 분이 되어서였다. 당구실에서였다.","title":"프린세스 브라이드","author":"윌리엄 골드먼","ampm":"am","kind":"역"}],"05:42":[{"t":"여섯 시 십팔 분 전","q":"여섯 시 십팔 분 전, 그들은 벽을 폭파했다. 그때조차 거의 늦은 뒤였다.","title":"신사의 게임","author":"그렉 루카","ampm":"am","kind":"역"}],"05:43":[{"t":"다섯 시 사십삼 분","q":"다섯 시 사십삼 분, 그리니치 표준시. 전화벨 소리에 윌리엄이 잠에서 깼다.","title":"낫싱 벤처드","author":"제프리 아처","ampm":"am","kind":"역"}],"05:44":[{"t":"다섯 시 사십사 분","q":"\"그럼 피고가 그 말을 한 게 정확히 몇 시였습니까?\" \"필름 테이프를 멈춘 화면에 시간이 나와 있을 겁니다. 다섯 시 사십사 분이었습니다.\"","title":"사생활 침해","author":"페리 오쇼너시","ampm":"am","kind":"역"}],"05:45":[{"t":"다섯 시 사십오 분","q":"다음 날 아침 다섯 시 사십오 분, 장군은 정복 차림으로 조지의 막사 밖에 서 있었다.","title":"영광의 길","author":"제프리 아처","ampm":"am","kind":"역"}],"05:46":[{"t":"다섯 시 사십육 분","q":"허버트는 아무 감각도 느끼지 못했다. 그는 사형이 다섯 시 사십육 분에 집행되었다고 법률 투로 적었다.","title":"속삭인 이름","author":"윌리엄 브로드릭","ampm":"am","kind":"역"}],"05:48":[{"t":"여섯 시 십이 분 전","q":"성 파울리 걸 시계의 바늘은 여섯 시 십이 분 전에서 멈춰 있었다.","title":"북서쪽 모퉁이","author":"존 번햄 슈워츠","ampm":"am","kind":"역"}],"05:49":[{"t":"다섯 시 사십구 분","q":"전화벨 소리에 그는 즉시 정신이 들었다. 여행용 시계의 불 켜진 문자판은 다섯 시 사십구 분을 가리켰다.","title":"나이팅게일을 위한 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"05:50":[{"t":"다섯 시 오십 분","q":"다섯 시 오십 분, 그는 비틀거리며 방을 나섰다. 어디로 가는지도 모른 채였다.","title":"프린세스 브라이드","author":"윌리엄 골드먼","ampm":"am","kind":"역"}],"05:51":[{"t":"여섯 시 구 분 전","q":"여섯 시 구 분 전, 새벽이 오기 한 시간 전이었다. 여단은 오늘 이동할 예정이 없었다.","title":"죽는 것이 그들의 임무","author":"에이드리언 골즈워디","ampm":"am","kind":"역"}],"05:52":[{"t":"다섯 시 오십이 분","q":"다섯 시 오십이 분, 세인트피터즈버그 소방서와 선스타 메딕 원 구급대가 응급 신고를 받고 출동했다.","title":"침묵의 증인","author":"마크 퍼먼","ampm":"am","kind":"역"}],"05:53":[{"t":"다섯 시 오십삼 분","q":"다섯 시 오십삼 분, 핏빛 태양이 지평선 위로 고개를 내밀 때 베리 권총이 발사되었다.","title":"까마귀가 나는 대로","author":"제프리 아처","ampm":"am","kind":"역"}],"05:54":[{"t":"여섯 시 육 분 전","q":"오늘 아침 해는 여섯 시 육 분 전에 떠올랐다. 마제스타 다리에는 이미 출근길 정체가 시작되고 있었다.","title":"그저 증오일 뿐","author":"에드 맥베인","ampm":"am","kind":"역"}],"05:55":[{"t":"여섯 시 오 분 전","q":"빌리는 주차장으로 차를 몰지 않는다. 여섯 시 오 분 전, 그는 메인 스트리트에 차를 세운다.","title":"빌리 서머스","author":"스티븐 킹","ampm":"am","kind":"역"}],"05:56":[{"t":"여섯 시 사 분 전","q":"코가 깨진 장교가 페로 장군의 시계를 빌리러 갔다. 두 사람은 한동안 고개를 맞대었다. \"됐군. 당신 시계로 여섯 시 사 분 전이오.\"","title":"여섯 편의 이야기","author":"조지프 콘래드","ampm":"am","kind":"역"}],"05:57":[{"t":"다섯 시 오십칠 분","q":"다음 숨은 신음처럼 크게 터져 나온다. 다섯 시 오십칠 분에 나는 말한다. \"엄마, 거의 여섯 시야.\"","title":"룸","author":"에마 도노휴","ampm":"am","kind":"역"}],"05:58":[{"t":"여섯 시 직전","q":"그랜트는 다음 날 아침 여섯 시 직전에 성 마리아 루터교회 사무실로 들어섰다. 평소보다 이른 시간이었다.","title":"황금 돔 아래에서","author":"레이 키팅","ampm":"am","kind":"역"}],"05:59":[{"t":"여섯 시 일 분 전","q":"여섯 시 일 분 전, 홀리스는 회중시계를 꺼냈다. 그는 한숨을 쉬고 시계를 도로 넣은 뒤 의자에 등을 기댔다.","title":"법의 도래","author":"찰스 올든 셀처","ampm":"am","kind":"역"}],"06:00":[{"t":"여섯 시","q":"\"그 뒤로 말이야,\" 모자 장수가 침울한 어조로 말을 이었다. \"그는 내가 시키는 일을 하나도 하지 않아! 늘 여섯 시거든.\"","title":"이상한 나라의 앨리스","author":"루이스 캐럴","ampm":"am","kind":"역"}],"06:01":[{"t":"여섯 시 일 분","q":"그는 카메라를 정면으로 올려다보고 있었다. 화면 오른쪽 아래 시간 표시는 그날 아침 여섯 시 일 분이라고 알려주었다.","title":"패신저","author":"저스틴 크로닌","ampm":"am","kind":"역"}],"06:02":[{"t":"여섯 시 이 분","q":"버밍엄 뉴 스트리트 다섯 시 이십오 분, 월솔 다섯 시 오십오 분. 이어 블록스위치 여섯 시 이 분, 와이얼리 여섯 시 구 분.","title":"아서와 조지","author":"줄리언 반스","ampm":"am","kind":"역"}],"06:03":[{"t":"여섯 시 삼 분","q":"작은 탁자 위 회중시계는 여섯 시 삼 분을 가리키고 있었다.","title":"파티와 다른 이야기들","author":"안톤 파블로비치 체호프","ampm":"am","kind":"역"}],"06:04":[{"t":"여섯 시 사 분","q":"여섯 시 사 분이었다. 그녀는 몸을 떨었다. 그녀는 기다렸다.","title":"위험의 심장","author":"제럴드 시모어","ampm":"am","kind":"역"}],"06:05":[{"t":"여섯 시 오 분","q":"두 번째 남자가 들어가 보니 가게는 여섯 시 오 분에 이미 비어 있었다.","title":"ABC 살인 사건","author":"애거사 크리스티","ampm":"am","kind":"역"}],"06:08":[{"t":"여섯 시 팔 분","q":"여섯 시 팔 분, 다 해진 트렌치코트를 입은 두 남자가 카지노로 다가왔다.","title":"매직 블리즈","author":"일로나 앤드루스","ampm":"am","kind":"역"}],"06:09":[{"t":"여섯 시 구 분","q":"여섯 시 구 분, 중앙유럽시. \"왜 네 시에 나를 안 깨웠나?\" 몬티가 다그쳤다.","title":"낫싱 벤처드","author":"제프리 아처","ampm":"am","kind":"역"}],"06:10":[{"t":"여섯 시 십 분","q":"회장은 일곱 시 이십 분에 일어나 첫 담배에 불을 붙였다. 정확히 언제 깼는지는 기억나지 않았다. 여섯 시 십 분에 그는 이미 일어나 기다리고 있던 토니에게 전화를 걸었었다.","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"06:11":[{"t":"여섯 시 십일 분","q":"\"라과디아요,\" 덱스터가 말하고는 밤새 뜬눈으로 기다려준 관제사에게 고맙다고 전했다. 디지털시계가 여섯 시 십일 분에서 십이 분으로 바뀌는 사이, 스콧은 앞좌석 두 사람을 번갈아 바라보았다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"06:12":[{"t":"아침 여섯 시 십이 분","q":"\"커리슨 박사님?\" 물을 필요도 없는 질문이었다. 절반은 비어 소리만 울리는 이 집에서 아침 여섯 시 십이 분에 전화를 받을 사람이 그 말고 또 누가 있겠는가. 그는 대답하지 않았고 목소리는 계속 이어졌다.","title":"전문가 증인의 죽음","author":"P.D. 제임스","ampm":"am","kind":"역"}],"06:13":[{"t":"여섯 시 십삼 분","q":"지금은 여섯 시 십삼 분. 엄마는 내가 벌써 러그 속에 들어가 있어야 한다고 했다, 올드 닉이 올지도 모르니까.","title":"룸","author":"엠마 도너휴","ampm":"am","kind":"역"}],"06:14":[{"t":"여섯 시 십사 분","q":"가상의 커튼이 그녀의 움직임을 그대로 비추며 화면을 가로질러 미끄러지고 방의 조명을 낮췄다. 붉은 숫자 여섯 시 십사 분이 흐려졌지만 오른쪽 상단 구석에는 여전히 떠 있었다.","title":"마더 문","author":"밥 고더드","ampm":"am","kind":"역"}],"06:15":[{"t":"여섯 시 십오 분","q":"아버지는 여섯 시 십오 분에 면도할 물이 준비되어 있기를 바랐다. 정확히 칠 분 늦게, 도로시는 주전자를 들고 이층으로 올라가 아버지의 방문을 두드렸다.","title":"목사의 딸","author":"조지 오웰","ampm":"am","kind":"역"}],"06:16":[{"t":"여섯 시 십육 분","q":"미텔슈타이네행 여섯 시 십육 분 열차에 오르면서, 에리카는 이 여정의 매 순간이 어머니로부터 멀어지게 하는 동시에 막스를 다시 만나고 새로운 작은 가족을 꽃피울 가능성에 가까이 데려다줄 거라는 생각을 떨치지 못했다.","title":"열다섯 개의 단어","author":"모니카 제프콧 토머스","ampm":"am","kind":"역"}],"06:17":[{"t":"여섯 시 십칠 분","q":"\"디지, 이리 와.\" 그는 천천히 몸을 돌려 고양이를 살살 달래 베개 위로 내려앉혔다. 시계는 여섯 시 십칠 분을 가리켰다. 또 다른 고양이 마일스는 레스닉의 다리가 만들어놓은 이불 속 V자 자리에서 만족스럽게 가르랑거렸다.","title":"외로운 마음들","author":"존 하비","ampm":"am","kind":"역"}],"06:19":[{"t":"아침 여섯 시 십구 분","q":"2004년 6월 8일, 아침 여섯 시 십구 분, 그대 눈동자의 금빛 속에 검은 동공이 박혀 있었다.","title":"비너스","author":"캐럴 앤 더피","ampm":"am","kind":"역"}],"06:20":[{"t":"여섯 시 이십 분","q":"그 시계가 여섯 시 이십 분을 가리켰을 때 사실은 겨우 오 분이 지났을 뿐이었고, 다섯 시 오 분에는 프로세로 대령이 그 집에 도착조차 하지 않았을 것이다.","title":"목사관 살인 사건","author":"애거사 크리스티","ampm":"am","kind":"역"}],"06:21":[{"t":"여섯 시 이십일 분","q":"채찍 맞은 노새들이 물에 잠긴 갈래 길로 마차를 끌고 갔다. 나는 시동을 건 채 구드거와 내 담배에 불을 붙였다. 그때가 여섯 시 이십일 분이었다.","title":"이제 유명한 사람들을 찬양하자","author":"제임스 에이지, 워커 에번스","ampm":"am","kind":"역"}],"06:22":[{"t":"여섯 시 이십이 분","q":"그가 앞으로 쓰러지면서 시계가 넘어졌다. 그것으로 범행 시각을 알 수 있겠군. 여섯 시 이십이 분이었다.","title":"목사관 살인 사건","author":"애거사 크리스티","ampm":"am","kind":"역"}],"06:23":[{"t":"여섯 시 이십삼 분","q":"여섯 시 이십삼 분이었다. 그는 라디오를 켠 채 이즐링턴을 몇 바퀴고 돌며 소리를 질러볼까 진지하게 생각했다.","title":"그래야만 했다","author":"데이비드 노브스","ampm":"am","kind":"역"}],"06:24":[{"t":"여섯 시 이십사 분","q":"마침내 위쪽의 초록빛으로 전화기를 찾아냈다. 전화를 받기 전 시각 표시가 여섯 시 이십사 분인 걸 확인했다. 엄마였다.","title":"심플리 헤븐","author":"세레나 매키지","ampm":"am","kind":"역"}],"06:25":[{"t":"아침 여섯 시 이십오 분","q":"그는 아침 여섯 시 이십오 분에 놀라 잠에서 깼다, 머릿속에는 단 한 장면만 남아 있었다.","title":"소원은 신중하게","author":"제프리 아처","ampm":"am","kind":"역"}],"06:26":[{"t":"여섯 시 이십육 분","q":"이 시각 안방에는 불이 켜져 있지 않았지만, 그날 공식 일출 시각이 여섯 시 이십육 분이었다는 점은 기록에 남아 있다. 피해자는 커다란 창문으로 충분한 빛이 들어와 시야를 확보하기에 무리가 없었다고 분명히 밝혔다.","title":"룰렛","author":"돈 펜들턴, 린다 펜들턴","ampm":"am","kind":"역"}],"06:27":[{"t":"여섯 시 이십칠 분","q":"여섯 시 이십칠 분이었다. 프랜시스 페버렐의 아파트에서 전화벨이 울렸다. 제임스가 그녀의 이름을 부르는 순간, 그녀는 뭔가 잘못되었다는 걸 알아챘다.","title":"원죄","author":"P.D. 제임스","ampm":"am","kind":"역"}],"06:28":[{"t":"목요일 아침 여섯 시 이십팔 분","q":"목요일 아침 여섯 시 이십팔 분. 아침 공기는 쌀쌀했고, 그녀는 나오기 전에 아드리아나의 검은 니트 숄을 챙겼어야 했다고 후회했다. 구부정한 그리스 농가 여인처럼 보일 수 있을까 생각해봤지만, 가능성은 낮았다. 그녀는 몸을 떨며 얇은 코트를 여몄다.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"06:29":[{"t":"여섯 시 이십구 분","q":"이후 십오 분 동안 그는 와인과 맥주 상자를 계속 계단으로 날랐고, 수시로 멈춰 시계를 확인했다. 여섯 시 이십구 분, 그는 뒷문을 열었다가 몸을 데우려고 껑충껑충 뛰며 옆구리를 두드리는 독일군 상병을 보았다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"06:30":[{"t":"여섯 시 반","q":"토니는 늘 그렇듯 여섯 시 반에 일어난다. 웨스트는 나지막이 신음하며 계속 잠들어 있다. 꿈속에서 그는 아마 소리를 지르고 있을 것이다. 꿈속의 소리는 언제나 더 크게 들리니까.","title":"도둑 신부","author":"마거릿 애트우드","ampm":"am","kind":"역"}],"06:31":[{"t":"아침 여섯 시 삼십일 분","q":"아침 여섯 시 삼십일 분. \"알파 리더, 여기는 씰 원. 적군으로 보이는 인원을 발견한 것 같다.\"","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"06:32":[{"t":"아침 여섯 시 삼십이 분","q":"아침 여섯 시 삼십이 분, 마크는 잠에서 깼지만 온전히 깨어나지는 못했다. 머릿속이 두서없는 생각들로 어지러웠다. 가장 먼저 떠오른 것은 엘리자베스의 모습이었고, 그는 미소를 지었다.","title":"대통령께 말씀드릴까요","author":"제프리 아처","ampm":"am","kind":"역"}],"06:33":[{"t":"여섯 시 삼십삼 분","q":"여섯 시 삼십삼 분에 깼다. 앤더슨과의 마지막 세션. 그는 이제 나를 충분히 봤으니 앞으로는 혼자가 낫겠다고 분명히 말했다. 여덟 시에 다시 잠들까? (이 카운트다운이 나를 두렵게 한다.) 그는 잠시 멈췄다가 덧붙였다, 잘 있어라, 에니웨톡.","title":"시간의 목소리들","author":"J.G. 밸러드","ampm":"am","kind":"역"}],"06:34":[{"t":"아침 여섯 시 삼십사 분","q":"아침 여섯 시 삼십사 분. 씰 팀장 데번 로빈스 중위가 얇은 마이크에 대고 말했다. \"보이나? 적외선 스코프가 있으면 좋겠는데.\" 씰 팀은 평소대로 두 조로 나뉘었고, 그가 첫 번째 조를 이끌고 있었다.","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"06:35":[{"t":"여섯 시 삼십오 분","q":"화장대 위에 놓인 내 시계를 보니 여섯 시 삼십오 분이었다. 가족들은 아홉 시에 아침을 먹는다고 들었으니, 두 시간 반 가까이 여유가 있었다. 물론 나는 밖으로 나가 아침의 신선한 공기를 즐기기로 했다.","title":"레이븐스딘 코트","author":"J.S. 플레처","ampm":"am","kind":"역"}],"06:36":[{"t":"여섯 시 삼십육 분","q":"콜드런은 빛나는 그림자처럼 나를 쫓아다닌다. 그는 대문에 '96,688,365,498,702'라고 적어놓았다. 우체부를 헷갈리게 하겠지. 아홉 시 오 분에 깼다. 여섯 시 삼십육 분에 다시 잠들었다.","title":"시간의 목소리들","author":"J.G. 밸러드","ampm":"am","kind":"역"}],"06:37":[{"t":"여섯 시 삼십칠 분","q":"그리니치 표준시로 여섯 시 삼십칠 분. 재키는 그날 아침 모닝콜이 필요 없었다. 윌리엄이 M4 고속도로를 질주할 때, 그녀는 이미 워털루역으로 향하고 있었다.","title":"아무것도 걸지 않으면","author":"제프리 아처","ampm":"am","kind":"역"}],"06:38":[{"t":"여섯 시 삼십팔 분","q":"계기판 시계는 여섯 시 삼십팔 분을 가리키고 있었다. 그는 차 안에 열쇠를 두고 나무를 향해 걸어갔다.","title":"신들의 전쟁","author":"닐 게이먼","ampm":"am","kind":"역"}],"06:39":[{"t":"여섯 시 삼십구 분","q":"그는 여섯 시 삼십구 분, 오백 미터 거리에서 어뢰를 한 발 더 발사했다. 이번에도 목표를 빗나갔지만 칠 분 후 폭발했다. 그 어뢰는 단단한 물체에 부딪혀야만 터지도록 되어 있었다.","title":"골드파인더","author":"키스 제소프, 닐 핸슨","ampm":"am","kind":"역"}],"06:40":[{"t":"여섯 시 사십 분","q":"열한 시에 전화벨이 울렸지만 그 인물은 여전히 반응하지 않았다. 아침 여섯 시 삼십오 분에 전화가 울렸을 때도, 다시 여섯 시 사십 분에 울렸을 때도 반응이 없었던 것과 마찬가지였다.","title":"영혼의 길고 어두운 티타임","author":"더글러스 애덤스","ampm":"am","kind":"역"}],"06:41":[{"t":"여섯 시 사십일 분","q":"차 한 대가 서행하며 지나갔고, 운전자는 천천히 움직이는 와이퍼 너머로 그녀를 흘끔거렸다. 그녀는 평범한 사람인 척, 평범한 하루로 향하는 척 주머니를 뒤적이는 시늉을 했다. 여섯 시 사십일 분이었다.","title":"말을 다루는 여자","author":"조조 모예스","ampm":"am","kind":"역"}],"06:42":[{"t":"여섯 시 사십이 분","q":"여섯 시 사십이 분, 그는 막 혼자만의 아침 운동을 마친 참이었다. 거주구 원반에서 두 번째로 긴 고리인 링 7을 세 바퀴 돈 뒤, 체육관에서 삼십 분간 저항 채널을 밀고 당겼다.","title":"마린 캐뎃","author":"팀 C. 테일러","ampm":"am","kind":"역"}],"06:43":[{"t":"여섯 시 사십삼 분","q":"고집스러운 쇳소리는 어쩌면 꿈의 일부일지도 몰랐다. 그는 마지못해 돌아누워 침대맡 시계의 인광 초록빛 바늘을 흘겨보았다. 여섯 시 사십삼 분이었다.","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"06:44":[{"t":"여섯 시 사십사 분","q":"사이먼은 혼자 다닐 땐 기꺼이 삼등석을 타고 일부러 6시 25분 기차를 노리기도 했다. 하지만 오늘은 그 기차가 여섯 시 사십사 분으로 지연되었다.","title":"죽음들","author":"마크 로슨","ampm":"am","kind":"역"}],"06:45":[{"t":"여섯 시 사십오 분","q":"\"여섯 시 사십오 분이야.\" 그녀는 문간에 서서, 오래전 벗겨진 빨간 선 바로 뒤에 두 발을 가지런히 맞춰 놓고 있었다.","title":"비포 아이 폴","author":"로렌 올리버","ampm":"am","kind":"역"}],"06:46":[{"t":"여섯 시 사십육 분","q":"그는 책상 위 서류를 서류가방에 쓸어 담고 엘리베이터로 달려갔다. 첫 번째 행운으로 엘리베이터는 꼭대기 층에 있었다. 아래층 시계는 여섯 시 사십육 분을 가리켰다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"06:47":[{"t":"여섯 시 사십칠 분","q":"시각은 여섯 시 사십칠 분이었다. 제러미는 자명종들이 맞는지 확인하려 힐끗 보고는 가운을 여미며 서둘러 아래층으로 내려갔다.","title":"시간 도둑","author":"테리 프래쳇","ampm":"am","kind":"역"}],"06:48":[{"t":"여섯 시 사십팔 분","q":"차는 단번에 시동이 걸렸다. 믿음직한 메르세데스였다. 여섯 시 사십팔 분, 차는 도로로 접어들었다. 제한 속도를 넘기면 안 된다. 절대 청을 곤란하게 해선 안 된다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"06:49":[{"t":"여섯 시 사십구 분","q":"밤이 끝난다, 여섯 시 사십구 분. 일곱 시 반에 커피숍에서 만나고, 열 시에 기자회견이 있다.","title":"공포와 혐오: 72년 대선 유세 현장","author":"헌터 S. 톰슨","ampm":"am","kind":"역"}],"06:50":[{"t":"여섯 시 오십 분","q":"내 약혼자 윌은 보스턴에서 여섯 시 오십 분 기차, 그러니까 새벽 기차로 오고 있었다. 내가 살던 오하이오의 작은 도시에 여전히 서는 유일한 기차였다.","title":"프리티 아이스","author":"메리 로비슨","ampm":"am","kind":"역"}],"06:51":[{"t":"여섯 시 오십일 분","q":"문 하트넬은 눈을 뜨고 휴대폰을 더듬었다. 화면에는 밸런타인데이인 2월 14일, 여섯 시 오십일 분이라고 떠 있었다. 평소라면 알람이 울릴 때까지, 아니 엄마가 방문을 두드릴 때까지 침대에 머물렀을 것이다.","title":"네 형제를 죽여라","author":"잭 히스","ampm":"am","kind":"역"}],"06:52":[{"t":"여섯 시 오십이 분","q":"엄마에게 거짓말을 한 뒤 나는 마치 해고당한 적 없는 사람처럼 여섯 시 오십이 분 기차를 타고 런던으로 가는 수밖에 없다는 걸 깨달았다.","title":"킬리언 론의 굶주림과 울부짖음","author":"윌 스토","ampm":"am","kind":"역"}],"06:53":[{"t":"일곱 시 칠 분 전","q":"그러니까 질문의 열쇠는, 일곱 시 칠 분 전이 되기까지 정확히 칠십칠 분을 기다렸다가 답을 얻는 것이었다.","title":"쿼터 문","author":"스테퍼니 허드슨","ampm":"am","kind":"역"}],"06:54":[{"t":"일곱 시 육 분 전","q":"그가 혹시라도, 정말 혹시라도 답을 했을지 확인하고 싶었다. 지금은 아침 일곱 시 육 분 전이었는데도 말이다.","title":"그녀의 억만장자들","author":"줄리아 켄트","ampm":"am","kind":"역"}],"06:55":[{"t":"여섯 시 오십오 분","q":"여섯 시 오십오 분, 리사는 차를 세우고 얼어붙은 지하 주차장에서 엘리베이터를 타고 그린 오크스 쇼핑센터 1층으로 올라갔다.","title":"사라진 것","author":"캐서린 오플린","ampm":"am","kind":"역"}],"06:56":[{"t":"일곱 시 사 분 전","q":"\"소란을 피워 죄송할 따름입니다. 그럼요, 담배 한 대 피우고 싶습니다.\" 사형수가 답하고는 서둘러 덧붙였다. \"지금은 일곱 시 사 분 전이네,\" 러널드 소령이 말했다. \"관영 감옥에 담배와 성냥이 있어선 안 되는데.\"","title":"표류목 돛대","author":"퍼시벌 크리스토퍼 렌","ampm":"am","kind":"역"}],"06:57":[{"t":"일곱 시 삼 분 전","q":"그 말은 헬렌이 서둘러 달려가 상을 차려야 한다는 뜻이었다. 이미 일곱 시 삼 분 전이었으니까.","title":"카터가 자매들의 수상한 이웃","author":"닐 스피드","ampm":"am","kind":"역"}],"06:58":[{"t":"일곱 시 이 분 전","q":"그들은 기다렸다. 정확히 일곱 시 이 분 전, 흰 차 한 대가 나타나 건물 뒤 직원 주차장으로 들어섰다.","title":"작은 희생","author":"앤 룰","ampm":"am","kind":"역"}],"06:59":[{"t":"여섯 시 오십구 분","q":"그녀는 흘낏 눈을 들었다. 국장실 문을 두드렸지만 대답이 없어 지시대로 안으로 들어갔다. 국장은 없었다. 여섯 시 오십구 분, 그녀는 안락의자에 몸을 파묻었다. 국장이 늦으리라는 생각에 만족스러운 미소가 번졌다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"07:00":[{"t":"일곱 시","q":"그는 우유 배달부를 마음에 들어했다. 규칙적이고 시간을 잘 지켜 매일 아침 일곱 시 정각에 어김없이 문 앞에 병을 놓아두었기 때문이다.","title":"시간 도둑","author":"테리 프래쳇","ampm":"am","kind":"역"}],"07:01":[{"t":"일곱 시 일 분","q":"다음 날 아침 일곱 시 일 분, 포트버드의 영안실에서 나는 진실을 찾기 위한 첫걸음을 조심스레 내디뎠다.","title":"적","author":"리 차일드","ampm":"am","kind":"역"}],"07:02":[{"t":"일곱 시 이 분","q":"일곱 시 이 분, 남은 시간은 한 시간 반. \"케이스,\" 그녀가 말했다. \"부탁이 있어.\"","title":"뉴로맨서","author":"윌리엄 깁슨","ampm":"am","kind":"역"}],"07:03":[{"t":"일곱 시 삼 분","q":"그때까지 정해진 대로라면 누군가 정확히 일곱 시 삼 분에 나를 씻기고 매만지기 시작해야 했다.","title":"트리피드의 날","author":"존 윈덤","ampm":"am","kind":"역"}],"07:04":[{"t":"일곱 시 사 분","q":"일곱 시 사 분, 진정제에 취해 있던 의식 속으로 엔진의 굉음이 파고들며 스톤은 정신이 돌아오는 것을 느꼈다. 여기가 어디지? 사방에서 진동이 느껴졌고 귀를 찢는 굉음이 서서히 높아지고 있었다.","title":"신드롬","author":"토머스 후버","ampm":"am","kind":"역"}],"07:05":[{"t":"일곱 시 오 분","q":"창밖 하늘은 낮게 잿빛으로 드리워 있었다. 눈이 올 것 같은 날씨가 우울함을 더했다. 시계는 일곱 시 오 분을 가리켰다. 나는 리모컨을 누르고 침대에 누운 채 아침 뉴스를 보았다.","title":"댄스 댄스 댄스","author":"무라카미 하루키","ampm":"am","kind":"역"}],"07:06":[{"t":"일곱 시 육 분","q":"퍼시는 낙마했으면 곧바로 다시 말에 올라타야 한다는 오랜 격언을 믿는 사람이었다. 그는 일곱 시 육 분에 문을 열고 들어왔다. 한쪽 허리엔 권총을, 다른 쪽엔 우스꽝스러운 맞춤 홀스터에 꽂은 히코리 지팡이를 찬 채 푸른 제복 차림으로 눈부시게 등장했다.","title":"그린 마일","author":"스티븐 킹","ampm":"am","kind":"역"}],"07:07":[{"t":"일곱 시 칠 분","q":"일월 첫날 일곱 시 칠 분, 주베르가 회의실로 들어섰을 때 마흔 명의 형사들이 네 벽을 둘러싼 청회색 관용 의자에 이미 앉아 있었다.","title":"죽기 전에 죽다","author":"데온 마이어","ampm":"am","kind":"역"}],"07:08":[{"t":"일곱 시 팔 분","q":"일곱 시 팔 분, 무전기에서 한스의 목소리가 들려왔다. \"팀 투, 상황 이상 없음.\" 그와 마르셀은 청사진에 상세히 그려진, 지휘실 위쪽 환기 덕트 안에 있었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"07:09":[{"t":"일곱 시 구 분","q":"우리가 깨어나니 공기가 더 서늘했다. 손목시계는 일곱 시 구 분을 가리켰다. 배터리가 들어 있으니 그 안에 자기만의 작은 힘을 숨기고 있는 셈이었다.","title":"룸","author":"에마 도너휴","ampm":"am","kind":"역"}],"07:10":[{"t":"일곱 시 십 분","q":"\"백악관 비밀경호국 국장을 연결해 주게.\" \"알겠습니다.\" 국장은 손목시계를 흘긋 보았다. 일곱 시 십 분. 앤드루스는 여덟 시 십오 분에 오기로 되어 있었다. 그때 전화가 울렸다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"07:11":[{"t":"일곱 시 십일 분","q":"\"아무튼 매일 아침 일곱 시 십일 분이면 그는 문을 쾅 닫고 그랑프리라도 시작하듯 엔진을 부릉거려서, 특히 야간 근무를 막 마친 날이면 내 단잠을 완전히 망쳐놓곤 했지.\"","title":"라임스톤 카우보이","author":"스튜어트 포슨","ampm":"am","kind":"역"}],"07:12":[{"t":"일곱 시 십이 분","q":"일곱 시 십이 분, 부엌에서 킴벌리는 초조해지고 있었다. 홀랜드 수녀에게서 그래드윈 양이 아침 차 쟁반을 일곱 시에 올려달라고 청했다는 말을 전해 들은 터였다.","title":"사설 환자","author":"P.D. 제임스","ampm":"am","kind":"역"}],"07:13":[{"t":"일곱 시 십삼 분","q":"아우스터리츠의 말에 따르면, 기차가 일곱 시 십삼 분에 출발하기 직전 객차 복도 창밖을 내다보았을 때, 플랫폼 위 유리와 철제 지붕의 무늬를 전에도 본 적이 있다는 확신이 문득 밀려와 그는 더욱 놀라고 은근히 불안해졌다.","title":"아우스터리츠","author":"W.G. 제발트","ampm":"am","kind":"역"}],"07:14":[{"t":"일곱 시 십사 분","q":"일곱 시 십사 분, 그리니치 표준시. 윌리엄은 그가 터미널에 들어서는 순간 알아보았다. 짙은 남색 더블브레스티드 블레이저에 흰 셔츠, 줄무늬 넥타이 차림. 저 사령관은 아마 더블브레스티드 잠옷을 입고 잘 것이다.","title":"모험 없이","author":"제프리 아처","ampm":"am","kind":"역"}],"07:15":[{"t":"일곱 시 십오 분","q":"이 기이한 순환 고리는 인과율에 묘한 영향을 미친다. 아홉 시까지 출근해야 하기에 우리는 아침에 일어나 일곱 시 십오 분에 집을 나선다. 과학적으로 보면 이는 매우 기묘한 형태의 인과율이니, 미래가 과거에 영향을 미치는 셈이다.","title":"글로브","author":"테리 프래쳇","ampm":"am","kind":"역"}],"07:16":[{"t":"일곱 시 십육 분","q":"좀비 스마트가이드는 살아 있을 때 평범한 양치질 시나리오를 처리하던 것보다 이런 허구적인 시간여행 양치질 시나리오를 구성하는 데 훨씬 더 공을 들인다. 문자 그대로 하루 종일 그 일을 한다. 요즘은 일곱 시 십육 분에서 십칠 분으로 넘어가는 순간을 유독 자주 보여준다.","title":"씨앗 수집가들","author":"스칼렛 토머스","ampm":"am","kind":"역"}],"07:17":[{"t":"일곱 시 십칠 분","q":"1908년 6월 30일 현지 시각 일곱 시 십칠 분, 파지트노프는 거의 일 년째 오흐라나의 계약 요원으로 일하며 다달이 오백 루블을 받고 있었으니, 당시 첩보 예산 지출로는 터무니없이 후한 금액이었다.","title":"그날에 맞서","author":"토머스 핀천","ampm":"am","kind":"역"}],"07:18":[{"t":"일곱 시 십팔 분","q":"일곱 시 십팔 분. '율리시스가 시렌에게. 응답하라.' 무전기가 지직거렸을 때 아르몽은 베이츠 모텔의 의무실에서 디미트리의 팔에 혈장 링거가 꽂히는 것을 지켜보고 있었다. 그는 즉시 무전기를 움켜쥐었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"07:19":[{"t":"일곱 시 십구 분","q":"피로와 싸우려고 선루프를 열고 CD 플레이어 볼륨을 높였고, 토요일 일곱 시 십구 분, 카페인이 여전히 뇌 속을 휘돌 때 잭슨 브라운과 나는 모리에 들어섰다.","title":"로지 프로젝트","author":"그레임 심슨","ampm":"am","kind":"역"}],"07:20":[{"t":"일곱 시 이십 분","q":"일곱 시 이십 분, 문이 열리며 앤이 다시 나타나 그날의 가장 중요한 임무를 수행했다. '해리, 이제 스튜디오로 모실 시간이에요.'","title":"때가 되면","author":"제프리 아처","ampm":"am","kind":"역"}],"07:21":[{"t":"일곱 시 이십일 분","q":"왜 그 시각을 아는 게 중요하게 느껴졌는지, 이 혼돈 속에서 자신을 붙잡아 두려는 것 말고는 이유가 없었다. 일곱 시 이십일 분. 수많은 사람들이 아침을 먹거나 출근 준비를, 혹은 유월절 준비를 하고 있었을 시각이었다.","title":"전시의 작은 도서관","author":"케이트 톰프슨","ampm":"am","kind":"역"}],"07:23":[{"t":"일곱 시 이십삼 분","q":"세바스찬은 패딩턴행 일곱 시 이십삼 분 기차를 놓치지 않으려고 어머니의 자명종을 빌려야 했다. 현관에서 기다리던 에마가 템플 미즈까지 태워다 주겠다고 나섰다. 그 이유는 곧 분명해졌다.","title":"가장 은밀한 비밀","author":"제프리 아처","ampm":"am","kind":"역"}],"07:24":[{"t":"일곱 시 이십사 분","q":"잠시 웅성거리는 목소리가 들리더니 스티븐 코트니브릭스가 그녀를 따라 응접실로 들어섰다. 시계를 흘긋 본 댈글리시는 시곗바늘이 일곱 시 이십사 분을 가리키는 것을 보았다. 하루 일과가 거의 시작된 셈이었다.","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"07:25":[{"t":"일곱 시 이십오 분","q":"일곱 시 이십오 분, 케르 카라제와 세르코 기사, 스페이드 선장은 곶의 끝까지 나아가 망원경으로 북서쪽 수평선을 훑었다.","title":"깃발 앞에서","author":"쥘 베른","ampm":"am","kind":"역"}],"07:26":[{"t":"일곱 시 이십육 분","q":"일곱 시 이십육 분, 척이 갑판에 나와 있을 때 헬멧과 배낭을 멘 해병들이 배 옆에 늘어뜨려진 밧줄 그물을 타고 내려와 뱃전 높은 상륙정으로 뛰어들기 시작했다.","title":"세계의 겨울","author":"켄 폴릿","ampm":"am","kind":"역"}],"07:27":[{"t":"일곱 시 이십칠 분","q":"조종사가 승객들을 맞으며 약간의 지연이 있을 수 있다고 알렸다. 덱스터는 손목시계를 확인했다. 일곱 시 이십칠 분. 그는 스콧과 자신 사이를 가르는 팔걸이를 손가락으로 두드리기 시작했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"07:28":[{"t":"일곱 시 이십팔 분","q":"'아시다시피 저희는 24시간 대기라 일곱 시 이십팔 분에 도착했습니다. 바로 수사를 시작하기로 했지요. 조사가 끝나는 대로 장의사들이 시신을 수습할 겁니다.'","title":"살인의 방","author":"P.D. 제임스","ampm":"am","kind":"역"}],"07:29":[{"t":"일곱 시 이십구 분","q":"라몬트는 11번 승강장에서 그녀를 기다리고 있었고, 두 사람은 이등석으로 길퍼드행 일곱 시 이십구 분 기차에 올랐다. 도착하자 서리 경찰청에서 그날 남은 일정을 온전히 전달받은 유일한 인물인 월 총경이 그들을 맞았다.","title":"모험 없이","author":"제프리 아처","ampm":"am","kind":"역"}],"07:31":[{"t":"일곱 시 삼십일 분","q":"일곱 시 삼십일 분. 빌 베이츠는 시코르스키 헬기의 넓은 앞유리 너머로 그들이 다가오는 것을 보았다. 이제야말로 움직일 때라는 것을, 그는 즉시 깨달았다. 지금이 아니면 안 되었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"07:32":[{"t":"일곱 시 삼십이 분","q":"일곱 시 삼십이 분, 그는 치명적인 뇌졸중을 일으켰다.","title":"그것","author":"스티븐 킹","ampm":"am","kind":"역"}],"07:33":[{"t":"일곱 시 삼십삼 분","q":"수요일 일곱 시 삼십삼 분. '이 자리를 좋아하니 망정이지.' 밴스가 도시를 내려다보며 말했다. '이 지구상에 이런 이른 시각에 날 깨울 수 있는 건 아무것도 없었을 텐데.'","title":"프로젝트 다이달로스","author":"토머스 후버","ampm":"am","kind":"역"}],"07:34":[{"t":"일곱 시 삼십사 분","q":"그는 서머스가 일곱 시 삼십사 분에 건물에서 나오는 것을 보고 수첩에 다시 기록한 뒤, 무전이 울리자 인근 경찰서 쪽으로 향했다. 폴이 보고하는 내용을 주의 깊게 듣고는 사무실에 돌아가는 대로 처리하겠다고 말했다.","title":"눈감아 주다","author":"제프리 아처","ampm":"am","kind":"역"}],"07:35":[{"t":"일곱 시 삼십오 분","q":"플로렌티나 케인은 일곱 시 삼십오 분이 되어서야 잠에서 깼다. 그녀는 몸을 뒤척이며 방금 꾼 꿈을 떠올리려 했지만 아무것도 되살아나지 않아, 생각이 흘러가는 대로 내버려두었다.","title":"대통령께 말씀드릴까요?","author":"제프리 아처","ampm":"am","kind":"역"}],"07:36":[{"t":"일곱 시 삼십육 분","q":"일곱 시 삼십육 분, 해가 떴다. 병원 블라인드는 그녀의 집 것보다 훨씬 나았고, 훨씬 어두웠다.","title":"렛미인","author":"욘 아이비데 린드크비스트","ampm":"am","kind":"역"}],"07:37":[{"t":"일곱 시 삼십칠 분","q":"전화벨이 일곱 시 삼십칠 분에 울렸다. 마침 아침 식탁에 커피 잔을 내려놓던 참이었다.","title":"위성 인간","author":"한스 올라브 라흘룸","ampm":"am","kind":"역"}],"07:38":[{"t":"일곱 시 삼십팔 분","q":"일곱 시 삼십팔 분. '수신했다.' 니콜스가 마이크에 대고 말했다. '헬기는 언제 이륙했지?'","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"07:39":[{"t":"일곱 시 삼십구 분","q":"일곱 시 삼십구 분, 항공기는 이륙을 준비하려 활주로로 이동했다. 기체가 멈추자 덱스터는 승무원에게 무엇 때문에 지체되는지 물었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"07:40":[{"t":"일곱 시 사십 분","q":"일곱 시 사십 분, 아침을 먹는다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"07:41":[{"t":"일곱 시 사십일 분","q":"그는 서둘러 아래층으로 뛰어내려갔다. 현관은 텅 비어 있었다, 일곱 시 사십일 분! 기차는 여덟 시에 떠났다. 볼레로에 안장을 얹을 시간이 있을까?","title":"어두운 꽃","author":"존 골즈워디","ampm":"am","kind":"역"}],"07:42":[{"t":"일곱 시 사십이 분","q":"일곱 시 사십이 분, 가스파리안 씨. 나는 당신을 저주한다. 당신의 팔이 시들어 죽고 몸에서 떨어져 나가기를.","title":"피 흘리는 마법","author":"일로나 앤드루스","ampm":"am","kind":"역"}],"07:43":[{"t":"여덟 시 십칠 분 전","q":"여덟 시 십칠 분 전이었다. 시간은 충분하다고 생각했지만, 도착한 지 오 분도 안 되어 그를 놓친 건 아닌지 걱정되기 시작했다.","title":"보가트가 된 줄 알았던 도둑","author":"로렌스 블록","ampm":"am","kind":"역"}],"07:44":[{"t":"여덟 시 십육 분 전","q":"제닝스 경사 말씀이시라면, 제가 오늘 아침 여덟 시 십육 분 전에 도착했을 때 그는 근무 중임에도 면도도 안 하고 복장도 엉망이었습니다. 크게 나무라진 않았지만, 경찰관으로서의 태도와 몸가짐에 대해 제가 어떻게 느꼈는지는 분명히 전했습니다.","title":"다음 차례","author":"제프리 아처","ampm":"am","kind":"역"}],"07:45":[{"t":"여덟 시 십오 분 전","q":"평소 지각하던 버릇과 달리, 그날 피에르는 열 시가 아니라 여덟 시 십오 분 전에 베르크 가에 도착했다.","title":"전쟁과 평화","author":"레프 톨스토이","ampm":"am","kind":"역"}],"07:46":[{"t":"일곱 시 사십육 분","q":"잠에서 화들짝 깼다. 침대맡 시계는 일곱 시 사십육 분을 가리키고 있었다. 그는 욕을 하며 침대에서 뛰쳐나와 옷을 입었다.","title":"리가의 개들","author":"헤닝 만켈","ampm":"am","kind":"역"}],"07:47":[{"t":"일곱 시 사십칠 분","q":"그는 아들을 건너다보았다. \"내가 가르친 대로 이름들을 다 기록해뒀지?\" \"그럼요, 아버지. 파넬 씨, 일곱 시 사십칠 분. 파커 씨, 여덟 시 구 분. 튜더존스 씨, 여덟 시 십일 분. 알렉산더 씨, 여덟 시 이십삼 분.\"","title":"잔디는 언제나 더 푸르다","author":"제프리 아처","ampm":"am","kind":"역"}],"07:48":[{"t":"일곱 시 사십팔 분","q":"일곱 시 사십팔 분, 밴스는 어리둥절한 얼굴로 산을 올려다보았다. 정적이 그를 당혹스럽게 했고, 이내 이유를 깨달았다. 변압기의 익숙한 고압 소음이 들리지 않았다. 전력이 끊긴 것이었다.","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"07:49":[{"t":"여덟 시 십일 분 전","q":"\"여덟 시 십일 분 전이야.\" \"넌 항상 맞더라, 머릿속에 시계라도 든 게 분명해.\"","title":"시작의 끝","author":"레이 브래드버리","ampm":"am","kind":"역"}],"07:50":[{"t":"여덟 시 십 분 전","q":"호건 경위는 여덟 시 십 분 전에 현관 초인종을 눌렀다. 잠시 후 말끔히 면도하고 단정하게 차려입은 채 그를 기다리고 있던 누군가가 문을 열었다.","title":"다음 차례","author":"제프리 아처","ampm":"am","kind":"역"}],"07:51":[{"t":"일곱 시 오십일 분","q":"비행기는 일곱 시 오십일 분에 활주로로 방향을 틀었고, 제트 엔진 소리를 높이며 서서히 앞으로 나아가다 속도를 붙였다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"07:52":[{"t":"여덟 시 팔 분 전","q":"강력계 형사 데이비드 나이저는 여덟 시 팔 분 전에 트윈픽스 드라이브의 그 집에 도착했다. 조 도엔치 수석 형사반장은 이미 그곳에 와 있었다.","title":"고요한 밤에","author":"앤 룰","ampm":"am","kind":"역"}],"07:53":[{"t":"일곱 시 오십삼 분","q":"바퀴가 땅에서 떨어진 것은 일곱 시 오십삼 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"07:54":[{"t":"아침 여덟 시 육 분 전","q":"다른 이들이 도착했을 때 내가 눈을 뜨니, 그날 아침 여덟 시 육 분 전이었다. 일어난 지 두 시간도 지나지 않았고, 시간은 다시 정상으로 돌아와 있었다. 하지만 그 시간 안에 벌어진 일들은 결코 두 시간 안에 다 담을 수 없는 것들이었다.","title":"시간의 여섯 손가락","author":"R.A. 래퍼티","ampm":"am","kind":"역"}],"07:55":[{"t":"여덟 시 오 분 전","q":"벽시계를 올려다보았다. 여덟 시 오 분 전이었다. \"그녀가 일찍 와 달라고 했거든요.\" 나는 옆으로 비켜 그를 지나쳤다.","title":"풀 문","author":"짐 부처","ampm":"am","kind":"역"}],"07:56":[{"t":"여덟 시가 되기 직전","q":"여덟 시가 되기 직전, 에릭 스노우는 예고도 없이 들이닥쳐 부목사의 책상에 신문을 내던졌다. 아트는 신문은 거들떠보지도 않고 상사와 눈을 맞추며 속이 훤히 보이는 웃음을 지어 보였다.","title":"야망","author":"리 스트로벨","ampm":"am","kind":"역"}],"07:57":[{"t":"일곱 시 오십칠 분","q":"엠마는 런던을 가로지르는 동안 두 회장의 상세한 제출 자료를 읽었지만, 차가 할리 스트리트에 들어설 때까지도 어느 쪽 손을 들어줄지 정하지 못했다. 서류를 붉은 상자에 도로 넣고 손목시계를 확인했다. 일곱 시 오십칠 분.","title":"그는 한 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"07:58":[{"t":"일곱 시 오십팔 분","q":"매커내니는 화면 구석의 시계를 보았다. 일곱 시 오십팔 분이었다. 몇 번 더 자판을 두드리자 페이지 콜드웰의 목소리가 헤드셋을 타고 들려왔다.","title":"살인자들의 열","author":"레이 키팅","ampm":"am","kind":"역"}],"07:59":[{"t":"여덟 시 일 분 전","q":"여덟 시 일 분 전, 그는 산기슭으로 이어지는 길을 따라 빠른 걸음으로 나섰다.","title":"영광의 길","author":"제프리 아처","ampm":"am","kind":"역"}],"08:01":[{"t":"여덟 시 일 분","q":"여덟 시 일 분, 째깍째깍, 여덟 시 일 분이야, 학교 갈 시간, 일하러 갈 시간, 뛰어, 뛰어, 여덟 시 일 분!","title":"부드러운 비가 내리리라","author":"레이 브래드버리","ampm":"am","kind":"역"}],"08:02":[{"t":"여덟 시 이 분","q":"여덟 시 이 분, 리틀보텀보텀 상병 사망... 여덟 시 삼 분, 데트리투스 병장 사망... 여덟 시 삼 분 삼십삼 초, 비지트 순경 사망... 죽음의 죽음의 죽음...","title":"징고","author":"테리 프래쳇","ampm":"am","kind":"역"}],"08:03":[{"t":"여덟 시 삼 분","q":"마지막 한 입을 다 먹고 나서 스콧은 손목시계를 확인했다. 여덟 시 삼 분, 공항으로 가는 택시를 잡기 전에 커피 한 잔 마실 시간은 충분했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:04":[{"t":"여덟 시 사 분","q":"여덟 시 사 분, 전화벨이 울리고 있었지만 마크는 여전히 깊이 잠들어 있었다. 벨소리는 계속 울렸다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"08:05":[{"t":"여덟 시 오 분","q":"여덟 시 오 분, 책가방을 챙긴다.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"am","kind":"역"}],"08:06":[{"t":"여덟 시 육 분","q":"열이 좀 있어 잠을 설쳤고 출발이 조금 늦었습니다. 등대에 도착한 건 여덟 시 육 분이었어요. 안으로 들어갈 수 없었습니다. 문이 잠겨 있었거든요.","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:07":[{"t":"여덟 시 칠 분","q":"여덟 시 칠 분, 라라는 베티 제프리스가 아이들을 데리고 학교로 서둘러 가는 모습을 보았다.","title":"붉은 태양 아래의 꿈","author":"엘리자베스 하란","ampm":"am","kind":"역"}],"08:08":[{"t":"여덟 시 팔 분","q":"직원들은 저마다 정해진 출근 시간이 있어 시내에서 오는 트램 편과 맞물렸다. A는 여덟 시, B는 여덟 시 사 분, C는 여덟 시 팔 분에 맞춰 왔고, 퇴근 시간도 마찬가지여서 두 동료가 같은 트램을 탈 일은 결코 없었다.","title":"주기율표","author":"프리모 레비","ampm":"am","kind":"역"}],"08:09":[{"t":"여덟 시 구 분","q":"그는 아들을 건너다보았다. \"내가 가르친 대로 이름들을 다 기록해뒀지?\" \"그럼요, 아버지. 파넬 씨, 일곱 시 사십칠 분. 파커 씨, 여덟 시 구 분. 튜더존스 씨, 여덟 시 십일 분. 알렉산더 씨, 여덟 시 이십삼 분.\"","title":"잔디는 언제나 더 푸르다","author":"제프리 아처","ampm":"am","kind":"역"}],"08:10":[{"t":"여덟 시 십 분","q":"여덟 시 십 분, 책을 읽거나 비디오를 본다.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"am","kind":"역"}],"08:11":[{"t":"여덟 시 십일 분","q":"그는 아들을 건너다보았다. \"내가 가르친 대로 이름들을 다 기록해뒀지?\" \"그럼요, 아버지. 파넬 씨, 일곱 시 사십칠 분. 파커 씨, 여덟 시 구 분. 튜더존스 씨, 여덟 시 십일 분. 알렉산더 씨, 여덟 시 이십삼 분.\"","title":"잔디는 언제나 더 푸르다","author":"제프리 아처","ampm":"am","kind":"역"}],"08:12":[{"t":"여덟 시 십이 분","q":"여덟 시 십이 분, 정적이 찾아오기 직전, 지하 저장고들은 온통 분주했다. 쓰레기를 작은 통에서 큰 통으로 옮기고, 불면증에 시달리며 일찌감치 깬 할머니들은 세탁물을 큰 통에 쏟아부었고, 수영복 차림의 소년들은 유모차를 밀며 서늘한 아침 공기 속으로 나섰다.","title":"우리 모두를 원숭이로 만든 시간 속에서","author":"그레이스 페일리","ampm":"am","kind":"역"}],"08:13":[{"t":"여덟 시 십삼 분","q":"여덟 시 십삼 분, 실험실 자명종이 울렸다. 에디는 평범한 유리 커피포트 밑동의 버튼을 눌렀고, 주둥이에서 관 두 개가 벽 속으로 이어졌다.","title":"우리 모두를 원숭이로 만든 시간 속에서","author":"그레이스 페일리","ampm":"am","kind":"역"}],"08:14":[{"t":"여덟 시 십사 분","q":"여덟 시 십사 분, 양가죽 외투를 입은 남자가 들어와 손수 만 담배를 빨며 명랑하게 손을 내밀었다. \"문 씨로군요.\"","title":"글렌의 군주","author":"닐 게이먼","ampm":"am","kind":"역"}],"08:15":[{"t":"여덟 시 십오 분","q":"국장은 시계를 보았다. 일곱 시 십 분. 앤드루스는 여덟 시 십오 분에 오기로 되어 있었다. 그때 전화벨이 울렸다.","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"am","kind":"역"}],"08:16":[{"t":"여덟 시 십육 분","q":"손가락이 근질거려 시계를 보니, 아직 여덟 시 십육 분이었다. 아, 이런.","title":"가정적이지 않은 여신","author":"소피 킨셀라","ampm":"am","kind":"역"}],"08:17":[{"t":"여덟 시 십칠 분","q":"\"그럼 가지.\" T. 해밀턴 매켄지가 시계를 확인했다. 여덟 시 십칠 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:18":[{"t":"여덟 시 십팔 분","q":"그들이 여덟 시 십칠 분이나 여덟 시 십팔 분쯤 떠났다고 치자. 그렇다면 조앤 갈런드를 뒤쫓았을 테고, 어쩌면 그녀보다 빨리 달리고 있을지도 몰랐다.","title":"포수의 딸에게 입맞춤을","author":"루스 렌델","ampm":"am","kind":"역"}],"08:19":[{"t":"여덟 시 십구 분","q":"여덟 시 십구 분, 그녀는 두 번째 전화를 받고 비행기가 '화물'을 실은 채 암만을 이륙했다는 소식을 들었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:20":[{"t":"여덟 시 이십 분","q":"\"오늘 아침 엔진을 시험해 보려고 사십 분쯤 배를 몰고 나갔다 왔소. 일곱 시 사십오 분부터 여덟 시 이십 분까지, 거의 그쯤이었지.\"","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:22":[{"t":"여덟 시 이십이 분","q":"데이지 플로리는 여덟 시 이십이 분에 신고 전화를 걸었다. 그들이 떠난 지 몇 분 지나지 않은 때였다.","title":"포수의 딸에게 입맞춤을","author":"루스 렌델","ampm":"am","kind":"역"}],"08:23":[{"t":"여덟 시 이십삼 분","q":"\"물론이죠, 아빠. 파넬 씨, 일곱 시 사십칠 분. 파커 씨, 여덟 시 구 분. 튜더존스 씨, 여덟 시 십일 분. 알렉산더 씨, 여덟 시 이십삼 분.\"","title":"잔디는 늘 더 푸르다","author":"제프리 아처","ampm":"am","kind":"역"}],"08:24":[{"t":"여덟 시 이십사 분","q":"여덟 시 이십사 분, 선임 파트너가 들어왔다. \"업무를 방해해서 미안하네만, 사내 메모 한 장으로 넘길 일이 아니었네.\"","title":"행운의 아들들","author":"제프리 아처","ampm":"am","kind":"역"}],"08:25":[{"t":"여덟 시 이십오 분","q":"여덟 시부터 여덟 시 이십오 분까지, 그 이십오 분이 여성 용의자 전원이 콜린스 양의 눈길 아래 함께 있었던 유일한 시간이었다.","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:26":[{"t":"여덟 시 이십육 분","q":"\"몇 시야?\" 젊은이는 새로 산 시계에서 눈을 떼지 못한 채 자랑스럽게 대답했다. \"여덟 시 이십육 분 이십 초입니다.\"","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:27":[{"t":"여덟 시 이십칠 분","q":"그는 세븐오크스 역 1번 승강장에 도착하면 데일리 익스프레스 한 부를 사고 나서, 캐넌 스트리트행 여덟 시 이십칠 분 기차에 올랐다.","title":"깨진 일과","author":"제프리 아처","ampm":"am","kind":"역"}],"08:28":[{"t":"여덟 시 이십팔 분","q":"이튿날 아침 여덟 시 이십팔 분, 윗입술에 낯선 서늘함을 느끼며 넘치는 기운을 안고, 나는 완두 재킷에 챙 모자, 목도리를 두른 선원 차림으로 독일행 삼등칸에 앉아 있었다.","title":"모래톱의 수수께끼","author":"어스킨 차일더스","ampm":"am","kind":"역"}],"08:29":[{"t":"여덟 시 이십구 분","q":"트렌트 씨는 하루도 어김없이 아침 일곱 시에 일어나 일곱 시 반에 아침을 먹고, 여덟 시 십 분에 출근해 여덟 시 이십구 분에 도착했다.","title":"위대한 열차 강도","author":"마이클 크라이튼","ampm":"am","kind":"역"}],"08:30":[{"t":"여덟 시 반","q":"그는 여덟 시 반에 눈을 떠 쌓인 서류를 읽고는 작은 비명을 삼켰다. 그래, 그래, 딱히 서두를 것 없어. 언제든 다시 바꾸면 되니까. 시간 여행이란 그런 거야.","title":"다윈의 시계","author":"테리 프래쳇","ampm":"am","kind":"역"}],"08:31":[{"t":"여덟 시 삼십일 분","q":"오전 여덟 시 삼십일 분, TWA 196편의 한 여자 승객이 울음을 터뜨리며 비행기가 추락할 거라는 자신의 생각을 목청껏 외쳐댔다.","title":"샤이닝","author":"스티븐 킹","ampm":"am","kind":"역"}],"08:32":[{"t":"여덟 시 삼십이 분","q":"책이 바닥에 쿵 떨어지는 소리에 놀라 다시 깨어난 그는 손을 더듬어 시계를 찾았다. 여덟 시 삼십이 분, 하루를 시작하기엔 늦은 시각이었다.","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:33":[{"t":"여덟 시 삼십삼 분","q":"그는 여덟 시 삼십삼 분에 하강을 시작했고, 몇 달 만에 처음으로 예정대로 게이트에 도착했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:34":[{"t":"여덟 시 삼십사 분","q":"정확히 여덟 시 삼십사 분, 콘래드 파인 장군의 검은 공용 로버 800이 다우닝가 입구를 지키는 볼썽사나운 철제 차단봉 앞에 멈춰 섰다.","title":"최후통첩","author":"제임스 폴렛","ampm":"am","kind":"역"}],"08:35":[{"t":"여덟 시 삼십오 분","q":"\"이 아이를 데려가거라, 나의 사랑. 여덟 시 삼십오 분이면 너는 천국에 있을 것이고 아일랜드는 자유로워질 것이다.\"","title":"율리시스","author":"제임스 조이스","ampm":"am","kind":"역"}],"08:36":[{"t":"여덟 시 삼십육 분","q":"첫 번째 신호탄은 여덟 시 삼십육 분에 쏘아 올려졌고, 두 번째는 곧이어 발사되었다.","title":"구명보트!","author":"마거릿 디킨슨","ampm":"am","kind":"역"}],"08:37":[{"t":"여덟 시 삼십칠 분","q":"피어스는 자리에서 일어나 조끼에서 시계를 꺼내 뚜껑을 열었다. 여덟 시 삼십칠 분이었다.","title":"위대한 열차 강도","author":"마이클 크라이튼","ampm":"am","kind":"역"}],"08:38":[{"t":"여덟 시 삼십팔 분","q":"\"바스케스의 차가 카프레밀에서 멈췄어. 여덟 시 삼십팔 분에.\" \"그런데?\" \"북쪽으로 가고 있다고!\"","title":"일탈한 종족","author":"스티븐 코일","ampm":"am","kind":"역"}],"08:39":[{"t":"여덟 시 삼십구 분","q":"오전 여덟 시 삼십구 분. \"오 분 뒤 진행합니다.\" 캐럴라인 셰퍼가 그의 어깨 너머로 속삭이듯 알렸다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"08:40":[{"t":"여덟 시 사십 분","q":"그는 여덟 시 사십 분이 막 지나 셰리네덜란드를 나섰고, 렉싱턴에 다다를 즈음엔 교장의 노여움을 마주할 각오가 되어 있었다.","title":"때가 오면","author":"제프리 아처","ampm":"am","kind":"역"}],"08:41":[{"t":"여덟 시 사십일 분","q":"지금은 여덟 시 사십일 분, 나는 침대에서 연습 중이다. 엄마는 뜨거운 물을 담은 비닐봉지를 꽁꽁 묶어 다른 봉지에 한 번 더 넣고 묶는다.","title":"룸","author":"에마 도너휴","ampm":"am","kind":"역"}],"08:42":[{"t":"여덟 시 사십이 분","q":"여덟 시 사십이 분, 마침내 블랙이 나타났을 때 그녀는 수요일 감시 내용에 몰두한 척하느라, 그가 문가에 서 있는 것도 알아채지 못했다.","title":"그의 뜨거운 상대","author":"섀넌 홀리스","ampm":"am","kind":"역"}],"08:43":[{"t":"여덟 시 사십삼 분","q":"전화가 끊겼다. 카발리는 아버지의 말이 옳다는 걸 알았다. 그는 시계를 다시 확인했다. 여덟 시 사십삼 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"08:44":[{"t":"여덟 시 사십사 분","q":"병사 몇 명이, 제복 단추를 풀어헤친 이도 있었다, 오토바이를 살펴보며 다투고 있었다. 상사가 시계를 보니 여덟 시 사십사 분이었다. 아홉 시까지 기다려야 했다. 흘라디크는 불운하다기보다 하찮다는 느낌에 사로잡힌 채 장작더미 위에 주저앉았다.","title":"비밀의 기적","author":"호르헤 루이스 보르헤스","ampm":"am","kind":"역"}],"08:45":[{"t":"여덟 시 사십오 분","q":"데이비드는 월요일 아침 아홉 시에 사무실에 도착했지만 정문이 잠겨 있었다. 도무지 이해할 수 없었다. 비서들은 여덟 시 사십오 분까지는 출근해 있어야 했다.","title":"한 푼도 더 말고 덜도 말고","author":"제프리 아처","ampm":"am","kind":"역"}],"08:47":[{"t":"여덟 시 사십칠 분","q":"여덟 시 사십칠 분. 방금 담배 한 대를 피웠다. 하지만 금연의 날은 옷을 다 갈아입어야 공식적으로 시작된다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"am","kind":"역"}],"08:48":[{"t":"아홉 시 십이 분 전","q":"스웨인 스트리트를 걸어 내려가 리즈 로드를 지나면, 낡은 문으로 들어가 낡은 계단을 올라 낡은 의자에 슬쩍 앉아, 종이와 향수와 풀 더미를 그러모아 멈췄던 자리에서 다시 일을 시작할 수 있지 않을까? 하지만 시계는 아홉 시 십이 분 전이었다.","title":"용기","author":"말라키 휘태커","ampm":"am","kind":"역"}],"08:49":[{"t":"여덟 시 사십구 분","q":"여덟 시 사십구 분, 문에서 요란한 노크 소리가 났고 해미시 경은 데이비드 히스가 문을 열러 가는 사이 들리지 않을 만큼 낮게 투덜거렸다. 문 앞에는 그의 정보원이 서 있었다.","title":"원칙의 문제","author":"제프리 아처","ampm":"am","kind":"역"}],"08:50":[{"t":"아홉 시 십 분 전","q":"아홉 시 십 분 전, 체비셤 외곽 스프로그스 코티지 앞에 우편 트럭이 멈춰 서서 편지 한 통을 배달했다.","title":"전문가 증인의 죽음","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:51":[{"t":"여덟 시 오십일 분","q":"여덟 시 오십일 분, 학교에 도착했다.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"am","kind":"역"}],"08:52":[{"t":"여덟 시 오십이 분","q":"첫 번째 메시지. 화요일, 여덟 시 오십이 분. 거기 누구 없어요? 여보세요?","title":"엄청나게 시끄럽고 믿을 수 없게 가까운","author":"조너선 사프란 포어","ampm":"am","kind":"역"}],"08:53":[{"t":"여덟 시 오십삼 분","q":"로스는 창밖을 내다보니 디에고 마르티네스가 전속력으로 선로를 따라 역으로 달려오고 있었다. 시계를 확인했다, 여덟 시 오십삼 분.","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"08:54":[{"t":"여덟 시 오십사 분","q":"택시비로 거의 1파운드를 써야 했지만, 그는 여덟 시 오십사 분에 경찰서에 도착할 수 있었다. 젊은 순경이 그를 곧장 취조실이 아닌 워릭 형사 반장의 사무실로 안내했다.","title":"헤즈 유 윈","author":"제프리 아처","ampm":"am","kind":"역"}],"08:55":[{"t":"여덟 시 오십오 분","q":"전화벨이 울린 것은 여덟 시 오십오 분이 되어서였고, 그가 기다리던 목소리가 들려왔다. 캐럴라인의 음성은 더없이 침착했지만 말만은 다급했다. \"당신을 만나야 해요. 지금 당장. 빠져나올 수 있어요?\"","title":"음모와 욕망","author":"P.D. 제임스","ampm":"am","kind":"역"}],"08:56":[{"t":"아홉 시 사 분 전","q":"나는 주말에 있었던 일을 그녀에게 들려주었고, 총소리 이야기를 하자 그녀의 얼굴이 하얗게 질렸다. \"다치지 않아서 다행이야.\" 우리는 그 사건을 몇 분 더 이야기했고, 그제야 시간을 확인했다. 아홉 시 사 분 전이었다.","title":"고양이 출입 금지","author":"미란다 제임스","ampm":"am","kind":"역"}],"08:57":[{"t":"아홉 시 삼 분 전","q":"찰스 애플게이트가 아홉 시 삼 분 전에 우리 집 초인종을 누른 것은 놀랄 일이 아니었다. 그는 전화 통화에서부터 믿음직스러운 사람의 표본처럼 들렸었다.","title":"미술품 수집가의 죽음","author":"로버트 골즈버러","ampm":"am","kind":"역"}],"08:58":[{"t":"아홉 시 이 분 전","q":"지금은 아홉 시 이 분 전, 즉 폭탄이 터지기로 예정된 이 분 전이었다. 은행 앞에는 서너 사람이 모여 문이 열리기를 기다리고 있었다.","title":"겟어웨이","author":"짐 톰슨","ampm":"am","kind":"역"}],"08:59":[{"t":"아홉 시 일 분 전","q":"빙엄이 웃었다. \"그럼 월요일 아홉 시 일 분 전에 전화기 앞에서 기다리고 있겠소.\" 그는 수첩을 확인했다. \"팔월 십칠일이군요.\"","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"09:01":[{"t":"아홉 시 일 분","q":"\"좋습니다. 그날 아침 아홉 시 일 분에 전화를 걸지도 모르겠군요. 그럼 당신에게 진 신세를 몇 가지 갚을 수 있을 겁니다.\"","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"09:02":[{"t":"아홉 시 이 분","q":"아홉 시 이 분이었다. 핸리가 주택 담당 책임자에게 고개를 끄덕였다. \"진행하시오.\" 그가 말했다. 담당관이 집 문 앞으로 다가가 세게 두드렸다.","title":"돌이킬 수 없는 일들","author":"프레더릭 포사이스","ampm":"am","kind":"역"}],"09:03":[{"t":"아홉 시 삼 분","q":"세바스천은 자리에 앉은 채 전화기를 노려보며 울리기를 간절히 바랐다. 아홉 시 삼 분, 마침내 누군가 그의 바람에 응답했다.","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"09:04":[{"t":"아홉 시 사 분","q":"좁은 손전등 불빛 아래서 피어스는 시계를 확인했다. 아홉 시 사 분이었다. 탈출을 감추기 위해 발로우가 양동작전을 펼치기 전까지 열쇠를 찾을 시간은 한 시간 남아 있었다.","title":"대열차 강도","author":"마이클 크라이튼","ampm":"am","kind":"역"}],"09:05":[{"t":"아홉 시 오 분","q":"아홉 시 오 분, 천장을 바라보며 침대에 누워 있었다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:06":[{"t":"아홉 시 육 분","q":"실은 아직 아홉 시 육 분밖에 안 됐다. 나는 커다란 시계를, 렌즈를 안 껴도 보이도록 일부러 크게 산, 구 분 빠르게 맞춰 두었다. 이렇게 자신을 속이면 어떻게든 제시간에 도착할 수 있을 거라는 희망에서였다.","title":"밀크런","author":"세라 믈리노프스키","ampm":"am","kind":"역"}],"09:07":[{"t":"아홉 시 칠 분","q":"그 여정 동안 셉티무스는 신문을 읽고 담배 두 대를 피우다가, 아홉 시 칠 분에 캐넌 스트리트에 도착했다.","title":"깨진 일상","author":"제프리 아처","ampm":"am","kind":"역"}],"09:08":[{"t":"아홉 시 팔 분","q":"아홉 시 팔 분, 몸을 돌려 왼쪽으로 누웠다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:09":[{"t":"아홉 시 구 분","q":"아홉 시 구 분, 벽을 바라보며 침대에 누워 있었다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:10":[{"t":"아홉 시 십 분","q":"아홉 시 십 분. 문득 머리가 이상한 모양으로 말라가고 있다는 걸 깨달았다. 빗을 찾았다. 핸드백 속에서 발견했다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"am","kind":"역"}],"09:11":[{"t":"아홉 시 십일 분","q":"새 자물쇠들은 아거의 손길에 순순히 열렸다. 아홉 시 십일 분, 그들은 격자문을 열어젖히고 와인 저장고 안으로 들어갔다. 곧바로 열쇠를 찾기 시작했다.","title":"대열차 강도","author":"마이클 크라이튼","ampm":"am","kind":"역"}],"09:12":[{"t":"아홉 시 십이 분","q":"그리하여 어느 수요일 아침, 동부 표준시로 아홉 시 십이 분, 플레이아데스성단은 태양계기업 본사 청사 저 높은 하늘에 걸려 있었다.","title":"갤럭시 프라임스","author":"E.E. 스미스","ampm":"am","kind":"역"}],"09:13":[{"t":"아홉 시 십삼 분","q":"아홉 시 십삼 분, 벽을 바라보며 침대에 누워 있었다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:14":[{"t":"아홉 시 십사 분","q":"이튿날 아침 잠에서 깬 버지니아는 현관 매트 위에 놓인 커다란 봉투를 발견했다. 누가, 언제 가져다 놓았는지는 알고 싶지 않았다. 시계를 확인하니 아홉 시 십사 분이었다.","title":"이것이 한 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"09:15":[{"t":"아홉 시 십오 분","q":"아침 아홉 시 십오 분이었지만, 이른 안개는 이미 걷히고 하늘은 구름 한 점 없이 뽀얗게 밝아오며 부드럽고 맑은 푸른빛이 언뜻언뜻 비쳤다.","title":"원죄","author":"P.D. 제임스","ampm":"am","kind":"역"}],"09:16":[{"t":"아홉 시 십육 분","q":"아홉 시 십육 분, 그는 침대에 앉아 창밖을 바라보았다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:17":[{"t":"아홉 시 십칠 분","q":"아홉 시 십칠 분, 그는 침대에 앉아 창밖을 바라보았다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:18":[{"t":"아홉 시 십팔 분","q":"이 웅덩이에서 사십 년 가까이 낚시를 해왔는데, 이 선피시들은 정확히 아홉 시 십팔 분이면 아침 식사를 끝낸다는 걸 알게 됐지.","title":"퀼의 창","author":"조지 바 매커친","ampm":"am","kind":"역"}],"09:19":[{"t":"아홉 시 십구 분","q":"아홉 시 십구 분, 그는 침대에 앉아 창밖을 바라보았다.","title":"전체의 한 조각","author":"스티브 톨츠","ampm":"am","kind":"역"}],"09:20":[{"t":"아홉 시 이십 분","q":"올리버는 아홉 시에 채혈을 하기로 되어 있었다. 아홉 시 이십 분이 되어도 그가 오지 않자, 나는 무슨 일이 있는지 알아보려고 여기저기 전화를 걸기 시작했다.","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"09:21":[{"t":"아홉 시 이십일 분","q":"아홉 시 이십일 분이었다. 일 분밖에 남지 않았는데도 허버트의 어머니는 보이지 않았다.","title":"이것이 인생이다","author":"댄 로즈","ampm":"am","kind":"역"}],"09:22":[{"t":"아홉 시 이십이 분","q":"돌 던지는 건 그만두렴, 정확히 일주일 뒤 이 자리에서 다시 보자꾸나. 그녀는 시계를 보며 말했다, 다음 주 수요일 아홉 시 이십이 분에.","title":"이것이 인생이다","author":"댄 로즈","ampm":"am","kind":"역"}],"09:23":[{"t":"아홉 시 이십삼 분","q":"휴고는 이 년 만에 처음으로 아홉 시 이십삼 분, 배링턴 조선소의 정문을 지나 부가티를 몰고 들어갔다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"09:24":[{"t":"아홉 시 이십사 분","q":"아홉 시 이십사 분. 그 양배추 때문에 속이 더부룩하군. 에나멜 구두 위에 앉은 먼지 한 톨.","title":"율리시스","author":"제임스 조이스","ampm":"am","kind":"역"}],"09:25":[{"t":"아홉 시 이십오 분","q":"책상 위 전화벨이 울려 그를 놀라게 했다. 아홉 시 이십오 분이었다. 그는 자신이 몽롱한 상태로 그렇게 앉아 있었다는 걸 깨닫지 못했다.","title":"등대","author":"P.D. 제임스","ampm":"am","kind":"역"}],"09:26":[{"t":"아홉 시 이십육 분","q":"시험 비행은 지도상 45지점, 14구역에서 아홉 시 이십육 분에 종료되었습니다.","title":"닥터 후 신작: 잠퍼","author":"개러스 로버츠","ampm":"am","kind":"역"}],"09:27":[{"t":"아홉 시 이십칠 분","q":"아홉 시 이십칠 분, 전화벨이 울렸다.","title":"도둑들 사이의 의리","author":"제프리 아처","ampm":"am","kind":"역"}],"09:28":[{"t":"아홉 시 이십팔 분","q":"그 전화는 아홉 시 이십팔 분에 걸려온 것이었다. 그것은 살인범이 성 안셀름 안에 있었다는, 처음부터 의심해왔던 사실을 뒷받침하는 또 하나의 중요한 증거였다.","title":"성직자들의 죽음","author":"P.D. 제임스","ampm":"am","kind":"역"}],"09:29":[{"t":"아홉 시 반이 다 되어가고 있었다","q":"어느덧 아홉 시 반이 다 되어가고 있었다. 열 시면 교회의 아침 예배가 시작될 터였다. 이제 나설 시간이었다.","title":"신의 망치","author":"보 예르츠","ampm":"am","kind":"역"}],"09:30":[{"t":"아홉 시 반","q":"그는 떨리는 손으로 봉인을 뜯어 읽기 시작했다. 오랫동안 읽고 나서야 겨우 이해했다. 그날 아홉 시 반까지 지구 경찰서장 사무실로 출두하라는 평범한 소환장이었다.","title":"죄와 벌","author":"표도르 도스토옙스키","ampm":"am","kind":"역"}],"09:31":[{"t":"아홉 시 삼십일 분","q":"아홉 시 삼십일 분, 그의 전화가 울렸다. 팻은 얼른 받아 들었고, 수화기 너머로 레비 씨의 목소리가 들리자 안도했다.","title":"결코 후회할 일 없을 거야","author":"제프리 아처","ampm":"am","kind":"역"}],"09:32":[{"t":"아홉 시 삼십이 분","q":"샌디는 아홉 시 삼십이 분 열차를 간신히 잡아타고 금연칸에 자리를 잡았다.","title":"아내","author":"주디 블룸","ampm":"am","kind":"역"}],"09:33":[{"t":"아홉 시 삼십삼 분","q":"해리는 아홉 시 삼십삼 분, 대사관 앞에 서 있는 자신을 발견했다.","title":"가장 잘 지킨 비밀","author":"제프리 아처","ampm":"am","kind":"역"}],"09:34":[{"t":"아홉 시 삼십사 분","q":"리버풀을 정오에 출발한 여행자는 아홉 시 삼십사 분에 이곳 역에 도착하게 될 것이다, 즉 출발보다도 더 이른 시각에 말이다.","title":"미래의 급행열차","author":"쥘 베른","ampm":"am","kind":"역"}],"09:35":[{"t":"아홉 시 삼십오 분","q":"그는 마침내 노트북 오른쪽 상단의 시계를 확인했다. 아홉 시 삼십오 분이었다.","title":"황금 돔 아래에서","author":"레이 키팅","ampm":"am","kind":"역"}],"09:36":[{"t":"아홉 시 삼십육 분","q":"대니는 닉의 손목시계를 확인했다. 아홉 시 삼십육 분. 그는 서둘러 계단을 내려가 접수처로 향했다.","title":"태생의 죄수","author":"제프리 아처","ampm":"am","kind":"역"}],"09:37":[{"t":"아홉 시 삼십칠 분","q":"선두 차량은 경찰 바리케이드 사이를 미끄러지듯 빠져나가 아홉 시 삼십칠 분, 헌법대로로 접어들었다.","title":"도둑들 사이의 의리","author":"제프리 아처","ampm":"am","kind":"역"}],"09:38":[{"t":"아홉 시 삼십팔 분","q":"열 시까지 이십이 분, 그러니까 아홉 시 삼십팔 분이 남아 있었다. 그는 돼지우리 뒤편 오솔길로 막 접어들고 있었다.","title":"신의 망치","author":"보 예르츠","ampm":"am","kind":"역"}],"09:39":[{"t":"아홉 시 삼십구 분","q":"디스플레이가 정확히 아홉 시 삼십구 분으로 바뀌는 순간, 현관문에서 멀리 쿵쿵거리는 소리가 들려왔다.","title":"운명 지어진","author":"베네딕트 재커","ampm":"am","kind":"역"}],"09:40":[{"t":"아홉 시 사십 분","q":"의장은 회선을 끊고 담배에 다시 불을 붙였다, 아홉 시 사십 분.","title":"대통령께 말씀드릴까요?","author":"제프리 아처","ampm":"am","kind":"역"}],"09:41":[{"t":"아홉 시 사십일 분","q":"마리야는 화면 오른쪽 아래의 시각 표시를 보았다. 아홉 시 사십일 분, 제조 단지에 들어온 지 정확히 십일 분째였다.","title":"돌의 개들","author":"S.M. 스털링","ampm":"am","kind":"역"}],"09:42":[{"t":"아홉 시 사십이 분","q":"열 시 십팔 분 전, 그러니까 아홉 시 사십이 분 사 초를 지나면서 열차는 속도를 늦추더니 완전히 멈춰 섰다.","title":"스페이스 머신","author":"크리스토퍼 프리스트","ampm":"am","kind":"역"}],"09:43":[{"t":"아홉 시 사십삼 분","q":"월요일 아홉 시 사십삼 분. 마이클, 자네 목소리를 들으니 얼마나 반가운지 모르겠군. 오늘 꼭 점심이나 함께하세.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"09:44":[{"t":"아홉 시 사십사 분","q":"금요일 아홉 시 사십사 분. 이제 진짜 숨바꼭질을 시작해야겠군, 밴스가 말했다.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"am","kind":"역"}],"09:45":[{"t":"아홉 시 사십오 분","q":"아홉 시 십오 분, 아홉 시 삼십 분, 아홉 시 사십오 분, 열 시! 본드는 고양이털처럼 흥분이 부풀어 오르는 것을 느꼈다.","title":"007 여왕 폐하 대작전","author":"이언 플레밍","ampm":"am","kind":"역"}],"09:46":[{"t":"아홉 시 사십육 분","q":"정확히 아홉 시 사십육 분, 이런 일에는 정확해야 하는 법이니까, 나는 그 물고기가 숨어 있다고 알려진 자리 위로 세 번이나 낚싯줄을 던졌다. 그리고 습관처럼 별 기대 없이 네 번째로 던졌다. 그러자 싸움이 시작되었다.","title":"마 페텐길","author":"해리 레온 윌슨","ampm":"am","kind":"역"}],"09:47":[{"t":"아홉 시 사십칠 분","q":"그는 평소처럼 씩씩한 걸음으로 아홉 시 사십칠 분에 호텔을 나섰다. '작전 개시.' 스티븐과 로빈은 몽상에서 퍼뜩 깨어났다.","title":"한 푼도 더도 덜도 말고","author":"제프리 아처","ampm":"am","kind":"역"}],"09:48":[{"t":"아홉 시 사십팔 분","q":"\"이것이 내가 10월 15일 금요일 아홉 시 사십팔 분에 이노센트 하우스, 이노센트 워크, 와핑에서 처음 본 시신이다.\"","title":"오리지널 신","author":"P.D. 제임스","ampm":"am","kind":"역"}],"09:49":[{"t":"아홉 시 사십구 분","q":"스물네 시간 뒤, 수신국에 새 메시지가 도착했다. 포터는 그것을 두 번 듣고서야 해독했다. 내용은 간단했다. 메시지 수신함, 요원 이동 중, 내일 아홉 시 사십구 분 착륙 예정.","title":"데스리스트","author":"크리스 라이언","ampm":"am","kind":"역"}],"09:50":[{"t":"아홉 시 오십 분","q":"\"그럴 줄 알았어야 했는데.\" 매디가 말했다. 교회는 아홉 시 오십 분엔 텅 비어 있다가 아홉 시 오십구 분엔 가득 차곤 했다.","title":"핏자국","author":"게일 시겔","ampm":"am","kind":"역"}],"09:51":[{"t":"아홉 시 오십일 분","q":"그들은 독립선언서를 보관하기 위해 지어진 거대한 콘크리트 구조물 앞에 마치 사제가 제단 앞에 서듯 멈춰 섰다. 스콧이 손목시계를 확인했다. 아홉 시 오십일 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"09:52":[{"t":"열 시 팔 분 전","q":"그런 이유로 에마는 그날 아침 아홉 시 이십오 분에 저택을 나서, 정확히 열 시 팔 분 전 배링턴 조선소 정문을 지나 안으로 들어섰다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"09:53":[{"t":"열 시 칠 분 전","q":"사람들은 그녀에게 그런 식으로 말하지 않았다. 그녀의 아버지는 변호사였다. 열 시 칠 분 전이었다.","title":"캐리","author":"스티븐 킹","ampm":"am","kind":"역"}],"09:54":[{"t":"열 시 육 분 전","q":"차는 열 시 육 분 전 배링턴 하우스 앞에 멈춰 섰다. 그녀가 승강기에서 내려 오층 복도를 지나 회장실에 다다랐을 때는 열 시 이 분 전이었다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"09:55":[{"t":"열 시 오 분 전","q":"열 시 오 분 전에 방을 나서 로비의 악단과 합류한 다음, 정문으로 향하면 그들의 마차가 대기하고 있을 것이다.","title":"명예의 문제","author":"제프리 아처","ampm":"am","kind":"역"}],"09:56":[{"t":"아홉 시 오십육 분","q":"아홉 시 오십육 분, 앨리는 커다란 가죽 서류가방을 든 채 택시에서 내려, 문 위 청동 명패의 번호를 카드와 대조했다. 윈스턴 바틀릿은 19세기 강도 귀족처럼 살고 있었다.","title":"신드롬","author":"토머스 후버","ampm":"am","kind":"역"}],"09:57":[{"t":"열 시 삼 분 전","q":"그 목요일 아침, 이사회 임원들은 열 시 삼 분 전에 모두 탁자에 둘러앉았다. 회의는 조용히, 불참자에 대한 양해와 지난 회의록 승인으로 시작되었다.","title":"일직선으로","author":"제프리 아처","ampm":"am","kind":"역"}],"09:58":[{"t":"열 시 이 분 전","q":"열 시 이 분 전, 두 사람은 다우닝가 10번지에 도착해 곧바로 수상 앞으로 안내되었다.","title":"토론토의 존 딘","author":"허버트 조지 젠킨스","ampm":"am","kind":"역"}],"09:59":[{"t":"아홉 시 오십구 분","q":"\"그럴 줄 알았어야 했는데.\" 매디가 말했다. 교회는 아홉 시 오십 분엔 텅 비어 있다가 아홉 시 오십구 분엔 가득 차곤 했다.","title":"핏자국","author":"게일 시겔","ampm":"am","kind":"역"}],"10:01":[{"t":"열 시 일 분","q":"그는 열 시 일 분에 변호사의 유리 사무실로 들어와 의뢰인 맞은편에 앉아 미소 짓고는, 글래드스턴 가방을 의자 옆 바닥에 내려놓았다.","title":"다음 차례","author":"제프리 아처","ampm":"am","kind":"역"}],"10:02":[{"t":"열 시 이 분","q":"열 시 이 분, 그녀의 눈길은 들어오는 사람마다 잠깐씩 머물렀다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"10:03":[{"t":"열 시 삼 분","q":"그녀는 열 시 삼 분에 FBI 청사를 지나고, 열 시 오 분엔 국회의사당 부지 북서쪽 모퉁이의 평화 기념비를 지난다.","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"10:04":[{"t":"열 시 사 분","q":"1955년 11월 12일 토요일, 힐 밸리 법원 시계탑에 벼락이 떨어져 1.21기가와트의 에너지가 건물로 쏟아졌다. 그날 이후 시계는 열 시 사 분에 멈춰 있었다.","title":"백 투 더 퓨처: 시간을 가로질러","author":"마크 수머락","ampm":"am","kind":"역"}],"10:05":[{"t":"열 시 오 분","q":"그녀는 열 시 삼 분에 FBI 청사를 지나고, 열 시 오 분엔 국회의사당 부지 북서쪽 모퉁이의 평화 기념비를 지난다.","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"10:06":[{"t":"열 시 육 분","q":"\"좋아, 매트, 최대 위험 지점이 국회의사당 자체, 그러니까 열 시 육 분에 바로 그 계단이라고 해보자, 그럼 어떻게 되지?\"","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"10:07":[{"t":"열 시 칠 분","q":"\"우회 표지판을 따라가.\" 그는 그녀를 쳐다보지도 않고 말했다. 그녀는 계기판 시계를 흘끗 보았다. 열 시 칠 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"am","kind":"역"}],"10:08":[{"t":"열 시 팔 분","q":"애덤 댈글리시 총경은 죽은 소녀의 옷가지를 살피다 고개를 들었다. 190센티가 넘는 그의 몸은 침대 발치와 옷장 문 사이에 불편하게 끼어 있었다. 그는 시계를 보았다. 열 시 팔 분이었다.","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"am","kind":"역"}],"10:09":[{"t":"열 시 구 분","q":"그는 비명 소리를 따라 복도를 걸었다. 벽시계는 댈러스 시각으로 열 시 구 분을 가리키고 있었다.","title":"아메리칸 타블로이드","author":"제임스 엘로이","ampm":"am","kind":"역"}],"10:10":[{"t":"열 시 십 분","q":"다음 날 아침 열 시 십 분, 윌리엄은 이제는 안절부절못하는 중개인으로부터 다시 전화를 받았다. 개장과 동시에 인터스테이트 주식이 또다시 백만 달러어치나 시장에 풀린 것이다.","title":"케인과 아벨","author":"제프리 아처","ampm":"am","kind":"역"}],"10:11":[{"t":"열 시 십일 분","q":"\"좋아요.\" 플로렌티나 케인이 시계를 보며 말했다. 열 시 십일 분이었다. 숫자가 바뀌더니 심박수로 바뀌었다, 72. 정상이군, 그녀는 생각했다.","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"10:12":[{"t":"열 시 십이 분","q":"이 화면이 사라지고 시계는 열 시 십이 분을 가리켰다. 대통령은 마지막으로 연설의 첫 문장을 되뇌었다. 그날 아침 에드워드와 함께 최종 원고를 검토했고, 결과에 만족하고 있었다.","title":"대통령에게 말할까?","author":"제프리 아처","ampm":"am","kind":"역"}],"10:13":[{"t":"열 시 십삼 분","q":"\"열 시 십삼 분이야.\" 클랜시가 알렸다. \"이제 이 분만 있으면...\" \"출발 시간이군.\" 내가 말했다.","title":"국가 스프린터들","author":"레이 브래드버리","ampm":"am","kind":"역"}],"10:14":[{"t":"열 시 십사 분","q":"열 시 십사 분, 다음 약속 상대는 브렛 엘더스 씨가 되어야 할까?","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"10:15":[{"t":"열 시 십오 분","q":"열 시 십오 분에 알레나는 밀회 장소를 떠났고, 몇 분 뒤 패트릭 레드펀이 내려와 놀라움과 짜증을 연기했다. 크리스틴의 일은 어렵지 않았다.","title":"백주의 악마","author":"애거사 크리스티","ampm":"am","kind":"역"}],"10:16":[{"t":"열 시 십육 분","q":"열 시 십육 분. 드디어. 힘겨운 사십 분을 들여 침대를 딱 하나 정리했다. 한참 뒤처졌지만 상관없다, 그저 계속 움직일 것, 다음은 빨래다.","title":"언도메스틱 갓데스","author":"소피 킨셀라","ampm":"am","kind":"역"}],"10:17":[{"t":"열 시 십칠 분","q":"페이시는 콧노래를 부르며 아벨의 사무실로 천천히 걸어갔다, 매일 열 시에 열리는 회의를 위해. 시계는 열 시 십칠 분을 가리켰다.","title":"케인과 아벨","author":"제프리 아처","ampm":"am","kind":"역"}],"10:18":[{"t":"열 시 십팔 분","q":"수요일 오전 열 시 십팔 분, 겐지 노가미는 넓은 참나무 책상에 꼿꼿이 앉아 전화벨이 울리기를 기다렸다.","title":"프로젝트 다이달로스","author":"토마스 후버","ampm":"am","kind":"역"}],"10:19":[{"t":"열 시 십구 분","q":"금요일 오전 열 시 십구 분, 고도 칠만 삼천 피트, 속도 구천 노트. 중력가속도가 잦아들며 그의 시야가 서서히 돌아오고 있었다.","title":"프로젝트 다이달로스","author":"토마스 후버","ampm":"am","kind":"역"}],"10:20":[{"t":"열 시 이십 분","q":"그들은 열 시 이십 분에 브라이즈 오브 봄베이 앞에 도착했다. 세브는 결코 이 약속에 늦을 사람이 아니었다.","title":"때가 오면","author":"제프리 아처","ampm":"am","kind":"역"}],"10:21":[{"t":"열 시 이십일 분","q":"열 시 이십일 분, 등 뒤에서 목소리가 들렸다. \"좋은 아침이에요, 배링턴 양.\"","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"10:22":[{"t":"열 시 이십이 분","q":"세브는 육십 초마다 튕기듯 움직이는 벽시계의 커다란 검은 분침을 올려다보았다. 열 시 이십이 분. 세드릭이 쏟아부은 노력이 모두 헛수고가 되는 걸까?","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"10:23":[{"t":"열 시 이십삼 분","q":"날짜는 5월 14일이었고 책상 위 시계는 열 시 이십삼 분을 가리켰다, 그래서 그는 10.23이라는 숫자를 입력했다. 적어도 그럴 생각이었다. 실제로는 10.03을 입력하고 말았다.","title":"Ctrl-Z","author":"앤드루 노리스","ampm":"am","kind":"역"}],"10:24":[{"t":"열 시 이십사 분","q":"아넷은 열 시 이십사 분에 피바디 야생동물 보호구역에 들어섰고, 능선을 넘자 도로변에 어둡고 웅덩이 같은 얼룩으로 이어지는 신선한 스키드 마크를 발견했다.","title":"미로","author":"마크 T. 설리번","ampm":"am","kind":"역"}],"10:25":[{"t":"열 시 이십오 분","q":"무장한 FBI 네 개 팀이 열 시 이십오 분에 창고를 포위했을 때, 자리에 없는 사람은 네드 제닝스뿐이었다.","title":"종교적 자유를 위한 대림절","author":"레이 키팅","ampm":"am","kind":"역"}],"10:26":[{"t":"열 시 이십육 분","q":"내 시야 정중앙에는 자명종 시계가 놓여 있었고, 바늘은 열 시 이십육 분을 가리키고 있었다. 누군가의 결혼식 답례품으로 받은 시계였다.","title":"세계의 끝과 하드보일드 원더랜드","author":"무라카미 하루키","ampm":"am","kind":"역"}],"10:27":[{"t":"열 시 이십칠 분","q":"하코트 씨는 열 시 이십칠 분에 이상하리만치 갑작스럽게 잠에서 깼고, 묘하게도 바로 그 순간 집사가 위스키와 브랜디, 소다수, 잔, 비스킷을 실은 쟁반을 든 하인 둘을 데리고 들어왔다.","title":"그들의 잉글랜드","author":"A.G. 맥도넬","ampm":"am","kind":"역"}],"10:29":[{"t":"열 시 이십구 분","q":"\"지금 몇 시야?\" 그가 내게 물었다. \"열 시 이십구 분,\" 내가 대답했다.","title":"눈먼 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"am","kind":"역"}],"10:30":[{"t":"열 시 반","q":"열 시 반, 휴식 시간.","title":"한밤중에 개에게 일어난 기이한 사건","author":"마크 해던","ampm":"am","kind":"역"}],"10:31":[{"t":"열 시 삼십일 분","q":"샌더슨 경위는 열 시 삼십일 분에 금고를 조사했고 바닥에서 제법 큰 핏방울 두 개를 발견했다고 진술했다.","title":"붉은 엄지손가락 자국","author":"R. 오스틴 프리먼","ampm":"am","kind":"역"}],"10:32":[{"t":"열 시 삼십이 분","q":"2009년 5월 16일 토요일 오전 열 시 삼십이 분. 제목: 회신: 운석. 친애하는 알렉스에게, 저는 아주 잘 지내고 있고(물어봐줘서 고마워요), 네가 많이 나아졌다니 정말 기쁘구나.","title":"우주 대 알렉스 우즈","author":"개빈 익스텐스","ampm":"am","kind":"역"}],"10:33":[{"t":"열 시 삼십삼 분","q":"\"시간은 맞습니다. 12월 12일 오전 열 시 삼십삼 분. 제임스 말로는 발신자가 목소리를 변조했다더군요. 그녀의 방에서 음성 변조기를 찾아냈습니다.\"","title":"빅 로","author":"척 로건","ampm":"am","kind":"역"}],"10:34":[{"t":"열 시 삼십사 분","q":"198.088일, 오전 열 시 삼십사 분에 래브라도의 불이 꺼지고 예비 발전기가 돌아갔지만, 래브라도의 인공 태양은 끝내 켜지지 않았다.","title":"오로라","author":"킴 스탠리 로빈슨","ampm":"am","kind":"역"}],"10:35":[{"t":"열 시 삼십오 분","q":"열 시 삼십오 분이었고, 호가트 연구소 본관 뒤쪽 접수대에 있던 브렌다 프리드모어는 블레이클록 경위가 클런치 채석장 살인 사건의 첫 증거물 봉투를 끌어당기는 모습을 눈을 크게 뜬 채 지켜보았다.","title":"전문가 증인의 죽음","author":"P.D. 제임스","ampm":"am","kind":"역"}],"10:36":[{"t":"열 시 삼십육 분","q":"\"스트랜드 소인, 발송 시각 열 시 삼십육 분,\" 홈즈가 몇 번이고 되풀이해 읽으며 말했다. \"오버턴 씨는 이걸 보낼 때 상당히 흥분해 있었던 게 분명하고, 그래서 문장이 다소 앞뒤가 안 맞는군.\"","title":"실종된 스리쿼터 백","author":"아서 코난 도일","ampm":"am","kind":"역"}],"10:37":[{"t":"열 시 삼십칠 분","q":"\"전적으로 동감입니다,\" 머블스 씨가 말했다. \"몹시 곤란한 상황이군요. 도머 부인은 11월 11일 정확히 열 시 삼십칠 분에 숨을 거두었습니다.\"","title":"벨로나 클럽의 불쾌한 사건","author":"도로시 L. 세이어즈","ampm":"am","kind":"역"}],"10:38":[{"t":"열 시 삼십팔 분","q":"오전 열 시 삼십팔 분, 윈스턴 바틀릿은 상황이 돌아가는 방식이 전혀 만족스럽지 않았다. 그녀를 살피는 그의 머릿속은 복잡했다.","title":"신드롬","author":"토마스 후버","ampm":"am","kind":"역"}],"10:39":[{"t":"열 시 삼십구 분","q":"하지만 우리는 서로 낯선 사이고 이 만남에서 아무 일도 없을 수 있으니 당신이 제 여비를 대는 건 받아들일 수 없어요. 제 비행기는 오전 열 시 삼십구 분에 도착해요.","title":"던컨의 신부","author":"린다 하워드","ampm":"am","kind":"역"}],"10:40":[{"t":"열 시 사십 분","q":"\"아침 열 시 사십 분은 술을 시작하기에 적당한 시각이 아니니, 가져가시는 게 좋겠군요. 오래 머무르진 않으실 것 같은데요.\"","title":"사설 환자","author":"P.D. 제임스","ampm":"am","kind":"역"}],"10:41":[{"t":"열 시 사십일 분","q":"바다를 마주한 아파트 육층 창가에 서 있던 한 노인은 폭발 순간을 목격했고, 시각을 동부 표준시로 정확히 열 시 사십일 분이라 특정할 수 있었다.","title":"시나몬 스킨","author":"존 D. 맥도널드","ampm":"am","kind":"역"}],"10:42":[{"t":"열 시 사십이 분","q":"엘리스는 네 개 시간대를 표시한 벽시계들을 훑어보았다. 현지 시각은 열 시 사십이 분을 가리켰다. 그의 실수가 벌써 트림블의 귀에까지 들어간 걸까?","title":"월요일에 팔린 아이들","author":"크리스티나 맥모리스","ampm":"am","kind":"역"}],"10:43":[{"t":"열 시 사십삼 분","q":"1월 24일, 오전 열 시 사십삼 분, 한 달 하고도 이틀이 지난 지금, 사랑스러운 남자친구가 사준 생일 선물이 순식간에 죽음을 부를 수도 있다는 사실을 걱정해야 하는 건 아닌지 모르겠다.","title":"위시리스트","author":"제인 코스텔로","ampm":"am","kind":"역"}],"10:44":[{"t":"열 시 사십사 분","q":"\"레이디 휘슬다운의 정체를 밝히는 사람에게 천 파운드를 주겠다\"는 말이 나왔을 때, 시계는 열 시 사십사 분을 가리키고 있었다.","title":"브리저튼 씨와의 로맨스","author":"줄리아 퀸","ampm":"am","kind":"역"}],"10:45":[{"t":"열한 시 십오 분 전","q":"그들은 열한 시 십오 분 전에 킹스크로스에 도착했다. 위즐리 씨는 트렁크를 실을 손수레를 가져오려 길을 가로질러 뛰어갔고, 모두 서둘러 역 안으로 들어갔다.","title":"해리 포터와 비밀의 방","author":"J.K. 롤링","ampm":"am","kind":"역"}],"10:46":[{"t":"열한 시 십사 분 전","q":"올리브: [캐서린 곁에서 시계 스탠드를 살피며] 열한 시 십사 분 전이에요. 캐서린: 올리브, 올리브! 올리브: 그냥 시간이 궁금해서요.","title":"군중","author":"존 골즈워디","ampm":"am","kind":"역"}],"10:47":[{"t":"열 시 사십칠 분","q":"열 시 사십칠 분. 그에게 그냥 짧고 다정한 메시지나 하나 보내야지, 추파랄 것도 없이 그냥 관계 회복 차원에서.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"am","kind":"역"}],"10:48":[{"t":"열 시 사십팔 분","q":"열 시 사십팔 분, 나는 폴더를 덮었지만 굳이 가방에 넣지는 않았다. 그래서 당신은 내가 근처 위원회나 회의실로 가는 길이라는 걸 알았을 것이다.","title":"애플트리 야드","author":"루이즈 다우티","ampm":"am","kind":"역"}],"10:49":[{"t":"열 시 사십구 분","q":"열 시 사십구 분, 앨리는 윈스턴 바틀릿이 방을 빠져나가는 모습을 지켜보며 여전히 그 남자를 가늠하고 있었다.","title":"신드롬","author":"토머스 후버","ampm":"am","kind":"역"}],"10:50":[{"t":"열 시 오십 분","q":"브리스틀 도클랜즈의 배링턴 경은 1992년 4월 10일 아침 열 시 오십 분에 세인트 폴 대성당에 도착할 예정이었다.","title":"한 남자의 일생","author":"제프리 아처","ampm":"am","kind":"역"}],"10:51":[{"t":"열 시 오십일 분","q":"그는 열 시 오십일 분, 해발 이만칠천오백오십 피트에 이르렀을 때도 여전히 정상까지 오를 수 있다는 자신감을 잃지 않았다.","title":"영광의 길","author":"제프리 아처","ampm":"am","kind":"역"}],"10:52":[{"t":"열한 시 팔 분 전","q":"이제 열한 시 팔 분 전이었고, 그는 슬슬 짜증과 초조함을 느끼기 시작했다.","title":"심연에서","author":"마리 벨록 론즈","ampm":"am","kind":"역"}],"10:53":[{"t":"열 시 오십삼 분","q":"열 시 오십삼 분, 그는 북서쪽 문에서 재임 중인 참사회원 에릭 에번스 사제를 만나기로 되어 있었다.","title":"한 남자의 일생","author":"제프리 아처","ampm":"am","kind":"역"}],"10:54":[{"t":"열 시 오십사 분","q":"\"오늘 열 시 오십사 분에 하이 스트리트의 베닝턴 은행에 육천사백구십오 파운드를 입금했잖소.\" 프로스트가 다그쳤다.","title":"하드 프로스트","author":"R.D. 윙필드","ampm":"am","kind":"역"}],"10:55":[{"t":"열 시 오십오 분","q":"열 시 오십오 분이면 그들은 파홀름 게이트에 들어서고, 채 십 분 반이 지나지 않아 배너미어 게이트로 나오게 될 것이었다. 사십 광년 떨어진 곳으로.","title":"그림자와 밤","author":"크리스 월리","ampm":"am","kind":"역"}],"10:56":[{"t":"열 시 오십육 분","q":"부스 왓슨은 일을 성사시키려면 시간을 정교하게 맞춰야 한다는 걸 알고 있었다. 움직이기 전에 정확히 열 시 오십육 분이 되었는지 시계에서 눈을 떼지 않아야 했다.","title":"넥스트 인 라인","author":"제프리 아처","ampm":"am","kind":"역"}],"10:57":[{"t":"열 시 오십칠 분","q":"열 시 오십오 분에 참사회원이 대법관을 성당 안으로 안내하고, 이어 신랑 앞쪽으로 나아가 참사회원의 표현대로 열 시 오십칠 분에 착지하게 될 것이었다.","title":"한 남자의 일생","author":"제프리 아처","ampm":"am","kind":"역"}],"10:58":[{"t":"열 시 오십팔 분","q":"어느 날 조는 사무실에서 열한 시 약속을 기다리고 있었는데, 열 시 오십팔 분에 그 흑인 여성이 들어왔다.","title":"라이트닝 로즈","author":"헬렌 드윗","ampm":"am","kind":"역"}],"10:59":[{"t":"열 시 오십구 분","q":"열 시 오십구 분, 집사가 현관문을 열자 군중이 환호하기 시작했다.","title":"대통령에게 알릴까요?","author":"제프리 아처","ampm":"am","kind":"역"}],"11:01":[{"t":"열한 시 일 분","q":"시계 바늘이 계속 움직였다. 열한 시가 되기 직전까지는 모든 것이 평화롭고 질서정연했다. 열한 시가 되자 선생님들은 늘 그렇듯 잠깐 자리를 비웠다. 열한 시 일 분이 되자 온통 전쟁과 소란이었다!","title":"양쪽의 잭: 어느 교내 전쟁 이야기","author":"플로렌스 쿰","ampm":"am","kind":"역"}],"11:02":[{"t":"열한 시 이 분","q":"\"그래.\" 페레나는 단호한 어조로 반박을 허용하지 않았다. \"열한 시 칠 분에 폭발했어. 넌 열한 시 이 분에 들어갔을 테니, 그때쯤이면 정확히 두 게이트 사이 중간 지점에 있었을 거야.\"","title":"그림자와 밤","author":"크리스 월리","ampm":"am","kind":"역"}],"11:03":[{"t":"열한 시 삼 분","q":"\"몇 시에 그를 만나기로 했어?\" 그녀가 부엌에서 소리쳐 물었다. \"열한 시 삼 분,\" 그가 답했다. \"그래서 진짜라는 생각이 들었어. 군이나 정보기관 사람들은 혼란을 없애려고 약속 시간을 정확히 정하거든.\"","title":"리틀 그린 맨","author":"크리스토퍼 버클리","ampm":"am","kind":"역"}],"11:04":[{"t":"열한 시 사 분","q":"그런 이유로 초과 변명이 모두 소진되었으니, 열한 시 사 분발 시드니행 딥드롭 열차가 육 번 게이트에서 탑승을 시작한다는 것을 기쁘게 알려 드립니다.","title":"좋은 책 속에서 길을 잃다","author":"재스퍼 포드","ampm":"am","kind":"역"}],"11:05":[{"t":"열한 시 오 분","q":"열한 시 오 분, 아메시스트가 성공하느냐 실패하느냐가 갈리기까지 십오 분도 채 남지 않았다.","title":"무한한 낮","author":"크리스 월리","ampm":"am","kind":"역"}],"11:06":[{"t":"열한 시 육 분","q":"열한 시 육 분. 아... 다림질. 저건 대체 어떻게 해야 하지?","title":"살림 못하는 여신","author":"소피 킨셀라","ampm":"am","kind":"역"}],"11:07":[{"t":"열한 시 칠 분","q":"\"그래.\" 페레나는 단호한 어조로 말했다. \"열한 시 칠 분에 폭발했어. 넌 열한 시 이 분에 들어갔을 테니, 그때쯤엔 정확히 두 게이트 사이 중간 지점에 있었을 거야.\"","title":"그림자와 밤","author":"크리스 월리","ampm":"am","kind":"역"}],"11:08":[{"t":"열한 시 팔 분","q":"그는 헬멧 윗단의 데이터 스트립에서 시간을 확인하려고 눈을 들었다. 열한 시 팔 분 이십삼 초. 십 분 남았다. 그들은 비틀거리며 계속 걸었다.","title":"무한한 낮","author":"크리스 월리","ampm":"am","kind":"역"}],"11:09":[{"t":"열한 시 구 분","q":"마지막은 십월 십이일 열한 시 구 분이었다. \"그놈은 꼬박 오 주가 걸렸어,\" 내가 말했다. \"그런데...\" 말이 나오지 않았다.","title":"NYPD 레드 3","author":"제임스 패터슨","ampm":"am","kind":"역"}],"11:10":[{"t":"열한 시 십 분","q":"그녀는 진입로를 빠져나와 차량을 확인하고 고속도로 쪽으로 방향을 틀었다. 열한 시 십 분. 시간은 충분했다.","title":"이프 잇 블리즈","author":"스티븐 킹","ampm":"am","kind":"역"}],"11:11":[{"t":"열한 시 십일 분","q":"그의 슈퍼 지 디지털 애슬레틱 크로노미터 액정 화면이 깜박였다. 열한 시 십일 분, 켜졌다 꺼졌다, 켜졌다 꺼졌다.","title":"무관심자들의 리그","author":"리처드 스카스브룩","ampm":"am","kind":"역"}],"11:12":[{"t":"열한 시 십이 분","q":"\"열한 시 십이 분, 전투 배치, 전투 배치.\" 제임스는 재빨리 라만 갤러리로 미끄러져 들어갔다.","title":"한 푼도 더도 덜도 아닌","author":"제프리 아처","ampm":"am","kind":"역"}],"11:13":[{"t":"열한 시 십삼 분","q":"그의 처지는 더 절박해서, 표도 사지 않고 열한 시 십삼 분 기차에 올라타는 무모한 방법을 써야 했다.","title":"황금 가지","author":"조지 기브스","ampm":"am","kind":"역"}],"11:14":[{"t":"열한 시 십사 분","q":"\"열한 시 십사 분,\" 멀리사가 말했다. \"세상이 끝나기까지 아직 사십사 분이나 죽여야 해.\"","title":"유리 호텔","author":"에밀리 세인트존 맨델","ampm":"am","kind":"역"}],"11:15":[{"t":"열한 시 십오 분","q":"시계는 열한 시 십오 분을 가리켰다. 빔즈는 문으로 다가가, 관례를 깨고 조용히 노크했다.","title":"점토 발","author":"테리 프래쳇","ampm":"am","kind":"역"}],"11:16":[{"t":"열한 시 십육 분","q":"마침내 열한 시 십육 분에 그가 나타나 바카라 테이블의 예약석에 앉았다.","title":"한 푼도 더도 덜도 없이","author":"제프리 아처","ampm":"am","kind":"역"}],"11:17":[{"t":"열한 시 십칠 분","q":"테드는 다음 날 열한 시 십칠 분에 다우닝가 10번지 정문에 나타났다.","title":"구두닦이 소년","author":"제프리 아처","ampm":"am","kind":"역"}],"11:18":[{"t":"열한 시 십팔 분","q":"열한 시 십팔 분이다. 낙엽송 무리를 가운데 두고 둥글게 늘어선 방갈로들.","title":"트럼펫","author":"재키 케이","ampm":"am","kind":"역"}],"11:19":[{"t":"열한 시 십구 분","q":"폴리는 손목시계를 내려다보았다. 열한 시 십구 분. 기차가 올 시간이었다.","title":"블랙아웃","author":"코니 윌리스","ampm":"am","kind":"역"}],"11:20":[{"t":"열한 시 이십 분","q":"끔찍했다, 열한 시 이십 분이었으니! 그러니 대체 무슨 소용이란 말인가?","title":"거장과 마르가리타","author":"미하일 불가코프","ampm":"am","kind":"역"}],"11:21":[{"t":"열한 시 이십일 분","q":"조엘 카이로가 거리에서 들어왔을 때, 엘리베이터 문 위 시계는 열한 시 이십일 분을 가리키고 있었다.","title":"몰타의 매","author":"대실 해밋","ampm":"am","kind":"역"}],"11:23":[{"t":"열한 시 이십삼 분","q":"그녀는 침묵 속에 누워 잠을 기다렸다. 열한 시 이십삼 분이었다.","title":"검은 회랑","author":"마이클 무어콕","ampm":"am","kind":"역"}],"11:24":[{"t":"열한 시 이십사 분","q":"열한 시 이십사 분, 우리는 헬렌 길러드에게 감사를 전하고 집을 나섰다.","title":"마지막 추리","author":"렉스 스타우트","ampm":"am","kind":"역"}],"11:25":[{"t":"열한 시 이십오 분","q":"BEA 비스카운트기는 그날 아침 현지 시각 열한 시 이십오 분, 예정보다 조금 늦게 제네바 공항에 착륙했다.","title":"명예의 문제","author":"제프리 아처","ampm":"am","kind":"역"}],"11:26":[{"t":"열한 시 이십육 분","q":"열한 시 이십육 분, 0xAA289는 자신이 실행되던 노드 하나에서 원인 불명의 하드웨어 고장을 겪었다.","title":"튜링 익셉션","author":"윌리엄 헤틀링","ampm":"am","kind":"역"}],"11:27":[{"t":"열한 시 이십칠 분","q":"톰은 열한 시 이십칠 분에 사보이 플레이스로 접어들어, 호텔 앞에 손님을 쏟아내는 리무진 행렬과 마주쳤다.","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"11:28":[{"t":"열한 시 이십팔 분","q":"열한 시 이십오 분부터 열한 시 이십팔 분까지, 학교의 영웅들은 그 넓은 친목의 자리에 모여 있었다.","title":"불길한 거리","author":"콤프턴 매켄지","ampm":"am","kind":"역"}],"11:29":[{"t":"열한 시 이십구 분","q":"그는 로비 시계를 올려다보았다. 열한 시 이십구 분.","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"am","kind":"역"}],"11:30":[{"t":"열한 시 반","q":"평소 여덟 시부터 열한 시 반까지였던 수업이 그날은 오후 내내 이어진다는 말에 소년들의 웃음소리는 신음으로 바뀌었다.","title":"사랑의 빛나는 골짜기","author":"에드나 홍","ampm":"am","kind":"역"}],"11:31":[{"t":"열한 시 삼십일 분","q":"앨버트로스 8호는 현지 시각 열한 시 삼십일 분에 팜리코 사운드 상공을 통과했다.","title":"붉은 10월","author":"톰 클랜시","ampm":"am","kind":"역"}],"11:32":[{"t":"열한 시 삼십이 분","q":"대략 열한 시 삼십이 분쯤이었을까, 코밍홈 해안 앞바다에서였다.","title":"피네간의 경야","author":"제임스 조이스","ampm":"am","kind":"역"}],"11:33":[{"t":"열한 시 삼십삼 분","q":"열한 시 삼십삼 분, 애스턴 마틴의 매끈한 크림색 앞머리가 대문 앞에 멈춰 서더니 모리스 켐프로어가 차에서 내렸다.","title":"신경","author":"딕 프랜시스","ampm":"am","kind":"역"}],"11:34":[{"t":"열한 시 삼십사 분","q":"사립 탐정은 패딩턴발 급행열차가 템플 미즈 역에 들어온 지 불과 몇 분 뒤인 열한 시 삼십사 분에 그와 합류했다.","title":"아버지의 죄","author":"제프리 아처","ampm":"am","kind":"역"}],"11:35":[{"t":"열한 시 삼십오 분","q":"열한 시 삼십오 분에 대령이 나왔다. 그는 덥고 화가 난 얼굴로 엘리베이터를 향해 성큼성큼 걸었다.","title":"아바나의 우리 남자","author":"그레이엄 그린","ampm":"am","kind":"역"}],"11:36":[{"t":"열한 시 삼십육 분","q":"칼링 부인의 문학 에이전트 벨마 피트카울리는 열한 시 반까지 오기로 해놓고, 육 분 늦은 열한 시 삼십육 분에야 도착했다.","title":"원죄","author":"P.D. 제임스","ampm":"am","kind":"역"}],"11:37":[{"t":"열한 시 삼십칠 분","q":"열한 시 삼십칠 분, 나는 첼시 테라스 1번지의 소유권과 맞바꾸어 포더길 씨에게 최종 잔금을 건넸다.","title":"까마귀가 날듯이","author":"제프리 아처","ampm":"am","kind":"역"}],"11:38":[{"t":"열한 시 삼십팔 분","q":"열한 시 삼십팔 분, 그녀는 책상을 떠나 강당 옆문으로 걸어갔다.","title":"서클","author":"데이브 에거스","ampm":"am","kind":"역"}],"11:39":[{"t":"열한 시 삼십구 분","q":"열한 시 삼십구 분발 파리 에스트행 열차는 자전거를 동반해도 무료로 탈 수 있는 편이라는 것을 겨우 확인했다.","title":"프렌치 레볼루션스","author":"팀 무어","ampm":"am","kind":"역"}],"11:40":[{"t":"열한 시 사십 분","q":"열한 시 사십 분 기차를 기다리는 스무 명 남짓한 사람들 무리가 있었다.","title":"순결한 피","author":"P.D. 제임스","ampm":"am","kind":"역"}],"11:41":[{"t":"열한 시 사십일 분","q":"자일스가 돌아보니 학장이 곁에 서 있었다. 그는 고개를 숙였다. 틀림없이 열한 시 사십일 분이었다.","title":"이것이 남자였다","author":"제프리 아처","ampm":"am","kind":"역"}],"11:42":[{"t":"열한 시 사십이 분","q":"현관문이 열린다. 그녀의 심장이 쿵쾅거린다. 화면 오른쪽 아래 시각을 본다. 열한 시 사십이 분.","title":"아래층 여자","author":"엘리자베스 카펜터","ampm":"am","kind":"역"}],"11:43":[{"t":"열한 시 사십삼 분","q":"열한 시 사십삼 분. 앞으로 사 분쯤 뒤면 에마는 죽을 것이었다.","title":"피의 의식","author":"짐 부처","ampm":"am","kind":"역"}],"11:44":[{"t":"열한 시 사십사 분","q":"바이스의 손목시계는 열한 시 사십사 분을 가리켰고, 폭발은 정오에 맞춰져 있었다.","title":"다리를 지켜라","author":"가스 닉스","ampm":"am","kind":"역"}],"11:45":[{"t":"열한 시 사십오 분","q":"어머니는 벽난로 선반 한가운데 옆으로 누워 있던 낡은 자명종을 바로 세워 시계바늘이 열한 시 사십오 분을 가리키게 한 뒤 다시 옆으로 눕혀 놓았다.","title":"젊은 예술가의 초상","author":"제임스 조이스","ampm":"am","kind":"역"}],"11:47":[{"t":"열한 시 사십칠 분","q":"그것은 살아 있는 자도 죽은 자도 없는 광막한 평원이었고, 나는 시간을 가늠할 수 없는 빛바랜 하늘 아래 오래 걸었다. 베를린 시각에 맞춰둔 내 시계는 헤엄에 못 이겨 고장 난 채 영원히 열한 시 사십칠 분을 가리키고 있었다.","title":"온화한 여신들","author":"조너선 리텔","ampm":"am","kind":"역"}],"11:48":[{"t":"열한 시 사십팔 분","q":"\"서두르면 열한 시 사십팔 분 기차를 탈 수 있어요,\" 그가 말했다. \"몇 가지는 바꿔야겠지만요.\"","title":"잘못된 쌍둥이","author":"해리 리언 윌슨","ampm":"am","kind":"역"}],"11:49":[{"t":"오전 열한 시 사십구 분","q":"리치는 오전 열한 시 사십구 분 이후로 건 전화가 한 통도 없었다. 그러나 그날 오후 걸려온 전화 목록은 길었다, 그가 다시는 받지 못할 전화들이었다.","title":"그 모든 세월이 지난 뒤","author":"수전 아이작스","ampm":"am","kind":"역"}],"11:50":[{"t":"정오 십 분 전","q":"그녀는 열한 시 삼십팔 분에 자리를 떴고, 정오 십 분 전에 도착했다.","title":"더 서클","author":"데이브 에거스","ampm":"am","kind":"역"}],"11:51":[{"t":"열두 시 구 분 전","q":"다음날, 열두 시 구 분 전에 마지막 시계가 멈춰 섰다. 그것은 이내 박물관으로 옮겨져 소장품으로 전시되었다.","title":"랜턴과 랜스","author":"제임스 서버","ampm":"am","kind":"역"}],"11:52":[{"t":"열두 시 팔 분 전","q":"그는 열두 시 팔 분 전에 딜레이니 가로 돌아가 서점을 둘러보는 척했다.","title":"이노센트 블러드","author":"P.D. 제임스","ampm":"am","kind":"역"}],"11:53":[{"t":"열두 시 칠 분 전","q":"훗날 사람들은 정오 직전, 정확히는 열두 시 칠 분 전에, 손바닥만 한 작은 구름 하나가 서둘러 해를 가로질렀다고 회상했다.","title":"앤더슨 크로우의 딸","author":"조지 바 매커천","ampm":"am","kind":"역"}],"11:54":[{"t":"열두 시 육 분 전","q":"그는 맥주를 마저 들이켜고 시계를 보았다. 열두 시 육 분 전이었다.","title":"행오버 스퀘어","author":"패트릭 해밀턴","ampm":"am","kind":"역"}],"11:55":[{"t":"열두 시 오 분 전","q":"열두 시 오 분 전, 문이 열리자 죄수들이 한 방향으로 쏟아져 나왔다.","title":"타고난 죄수","author":"제프리 아처","ampm":"am","kind":"역"}],"11:56":[{"t":"열두 시 사 분 전","q":"에런은 달리면서 시계를 확인했다, 열두 시 사 분 전이었다. 그는 해리가 늦기를 기도했다.","title":"때가 되면","author":"제프리 아처","ampm":"am","kind":"역"}],"11:57":[{"t":"정오 삼 분 전","q":"정오 삼 분 전이 되자, 문제의 우스꽝스러운 형체가 아주 작은 외국인 청년임이 드러났다.","title":"종탑 속의 악마","author":"에드거 앨런 포","ampm":"am","kind":"역"}],"11:58":[{"t":"오전 열한 시 오십팔 분","q":"응우옌은 어깨를 으쓱하며 오전 열한 시 오십팔 분을 가리키는 계기판 시계를 가리켰다. \"점심 먹으러 가나 보죠.\"","title":"라이언하츠","author":"레이 키팅","ampm":"am","kind":"역"}],"11:59":[{"t":"열두 시 일 분 전","q":"\"지금 열두 시 일 분 전이에요. 아직 그 옵션을 행사할 시간이 있어요!\"","title":"모험의 섬에서","author":"베스 모이어","ampm":"am","kind":"역"}],"12:01":[{"t":"정오 일 분","q":"\"대통령 각하...\" 플로렌티나는 재빨리 머리를 굴려 본능적인 반응을 감췄다. \"지금 정오 일 분이에요.\"","title":"대통령에게 말할까요?","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:02":[{"t":"열두 시 이 분","q":"열두 시 이 분, 문이 열리고 남자 두 명이 로비로 들어온다.","title":"빌리 서머스","author":"스티븐 킹","ampm":"pm","kind":"역"}],"12:03":[{"t":"정오 삼 분","q":"이제 정오 삼 분이었다. 블라인드는 이미 내려져 있어 늦은 오전의 흐릿한 빛마저 시간 감각과 함께 차단하고 있었다.","title":"살인의 방","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"12:04":[{"t":"정오 사 분","q":"다음 날 나는 공포에 질려 잠에서 깬다. 침대에서 뛰쳐나와 비틀거리며 부엌으로 가 전자레인지 시계를 본다, 정오 사 분.","title":"드라이","author":"어거스틴 버로우즈","ampm":"pm","kind":"역"}],"12:05":[{"t":"열두 시 오 분","q":"\"폴린 스테이시는 열두 시 오 분에 이 층에서 땅으로 떨어졌습니다.\"","title":"아폴로의 눈","author":"G.K. 체스터턴","ampm":"pm","kind":"역"}],"12:06":[{"t":"정오 육 분","q":"하지만 이것만은 말해줄 수 있어, 로트필드 몰에서의 좀비 목격이 어제 정오 육 분에 확인됐어.","title":"좀비 필드 데이","author":"나디아 히긴스","ampm":"pm","kind":"역"}],"12:07":[{"t":"열두 시 칠 분","q":"월요일, 사이먼 허시는 열두 시 칠 분에 다리가 부러질 예정이었다.","title":"젊은 사탄의 연대기","author":"마크 트웨인","ampm":"pm","kind":"역"}],"12:08":[{"t":"열두 시 팔 분","q":"워싱턴 D.C.에서 정오를 알리는 종이 울릴 때, 필라델피아는 열두 시 팔 분, 뉴욕은 열두 시 십이 분, 보스턴은 열두 시 이십사 분이었다.","title":"80일","author":"매튜 굿맨","ampm":"pm","kind":"역"}],"12:09":[{"t":"열두 시 구 분","q":"2069년 6월 6일, 그리니치 표준시 열두 시 구 분, 메시지 시퀀스 2.","title":"낙원의 샘","author":"아서 C. 클라크","ampm":"pm","kind":"역"}],"12:10":[{"t":"열두 시 십 분","q":"아이는 지금 열두 시 십 분이고 곤다가 벌써 늦었다고 말했다.","title":"이녹과 고릴라","author":"플래너리 오코너","ampm":"pm","kind":"역"}],"12:11":[{"t":"열두 시 십일 분","q":"열두 시 십일 분에 다시 정전이 일어날 것이고, 그 틈을 타 그녀는 외부 계단으로 일층까지 내려가 출구에서 배달 트럭을 기다릴 것이었다.","title":"인클레이브","author":"캐런 핸콕","ampm":"pm","kind":"역"}],"12:12":[{"t":"열두 시 십이 분","q":"캐리에타 화이트가 그 거리의 제일회중교회에서 나왔을 때, 당신은 대략 열두 시 십이 분에 칼린 가에 있었습니까?","title":"캐리","author":"스티븐 킹","ampm":"pm","kind":"역"}],"12:13":[{"t":"열두 시 십삼 분","q":"지금 열두 시 십삼 분이니까 점심을 먹어도 된다.","title":"룸","author":"엠마 도노휴","ampm":"pm","kind":"역"}],"12:14":[{"t":"열두 시 십사 분","q":"그녀는 패딩턴 역에서 열두 시 십사 분 기차로 런던을 떠나, 두 시 오십 분에 브리스틀에 도착했다.","title":"플리머스 특급 살인 사건","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"12:15":[{"t":"열두 시 십오 분","q":"그리고 이것과도 언젠가는 헤어져야 한다. 열두 시 십오 분, 이십 분, 삼십 분... 그는 이미 지루해진 침대의 끈질긴 온기 속에서 마지막 담배 한 대를 허락했다.","title":"재능","author":"블라디미르 나보코프","ampm":"pm","kind":"역"}],"12:16":[{"t":"열두 시 십육 분","q":"열두 시 십육 분, 글로리 양이 음식을 내왔다.","title":"새장에 갇힌 새가 왜 노래하는지 나는 아네","author":"마야 안젤루","ampm":"pm","kind":"역"}],"12:17":[{"t":"열두 시 십칠 분","q":"카바는 자신과 연인을 위해 커피 두 잔과 케이크를 주문했다. 두 사람이 정확히 열두 시 십칠 분에 자리를 뜨자, 클럽은 술렁이기 시작했다.","title":"반빌드 카바","author":"아이작 바셰비스 싱어","ampm":"pm","kind":"역"}],"12:18":[{"t":"열두 시 십팔 분","q":"월요일, 4월 6일, 열두 시 십팔 분. \"얘, 어땠어?\" 앨리가 문에 들어서자마자 제니퍼가 물었다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"12:19":[{"t":"열두 시 십구 분","q":"어젯밤 침대에서 잔 흔적은 없었고, 다리가 봉쇄되어 섬을 빠져나가지도 못했을 것이다. 가족 중 누구도 HV의 행방을 모른다. 열두 시 십구 분, G.M.이 전화로 이 상황을 통보받았다.","title":"밀레니엄 1: 여자를 증오한 남자들","author":"스티그 라르손","ampm":"pm","kind":"역"}],"12:20":[{"t":"열두 시 이십 분","q":"벌써 열두 시 이십 분이었지만, 회의가 끝나면 곧장 전화하라고 그토록 일러두었는데도 피셔에게서는 아무 연락이 없었다.","title":"소원을 조심하라","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:21":[{"t":"열두 시 이십일 분","q":"그리니치 표준시로 열두 시 이십일 분, 재키가 브리핑을 마치며 물었다. \"질문 있나요?\" 한 손이 번쩍 올라갔다. \"두 팀 중 어느 쪽이 더 필요할 것 같습니까?\"","title":"모험 없이는","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:22":[{"t":"열두 시 이십이 분","q":"열두 시 이십이 분이 되어서야, 못내 아쉬운 마음을 뒤로한 채 우리는 순례자들이 요단강을 찾아와 몸을 씻곤 하던 이 아름다운 곳을 떠났다.","title":"1850-1851년 사해 및 성서 지역 여행기","author":"펠리시앵 드 소시","ampm":"pm","kind":"역"}],"12:23":[{"t":"열두 시 이십삼 분","q":"두 해나 보지 못한 남자와 한 침대에 눕는다는 게 너무나 낯설게 느껴질 것 같았다. 그녀는 디지털 자명종의 시각을 보았다. 열두 시 이십삼 분.","title":"미드나잇 라이브러리","author":"매트 헤이그","ampm":"pm","kind":"역"}],"12:24":[{"t":"열두 시 이십사 분","q":"열두 시 이십사 분, 다리가 완전히 저려온다. 몇 시간째 딱딱한 타일 바닥에 무릎을 꿇고 욕조를 닦고 있다.","title":"살림 못하는 여신","author":"소피 킨셀라","ampm":"pm","kind":"역"}],"12:25":[{"t":"열두 시 이십오 분","q":"잠시 후 현실감이 돌아오자, 그녀는 자신이 환각을 본 게 아니라 꿈을 꾼 것임을 깨달았다. 책상 위 시계는 열두 시 오십오 분을 가리켰다. 십 분짜리 세션은 열두 시 이십오 분에 시작했으니, 이십 분의 행방을 알 수 없었다.","title":"인클레이브","author":"캐런 핸콕","ampm":"pm","kind":"역"}],"12:26":[{"t":"열두 시 이십육 분","q":"열두 시 이십육 분. \"나, 플로렌티나 케인은 엄숙히 맹세합니다...\" \"나, 플로렌티나 케인은 엄숙히 맹세합니다...\"","title":"대통령에게 알릴까?","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:27":[{"t":"열두 시 이십칠 분","q":"삼십 년 동안 시간은 열두 시 이십칠 분에 멈춰 있었다. 코코란 오코너의 아버지가 숨을 거둔 바로 그 순간에 시곗바늘이 멎었다는 이야기였다. 사실일 수도 있었다.","title":"바운더리 워터스","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"12:28":[{"t":"열두 시 이십팔 분","q":"'드링크 치어업 커피'라 적힌 벽시계는 열두 시 이십팔 분을 가리키고 있었다.","title":"11/22/63","author":"스티븐 킹","ampm":"pm","kind":"역"}],"12:29":[{"t":"열두 시 이십구 분","q":"\"몇 시야?\" 티니빗츠가 물었다. 역무원은 커다란 은시계를 꺼내 매섭게 들여다보더니 알렸다. \"열두 시 이십구 분이야.\" \"열두 시가 지났다고!\" 티니빗츠가 되뇌었다. \"그럴 리 없어.\"","title":"칼자국","author":"클레이턴 H. 언스트","ampm":"pm","kind":"역"}],"12:30":[{"t":"열두 시 반","q":"열두 시 반, 점심.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"12:32":[{"t":"열두 시 삼십이 분","q":"그는 벽난로 위 벽시계를 꼼꼼히 살피고 시각을 수첩에 기록했다. \"열두 시 삼십이 분, 코트니브릭스 씨가 윈체스터 로드 산책길에 쓰러진 나무를 신고함.\"","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"12:33":[{"t":"열두 시 삼십삼 분","q":"스티븐 맥시는 그의 눈을 똑바로 바라보며 거의 태연하게 말했다. \"제 시계로는 열두 시 삼십삼 분이었습니다.\"","title":"얼굴을 가려라","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"12:35":[{"t":"열두 시 삼십오 분","q":"\"안타깝게도 이른 아침 로마행 비행기는 놓치셨습니다. 하지만 열두 시 삼십오 분 항공편으로 예약을 잡아드렸고, 항공사에서 비즈니스석으로 업그레이드까지 해드렸습니다.\" \"그야 당연하죠,\" 베스가 말했다.","title":"훤히 보이는 곳에 숨겨진","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:36":[{"t":"열두 시 삼십육 분","q":"중앙유럽시로 열두 시 삼십육 분, 배가 부두에 닿자 윌리엄과 몬티는 난간에 기대어 그랜트가 관을 트랩 아래로 옮기는 모습을 지켜보았다.","title":"모험 없이는","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:37":[{"t":"열두 시 삼십칠 분","q":"청바지에 모자, 낡은 브이넥 스웨터 차림의 제이슨이 낡은 공장 정문에 다다랐을 때는 열두 시 삼십칠 분이었다. 그는 골루아즈 담뱃갑을 꺼내 벽에 기댄 채 성냥으로 불을 붙였다.","title":"본 얼티메이텀","author":"로버트 러들럼","ampm":"pm","kind":"역"}],"12:38":[{"t":"열두 시 삼십팔 분","q":"\"그날 포르트 드 샹페레 방면으로 가던 열두 시 이십삼 분발 S선 버스는 몇 시에 도착했습니까?\" \"열두 시 삼십팔 분에요.\"","title":"문체 연습","author":"레몽 크노","ampm":"pm","kind":"역"}],"12:39":[{"t":"열두 시 삼십구 분","q":"다음으로 그는 크리스마스 이튿날이 달의 스무이레째 날이 되며, 따라서 만조는 세 시 이십일 분, 반쯤 썰물은 일곱 시 십오 분, 간조는 아홉 시 삼십삼 분, 반쯤 밀물은 열두 시 삼십구 분이 되리라는 것을 떠올렸다.","title":"바다의 일꾼들","author":"빅토르 위고","ampm":"pm","kind":"역"}],"12:40":[{"t":"열두 시 사십 분","q":"일할 때 앤은 언제나 시간을 잘 지켰고, 열두 시 사십 분이 되자 피커딜리 쪽 거리 끝에서 모습을 드러냈다.","title":"한 푼도 더도 덜도 말고","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:41":[{"t":"열두 시 사십일 분","q":"열두 시 사십일 분, 대통령 당선자 부부는 마침내 리무진에 올랐다. 그는 지연에 대해 해명할 연설 삽입문을 필리와 함께 작성하라고 내게 지시했다.","title":"백악관의 난장판","author":"크리스토퍼 버클리","ampm":"pm","kind":"역"}],"12:42":[{"t":"한 시 십팔 분 전","q":"손끝에서 담배꽁초가 뜨겁게 타올라 이제 불씨가 살갗을 지졌다. 그녀는 담배를 비벼 끄고 일어나 검은 치마의 재를 털어냈다. 한 시 십팔 분 전이었다. 그녀는 방으로 전화를 걸었지만 아무도 받지 않았다.","title":"마조리 모닝스타","author":"허먼 우크","ampm":"pm","kind":"역"}],"12:43":[{"t":"열두 시 사십삼 분","q":"오 분 전에 죽었다고요? 그가 물었다. 그의 시선이 손목시계로 향했다. 열두 시 사십삼 분, 그는 압지에 그렇게 적었다.","title":"호주머니 속의 죽음","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"12:44":[{"t":"한 시 십육 분 전","q":"몇 분 뒤 그들은 애리조나 운하 위 다리를 건너고 있었다. 매트가 낡은 은시계를 꺼내 들었다. \"한 시 십육 분 전이야,\" 그가 의기양양하게 알렸다. \"그리고 우린 십오 마일이나 왔어.\"","title":"모터 매트의 센추리 런","author":"스탠리 R. 매튜스","ampm":"pm","kind":"역"}],"12:45":[{"t":"한 시 십오 분 전","q":"그때는 이미 한 시 십오 분 전이었지만, 칼 이바니치는 우리를 놓아줄 생각도 하지 않고 새 과제만 내주었다.","title":"유년시절","author":"레프 톨스토이","ampm":"pm","kind":"역"}],"12:46":[{"t":"열두 시 사십육 분","q":"\"월요일이에요. 오전 근무를 일찍 마쳐도 좋다는 허락을 받았대요. 아마 열두 시 사십육 분 기차를 탈 거예요.\" \"그럼 너무 늦잖아,\" 할이 억울한 듯 말했다.","title":"승리한 연극","author":"랠프 헨리 바버","ampm":"pm","kind":"역"}],"12:47":[{"t":"열두 시 사십칠 분","q":"열두 시 사십칠 분에 그들은 부표에 다다랐다. 부표는 완벽한 상태였고 거의 밀려나지 않은 듯했다.","title":"달나라 탐험","author":"쥘 베른","ampm":"pm","kind":"역"}],"12:48":[{"t":"열두 시 사십팔 분","q":"골프장을 벗어나자마자 그가 입을 열었다. 그때까지 그는 한마디도 하지 않았고 나 역시 그랬다. \"열두 시 사십팔 분 기차로 가신다면 배웅해드리죠.\"","title":"하나의 깃발 아래","author":"리처드 마시","ampm":"pm","kind":"역"}],"12:49":[{"t":"열두 시 사십구 분","q":"크레펠트 공습의 첫 희생자는 영국 이중 서머타임으로 열두 시 사십구 분에 B편대에서 숨졌지만, 그것은 부주의 때문은 아니었다.","title":"폭격기","author":"렌 데이턴","ampm":"pm","kind":"역"}],"12:50":[{"t":"열두 시 오십 분","q":"그는 손목시계를 확인했다. 열두 시 오십 분, 정상에 올랐다가 마지막 햇살이 스러지기 전에 작은 텐트로 돌아올 시간은 충분했다.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:51":[{"t":"열두 시 오십일 분","q":"열두 시 오십일 분, 제임스 버딕이 다시 무선으로 연결되어 왔다. 교환할 물건이 곧 도착하니 항공기 착륙 허가가 필요하다는 것이었다.","title":"코브라 각서","author":"애덤 홀","ampm":"pm","kind":"역"}],"12:52":[{"t":"열두 시 오십이 분","q":"콘수엘라는 보도에 서서 손목시계를 확인했다. 열두 시 오십이 분, 헛수고로 끝난 아침이었음을 인정할 수밖에 없었다.","title":"반값에 산 것","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:53":[{"t":"열두 시 오십삼 분","q":"십이 마일쯤 되겠지. 핀무어에서 따라잡을 수 있을 거야, 그 기차는 열두 시 오십삼 분에 그곳에 닿을 예정이니까.","title":"다섯 마리의 붉은 청어","author":"도로시 L. 세이어즈","ampm":"pm","kind":"역"}],"12:54":[{"t":"열두 시 오십사 분","q":"다른 날에는 열두 시 오십사 분에 똑같은 뱃고동 소리가 울렸고, 또 다른 날에는 정확히 여덟 시였다.","title":"소란의 종류들","author":"리디아 데이비스","ampm":"pm","kind":"역"}],"12:55":[{"t":"한 시 오 분 전","q":"경위는 시계를 힐끗 보았다. 한 시 오 분 전, 분주한 아침이었다.","title":"사내가 쓰러져 있었다","author":"은가이오 마시","ampm":"pm","kind":"역"}],"12:56":[{"t":"한 시 사 분 전","q":"한 시까지 아무도 봐주지 않으면 떠나겠노라 그는 다짐했다. 분침이 한 시 오 분 전에서 한 시 사 분 전으로 툭 움직이는 것을 그는 지켜보았다.","title":"샤프의 복수","author":"버나드 콘웰","ampm":"pm","kind":"역"}],"12:57":[{"t":"열두 시 오십칠 분","q":"월요일 오후 열두 시 오십칠 분, 스톤 에임스는 국립보건원의 방대한 데이터 속을 떠다니고 있었다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"12:58":[{"t":"한 시 이 분 전","q":"한 시 이 분 전, 찰리 던컨이 목깃을 풀어헤친 셔츠 차림으로 담배를 피우며 팜 코트 레스토랑에 들어섰다.","title":"타고난 죄수","author":"제프리 아처","ampm":"pm","kind":"역"}],"12:59":[{"t":"열두 시 오십구 분","q":"스티븐은 시간을 확인했다. 열두 시 오십구 분이었다.","title":"종교의 자유를 위한 대림절","author":"레이 키팅","ampm":"pm","kind":"역"}],"13:01":[{"t":"한 시 일 분","q":"멀리서 뒤엉킨 고함이 들려왔다. 하지만 중요한 건 오직 한 시 일 분에 넥서스 지점에 도착하는 것뿐이었다.","title":"생존 키트","author":"프레더릭 폴","ampm":"pm","kind":"역"}],"13:02":[{"t":"열세 시 이 분","q":"열세 시 이 분, 임플란트로 강화된 감각이 새빨간 경보를 울리자 트리스틴의 몸이 굳고 손가락이 반사적으로 움직였다.","title":"패러페이스 전쟁","author":"L.E. 모데싯 주니어","ampm":"pm","kind":"역"}],"13:03":[{"t":"한 시 삼 분","q":"월요일 오후 한 시 삼 분, \"마이클, 와 줘서 정말 기쁘군요.\" 겐지 노가미가 미소 지으며 호박색 라거잔을 집어 들었다.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"13:05":[{"t":"한 시 오 분","q":"한 시 오 분, 앨린은 바깥문을 열고 돌계단 모서리에 파이프를 두드려 재를 털어낸 뒤 진입로 쪽을 가만히 응시했다.","title":"사내가 쓰러져 있었다","author":"은가이오 마시","ampm":"pm","kind":"역"}],"13:06":[{"t":"열세 시 육 분","q":"그리고 정확히 열세 시 육 분, 그 사각 구역 안에서 혼란이 터져 나왔다.","title":"우리들","author":"예브게니 자먀찐","ampm":"pm","kind":"역"}],"13:07":[{"t":"십삼 시 칠 분","q":"넥사 박사는 인간과 볼리안과 잘단을 차례로 가리키며 말했다. \"허친슨 중위의 사망 시각, 십삼 시 칠 분.\"","title":"스타트렉: 데스티니 3 - 잃어버린 영혼들","author":"데이비드 맥","ampm":"pm","kind":"역"}],"13:08":[{"t":"열세 시 팔 분","q":"그리니치 표준시 열세 시 팔 분, 러몬트와 재키는 점심을 먹으러 구내식당에서 팀원들과 합류했다.","title":"무모하게 나선 것 없이","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:09":[{"t":"한 시 구 분","q":"한 시 구 분, 도시가 아니라 서쪽과 남서쪽으로 드넓게 펼쳐진 사막 쪽에서 말 두 마리가 다가왔다.","title":"고문받은 영혼들: 프라이모디움의 전설","author":"클라이브 바커","ampm":"pm","kind":"역"}],"13:10":[{"t":"한 시 십 분","q":"지미는 여전히 모든 환전소를 들를 생각이라면 한 시 십 분까지는 출발해야 한다고 고집을 부렸다.","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:11":[{"t":"한 시 십일 분","q":"거번 역에서 자전거를 끌고 한 시 십일 분 기차를 탄 신사가 있었다는 걸 알아냈네.","title":"다섯 마리의 붉은 청어","author":"도로시 L. 세이어즈","ampm":"pm","kind":"역"}],"13:12":[{"t":"한 시 십이 분","q":"한 시 십이 분, 부관 와일드와 나는 점심 자리에 앉았다. \"대령은 늦는다지만 우리까지 기다릴 필요는 없겠지요\" 하고 부관이 말했다.","title":"진격과 후퇴","author":"조지 허버트 포스다이크 니콜스","ampm":"pm","kind":"역"}],"13:13":[{"t":"한 시 십삼 분","q":"\"전진!\" 삼촌이 답했다. 한 시 십삼 분이었다.","title":"지구 속 여행","author":"쥘 베른","ampm":"pm","kind":"역"}],"13:14":[{"t":"한 시 십사 분","q":"브룩스 요원이 수첩을 펼쳤다. \"9월 26일 중부 표준시 오후 한 시 십사 분, 오클리 아케이디아 라보의 생체 추적기에 오류 코드가 떴습니다.\"","title":"익스팅션 아일랜드","author":"재니스 뵈코프","ampm":"pm","kind":"역"}],"13:15":[{"t":"한 시 십오 분","q":"오후 한 시 십오 분, 플레처가 눈을 들어 접수원을 바라보자 그녀는 미안한 얼굴로 커피를 한 잔 더 권했다.","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:16":[{"t":"한 시 십육 분","q":"첫 번째 정차는 십칠 분 뒤인 오후 한 시 십육 분이었다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"13:17":[{"t":"한 시 십칠 분","q":"오후 한 시 십칠 분, 브리스틀 공항에서 체포가 이루어졌고 경찰은 수사와 관련해 한 명을 구금했다고 밝혔다.","title":"그녀가 알았던 것","author":"길리 맥밀런","ampm":"pm","kind":"역"}],"13:18":[{"t":"한 시 십팔 분","q":"정확히 한 시 십팔 분. 그녀가 어리석게도 안으로 들어갈까, 아니면 그러지 않을까.","title":"테러리스트, 그가 지켜본다","author":"비스와바 심보르스카","ampm":"pm","kind":"역"}],"13:19":[{"t":"오후 한 시가 넘은","q":"오후 한 시가 넘은 시각, 하인이 그녀를 깨워 아르티노프 씨가 찾아왔다고 알렸다.","title":"파티 외 단편들","author":"안톤 파블로비치 체호프","ampm":"pm","kind":"역"}],"13:20":[{"t":"한 시 이십 분","q":"제라드와 나는 그리니치까지 배를 타고 가 트래펄가 태번에서 점심을 먹었지만, 그곳을 떠난 건 한 시 이십 분이 되어서였다.","title":"원죄","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"13:21":[{"t":"오후 한 시 이십일 분","q":"오후 한 시 이십일 분, 밴스는 온 힘을 다해 움직이며 착륙장에서 이제 천 야드쯤 떨어진 헬리콥터가 최종 접근을 시작하는 모습을 지켜보았다. 아군인가, 적군인가?","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"13:22":[{"t":"오후 한 시 이십이 분","q":"우리가 아빠의 무덤을 찾은 것은 오후 한 시 이십이 분이었다.","title":"엄청나게 시끄럽고 믿을 수 없게 가까운","author":"조너선 사프란 포어","ampm":"pm","kind":"역"}],"13:23":[{"t":"오후 한 시 이십삼 분","q":"스윈던에 도착했을 때 엄마는 집 열쇠를 갖고 있어서 우리는 안으로 들어갔고, 엄마가 \"여보세요?\" 하고 불렀지만 오후 한 시 이십삼 분이라 아무도 없었다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"13:24":[{"t":"오후 한 시 이십사 분","q":"리텔은 손목시계를 확인했다, 오후 한 시 이십사 분. 리텔은 침대 옆 전화기를 집어 들었다.","title":"콜드 식스 사우전드","author":"제임스 엘로이","ampm":"pm","kind":"역"}],"13:25":[{"t":"오후 한 시 이십오 분","q":"건조기에 돌려놓은 빨래 때문에 안 되겠다고 그녀에게 말했다. 시계를 흘낏 보니 오후 한 시 이십오 분이었다. 건조기는 이미 멈춰 있었다.","title":"세계의 끝과 하드보일드 원더랜드","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"13:26":[{"t":"오후 한 시 이십육 분","q":"오후 한 시 이십육 분, 그녀가 노이스 거리를 따라 캠퍼스 쪽으로 걸어갈 때, 지저귀는 커다란 나무들과 스무 살짜리들로 가득한 튼튼한 백 년 된 집들을 지나며, 하늘은 경기가 있는 날이면 그녀가 싫어하던 눈부신 은빛이었다.","title":"그레이트 미드웨스트의 부엌들","author":"J. 라이언 스트라달","ampm":"pm","kind":"역"}],"13:27":[{"t":"오후 한 시 이십칠 분","q":"실종되기 일흔두 시간 전인 6월 20일 그 금요일, 오후 한 시 이십칠 분에 만능 한량이자 디제이, 철학도인 아드리아 다이달로스 소라는 스케이트보드를 든 채 계단을 뛰어올랐다.","title":"서펜트 페이퍼스","author":"제시카 콘웰","ampm":"pm","kind":"역"}],"13:28":[{"t":"오후 한 시 이십팔 분","q":"오후 한 시 이십팔 분, 밴은 코르벨 상업 타워로 들어가 승강기를 타고 삼 층으로 올라갔다. 거기서 남쪽 복도를 따라 걸어가 담황색 회벽에 은빛 글씨로 IIS라고 적힌 열린 문 앞에 이르러 안으로 들어섰다.","title":"에토스 이펙트","author":"L.E. 모데싯 주니어","ampm":"pm","kind":"역"}],"13:29":[{"t":"오후 한 시 이십구 분","q":"4월 6일 월요일, 오후 한 시 이십구 분, 전화를 끊으며 앨리는 자신이 무슨 일에 발을 들이는 건지 다시 생각했다. 그래도 이 기적의 일꾼을 만나고는 싶었다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"13:30":[{"t":"한 시 반","q":"루핀이 내려오지 않기에 한 시 반에 다시 올라가 두 시에 저녁을 먹는다고 말했더니, 그는 \"가겠다\"고 했다.","title":"어느 무명인의 일기","author":"조지 그로스미스 & 위든 그로스미스","ampm":"pm","kind":"역"}],"13:31":[{"t":"한 시 삼십 분쯤","q":"레몽은 한 시 삼십 분쯤 마송과 함께 돌아왔다. 팔에는 붕대를 감았고 입가에는 반창고를 붙이고 있었다. 의사는 별일 아니라고 했지만 레몽은 몹시 심각한 얼굴이었다.","title":"이방인","author":"알베르 카뮈","ampm":"pm","kind":"역"}],"13:32":[{"t":"한 시 삼십이 분","q":"다시 소파에 앉아 시계를 보았다. 한 시 삼십이 분이었다. 눈을 감고 머릿속 한 지점에 의식을 모았다. 마음을 완전히 비운 채 시간의 모래에 몸을 맡기고 흐름이 이끄는 대로 나를 내버려두었다.","title":"장님 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"13:33":[{"t":"한 시 삼십삼 분","q":"그는 초록 불이 켜지길 기다렸다가 이제는 텅 빈 화물칸으로 다시 문을 열었다. \"...한 시 삼십삼 분 오십 초.\" 아주 좋군.","title":"안녕히, 그리고 물고기는 고마웠어요","author":"더글러스 애덤스","ampm":"pm","kind":"역"}],"13:34":[{"t":"한 시 삼십사 분","q":"\"세 번째 신호음이 울리면...\" 그는 발끝으로 걸어 나가 조종실로 돌아왔다. \"...한 시 삼십사 분 이십 초.\" 목소리는 마치 런던에서 전화로 듣는 것처럼 또렷했지만, 실제로는 전혀 그렇지 않았다.","title":"안녕히, 그리고 물고기는 고마웠어요","author":"더글러스 애덤스","ampm":"pm","kind":"역"}],"13:35":[{"t":"오후 한 시 삼십오 분","q":"플레처는 다시 손목시계를 확인했다. 오후 한 시 삼십오 분이었다. 그는 한숨을 쉬고 접수원에게 화장실을 써도 되겠느냐고 물었다.","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:38":[{"t":"한 시 삼십팔 분","q":"헬멧 안 디지털 표시에 따르면 아직 한 시 삼십팔 분이었다. 힘겨운 뒷정리에 세 시간을 더 쓰지 않아도 된다는 소식은 나를 크게 기쁘게 했어야 했지만, 오히려 스무 배는 더 의심스럽게 만들었다.","title":"미니와 얼의 일요일 밤 얌 요리","author":"애덤 트로이 카스트로","ampm":"pm","kind":"역"}],"13:39":[{"t":"오후 한 시 삼십구 분","q":"이제 오후 한 시 삼십구 분, 정차한 지 이십삼 분이 지났으니 기차가 크게 곡선을 그리지 않는다면 우리는 바다에 다다를 것이었다. 하지만 곡선을 그리는지는 알 수 없었다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"13:40":[{"t":"한 시 사십 분","q":"손목시계를 흘낏 본 챈들러파월은 한 시 사십 분임을 알았다. 이제 부엌에 틀어박혀 있는 보스톡 부부와 이야기를 나눠야 할 것 같았다.","title":"사적인 환자","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"13:41":[{"t":"오후 한 시 사십일 분","q":"\"누출이 시작되기 몇 분 전, 그러니까 오후 한 시 사십일 분, 세계 표준시로 십삼 시 사십일 분, 지금으로부터 한 시간 이십삼 분 전부터 이야기를 시작하겠습니다.\"","title":"검게 탄 뼈","author":"스티븐 유인 콥","ampm":"pm","kind":"역"}],"13:42":[{"t":"오후 한 시 사십이 분","q":"마지막 기록은 오후 한 시 사십이 분에 남겨져 있었다. G.M.이 현장에 도착했으며 사건을 인계받겠다는 내용이었다.","title":"여자를 증오한 남자들","author":"스티그 라르손","ampm":"pm","kind":"역"}],"13:43":[{"t":"두 시 십칠 분 전","q":"\"두 시 십칠 분 전에 기차가 있어요,\" 디디에가 말했다. 그는 성호를 긋고 일어섰다. 그러다 망설였다. \"왜 그래?\" \"할아버지께 인사드려야 하지 않을까요? 보통 수표를 주시잖아요.\"","title":"검사","author":"예프 헤라르츠","ampm":"pm","kind":"역"}],"13:44":[{"t":"한 시 사십사 분","q":"다행히도 다음 기차는 한 시 사십사 분에 있었고, 십 분 후 다음 역인 예이틀랜드에 도착했다.","title":"경관과 요리사","author":"윌키 콜린스","ampm":"pm","kind":"역"}],"13:45":[{"t":"한 시 사십오 분","q":"\"하비가 자기 자리를 뜨는 순간 바로 알려주게. 내 짐작으로는 한 시 사십오 분쯤 그가 두 시 경주에 나갈 말들을 보러 올 테니, 우리에게 꼬박 한 시간이 있는 셈이지.\"","title":"한 푼도 많지 않게, 한 푼도 적지 않게","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:46":[{"t":"십삼 시 사십육 분","q":"폴: 엄마가 전화한 직후, 그러니까 목요일 이십사 일 십삼 시 사십육 분에 말라타르시스를 알아챘어. 브렛은 적어도 열네 시간 뒤인 이십오 일 새벽에 살해당했지.","title":"육체 없는 잭","author":"줄리언 메이","ampm":"pm","kind":"역"}],"13:47":[{"t":"오후 한 시 사십칠 분","q":"포피는 브리앤의 침대에 널브러져 뭉툭한 속눈썹에 검은 마스카라를 바르고 있었다. 브리앤은 책상에 앉아 오후 두 시 마감 전에 에세이를 끝내려 애쓰고 있었다. 오후 한 시 사십칠 분이었다.","title":"일 년 동안 잠자리에 든 여자","author":"수 타운센드","ampm":"pm","kind":"역"}],"13:48":[{"t":"오후 두 시 십이 분 전","q":"클로드 모로와 그가 가장 신뢰하는 현장 요원 자크 베르주롱이 파리 지하철 조르주생크 역에 도착한 것은 오후 두 시 십이 분 전이었다. 둘은 따로 떨어져 플랫폼 뒤쪽으로 걸어가 서로 주파수를 맞춘 휴대용 무전기를 하나씩 들고 있었다.","title":"아포칼립스 워치","author":"로버트 러들럼","ampm":"pm","kind":"역"}],"13:49":[{"t":"한 시 사십구 분","q":"매점 점원은 회색 옷을 입은 승객이 한 시 사십구 분에 매점을 지나 출구 쪽으로 가는 것을 보았다.","title":"다섯 마리의 붉은 청어","author":"도러시 L. 세이어즈","ampm":"pm","kind":"역"}],"13:50":[{"t":"한 시 오십 분","q":"그날 최고의 기차는 패딩턴발 한 시 오십 분 기차로, 일곱 시가 막 지나 폴가스에 도착했다.","title":"콘월의 미스터리","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"13:51":[{"t":"오후 한 시 오십일 분","q":"그 말인즉 지금, 오후 한 시 오십일 분에는 로어 맨해튼이 악몽 같은 상황이라는 뜻이었다. 월스트리트는 사방으로 몇 블록씩 차단되어 있었다. 도보 경찰들이 호루라기를 불고 초조하게 손짓하며 브로드웨이의 교통을 통제했다.","title":"브릴리언스","author":"마커스 세이키","ampm":"pm","kind":"역"}],"13:52":[{"t":"두 시 팔 분 전","q":"\"알려드리려고 문 앞까지 왔어요. 점심시간이 다 됐잖아요. 그래요, 두 시 팔 분 전이에요. 비비안은 점심을 먹고 있을 거예요. 저는 점심을 안 먹지만 들어가는 건 상관없어요. 그를 놓칠 순 없으니까요.\"","title":"장미와 열쇠","author":"조지프 셰리든 레퍼뉴","ampm":"pm","kind":"역"}],"13:53":[{"t":"한 시 오십삼 분","q":"\"미스터 잭슨,\" 로시터 씨가 소리쳤다. \"점심 식사에서 제때 돌아오는 정도의 성의는 보여주셔야겠습니다. 한 시 오십삼 분이나 되어서야 돌아오시다니, 그리고...\"","title":"도시의 프스미스","author":"P.G. 우드하우스","ampm":"pm","kind":"역"}],"13:54":[{"t":"한 시 오십사 분","q":"박물관 측은 소장품 중 도난당한 것은 없다고 본다. 인기 관광지인 박물관과 성당은 추후 공지가 있을 때까지 폐쇄된다. 한 시 오십사 분, 2014년 5월 5일.","title":"카타콤","author":"제러미 베이츠","ampm":"pm","kind":"역"}],"13:55":[{"t":"한 시 오십오 분","q":"한 시 오십오 분, 그는 오후 네 시의 십오 분짜리 티타임까지 보험 서류로 돌아갔다. 그 휴식 시간은 담배 두 개비를 더 태우는 또 하나의 의식이었다.","title":"부서진 일과","author":"제프리 아처","ampm":"pm","kind":"역"}],"13:57":[{"t":"한 시 오십칠 분","q":"한 시 오십칠 분이었다. \"그럼 그를 붙잡을 수 있길 바라요. 고마워요. 정말 감사해요.\"","title":"도시의 주술사","author":"C.E. 머피","ampm":"pm","kind":"역"}],"13:58":[{"t":"한 시 오십팔 분","q":"그날 오후 한 시 오십팔 분 정각, 두 소령은 펜타곤 밖 임시 사무실에서 오스틴 장군의 비서 앞에 모습을 드러냈다.","title":"스틸 타이거","author":"마크 베런트","ampm":"pm","kind":"역"}],"13:59":[{"t":"한 시 오십구 분","q":"이십 분 동안 그는 앉아서 배와 에푼 사이의 간격이 좁혀지는 것을, 배의 컴퓨터가 그 작은 위성을 도는 궤도로 진입시킬 숫자들을 어루만지고 반죽하는 것을 지켜보았다. 시각은, 한 시 오십구 분...","title":"그럼 잘 있어요, 물고기는 고마웠어요","author":"더글러스 애덤스","ampm":"pm","kind":"역"}],"14:01":[{"t":"두 시쯤","q":"두 시쯤 되었을 때, 주인의 젊은 아내가 손잡이 없는 잔과 누빔 덮개를 씌운 주전자를 들고, 여전히 낙담한 채 누워 있는 내게로 다가왔다.","title":"조약돌 하나","author":"존 허시","ampm":"pm","kind":"역"}],"14:02":[{"t":"두 시 이 분","q":"시계가 운명적으로 종을 치자마자 모인 사람들은 마치 불이라도 난 것처럼 저마다 자리를 박차고 뛰쳐나갔다. 내 질문을 들은 늙은 서기가 대답했다. \"공무원의 첫째 의무는 시간 엄수입니다, 선생님!\" 두 시 이 분이 되자 그 방에는 사람 하나 남아 있지 않았다.","title":"붉은 방","author":"아우구스트 스트린드베리","ampm":"pm","kind":"역"}],"14:03":[{"t":"두 시 삼 분","q":"두 시 삼 분, 타후마 전투가 시작되었다.","title":"무한한 날","author":"크리스 월리","ampm":"pm","kind":"역"}],"14:04":[{"t":"두 시 사 분","q":"두 시 사 분. 병참감실에서 다시 전화가 걸려와 핀크 대령을 찾았고, 핀크는 또다시 그 조용하고 무심하며 낯선 목소리를 들었다.","title":"장군들의 밤","author":"한스 헬무트 키르스트","ampm":"pm","kind":"역"}],"14:05":[{"t":"두 시 오 분","q":"...그리고 잊을 수 없는 그해 1916년 9월 17일 두 시 오 분, 나는 무료보 병원 마당에 서 있었다. 9월의 비에 짓눌려 시든 풀을 밟은 채였다.","title":"어느 시골 의사의 수기","author":"미하일 불가코프","ampm":"pm","kind":"역"}],"14:06":[{"t":"두 시 육 분","q":"트랙터를 몰던 한 남자가 그녀를 보았다. 그날 오후 두 시 육 분, 그녀의 집에서 사백 야드 떨어진 곳이었다.","title":"기후의 변화","author":"힐러리 맨텔","ampm":"pm","kind":"역"}],"14:07":[{"t":"두 시 칠 분","q":"두 시 칠 분쯤 그는 토네이의 사무실에 고개를 들이밀며 말했다. \"반장님, 뷰익에 뭔가 일어나고 있는 게 분명해요.\"","title":"뷰익 8에서","author":"스티븐 킹","ampm":"pm","kind":"역"}],"14:08":[{"t":"두 시 팔 분","q":"두 시 팔 분, 발코니에서 내려오는 넓은 계단 옆에 서 있던 그 침울한 얼굴의 남자는 목을 길게 빼고 몽크 메이페어, 햄 브룩스, 대니얼 W. 로차버, 엘마 챔피언을 발견했다.","title":"겁에 질린 남자","author":"케네스 로베슨","ampm":"pm","kind":"역"}],"14:09":[{"t":"두 시 구 분","q":"\"타인 씨는,\" 버틀러가 말했다. \"북쪽 타워 로비를 두 시 구 분에 엘리베이터 상행 튜브로 나서 육십 층의 체스 대회장에 두 시 십 분에 도착했습니다.\"","title":"네크로맨서","author":"고든 R. 딕슨","ampm":"pm","kind":"역"}],"14:10":[{"t":"두 시 십 분","q":"그는 두 시 십 분에 그녀의 집에 도착했다. 한 손에는 비디오테이프 두 개를, 다른 손에는 조리하지 않은 전자레인지용 팝콘 한 봉지를 들고서.","title":"집행유예","author":"제임스 한 매트슨","ampm":"pm","kind":"역"}],"14:11":[{"t":"두 시 십일 분","q":"자동응답기가 전자음으로 알렸다. \"메시지가 한 개 있습니다, 두 시 십일 분에 도착.\" 이어 느끼한 남자 목소리가 흘러나왔다. \"커비, 네가 거기 있는 거 알아. 아직 치료 중이잖아. 혼자 돌아다니면 안 돼. 지금은 우리랑 있는 게 훨씬 안전해.\"","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"14:12":[{"t":"두 시 십이 분","q":"세브는 벽시계를 올려다보았다. 두 시 십이 분. 이 속도라면 멜러와 사십 분 이상 이야기하기도 힘들겠지만, 그자는 준비된 이야기를 시간 낭비 없이 쏟아낼 게 뻔했다.","title":"그는 사람이었다","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:13":[{"t":"두 시 십삼 분","q":"세 번째 종이 울리면, 시각은 두 시 십삼 분 오십 초가 됩니다.","title":"그럼 잘 있어요, 물고기는 고마웠어요","author":"더글러스 애덤스","ampm":"pm","kind":"역"}],"14:14":[{"t":"두 시 십사 분","q":"자개를 박아 넣은, 더는 움직이지 않는 그 시계는 어머니의 혼수였는데, 잊힌 어느 날 두 시 십사 분에 멈춰 서 있었다.","title":"헛간을 태우다","author":"윌리엄 포크너","ampm":"pm","kind":"역"}],"14:15":[{"t":"두 시 십오 분","q":"두 시 십오 분. 신문에서 두 살배기 아이들이 유치원에 들어가려고 시험을 봐야 한다는 기사를 읽고 소스라치게 놀랐다. 대자 해리의 생일 파티에 가야 하는데.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"14:16":[{"t":"두 시 십육 분","q":"\"아, 안녕하세요. 제가 오늘 오후 두 시 십육 분에 들어올 때 개찰구에 계셨죠. 그런데 제가 표를 내지 않고 지나가게 두셨다는 거 아세요? 네, 네, 하하! 좀 더 신경 쓰셔야 할 것 같은데요.\"","title":"다섯 마리 붉은 청어","author":"도로시 L. 세이어즈","ampm":"pm","kind":"역"}],"14:17":[{"t":"두 시 십칠 분","q":"\"제가 아는 건 그녀가 화요일과 목요일마다 베이커가에서 두 시 십칠 분 기차를 타고 나가 여섯 시까지는 돌아왔다는 것뿐이에요. 그러니 그리 멀리 가지는 않았을 거예요.\"","title":"그 늦은 세입자","author":"루이스 트레이시","ampm":"pm","kind":"역"}],"14:18":[{"t":"두 시 십팔 분","q":"두 시 십팔 분. 피에르 아르몽은 마흔여섯 살로, 관자놀이가 희끗하고 올림픽 레슬링 선수 같은 체격을 지녔다. 통통한 뺨과 짙은 콧수염, 주변을 끊임없이 살피는 의심 많은 검은 눈을 가졌는데, 그것은 타고난 생존 본능이었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"14:19":[{"t":"두 시 십구 분","q":"두 시 십구 분, 듀에인 힌튼이 밖으로 나온다. 뒷마당을 가로지른다. 옷가지를 들고 있다. 어젯밤 입었던 그 옷이다. 그는 울타리로 걸어간다. 소각로에 불을 지핀다. 성냥을 긋는다.","title":"차가운 육천","author":"제임스 엘로이","ampm":"pm","kind":"역"}],"14:20":[{"t":"두 시 이십 분","q":"그는 손목시계를 확인했다. 두 시 이십 분. 킥오프는 세 시. 사만 명의 팬들이 모두 같은 방향으로 향하고 있었다. 대부분은 붉고 흰 스카프를 둘렀지만, 파랗고 흰 스카프를 두른 무리도 상당했다.","title":"외면하다","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:21":[{"t":"두 시 이십일 분","q":"네드는 어리둥절해서 주위를 둘러보았고, 자신이 처한 상황을 이해하기까지 한참이 걸렸다. 이해하고 나자 그는 벌떡 일어나 앉아 시계를 놀란 눈으로 바라보았다. 말도 안 됐다! 시계는 두 시 이십일 분을 가리키고 있었다!","title":"터너 쌍둥이","author":"랠프 헨리 바버","ampm":"pm","kind":"역"}],"14:22":[{"t":"두 시 이십이 분","q":"가스야. 일요일 오후. 못 만나서 아쉽지만, 자동응답기에 짧게 메시지 남길게. 대략 두 시 이십이 분쯤. 파티 정말 좋았어.","title":"래리의 파티","author":"캐럴 실즈","ampm":"pm","kind":"역"}],"14:23":[{"t":"두 시 이십삼 분","q":"\"그냥 평범한 안개야.\" 그가 말했다. \"그래도 참 신기하네. 지금 몇 시지? 시계 가진 사람?\" \"두 시 이십삼 분이야.\" 에번이 대답했다. \"서둘러야 축구 연습 시간에 맞춰 내려갈 수 있겠어.\"","title":"킹스퍼드, 쿼터","author":"랠프 헨리 바버","ampm":"pm","kind":"역"}],"14:24":[{"t":"두 시 이십사 분","q":"포커기는 두 시 이십사 분에 나이로비 활주로를 이륙했다. 새 일정보다 삼 분 앞선 시각이었다.","title":"콩고","author":"마이클 크라이튼","ampm":"pm","kind":"역"}],"14:25":[{"t":"두 시 이십오 분","q":"사이먼은 두 시 이십오 분에 도착했다. 당대표와의 면담까지는 오 분이 남아 있었다.","title":"동등한 자들 중 첫째","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:26":[{"t":"두 시 이십육 분","q":"두 시 이십육 분이었지만, 그곳은 여전히 점심시간 인파로 북적였다.","title":"자유낙하","author":"로버트 크레이스","ampm":"pm","kind":"역"}],"14:27":[{"t":"두 시 이십칠 분","q":"블룸즈버리 센터의 사천 개 방에 걸린 사천 개의 전기시계 바늘이 일제히 두 시 이십칠 분을 가리켰다.","title":"멋진 신세계","author":"올더스 헉슬리","ampm":"pm","kind":"역"}],"14:28":[{"t":"두 시 이십팔 분","q":"목요일 두 시 이십팔 분, 탄잔 미노가 조용히 말했다. 극초음속 시험비행은 예정대로 진행되어야 한다고.","title":"프로젝트 다이달로스","author":"토머스 후버","ampm":"pm","kind":"역"}],"14:29":[{"t":"두 시 이십구 분","q":"그날따라 그의 기상 감각은 다소 고장 난 듯, 그는 호텔 시계로 두 시 이십구 분이 되어서야 눈을 떴다.","title":"네 개의 돛대를 단 캣보트","author":"찰스 배텔 루미스","ampm":"pm","kind":"역"}],"14:30":[{"t":"두 시 반","q":"같은 날 오후 두 시 반, 소년과 노인은 내실과 대기실 바로 위층 방에 서 있다.","title":"코커의 자유","author":"존 버거","ampm":"pm","kind":"역"}],"14:31":[{"t":"두 시 삼십일 분","q":"이고르는 다시 시간을 확인했다. 이제 두 시 삼십일 분, 그녀는 공식적으로 지각이었다.","title":"뱀파이어의 조약","author":"맷 쇼","ampm":"pm","kind":"역"}],"14:32":[{"t":"두 시 삼십이 분","q":"두 시 삼십이 분, 비처가와 애벌론가, 좌회전 세 블록에 우회전 두 블록. 한 상자를 집어 든 뒤 삼 분 만에 다섯 블록을 달릴 방법이 궁금해졌다.","title":"우체국","author":"찰스 부코스키","ampm":"pm","kind":"역"}],"14:33":[{"t":"두 시 삼십삼 분","q":"그 순간 이모가 오두막 옆에 나타나 곶 위쪽을 바라보았다. 달글리시는 손목을 흘끗 보았다. 두 시 삼십삼 분이었다.","title":"부자연스러운 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"14:34":[{"t":"두 시 삼십사 분","q":"정확히 두 시 삼십사 분, 가장 크고 화려한 개인실에서 브럼펫 수간호사는 환자를 잃었다.","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"14:35":[{"t":"두 시 삼십오 분","q":"두 시 삼십오 분, 좌회전 세 블록에 우회전 두 블록. 그는 다시 한번 시간과의 싸움을 시작했다.","title":"우체국","author":"찰스 부코스키","ampm":"pm","kind":"역"}],"14:36":[{"t":"두 시 삼십육 분","q":"손목시계를 본다. 두 시 삼십육 분. 오늘 남은 일이라곤 빨래를 걷고 저녁을 짓는 것뿐이다.","title":"코끼리의 소멸","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"14:37":[{"t":"두 시 삼십칠 분","q":"핀즈버리 파크에서 스티브니지까지 역마다 서는 바람에, 기차가 케임브리지에 들어섰을 때 역 시계는 두 시 삼십칠 분을 가리키고 있었다.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:38":[{"t":"두 시 삼십팔 분","q":"손목시계를 확인하니 두 시 삼십팔 분이었다. 시간은 아직 충분히 남아 있었다.","title":"아버지의 죄","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:39":[{"t":"두 시 삼십구 분","q":"핀훼리 역장한테서 보고가 들어왔는데, 어떤 신사가 두 시 삼십구 분 기차를 탔다는 겁니다.","title":"다섯 마리 붉은 청어","author":"도로시 L. 세이어즈","ampm":"pm","kind":"역"}],"14:40":[{"t":"두 시 사십 분","q":"로렌스는 시계를 보며 말했다. 내가 아는 두 시 사십 분 차는 골더스 그린과 에지웨어를 오가는 버스뿐이라고, 서두르지 않으면 열네 번을 놓치고 만다고.","title":"명예의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:41":[{"t":"두 시 사십일 분","q":"두 시 사십일 분. 서두를 필요 없다고, 엠마에게 그녀가 말했다.","title":"시간만이 말해주리라","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:42":[{"t":"두 시 사십이 분","q":"정확히 두 시 사십이 분, 하늘에서 원형질 밧줄이 내려와 아파트 밖에 멈춰 섰다.","title":"불타는 도시","author":"월터 존 윌리엄스","ampm":"pm","kind":"역"}],"14:43":[{"t":"두 시 사십삼 분","q":"두 시 사십삼 분 기차가 정시에 턴브리지 웰스에 들어섰고, 윌리엄이 가장 먼저 내렸다.","title":"내 시체를 넘어서","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:44":[{"t":"두 시 사십사 분","q":"모자 가게에서 두 집 건너 창가의 벽시계가 두 시 사십사 분을 가리킬 때, 나는 몸을 돌려 오십 야드도 안 되는 곳에 있는 브루노를 보았다.","title":"높은 곳의 친구들","author":"캐로 피콕","ampm":"pm","kind":"역"}],"14:45":[{"t":"두 시 사십오 분","q":"데이비드는 두 시 사십오 분에 헌팅던 애비뉴의 콥리 호텔에 도착했다. 아드레날린이 온몸을 휘돌았다.","title":"한 푼도 더도 덜도 아닌","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:46":[{"t":"두 시 사십육 분","q":"아이러니는 무의식중에 찾아왔다. 그는 손목시계를 보았다. 두 시 사십육 분이었다.","title":"파르지팔 모자이크","author":"로버트 러들럼","ampm":"pm","kind":"역"}],"14:47":[{"t":"두 시 사십칠 분","q":"엘리베이터 옆 간호사가 말했다. 지금은 두 시 사십칠 분입니다, 여러분. 한 시간 뒤에 더 내려가셔도 좋습니다.","title":"안드로메다 스트레인","author":"마이클 크라이튼","ampm":"pm","kind":"역"}],"14:48":[{"t":"두 시 사십팔 분","q":"두 시 사십팔 분, 라이스는 휴이 조종석에서 크라이트론 상자를 꺼내는 일을 마치고 엘리베이터로 내려가고 있었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"14:49":[{"t":"두 시 사십구 분","q":"엔디콧은 그를 마주 보며 생각했다. 급류는 인터스테이트 오십번 도로 위에서 두 시 사십구 분에 발생하도록 되어 있었다.","title":"귀향","author":"카스텐 스트라우드","ampm":"pm","kind":"역"}],"14:50":[{"t":"두 시 오십 분","q":"두 시 오십 분, 그는 모두를 회원 전용석으로 불러 자신의 유명한 암말을 보여주었다.","title":"한 푼도 더도 덜도 아닌","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:51":[{"t":"두 시 오십일 분","q":"두 시 오십일 분, 폭풍이 되돌아왔다. 성난 먹구름이 하늘의 천장을 가득 메우며 밀려들었다.","title":"다리","author":"존 스킵, 크레이그 스펙터","ampm":"pm","kind":"역"}],"14:52":[{"t":"두 시 오십이 분","q":"케셀바흐 씨, 지금은 두 시 오십이 분입니다. 팔 분 안에 대답하지 않으면 당신은 죽은 목숨입니다.","title":"813","author":"모리스 르블랑","ampm":"pm","kind":"역"}],"14:53":[{"t":"두 시 오십삼 분","q":"두 시 오십삼 분, 그들은 텅 빈 회의실로 안내되었다. 스콧은 벽쪽 의자를 골라 앉았다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:54":[{"t":"세 시 육 분 전","q":"장식판이 달린 요란한 마구를 두른 대공가 트로이카들이 네프스키 대로를 오가며, 짧은 하루의 해가 진 지 한참 지난 세 시 육 분 전까지 오가는 인파 속에서 보고 보이기를 계속했다.","title":"러시안 램블스","author":"이저벨 F. 햅굿","ampm":"pm","kind":"역"}],"14:55":[{"t":"세 시 오 분 전","q":"세 시 오 분 전, 파올로와 신랑 들러리가 예배당에 들어서 천천히 통로를 걸어갔다.","title":"캣 오 나인 테일즈","author":"제프리 아처","ampm":"pm","kind":"역"}],"14:56":[{"t":"오후 두 시 오십육 분","q":"오후 두 시 오십육 분, 헬렌은 이제 혼자다. 그녀의 얼굴은 프레임 밖에 있고, 뷰파인더 너머로 구겨진 시트 한 자락과 그녀의 가슴과 어깨 윗부분만 보인다.","title":"60분 줌","author":"J.G. 밸러드","ampm":"pm","kind":"역"}],"14:57":[{"t":"세 시 삼 분 전","q":"그는 세 시 삼 분 전에 외투를 팔에 걸친 채 집을 나섰다. 유월 초의 무더운 날이었고, 문을 나서자 거리의 열기가 화로에서 뿜어져 나오듯 얼굴을 덮쳤다.","title":"맨섬 사람","author":"홀 케인 경","ampm":"pm","kind":"역"}],"14:58":[{"t":"세 시 이 분 전","q":"세 시 이 분 전, 블래키는 홀로 책상 앞에 앉아 있었다. 지연된 충격과 두려움이 뒤섞인 무기력이 그녀를 짓눌러 어떤 행동도 견딜 수 없는 일처럼 느껴졌다.","title":"오리지널 신","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"14:59":[{"t":"세 시 일 분 전","q":"세 시 일 분 전, 고위 간부 다섯 명이 방으로 들어섰고, 스콧은 그 가운데 수전 앤더슨이 있는 것을 보고 반가워했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:01":[{"t":"세 시 일 분","q":"세 시 일 분, 그가 걸을 때 대리석 바닥에 울리는 자신의 발소리가 문득 크게 느껴졌다. 그때 한 목소리가 들려왔다. \"고해하러 오셨습니까, 형제여?\"","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:02":[{"t":"세 시 이 분","q":"몇 달에 걸친 확인과 재확인 끝에, 혼혈인 조지프 리카르도가 1995년 10월 19일 서부 표준시로 세 시 이 분에 부에노스아이레스의 한 병원에서 사생아로 태어났음이 공식적으로 인정되었다.","title":"칠드런 오브 맨","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"15:03":[{"t":"오후 세 시 삼 분","q":"신기의 휴대전화를 확인하니 오후 세 시 삼 분이었다. 나는 침대에서 일어나 여행 가방을 열어 깨끗한 양말을 꺼냈는데, 어머니의 냄새가 코를 찔러 어지러움을 느꼈다.","title":"하라레 노스","author":"브라이언 치크와바","ampm":"pm","kind":"역"}],"15:04":[{"t":"오후 세 시 사 분","q":"그는 손목시계를 확인했다. 오후 세 시 사 분. 그는 다시 문을 두드렸지만 여전히 아무도 응답하지 않았다. 겨우 몇 분 늦었을 뿐인데 설마 들여보내 주지 않으랴 싶었다.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:05":[{"t":"세 시 오 분","q":"\"오 분 전만 해도 세 시였는데.\" 머피가 말했다. \"장담은 못 하지만, 아마 지금쯤 세 시 오 분쯤 되었을 거야.\" 나는 팔짱을 꼈다. \"난 보통 잠복근무는 안 해.\"","title":"화이트 나이트","author":"짐 부처","ampm":"pm","kind":"역"}],"15:06":[{"t":"세 시 육 분","q":"\"랄 기르자\" 탑 위의 시계는 세 시 육 분을 가리키고 있었다.","title":"폐허 속의 아침 식사","author":"마이클 무어콕","ampm":"pm","kind":"역"}],"15:07":[{"t":"세 시 칠 분","q":"이튿날은 잿빛으로 흐려 비가 올 듯했다. 그는 세 시 칠 분에 그곳에 도착했다. 길 건너 교회 시계가 그 시각을 가리키고 있었다. 그들은 세 시 십오 분에 만나기로 했었다.","title":"하늘 아래 이만 개의 거리","author":"패트릭 해밀턴","ampm":"pm","kind":"역"}],"15:08":[{"t":"세 시 팔 분","q":"안개가 이제 걷히고 있어 그는 그레인지 저택의 어두운 윤곽과 창문에서 번지는 흐릿한 불빛을 겨우 알아볼 수 있었다. 손목시계는 세 시 팔 분을 가리켰다.","title":"검은 탑","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"15:09":[{"t":"세 시 구 분","q":"\"이제 정말 가야 해, 세브. 요크셔에 계신 어머니를 뵈러 가는데, 지금 당장 출발하지 않으면 허더스필드행 세 시 구 분 기차를 놓치고 말 거야.\"","title":"펜은 칼보다 강하다","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:10":[{"t":"세 시 십 분","q":"이번에는 그저 시침이 세 시 십 분을 가리킨 순간, 바로 런던의 모든 시계가 일제히 멈춘 그 정확한 순간이었을 뿐이었다.","title":"자줏빛 구름","author":"M.P. 실","ampm":"pm","kind":"역"}],"15:11":[{"t":"세 시 십일 분","q":"버지니아가 세 시 십일 분에 찻집에 들어서자 자일스는 숨을 삼켰다. 이 우아한 여인이 예순을 넘겼다고는 그 누구도 믿지 못할 정도였다.","title":"이것이 한 남자였다","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:12":[{"t":"세 시 십이 분","q":"세 시 십이 분, 확성기에서 안내 방송이 흘러나왔다. \"카트라이트 사건 관계자 여러분께서는 배심원단이 돌아오고 있으니 4호 법정으로 돌아와 주시기 바랍니다.\"","title":"태생의 포로","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:13":[{"t":"세 시 십삼 분","q":"엘리베이터가 움직였다. 세 시 십삼 분이었다. 벨이 땡 하고 울렸다. 엘리베이터에서 앨런 노먼과 다른 남자가 내렸다. 토니 블레어가 사무실로 걸어 들어왔다.","title":"버추얼 어쌔신","author":"사이먼 컨스","ampm":"pm","kind":"역"}],"15:14":[{"t":"세 시 십사 분","q":"우리 둘만의 달콤한 몽상의 시간을 위해, 사랑스러운 그대여, 나는 정확히 세 시 십사 분에 돌아오겠소.","title":"길 위에서","author":"잭 케루악","ampm":"pm","kind":"역"}],"15:15":[{"t":"세 시 십오 분","q":"사소한 일들을 하나하나 기억할 순 없었다. 수요일: 오후 세 시, 공포 통치, 세 시 십오 분, 전갈 우리 청소...","title":"진흙 발","author":"테리 프래쳇","ampm":"pm","kind":"역"}],"15:16":[{"t":"세 시 십육 분","q":"님로드 정찰기는 그리니치 표준시로 세 시 십육 분에 경비행기와 랑데부했다.","title":"크로우 로드","author":"이언 뱅크스","ampm":"pm","kind":"역"}],"15:17":[{"t":"세 시 십칠 분","q":"\"세 시 십칠 분 기차를 타고 피터버러까지 가서 갈아탄 뒤 네 시 구 분 기차로 돈캐스터까지 가고, 거기서 다시 갈아타야 해요. 헐에는 여섯 시 삼십이 분에 도착할 거예요.\"","title":"더기 모티머의 오른팔","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:18":[{"t":"세 시 십팔 분","q":"그래픽 필름은 벌써 주름지고 있다. 독수리는 날개가 부러졌고, 시침은 휘어졌다. 시각은 세 시 십팔 분이다.","title":"페어리랜드","author":"폴 J. 매콜리","ampm":"pm","kind":"역"}],"15:19":[{"t":"세 시 십구 분","q":"세 시 십구 분, 여전히 침착함을 잃지 않았지만 더는 그리 단정치 못한 옷차림의 세실리 소로굿은 차가운 대서양 물에 어깨까지 잠긴 채 뒤집힌 소형 보트의 구명줄에 매달려 있었다.","title":"롱 트릭","author":"루이스 앤셀름 다코스타 리치","ampm":"pm","kind":"역"}],"15:20":[{"t":"세 시 이십 분","q":"제임스는 트릴비 모자를 귀까지 눌러쓰고 시선을 돌린 채, 샘 오플래허티와 세 시 이십 분 경주인 킹 조지 6세 앤드 퀸 엘리자베스 스테이크스 이야기를 나누며 시간을 보냈다.","title":"한 푼도 더 안 되고 덜 안 되고","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:21":[{"t":"세 시 이십일 분","q":"세 시 이십일 분. \"그들을 보내줘.\" 라미레스가 말했다. \"필요한 건 이미 얻었으니까.\" 그는 몸을 숙여 상자를 집어 들었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"15:22":[{"t":"세 시 이십이 분","q":"루스는 마침내 세 시 이십이 분에 문을 열고 들어왔다. \"메시지 온 거 있어요?\" 그녀가 접수원에게 물었다.","title":"거짓 인상","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:23":[{"t":"세 시 이십삼 분","q":"세 시 이십삼 분! 겨우 그거야? 시간이 안 가... 아니, 이미 했던 생각이지. 나는 앉아서 손목시계 위로 초침이 바뀌는 걸 지켜본다.","title":"에스퍼데어 스트리트","author":"이언 뱅크스","ampm":"pm","kind":"역"}],"15:24":[{"t":"세 시 이십사 분","q":"오르간 연주자는 믿기지 않는다는 안도감에 결혼행진곡 첫 소절을 엉망으로 연주했다. 지미가 그날 처음으로, 그조차 줄이지 못한 문장을 입 밖에 낸 것은 세 시 이십사 분이었다. \"저는 맹세합니다.\"","title":"레지널드 페린 옴니버스","author":"데이비드 노브스","ampm":"pm","kind":"역"}],"15:25":[{"t":"세 시 이십오 분","q":"다음날 오후 언더힐 씨는 사무실 일을 일찍 마치고 세 시 기차를 타서, 세 시 이십오 분에 그린타운에 도착했다. 가을 햇살을 만끽하기에 충분한 시간이었다.","title":"놀이터","author":"레이 브래드버리","ampm":"pm","kind":"역"}],"15:26":[{"t":"세 시 이십육 분","q":"거의 세 시 이십육 분이었다. 그는 크리스에게 \"다 괜찮음\"이라는 두 마디 메시지를 보낸 뒤, 자신이 하는 짓이 얼마나 미친 짓인지 애써 생각하지 않으려 하며 가장 가까운 이동식 건물을 향해 성큼성큼 걸어갔다.","title":"목격자","author":"사이먼 커닉","ampm":"pm","kind":"역"}],"15:27":[{"t":"세 시 이십칠 분","q":"그녀가 피터스 목사에게 전화를 걸자 그는 세 시 이십칠 분에 학교로 왔고, \"자, 젊은이, 이제 시작할 준비 됐나?\"라고 말했다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"15:28":[{"t":"세 시 이십팔 분","q":"\"세 시 이십팔 분!\" 그가 신이 나서 외쳤다. \"내가 말했잖아! 우리가 여기서도 시간을 못 지킬 줄 알았나! 배는 정확히 세 시 사십오 분에 널빤지를 뭍에 댈 거야!\"","title":"바깥에서 온 여자","author":"헐버트 풋너","ampm":"pm","kind":"역"}],"15:29":[{"t":"세 시 이십구 분","q":"오후 세 시 이십구 분. 사태가 심각해지면서 작전은 백악관 지하의 상황실로 옮겨졌다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"15:30":[{"t":"세 시 반","q":"세 시 반, 통학버스를 타고 집에 간다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"15:31":[{"t":"세 시 삼십일 분","q":"\"제 손목시계로 세 시 삼십일 분에, 당신이 제게 남겨준 유일한 장신구인 그 시계로 말이죠, 저는 버트럼 버터넛 각하의 병상에서 이 전갈을 받았습니다, 토드리 경!\"","title":"비명: 풍자극","author":"찰스 서머빌","ampm":"pm","kind":"역"}],"15:32":[{"t":"세 시 삼십이 분","q":"정확히 세 시 삼십이 분, 나는 케이틀린이 왁 하우스를 자신만만하게 지나쳐 걷는 것을 보았다. 그녀는 내가 손을 든 순간 나를 알아보고는 새로 교정한 새하얀 이를 드러내며 이쪽으로 걸어왔다.","title":"잘못은 우리 별에 있어","author":"존 그린","ampm":"pm","kind":"역"}],"15:33":[{"t":"세 시 삼십삼 분","q":"서류가방을 집어 들며 다시 시계를 보았다. 세 시 삼십삼 분.","title":"11/22/63","author":"스티븐 킹","ampm":"pm","kind":"역"}],"15:34":[{"t":"세 시 삼십사 분","q":"이제 세 시 삼십사 분, 졸음이 그의 몸속에서 납덩이처럼 무겁게 느껴졌다.","title":"악마의 봉우리","author":"데온 마이어","ampm":"pm","kind":"역"}],"15:35":[{"t":"세 시 삼십오 분","q":"세 시 삼십오 분 기차가 사우샘프턴역을 떠나 런던으로 향할 때, 사샤는 객차 한구석에 앉아 있었다. 그는 창밖을 바라볼 뿐 말이 없었다. 마음은 이미 고국에 가 있었고, 그들이 큰 실수를 한 건 아닌지 의심하기 시작했다.","title":"헤즈 유 윈","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:36":[{"t":"네 시 이십사 분 전","q":"한편 한 소녀가 공항 로비에 서 있었다. 천장에 매달린 커다란 시계는 네 시 이십사 분 전을 가리키고 있었다.","title":"인트루더스","author":"마이클 마셜","ampm":"pm","kind":"역"}],"15:37":[{"t":"세 시 삼십칠 분","q":"이 폭발은 공식적으로 \"신의 소행\"으로 규정되었다. 하지만 대체 어떤 신이, 왜, 히스로 공항 제2터미널을 어슬렁거리며 세 시 삼십칠 분 오슬로행 비행기를 잡으려 하겠는가?","title":"영혼의 길고 어두운 티타임","author":"더글러스 애덤스","ampm":"pm","kind":"역"}],"15:38":[{"t":"세 시 삼십팔 분","q":"멘데즈는 매직펜을 들고 칼리 빅커스가 실종된 날의 기록에 덧붙였다. 세 시 삼십팔 분, F. 파먼이 교통위반 딱지를 발부함.","title":"죽음보다 깊은 곳","author":"태미 호그","ampm":"pm","kind":"역"}],"15:39":[{"t":"세 시 삼십구 분","q":"나는 1965년 말과 1963년 초, 댈러스와 조디에서 두 개의 삶을 살았다. 그 둘은 4월 10일 오후 세 시 삼십구 분에 하나로 합쳐졌다.","title":"11/22/63","author":"스티븐 킹","ampm":"pm","kind":"역"}],"15:40":[{"t":"네 시 이십 분 전","q":"왜 아무도 오지 않은 걸까? 너무 일찍 왔나? 아니, 그럴 리 없다! 그들은 세 시 반이라 했고 지금은 이미 네 시 이십 분 전이었다. 그는 서둘러 문 쪽으로 향했다.","title":"엽란을 날려라","author":"조지 오웰","ampm":"pm","kind":"역"}],"15:41":[{"t":"세 시 사십일 분","q":"그리니치 표준시로 세 시 사십일 분, 세스나기의 엔진이 꺼지기 시작했다. 연료가 떨어진 듯한 비행기는 서서히 고도를 잃어갔다.","title":"까마귀 길","author":"이언 뱅크스","ampm":"pm","kind":"역"}],"15:42":[{"t":"세 시 사십이 분","q":"몬토야가 컴퓨터에 명령을 내리자 화면이 세 시 사십이 분으로 흐려지며 넘어갔다. 우리 차는 삼 분 뒤 진입로에 도착했다.","title":"데들리 크로스","author":"제임스 패터슨","ampm":"pm","kind":"역"}],"15:43":[{"t":"세 시 사십삼 분","q":"그는 그녀에게 손을 내밀었지만, 그녀가 무서운 눈빛으로 노려보자 물러나 내버려두었다. 세 시 사십삼 분, 그녀는 이를 악물고 계속 걸었다.","title":"돌 본즈","author":"홀리 블랙","ampm":"pm","kind":"역"}],"15:44":[{"t":"세 시 사십사 분","q":"스트렝네스에서 급파된 무장 대응팀이 세 시 사십사 분에 비우르만의 여름 별장에 도착했다.","title":"불장난하는 소녀","author":"스티그 라르손","ampm":"pm","kind":"역"}],"15:45":[{"t":"세 시 사십오 분","q":"그래도 그만큼 많은 폐차가 있으니 승산은 꽤 있어 보였다. 그는 시계를 흘긋 보았다, 오후 세 시 사십오 분.","title":"프렌치 크릭","author":"피터 레네봄","ampm":"pm","kind":"역"}],"15:46":[{"t":"네 시 십사 분 전","q":"자네에게 네 시 십사 분 전에 이 방을 나가도록 허락하겠네. 네 시 십사 분 전보다 단 일 초도 이르면 안 되네... 알겠나?","title":"금발의 여인","author":"모리스 르블랑","ampm":"pm","kind":"역"}],"15:47":[{"t":"세 시 사십칠 분","q":"세 시 사십칠 분. 그는 브리지 파티가 파하기까지 적어도 이십 분은 더 남았으리라 짐작했다.","title":"까마귀처럼 곧게","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:48":[{"t":"세 시 사십팔 분","q":"세 시 사십팔 분, 위성은 마드리드 컴퓨터가 지정한 \"관심 구역\"을 벗어났다.","title":"둠스데이 최후통첩","author":"제임스 폴렛","ampm":"pm","kind":"역"}],"15:49":[{"t":"세 시 사십구 분","q":"세 시 사십구 분, 통학버스에서 내려 집에 도착한다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"15:50":[{"t":"세 시 오십 분","q":"로마노프는 조바심을 내며 작은 대기실을 오갔지만, 비서는 시계 바늘이 일직선을 이룰 때까지 돌아오지 않았다. 세 시 오십 분, 로마노프는 의장실로 안내되었다.","title":"명예의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:51":[{"t":"세 시 오십일 분","q":"전보는 로마에서, 이십삼 시가 되기 십 분 전에 발송되었다. 전보는 이렇게 말하는 듯했다. \"폐하 내외와 왕실 자녀분들께서는 내일 세 시 오십일 분에 로마에 도착하실 예정이다.\"","title":"선생님 없이 배우는 이탈리아어","author":"마크 트웨인","ampm":"pm","kind":"역"}],"15:52":[{"t":"네 시 팔 분 전","q":"그는 커브를 돌았고, 매크레디가 말했던 바로 그 자리에 대피 공간이 있었다. 그는 시계를 확인했다, 네 시 팔 분 전. 도로는 텅 비어 있었다.","title":"기만자","author":"프레더릭 포사이스","ampm":"pm","kind":"역"}],"15:53":[{"t":"네 시 칠 분 전","q":"구름이 태양에서 걷히는 것 같았다. 조디가 리처를 흘긋 보았다. 그는 시계를 보았다. 네 시 칠 분 전. 이제 세 시간도 채 남지 않았다.","title":"트립와이어","author":"리 차일드","ampm":"pm","kind":"역"}],"15:54":[{"t":"세 시 오십사 분","q":"오후 세 시 오십사 분, 11번가 동쪽에서 온 화면 하단에 우리 모습이 잡혔다. 이 분 뒤, LA 다저스 모자를 쓰고 짙은 선글라스에 카키색 셔츠, 검은 반다나를 두른 남자가 '부자를 쏴라'라고 쓰인 팻말을 들고 나타났다.","title":"데들리 크로스","author":"제임스 패터슨","ampm":"pm","kind":"역"}],"15:55":[{"t":"세 시 오십오 분","q":"세 시 오십오 분, 토비에게 밥과 물을 줄 것.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"15:56":[{"t":"네 시 사 분 전","q":"네 시 사 분 전. 뉴먼은 다시 한숨을 쉬며 생각에 잠겼다.","title":"트립와이어","author":"리 차일드","ampm":"pm","kind":"역"}],"15:57":[{"t":"네 시 삼 분 전","q":"서기는 복도로 나갔다가 네 시 삼 분 전에야 느긋하게 돌아왔고, 캑스턴은 그가 백지 결혼 허가증 뒷면에 청원서를 써 놓았다는 것을 알아챘다.","title":"대령의 꿈","author":"찰스 W. 체스넛","ampm":"pm","kind":"역"}],"15:58":[{"t":"네 시 이 분 전","q":"일본인들에게 시간 엄수는 거의 강박이라, 네 시 이 분 전 말쑥하게 차려입은 여자가 나타나 인사하고 안나를 따라오라 청했을 때도 안나는 놀라지 않았다.","title":"거짓된 인상","author":"제프리 아처","ampm":"pm","kind":"역"}],"15:59":[{"t":"네 시 일 분 전","q":"그는 네 시 일 분 전에 길슨 산울타리의 문을 지나고 있었다. 그러나 세 시에는 이미 퀸 앤 힐에 도착해 있었다.","title":"자유로운 공기","author":"싱클레어 루이스","ampm":"pm","kind":"역"}],"16:00":[{"t":"네 시","q":"네 시가 되면 온실에 들어가 수선화 두 다스를 꺾어 와, 봄이 있다는 것을, 봄이 온다는 것을 우리에게 일깨워 줄 수 있다.","title":"사랑의 빛나는 골짜기","author":"에드나 홍","ampm":"pm","kind":"역"}],"16:01":[{"t":"네 시 일 분","q":"커튼 사이로 빛이 들어온다. 문득 자명종 라디오의 숫자가 연도처럼 보인다. 네 시 일 분. 조금 일찍 깼구나, 태어나려면 아직 사백 년이나 남았는데.","title":"101 레이캬비크","author":"할그리뮈르 헬가손","ampm":"pm","kind":"역"}],"16:02":[{"t":"네 시 이 분","q":"시간이 훌쩍 지나가버리지는 않았는지 확인하려 시계를 올려다본 순간, 총성이 들렸다. 네 시 이 분이었다. 나는 어찌할 바를 몰랐다.","title":"남부의 유령","author":"캐롤린 G. 하트","ampm":"pm","kind":"역"}],"16:03":[{"t":"네 시를 몇 분 넘긴 시각","q":"로즈 레닉은 네 시를 몇 분 넘긴 시각에, 작은 개 두 마리를 데리고 터무니없이 큰 모자를 쓴 채 나타났다.","title":"한 푼도 더 말고 덜도 말고","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:04":[{"t":"네 시 사 분","q":"네 시 사 분, 그는 계단을 우르르 내려오는 열차 소리를 들으며, 목이 도마에 얹힌 채 도끼를 기다리는 사람처럼 굳어 있었다.","title":"바다의 지배자","author":"M.P. 실","ampm":"pm","kind":"역"}],"16:05":[{"t":"네 시 오 분","q":"로버트 오들리 씨가 쇼디치 플랫폼에 내려선 것은 정확히 네 시 오 분이었고, 그는 태평하게 기다렸다. 모든 이의 요구를 맞추는 데는 한참이 걸렸고, 세속사에 초연한 그 변호사조차 인내심이 거의 바닥나 있었다.","title":"오들리 부인의 비밀","author":"메리 엘리자베스 브래던","ampm":"pm","kind":"역"}],"16:06":[{"t":"네 시 육 분","q":"네 시 육 분, 베니의 캐딜락이 보텔리아 씨 가게 앞에 멈춰 섰고, 베니의 어머니는 아이스크림콘 끝을 물어뜯고 있는 페넬로피와 함께 차에서 내렸다.","title":"나를 따라와","author":"조애나 스콧","ampm":"pm","kind":"역"}],"16:07":[{"t":"네 시 칠 분","q":"네 시 칠 분, 무전 침묵을 깨고 다섯 마디가 흘러나왔다. '절도범 검거, 반복한다, 절도범 검거.'","title":"동등한 자들 중 첫째","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:08":[{"t":"네 시 팔 분","q":"네 시 팔 분, 배심원단이 다시 자리로 돌아왔고, 알렉스는 그들의 표정이 무심함에서 당혹감으로 바뀌었음을 알아챘다. 색빌 판사는 그들을 다시 집으로 돌려보내는 수밖에 없었다.","title":"타고난 죄수","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:09":[{"t":"네 시 구 분","q":"'삼 시 십칠 분 기차로 피터버러까지 가서 갈아탄 뒤, 네 시 구 분 기차로 던커스터까지 가야 합니다. 거기서 다시 갈아타면 여섯 시 삼십이 분에 헐에 도착하죠.'","title":"더기 모티머의 오른팔","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:10":[{"t":"네 시 십 분","q":"이번 토요일에는 마틴 신부에게 인사를 맡겨 두었지만, 네 시 십 분이 되자 얼굴을 비치는 것이 예의겠다는 생각이 들었다.","title":"성직자들의 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"16:11":[{"t":"네 시 십일 분","q":"네 시 십일 분, 첫 버스가 주차장을 빠져나와 경사로를 올라 큰길로 나섰다.","title":"도전 없이는","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:12":[{"t":"네 시 십이 분","q":"나이젤 트렌섬과 그의 변호사가 마침내 나타난 것은 네 시 십이 분이었으나, 둘 중 누구도 지각을 사과할 필요는 느끼지 못하는 듯했다.","title":"까마귀가 날듯이","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:13":[{"t":"네 시 십삼 분","q":"그러나 정확히 네 시 십삼 분, 오만 명의 관중은 눈앞에서 전혀 예상치 못한 일이 벌어지는 것을 보았다. 남쪽 관중석에서 가장 붐비는 구역에서 갑자기 한 형체가 나타난 것이다.","title":"훌리아 아주머니와 시나리오 작가","author":"마리오 바르가스 요사","ampm":"pm","kind":"역"}],"16:14":[{"t":"네 시 십사 분","q":"그리고 삼월 십이일 네 시 십사 분, 나는 이 언덕에서 나를 지켜주는, 밝힐 수 없는 아연 지르코늄 화합물 뒤로 몸을 옮겼다. 신이시여 자비를 베푸소서, 진실과 거짓을 가려내려는 싸움은 끝나기는커녕 다음 싸움으로 이어져 나를 더욱 지치게 할 뿐이다.","title":"이미 죽은","author":"데니스 존슨","ampm":"pm","kind":"역"}],"16:15":[{"t":"네 시 십오 분","q":"아래층에서 시계가 네 시 십오 분을 알리며 울렸다. 그들은 부엌에서 잠시 멈춰 그녀가 둘러볼 수 있게 했다.","title":"다락방의 성","author":"엘리자베스 윈스롭","ampm":"pm","kind":"역"}],"16:16":[{"t":"네 시 십육 분","q":"네 시 십육 분, 바 밖 테라스는 빽빽이 들어찼고, 이고르는 자신의 계획성이 자랑스러웠다. 칸에 처음 와 봤음에도 정확히 이런 상황을 예견하고 테이블을 예약해 두었기 때문이다.","title":"승자는 혼자다","author":"파울로 코엘료","ampm":"pm","kind":"역"}],"16:17":[{"t":"네 시 십칠 분","q":"위대한 퍼시에게는 유머 감각이라곤 없는 모양인지, 네 시 십칠 분이 되자 지겨워졌는지 스키너의 오른쪽 눈을 한 방 날려 삽화 그대로 멍들게 만들었다.","title":"반장의 삼촌","author":"P.G. 우드하우스","ampm":"pm","kind":"역"}],"16:18":[{"t":"네 시 십팔 분","q":"네 시 십팔 분, 토비를 우리에 넣을 것.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"16:19":[{"t":"네 시 십구 분","q":"제시카 [네 시 십구 분] 그렇게 놀리지 마. 연극 보러 간 지도 몇 년째야. 찰스 [네 시 십구 분] 그럼 내가 쏘지. 자기랑 남편이랑 신나게 즐기라고.","title":"그 여자","author":"에릭 제롬 디키","ampm":"pm","kind":"역"}],"16:20":[{"t":"네 시 이십 분","q":"네 시 이십 분, 텔레비전이나 비디오를 볼 것.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"16:21":[{"t":"네 시 이십일 분","q":"네 시 이십일 분, 다시 걷기 시작하며 더그는 잔가지 하나를 주워 털어낸 뒤 입안에서 이리저리 굴리기 시작했다. '뭐 하는 거야?' 밥이 물었다. '자연식 양치질이지.' 더그가 답했다.","title":"이성을 넘어선 추적","author":"리처드 매드슨","ampm":"pm","kind":"역"}],"16:22":[{"t":"네 시 이십이 분","q":"월요일 네 시 이십이 분, 워싱턴 D.C.에서 폴 후드는 매일 늦은 오후마다 그러듯 컴퓨터 모니터에 뜬 이름 목록을 들여다보았다.","title":"균형의 저울: 옵센터 5","author":"톰 클랜시, 스티브 피에치닉, 제프 로빈","ampm":"pm","kind":"역"}],"16:23":[{"t":"네 시 이십삼 분","q":"중앙유럽시로 네 시 이십삼 분, 새로 온 두 순회 갑판원은 아래쪽 숙소에 짐을 넣어 두고 갑판으로 나와 근무를 신고했다.","title":"도전 없이는","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:24":[{"t":"네 시 이십사 분","q":"마이크는 애슐리에게 윙크하고 남은 인사와 포옹, 악수를 이어갔다. 시각은 네 시 이십사 분이었다. 여섯 시간이 남았다. 분들은 그저 녹아 없어지는 듯했다.","title":"티어드롭","author":"트래비스 스래셔","ampm":"pm","kind":"역"}],"16:25":[{"t":"네 시 이십오 분","q":"그는 세인트폴 성당 앞에서 내려, 천천히 걸었지만 네 시 이십오 분에는 치프사이드의 카우프먼 은행 앞에 서 있었다.","title":"펜은 칼보다 강하다","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:26":[{"t":"네 시 이십육 분","q":"그런 생각을 했다는 것 자체가 잘못된 것 같았다. 그녀는 생각했다. \"나는 그를 몰라. 그도 나를 몰라. 앞으로도 영영 그럴 거야.\" 그녀는 맨손을 햇볕 속에 내밀어 바람에 그을리도록 두었다. 시각은 네 시 이십육 분이었다.","title":"캐치 애즈 캐치 캔","author":"샬럿 암스트롱","ampm":"pm","kind":"역"}],"16:27":[{"t":"네 시 이십칠 분","q":"여전히 줄리엣의 모습은 보이지 않았다. 패트리샤는 슬쩍 시계를 훔쳐보았다. 네 시 이십칠 분, 아니 거의 이십팔 분이었다. 아, 서둘러, 줄리엣, 제발 서둘러!","title":"샬레 학교의 방문객들","author":"엘리너 브렌트다이어","ampm":"pm","kind":"역"}],"16:28":[{"t":"오후 네 시 이십팔 분","q":"같은 날 오후 네 시 이십팔 분, 주유소를 지나 두 번째 정류장에서 우회전. 첫 구 우체국 앞에 차를 세우고 모퉁이 담배 가게에서 물었다. M씨의 집은 우체국 오른쪽, 대각선 앞에 보였다.","title":"불타버린 지도","author":"아베 코보","ampm":"pm","kind":"역"}],"16:29":[{"t":"오후 네 시 이십구 분","q":"2007년 10월 21일 오후 네 시 이십구 분. 전화기는 빨간색이었다. 윌리엄이 그것을 가장 싫어했던 이유는, 좁은 구석 벽에 이상한 각도로 걸려 있다는 점 말고도, 벨이 울리면 너무 시끄럽게 울려 수화기를 들 때마다 체리색 수화기가 떨리는 게 보일 정도였기 때문이다.","title":"빌리빙 세드릭","author":"마크 라보라토","ampm":"pm","kind":"역"}],"16:30":[{"t":"네 시 반","q":"크리스마스이브 네 시 반에 출동 요청을 받는 걸 지역 경찰이 반길 리 없었고, 이게 어떤 장난이라면 그는 굳이 거기 적극 가담하고 싶지 않았다.","title":"미슬토 살인 사건","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"16:31":[{"t":"오후 네 시 삼십일 분","q":"발신: 르네 그린, 2011년 8월 5일 오후 네 시 삼십일 분. 수신: 셸리 매닝. 제목: Re: 올 액세스. 그럼 내가 뭘 걱정해야 하는 거야? 농담이야, 네 말이 맞아. 그럼 이만 갈게, 내 열혈 팬 친구야. 진짜 할 일이 있거든. 오늘 밤에 얘기하자.","title":"클릭: 온라인 러브 스토리","author":"리사 베커","ampm":"pm","kind":"역"}],"16:32":[{"t":"오후 네 시 삼십이 분","q":"오후 네 시 삼십이 분. 이제 우리 옆에 있던 여덟 명의 해병이 진지를 떠나 재빨리 지나가고, 마지막 병사가 외쳤다. \"가! 가! 가!\" 그들은 달리기 시작했다.","title":"시크","author":"데니스 존슨","ampm":"pm","kind":"역"}],"16:33":[{"t":"네 시 삼십삼 분","q":"네 시 삼십삼 분, 두 번째 버스가 큰길로 방향을 틀었다. 퇴근하는 출근자들과 출근하는 이들이 뒤엉켜 길이 막혔다.","title":"낫싱 벤처드","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:34":[{"t":"오후 네 시 삼십사 분","q":"평범한 물건들로 채워진 침실. 구석에는 옷장이 있었다. 침대맡 탁자에는 여러 시절의 물컵들과 빨간 디지털 숫자를 띄운 자명종이 놓여 있었다. 오후 네 시 삼십사 분.","title":"로 샤크 텍스트","author":"스티븐 홀","ampm":"pm","kind":"역"}],"16:35":[{"t":"네 시 삼십오 분","q":"\"당신이 필요한 비행기는 네 시 삼십오 분이 되어야 셰레메티예보 공항을 떠납니다. 어쨌든 이미 좌석 두 장을 예약해 두었습니다.\" \"두 장이요?\" 로마노프가 물었다. \"은행 일보다 성상화에 대해 훨씬 더 많이 알지 않는 한, 전문가 한 명이 동행해야 할 겁니다.\" 포스코노프가 덧붙였다.","title":"명예의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:36":[{"t":"네 시 삼십육 분","q":"그들은 유리 덮개 너머로 친구를 지켜보았다. 가슴의 오르내림이 점점 잦아들고 숨결도 점점 낮아지는 사이, 자줏빛이 몸을 뒤덮었다. 네 시 삼십육 분, 바퀴의 마지막 눈금에 다다랐다.","title":"A.D. 2000","author":"알바라도 M. 풀러","ampm":"pm","kind":"역"}],"16:37":[{"t":"네 시 삼십칠 분","q":"수전은 그날 오후 두 아들을 낳았다. 네 시 삼십칠 분에 냇을, 네 시 사십삼 분에 피터를. 이후 한 시간 동안 부모는 번갈아 아이들을 안았고, 그린우드 박사가 산모와 아기 모두 쉬어야 한다고 권할 때까지 그랬다.","title":"운명의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:38":[{"t":"네 시 삼십팔 분","q":"네 시 삼십팔 분, 세브는 은행으로 성큼성큼 들어가 접수원에게 말했다. \"카우프먼 씨와 약속이 있습니다.\"","title":"펜은 칼보다 강하다","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:39":[{"t":"네 시 삼십구 분","q":"그는 책상 위 시계를 보았다. 네 시 삼십구 분. \"칼리스 검문소를 연결해.\" 그가 젊은 중위에게 지시했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:40":[{"t":"네 시 사십 분","q":"카우프먼은 두 손을 기도하듯 모았고, 기도가 응답받은 듯 말했다. \"최종 결정을 내리기 전에 몇 통 전화를 해야 하니, 내일 오후 네 시 사십 분에 다시 사무실로 오시오. 확신이 서면 그때부터 얘기를 진행합시다.\"","title":"펜은 칼보다 강하다","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:41":[{"t":"네 시 사십일 분","q":"그녀는 네 시 사십일 분에 문을 열며, 자신이 세상을 어느 정도 통제하고 있다고 믿었다. 이제 그녀는 그것이 거짓이었음을 알았다. 한때 안다고 믿었던 모든 것이 뒤집혔고, 모든 것이 변해 있었다.","title":"누구를 믿을 것인가","author":"멀리사 제임스","ampm":"pm","kind":"역"}],"16:42":[{"t":"오후 네 시 사십이 분","q":"장거리 경주 결승선에 도달할 때면 늘 행복했지만, 이번엔 유독 마음을 세게 울렸다. 나는 오른손 주먹을 하늘로 뻗어 올렸다. 시각은 오후 네 시 사십이 분이었다. 경주가 시작된 지 열한 시간 사십이 분 만이었다.","title":"달리기를 말할 때 내가 하고 싶은 이야기","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"16:43":[{"t":"오후 네 시 사십삼 분","q":"부관들은 랜드크루저 뒤에 몸을 웅크리고 코크의 지시를 기다렸다. 오렌 에스터빌은 오후 네 시 사십삼 분에 아내가 실종됐다고 보안관 사무실에 신고한 터였다.","title":"코퍼스 델릭티","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"16:44":[{"t":"네 시 사십사 분","q":"네 시 사십사 분, 베버리지 씨는 에스콧 박사의 모피 코트를 편안히 걸친 채 클랭크우드 애비뉴 옆에 서서, 에스콧 박사의 훌륭한 시가 한 대를 더없이 즐겁게 피우고 있었다.","title":"탈옥한 광인","author":"J. 스토러 클라우스턴","ampm":"pm","kind":"역"}],"16:45":[{"t":"네 시 사십오 분","q":"국가가 그를 돌봐준다. 배정된 기사도 두 명 있다. 그래서 네 시 사십오 분이 되면 어김없이 한 사람이 전화를 건다. \"집에 가시나요, 세묜 이바노비치?\"","title":"바실리 슉신","author":"더 빅 보스","ampm":"pm","kind":"역"}],"16:46":[{"t":"네 시 사십육 분","q":"네 시 사십육 분, 뚱뚱한 중년 남자가 어슬렁거리며 들어왔다. 풀 먹인 과야베라 셔츠에 짙은 녹색 바지를 입은 우레냐는 제과 관련 책을 찾더니 같은 열람실 끝자리에 앉았다. 에벨리나와 레티시아는 놀란 눈빛을 주고받았다. 확실히 이상한 하루였다.","title":"아바나 월드시리즈","author":"호세 라투르","ampm":"pm","kind":"역"}],"16:47":[{"t":"네 시 사십칠 분","q":"어쩌면 그 이상이었을지도 모른다. 아펜라이트가 뭔가 크게 잘못 짚었는지도 몰랐다. 그의 손목시계로는 네 시 사십구 분, 벽시계로는 네 시 사십칠 분이었는데, 오언은 아직 오지 않았다.","title":"수비의 기술","author":"채드 하버크","ampm":"pm","kind":"역"}],"16:48":[{"t":"네 시 사십팔 분","q":"네 시 사십팔 분, 다섯 명으로 이루어진 팀이 그녀를 다시 돌보기 시작했고 엘런의 목숨을 구하려는 절박한 사투가 계속됐다. 벌써 두 시간 가까이 수술을 받고 있었고, 몸이 더 이상의 충격을 버텨낼지 의문이었다.","title":"테이킹 챈시스","author":"수전 루이스","ampm":"pm","kind":"역"}],"16:49":[{"t":"오후 네 시 사십구 분","q":"몇 주 지나지 않아 톰은 금요일 오후마다 뉴욕행 오후 네 시 사십구 분 기차에 올랐고, 월요일 아침에야 하트퍼드로 돌아왔다. 수령은 계속 진행 상황을 물었지만, 나트는 유독 아는 게 없어 보였다.","title":"운명의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:50":[{"t":"네 시 오십 분","q":"그들은 모두 칠 년 전 눈 내리던 밤, 같은 순간에 얼어붙어 버렸고, 그 뒤로 성 안의 시간은 언제나 네 시 오십 분에 멈춰 있었다.","title":"열세 개의 시계","author":"제임스 서버","ampm":"pm","kind":"역"}],"16:51":[{"t":"네 시 오십일 분","q":"네 시 오십일 분, 체리 레드 파카를 입은 인물이 도서관을 나와 후드를 뒤집어쓰고 눈삽으로 앞길을 오가며 눈을 치웠다.","title":"클라우드 커커우 랜드","author":"앤서니 도어","ampm":"pm","kind":"역"}],"16:52":[{"t":"네 시 오십이 분","q":"투우는 다섯 시에 시작될 예정이었다. 다섯 발 짐승들은 늦어도 칠팔 분 전에는 도착하는 법이었다. 이것도 하나의 의식이었다. 네 시 오십이 분, 마침내 그들이 도착했다. 개구쟁이들이 어깨를 툭 치는 것도 또 하나의 의식이었다.","title":"혼돈과 밤","author":"앙리 드 몽테를랑","ampm":"pm","kind":"역"}],"16:53":[{"t":"네 시 오십삼 분","q":"우체국 안은 어찌나 조용한지 트리니다드는 시계 초침이 움직일 때마다 나는 부드러운 똑딱 소리까지 들을 수 있었다. 시각은 이제 네 시 오십삼 분이었다.","title":"보나벤처 애로우의 침묵","author":"리타 레간스키","ampm":"pm","kind":"역"}],"16:54":[{"t":"다섯 시 육 분 전","q":"다섯 시 육 분 전, 그는 몸을 앞으로 기울여 검은 전화기를 집어 들었다. 메이페어의 부동산 중개업소 번호를 돌려 수석 파트너를 바꿔달라고 청했다.","title":"칼보다 강한 것","author":"제프리 아처","ampm":"pm","kind":"역"}],"16:55":[{"t":"네 시 오십오 분","q":"어둠이 내렸다. 계기판을 흘깃 보니 네 시 오십오 분이었다. 그녀는 거의 세 시간째 운전 중이었다.","title":"프라이빗 페이션트","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"16:56":[{"t":"다섯 시 사 분 전","q":"\"그 멍청한 늙은 판사가 좀 서둘렀으면 좋겠군,\" 찰스 경이 시계를 보며 대답했다. \"다섯 시 사 분 전이라 종이 울리기 전엔 법정에 도착하기 힘들겠어. 그 바람에 나는 판돈을 잃게 생겼네.\"","title":"롤런드 캐셜","author":"찰스 제임스 레버","ampm":"pm","kind":"역"}],"16:57":[{"t":"오후 다섯 시가 되기 직전","q":"톰 오설리번과 필립 테일러는 오후 다섯 시가 되기 직전 니키네 핫도그 가판대 카운터에서 농담을 주고받으며 주문을 넣었다.","title":"야망","author":"리 스트로벨","ampm":"pm","kind":"역"}],"16:58":[{"t":"다섯 시 이 분 전","q":"다섯 시 이 분 전, 다소곳한 안뜰과 정겨운 지붕창을 가진 마을 하나가 세워졌다.","title":"메인 스트리트","author":"싱클레어 루이스","ampm":"pm","kind":"역"}],"16:59":[{"t":"다섯 시 일 분 전","q":"\"다섯 시 일 분 전.\" 바늘들이 은빛 불꽃처럼 번쩍였다. 그것들은 어두워지는 여름 공기 속을 헤엄치는 작은 금속 물고기 떼 같았다.","title":"자수","author":"레이 브래드버리","ampm":"pm","kind":"역"}],"17:00":[{"t":"오후 다섯 시","q":"오후 다섯 시. 책을 읽는다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"17:01":[{"t":"다섯 시 일 분","q":"다섯 시 일 분, 베스는 박물관을 나와 택시를 세우고는 기사에게 주소를 알려준 뒤 뒷좌석에서 상자들에 둘러싸인 채 부끄러움도 없이 눈물 한 방울을 흘렸다.","title":"넥스트 인 라인","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:02":[{"t":"다섯 시 이 분","q":"\"다섯 시 이 분이군.\" \"그럼 거래는 성사됐네. 남은 구십 퍼센트를 삼십 일 안에 지불하기만 하면, 시프널 농장은 내 것이 되는 거야.\"","title":"칼보다 강한 것","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:03":[{"t":"다섯 시 삼 분","q":"트레이가 지난 크리스마스에 준 손목시계를 내려다보니, 섬세한 금빛 고리가 정말이지 낯설게 느껴졌다. 지금은 다섯 시 삼 분이었다. 나는 집까지 절반쯤 온 셈이었다.","title":"마더 메이 아이","author":"조슐린 잭슨","ampm":"pm","kind":"역"}],"17:04":[{"t":"오후 다섯 시 사 분","q":"프랭크 웜슬리는 사촌 바버라와 그녀의 남편을 발견하고 손을 흔들었다. 바로 앞에는 마빈과 그의 두 친구가 보였다. 갑자기 다리 전체가 요동쳤다. 시각은 오후 다섯 시 사 분이었다. 강철이 비명을 질렀다.","title":"모스맨의 예언","author":"존 A. 킬","ampm":"pm","kind":"역"}],"17:05":[{"t":"오후 다섯 시 오 분","q":"오후 다섯 시 오 분경, 조는 두 미터쯤 떨어진 곳에 서서 휴대전화로 중국어를 하는 한 남자를 알아챘다. 값싼 가죽 슬립온을 신고 허리 높은 검은 바지에 흰색 반소매 셔츠를 입은 중년의 한족이었다.","title":"타이푼","author":"찰스 커밍","ampm":"pm","kind":"역"}],"17:06":[{"t":"다섯 시 육 분","q":"훗날 그녀의 장부에는 그 역사적인 배달 순간이 다섯 시 육 분으로 기록되었는데, 이는 거짓이었지만 그만큼 무게를 실어주었다.","title":"명예로운 스쿨보이","author":"존 르카레","ampm":"pm","kind":"역"}],"17:07":[{"t":"다섯 시 칠 분","q":"커다란 문자판과 마치 영원을 나누려는 듯 천천히 규칙적으로 흔들리는 진자를 바라보다가, 나는 바늘이 다섯 시 칠 분을 가리키고 있는 것을 보았다.","title":"나이트메어 테일즈","author":"H.P. 블라바츠키","ampm":"pm","kind":"역"}],"17:08":[{"t":"오후 다섯 시 팔 분","q":"\"드와이트 슬론과 마지막으로 연락한 것은 어제였네. 오후 다섯 시 팔 분, 바로 여기서.\" 그는 엠버라스라는 호수를 손가락으로 짚었다. \"네 시간 뒤에 연락하기로 되어 있었는데 하지 않았어.\"","title":"바운더리 워터스","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"17:09":[{"t":"다섯 시 구 분","q":"그녀는 손목시계를 보고 다섯 시 구 분이라는 것을 알았다. \"아빠, 지금 일어나고 있어요! 해가 꺼지고 있어요!\" \"그래,\" 그가 동의했다.","title":"제럴드의 게임","author":"스티븐 킹","ampm":"pm","kind":"역"}],"17:10":[{"t":"오후 다섯 시 십 분","q":"그것은 여전히 태양 쪽으로 다가오며 파홈에 가장 근접한 지점, 추정상 십만 킬로미터 거리에 있었지만 아직은 얌전했다. 오후 다섯 시 십 분에 가디언이 다시 확인했을 때, 태양 방향에서 발견될 것으로 예상했으나 예측된 경로에서 사라지고 없었다.","title":"그림자와 밤","author":"크리스 월리","ampm":"pm","kind":"역"}],"17:11":[{"t":"다섯 시 십일 분","q":"다섯 시 십일 분, 딕 벨라미는 멜차드의 차를 하스버러의 한적한 죽은 듯한 역 매표소 앞에 세웠다. 그곳은 화이트베이로 가는 단선 철로와 지엔알의 복선 지선이 만나는 지점이었다.","title":"앰브로톡스와 다리 저는 딕","author":"올리버 플레밍","ampm":"pm","kind":"역"}],"17:12":[{"t":"다섯 시 십이 분","q":"\"자, 다 왔군,\" 줄리언 대령이 말했다. \"정확히 다섯 시 십이 분이야. 저들이 차를 마시는 한창에 붙잡을 수 있겠어. 잠시 기다리는 게 낫겠네.\" 맥심은 담배에 불을 붙이고 내게 손을 뻗었다. 그는 말이 없었다.","title":"레베카","author":"대프니 듀 모리에","ampm":"pm","kind":"역"}],"17:13":[{"t":"다섯 시 십삼 분","q":"그리하여 다섯 시 십삼 분, 캘럼 그린은 목걸이를 사고 있었고 그로부터 두어 시간 뒤 그는 죽었다.","title":"라이 인 웨이트","author":"G.J. 미네트","ampm":"pm","kind":"역"}],"17:14":[{"t":"다섯 시 십사 분","q":"\"지금 몇 시인지 아니, 애티커스?\" 그녀가 말했다. \"정확히 다섯 시 십사 분이야. 자명종은 다섯 시 반에 맞춰놨어. 그걸 알아두렴.\"","title":"앵무새 죽이기","author":"하퍼 리","ampm":"pm","kind":"역"}],"17:15":[{"t":"다섯 시 십오 분","q":"겨우 다섯 시 십오 분이었지만 저녁은 한밤중처럼 어두웠다. 그가 현관 끝에 다다랐을 때 비가 내리기 시작했다.","title":"죽음을 향한 취향","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"17:16":[{"t":"다섯 시 십육 분","q":"\"내가 기억하는 첫 사건은 런던 지하철 서클 라인에서, 오후 다섯 시 십육 분에 일어났던 것 같아요.\" 그녀는 무슨 일이 일어났는지, 혹은 일어나지 않았는지를 계속 설명해나갔다.","title":"돈은 결코 잠들지 않는다","author":"스텔라 화이틀로","ampm":"pm","kind":"역"}],"17:17":[{"t":"다섯 시 십칠 분","q":"그리고 딕 프렌치가 경주로 안쪽을 두르는 목책 너머로 극심한 불안에 떨며 매달려 있다가, 정확히 다섯 시 십칠 분에 울부짖음과 비슷한 소리를 내지르며 문으로 달려가 배신한 기수에게 신호를 보냈다.","title":"나는 수성","author":"엘리너 M. 잉그럼","ampm":"pm","kind":"역"}],"17:18":[{"t":"다섯 시 십팔 분","q":"루팽은 경멸 어린 침묵을 깨지 않은 채 일어나 그 종이를 집어 들었다. 나는 곧, 바로 그 순간 시계를 보았던 것을 기억해냈다. 다섯 시 십팔 분이었다.","title":"아르센 뤼팽의 고백","author":"모리스 르블랑","ampm":"pm","kind":"역"}],"17:19":[{"t":"다섯 시 십구 분","q":"스콧은 손목시계의 작은 유황빛 점들을 다시 한번 확인한 뒤 구석에 자리를 잡았다. 다섯 시 십구 분이었다. 그와 한나는 한 시간 십칠 분째 금고 안에 갇혀 있었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:20":[{"t":"다섯 시 이십 분","q":"\"여기 주차하고 걸어갈게. 동물원처럼 몰려드는 곳으로 차를 몰고 싶진 않아.\" 그는 손목시계를 흘긋 보았다. \"이제 겨우 다섯 시 이십 분이야. 유괴범 전화는 여섯 시에 오기로 되어 있어. 아직 시간이 있어.\"","title":"퍼가토리 리지","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"17:21":[{"t":"다섯 시 이십일 분","q":"그는 이어 죽은 남자의 주머니를 차례로 뒤져, 쓸모 있어 보이는 것들을 꺼냈다. 이를테면 틈새로 금화가 비치는 비단 지갑이나, 폭발로 손상되어 참사가 일어난 바로 그 순간인 다섯 시 이십일 분에 멈춰 선 시계 같은 것들이었다.","title":"조상의 발자취","author":"너새니얼 호손","ampm":"pm","kind":"역"}],"17:22":[{"t":"다섯 시 이십이 분","q":"\"그녀는 아버지를 불러들였다는 사실을 옥타비아가 알기를 원치 않았을 거예요, 계획을 다 짜기 전까지는요. 그리고 시간을 정한 건 저였어요. 열아홉 시 이십구 분에 워털루에 도착하는 다섯 시 이십이 분 기차보다 먼저 잡을 방법이 없었거든요.\"","title":"확실한 정의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"17:23":[{"t":"다섯 시 이십삼 분","q":"\"술 한잔 하러 만날 수 있을까 해서.\" \"뭐 때문에?\" \"그냥 이야기나 하려고. 센트럴역 근처 로열 배츠맨 알지? 내일 다섯 시에 볼까?\" \"다섯 시 이십삼 분,\" 나는 상황을 조금이라도 통제하려고 그렇게 말했다.","title":"만물의 작은 조각","author":"스티브 톨츠","ampm":"pm","kind":"역"}],"17:24":[{"t":"다섯 시 이십사 분","q":"볼티모어에서는 킬리만자로 자오선 위로 태양이 지나간 지 열두 시간 후, 다섯 시 이십사 분이라고 했다. 이 순간 사람들을 덮친 고통은 이루 다 형용할 수 없었다.","title":"뒤죽박죽","author":"쥘 베른","ampm":"pm","kind":"역"}],"17:25":[{"t":"다섯 시 이십오 분","q":"다섯 시 이십오 분이 되도록 둘 중 누구도 그의 곁에 없었고, 그 유명한 '냉정함'에도 슬슬 김이 오르기 시작했다.","title":"도둑들의 의리","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:26":[{"t":"다섯 시 이십육 분","q":"\"다섯 시 이십육 분에 토트네스를 떠나는 기차가 있습니다,\" 나는 말했다. \"그리고 런던에는...\"","title":"와일드트랙","author":"버나드 콘웰","ampm":"pm","kind":"역"}],"17:27":[{"t":"다섯 시 이십칠 분","q":"어느 날 저녁 다섯 시 이십칠 분, 셉티무스가 그날의 마지막 청구서 파일을 정리하고 있을 때 직속 상사인 부지점장이 그를 불러 상담을 청했다.","title":"일상의 균열","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:28":[{"t":"다섯 시 이십팔 분","q":"5월 15일 오후 다섯 시 이십팔 분, 그가 곧 떠나야 한다고 말하자 그녀는 정신을 잃었다. 그때 그녀는 그의 침대에 있었다.","title":"영리한 여자들","author":"주디 블룸","ampm":"pm","kind":"역"}],"17:29":[{"t":"다섯 시 이십구 분","q":"\"뭐요?\" 그가 말했다. \"지금은 다섯 시 이십구 분입니다, 여기에이름을넣으세요 님,\" 임프가 초조하게 말했다.","title":"떵!","author":"테리 프래쳇","ampm":"pm","kind":"역"}],"17:30":[{"t":"다섯 시 반","q":"홈즈가 돌아온 것은 다섯 시 반이 지나서였다. 그는 활기차고 열의에 차 있었으며, 평소 그를 사로잡던 암울한 우울과는 정반대의 기분이었다.","title":"네 사람의 서명","author":"아서 코난 도일","ampm":"pm","kind":"역"}],"17:31":[{"t":"다섯 시 삼십일 분","q":"그들은 전송 내용을 두고 이야기를 나누며 대체 어느 친구가 그런 짓을 했을지 궁금해했다. 그런데 다섯 시 삼십일 분, 픽에게서 다시 전화가 걸려왔다.","title":"무거운 물","author":"마틴 에이미스","ampm":"pm","kind":"역"}],"17:32":[{"t":"다섯 시 삼십이 분","q":"12월 9일 금요일 저녁, 정확히 다섯 시 삼십이 분이었다. 애널리 역장은 프리스트 힐 신호소로부터 런던 브리지발 하행 열차가 방금 통과했다는 전신을 받았다.","title":"명탐정 클리크","author":"토머스 W. 핸슈","ampm":"pm","kind":"역"}],"17:33":[{"t":"다섯 시 삼십삼 분","q":"그와 어슐러 부인이 예순두 번지로 돌아온 것은 다섯 시 삼십삼 분이었다. 차 안 시계를 봤기 때문에 그는 정확한 시각을 기억할 수 있었다.","title":"죽음의 맛","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"17:35":[{"t":"다섯 시 삼십오 분","q":"다섯 시 삼십오 분, 그는 무전으로 소식을 전해 들었다. 오로라 센티널지의 헬문트 하노버가 인디언들이 낚시를 하면 보복하겠다는 익명의 협박 전화를 받았다는 내용이었다.","title":"아이언 레이크","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"17:36":[{"t":"여섯 시 이십사 분 전","q":"\"그러니까 그것이 정확히 여섯 시 이십사 분 전에 일어났다는 거군요?\" \"그렇습니다.\"","title":"묻히지 못한 자","author":"찰스 팰리서","ampm":"pm","kind":"역"}],"17:37":[{"t":"다섯 시 삼십칠 분","q":"\"이봐, 루실,\" 다섯 시 삼십칠 분에 사무실로 어슬렁어슬렁 들어온 루실에게 조가 말했다. \"자네가 그 애한테 뭐라고 했는지 몰라도 정반대의 효과가 난 모양이야.\"","title":"피뢰침","author":"헬렌 드윗","ampm":"pm","kind":"역"}],"17:38":[{"t":"다섯 시 삼십팔 분","q":"그는 전화기를 바라보며 생각한다. 울려라, 지금 울려라. 하지만 전화는 잠잠하다. 오후 다섯 시 삼십팔 분, 버니는 지금쯤 청소 근무를 마쳤을 것이다.","title":"구름 뻐꾸기 나라","author":"앤서니 도어","ampm":"pm","kind":"역"}],"17:39":[{"t":"다섯 시 삼십구 분","q":"지금은 다섯 시 삼십구 분이라 저녁을 먹을 수 있다, 빠른 국수다. 국수가 뜨거운 물 속에 있는 동안 엄마는 우유팩에서 어려운 단어를 찾아 나를 시험한다.","title":"룸","author":"에마 도노휴","ampm":"pm","kind":"역"}],"17:40":[{"t":"다섯 시 사십 분","q":"'다른 안건'이 없었으므로 나는 다섯 시 사십 분에 회의를 마쳤고, 제러미에게 로즈메리와 나와 함께 저녁을 먹자고 권했다.","title":"시행착오","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:42":[{"t":"다섯 시 사십이 분","q":"폭풍은 스물아흐레 일곱 시간 이십삼 분 동안 서서히 힘을 모으더니, 그 주 여섯째 날 정확히 다섯 시 사십이 분에 그들을 덮쳤다.","title":"다지 클럽","author":"제임스 드 밀","ampm":"pm","kind":"역"}],"17:43":[{"t":"다섯 시 사십삼 분","q":"\"저는 언제나 영국 항공사를 이용하는 걸 선호합니다,\" 돈 페드로가 일등석으로 안내되며 승무원에게 말했다. 보잉 스트라토크루저는 예정보다 몇 분 늦은 다섯 시 사십삼 분에 이륙했다.","title":"가장 은밀한 비밀","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:44":[{"t":"다섯 시 사십사 분","q":"그들이 마침내 다섯 시 사십사 분 무렵 파오브이 열여덟 번 홀 경기를 마치고 돌아왔을 때, 재니스는 라운지에도 수영장 옆에도 그를 기다리고 있지 않았다.","title":"토끼는 부자다","author":"존 업다이크","ampm":"pm","kind":"역"}],"17:45":[{"t":"여섯 시 십오 분 전","q":"\"여섯 시 십오 분 전이에요,\" 산파가 대답했다. '내가 정말 죽는다면 어떡하지?' 올가 미하일로브나는 남편의 머리와 빗방울이 부딪히는 창유리를 바라보며 생각했다.","title":"파티","author":"안톤 파블로비치 체호프","ampm":"pm","kind":"역"}],"17:46":[{"t":"여섯 시 십사 분 전","q":"여섯 시 십사 분 전, 그들은 원장의 서재로 들어섰고, 샐리 또래의 젊은 여성이 손님들에게 드라이 셰리와 오렌지 주스 중 하나를 권했다.","title":"도둑들의 의리","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:47":[{"t":"여섯 시 십삼 분 전","q":"\"린드허스트에서 여섯 시 십삼 분 전에 출발하는 기차가 있습니다,\" 위저리가 시간표를 펼치며 말했다.","title":"우연의 바퀴","author":"H.G. 웰스","ampm":"pm","kind":"역"}],"17:48":[{"t":"다섯 시 사십팔 분","q":"아버지가 집에 돌아온 것은 오후 다섯 시 사십팔 분이었다. 나는 그가 현관문으로 들어오는 소리를 들었다.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"17:49":[{"t":"다섯 시 사십구 분","q":"1924년 6월 8일 일요일 다섯 시 사십구 분, 오델이 제4캠프로 돌아왔을 때 그는 흥분을 감추지 못했다.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:50":[{"t":"다섯 시 오십 분","q":"코크와 맥두걸은 다섯 시 오십 분에 그녀의 빨간 무스탕을 발견했다. 그녀는 집으로 돌아오지 않았던 것이다.","title":"범죄의 증거","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"17:51":[{"t":"여섯 시 구 분 전","q":"여섯 시 구 분 전, 태양은 붉게 물들고 그림자는 길고 짙었다. 호텔 안에서는 사람들이 마감 시간이 오기 전에 술을 최대한 들이켜고 있었다.","title":"독사의 집","author":"아서 업필드","ampm":"pm","kind":"역"}],"17:52":[{"t":"여섯 시 팔 분 전","q":"여섯 시 팔 분 전이었다. \"그를 연결해야 해요,\" 그는 열두 번째로 교환수에게 말했다.","title":"지미 커클랜드와 페넌트를 위한 음모","author":"휴 S. 풀러턴","ampm":"pm","kind":"역"}],"17:53":[{"t":"여섯 시 칠 분 전","q":"\"규칙적으로 살았나?\" \"그럼요!\" 나는 내 교육을 떠올리며 분개해서 외쳤다. \"좋아, 진정해. 지금 몇 시야?\" \"여섯 시 칠 분 전이에요.\"","title":"삼 기니짜리 시계의 모험","author":"탤벗 베인스 리드","ampm":"pm","kind":"역"}],"17:54":[{"t":"다섯 시 오십사 분","q":"아버지가 다시 거실로 돌아온 것은 다섯 시 오십사 분이었다. 그는 아주 조용히 \"이게 뭐지?\"라고 말했지만 소리치지 않아서 나는 그가 화났다는 걸 알아채지 못했다.","title":"한밤중에 개에게 일어난 기묘한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"17:55":[{"t":"여섯 시 오 분 전","q":"바람은 구슬프게 울며 노래했고, 사진사 모티머 젠킨 씨의 낡은 코트자락을 들추었다. 그는 더 이상의 장사를 포기한 채 차가운 손으로 직접 셔터를 내리고 있었다. 여섯 시 오 분 전이었다.","title":"미뤄진 약속","author":"앨저넌 블랙우드","ampm":"pm","kind":"역"}],"17:56":[{"t":"여섯 시 되기 사 분 전","q":"이보게, 지금 시곗바늘은 여섯 시 되기 사 분 전을 가리키고 있네. 종이 울리기 전에 스스로를 방자하고 근거 없는 중상모략가라 부르지 않는다면, 온 방을 돌며 자네를 매질하겠네.","title":"그윈의 기사","author":"찰스 제임스 레버","ampm":"pm","kind":"역"}],"17:57":[{"t":"여섯 시 되기 삼 분 전","q":"여섯 시 되기 삼 분 전, 샐리는 여전히 나타나지 않았지만 교장은 모두 대강당으로 이동하자고 제안했다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"17:58":[{"t":"다섯 시 오십팔 분","q":"그제야 창문이 눈에 들어온다. 반들반들 어둡다. 시계는 다섯 시 오십팔 분이라고 우긴다. 말도 안 돼. 이제 겨우 네 시를 넘겼을 뿐인데. 나를 괴롭히던 자의 배 너머로 이마퀼레 콩스탕탱을 찾아보지만, 그녀는 사라지고 없다.","title":"본클락","author":"데이비드 미첼","ampm":"pm","kind":"역"}],"17:59":[{"t":"여섯 시 되기 일 분 전","q":"여섯 시 되기 일 분 전, 교장은 귀빈을 무대 위로 안내했다. 그는 사백 명의 여학생들이 자리에서 일어나, 교장이라면 '숙녀답다'고 표현했을 법한 태도로 박수치는 모습을 지켜보았다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:00":[{"t":"여섯 시","q":"\"그 뒤로 줄곧,\" 모자 장수가 침울한 목소리로 말을 이었다. \"시간이 내 부탁을 하나도 들어주지 않아! 지금은 늘 여섯 시라네.\"","title":"이상한 나라의 앨리스","author":"루이스 캐럴","ampm":"pm","kind":"역"}],"18:01":[{"t":"여섯 시 일 분","q":"\"마지막 표가 던져지는 여섯 시 일 분까지, 누구도 숨 돌릴 틈조차 없이 멈추지 않는다.\"","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:02":[{"t":"오후 여섯 시 이 분","q":"\"참고로, 오후 여섯 시 이 분 헤런다운 북쪽 약 이백오십 킬로미터 지점에서 발생한 작고 불분명한 천발지진 기록으로 확인되었네. 하지만 중대한 문제가 하나 있어.\"","title":"그림자와 밤","author":"크리스 월리","ampm":"pm","kind":"역"}],"18:03":[{"t":"여섯 시 삼 분","q":"재로드는 컴퓨터 화면의 시계를 노려보았다. 여섯 시 삼 분이었다. 사무실 창밖은 어두웠다. 누군가 방 안의 산소를 모조리 빨아들인 듯한 느낌에, 그는 대답하기 전 숨을 한 번 더 들이쉬었다.","title":"모든 작은 조각들","author":"질리안 호프먼","ampm":"pm","kind":"역"}],"18:04":[{"t":"여섯 시 사 분","q":"\"우리는 이 순간을 기록해 둘 걸세, 로재나. 해마다 이 소중한 시각이 시계에서 울릴 때마다, 우리 평생 감사하며 기릴 걸세.\" \"그리하겠어요, 알론조!\" \"저녁 여섯 시 사 분, 나의 로재나...\"","title":"알론조 피츠 클래런스와 로재나 에셀턴의 사랑","author":"마크 트웨인","ampm":"pm","kind":"역"}],"18:05":[{"t":"오후 여섯 시 오 분","q":"오후 여섯 시 오 분. 다들 어디 있는 걸까? 아마 남자친구들이랑 나갔거나 가족들 곁으로 돌아갔겠지.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"18:06":[{"t":"여섯 시 육 분","q":"요한계시록에 따르면 큰 짐승의 숫자는 666이다. 그렇다면 정확한 시각은 육십육 년 유월 육일, 여섯 시 육 분이 될 것이다. 겹경사인 셈이지.","title":"디몰리션이라는 이름의 개","author":"로버트 랭킨","ampm":"pm","kind":"역"}],"18:07":[{"t":"여섯 시 칠 분","q":"분침이 째깍째깍 흘러갔다. 방 안의 침묵이 귀청을 울렸다. 여섯 시 칠 분, 찰스의 전화벨이 울렸다.","title":"배심원단","author":"펀 미첼스","ampm":"pm","kind":"역"}],"18:08":[{"t":"오후 여섯 시 팔 분","q":"오후 여섯 시 팔 분. 암호명 '발키리'가 폰 자이들리츠 가블러의 사령부에 도달했다.","title":"장군들의 밤","author":"한스 헬무트 키르스트","ampm":"pm","kind":"역"}],"18:09":[{"t":"여섯 시 구 분","q":"이슬비 내리는 토요일 저녁 여섯 시 구 분, 나는 지금 단숨에 책 한 권을 써내겠다는 각오로 여기 앉아 있다.","title":"쉴 틈 없는 삶","author":"닉 스폴딩","ampm":"pm","kind":"역"}],"18:10":[{"t":"여섯 시 십 분","q":"\"어제 오후 여섯 시 십 분 브뤼셀행 항공편의 승객 명단을 보고 싶습니다.\"","title":"내 죽은 몸을 넘어서야","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:11":[{"t":"여섯 시 십일 분","q":"첫 번째 폭발은 여섯 시 십일 분에 일어났다. 해도실과 함교 일부가 산산조각 났다. 둔중하게 부서지는 소리가 잇달아 세 번 이어졌고, 이는 폭탄이 특정 시각에 자동으로 터지도록 설정되었음을 의심의 여지 없이 증명했다.","title":"서풍표류","author":"조지 바 매커천","ampm":"pm","kind":"역"}],"18:12":[{"t":"여섯 시 십이 분","q":"그날 저녁 여섯 시 십이 분, 빌 러셀은 사무실을 나섰고 다시는 그 건물에 들어가지 않았다.","title":"행운의 아들들","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:13":[{"t":"여섯 시 십삼 분","q":"여섯 시 십삼 분, 이제 거의 저녁이 다 되었다. 엄마는 벌써 러그 안에 숨어 있어야 한다고 말한다, 내가 아프니까 올드 닉이 일찍 올지도 모른다고.","title":"룸","author":"에마 도너휴","ampm":"pm","kind":"역"}],"18:15":[{"t":"여섯 시 십오 분","q":"화면 구석의 시간을 확인했다. 오후 여섯 시 십오 분. 이 에세이를 사십오 분 안에 끝낼 리 없었다.","title":"실종된 소녀","author":"소피 매켄지","ampm":"pm","kind":"역"}],"18:16":[{"t":"여섯 시 십육 분","q":"문 위 시계는 여섯 시 십육 분을 가리켰다. 화면 속에는 문이 열리고 러그 한 장이 들어오는 모습이 보였다, 그저 러그 한 장이 수직으로 세워진 채 늘어져 있을 뿐이었다. 물론 그 뒤에는 누군가 있었다.","title":"죽음이 잠들 때","author":"렉스 스타우트","ampm":"pm","kind":"역"}],"18:17":[{"t":"여섯 시 십칠 분","q":"카드 앞면에는 버니스 샌드라는 이름이 인쇄되어 있었다. 뒷면에는 연필로 이렇게 쓰여 있었다: 여섯 시 십칠 분, 서쪽 방향 전차 정류장에서. 날짜도 서명도 없었다. 여섯 시 십칠 분, 아델은 트로베라를 옆에 두고 저택을 나섰다.","title":"영광으로 가는 길","author":"데이비드 드레이크","ampm":"pm","kind":"역"}],"18:18":[{"t":"여섯 시 십팔 분","q":"예순한 살의 티베트 여성이 불타는 차량을 진화하기 위해 소방차를 불렀던 것은 바로 여섯 시 십팔 분이었다.","title":"내 이름은 제이콥 램지가 아니다","author":"벤 트레빌콕","ampm":"pm","kind":"역"}],"18:19":[{"t":"여섯 시 십구 분","q":"그레이브젠드는 검은 구름이다. 비니와 스텔라와 엄마가 그 안에 있다. 그 자체다. 내 손목시계는 여섯 시 십구 분을 가리키고, 캡틴 말로 술집은 저녁 단골들이 하나둘 들어서며 활기차고 왁자해질 것이다.","title":"본클락","author":"데이비드 미첼","ampm":"pm","kind":"역"}],"18:20":[{"t":"여섯 시 이십 분","q":"사라 베론이 아이버 개러드에게 겨우 전화가 닿은 것은 여섯 시 이십 분이 되어서였다. 그녀는 오후 초반 대부분을 집에 있었지만, 거기서는 감히 전화를 걸 수 없었다.","title":"죽음의 맛","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:21":[{"t":"여섯 시 이십일 분","q":"오후 다섯 시 이십 분에서 여섯 시 이십일 분 사이, 페티그루 양은 어느새 복도로 떠밀려 들어가 있었다. 이제는 항변도 당혹도 놀라움도 지나버린 뒤였다. 두 눈이 빛났다. 얼굴이 환하게 달아올랐다. 마음이 붕 떠올랐다. 모든 일이 너무 빠르게 벌어지고 있었다. 도무지 따라잡을 수 없었지만, 맙소사, 그녀는 그것을 마음껏 즐길 수 있었다.","title":"미스 페티그루의 어느 특별한 하루","author":"위니프레드 왓슨","ampm":"pm","kind":"역"}],"18:22":[{"t":"여섯 시 이십이 분","q":"\"여섯 시 이십이 분이었습니다, 사령관님. 우연히 시계를 봤을 뿐입니다.\" 그는 문을 활짝 열어젖혔다. 그것은 나가라는 권유라기보다 명령처럼 보였다.","title":"살인의 방","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:23":[{"t":"여섯 시 이십삼 분","q":"부엌에서의 소풍 도시락, 혹시라도 불가능한 일이 벌어져 아버지가 저녁 여섯 시 이십삼 분 전에 은행에서 돌아올 경우를 대비해 현관문에 이중으로 걸어둔 빗장.","title":"작은 촛불 하나를 켜고","author":"메이브 빈치","ampm":"pm","kind":"역"}],"18:24":[{"t":"여섯 시 이십사 분","q":"관제탑은 여섯 시 이십사 분에 우리에게 이륙 허가를 내렸고, 예정된 출발 시각보다 칠 분 늦게 하늘로 떠올랐다. 저녁 하늘은 거의 맑았고, 남쪽 지평선을 따라 적운이 드문드문 흩어져 있었으며 풍향낭은 힘없이 늘어져 있었다.","title":"퀼러의 질주","author":"애덤 홀","ampm":"pm","kind":"역"}],"18:25":[{"t":"여섯 시 이십오 분","q":"여섯 시 이십오 분, 클로디아는 작업하던 서류를 자물쇠로 잠가두고 위층으로 올라가 씻고 코트를 챙겼다. 집 안은 불빛으로 환했다. 제라드가 죽은 뒤로 그녀는 어둠 속에서 홀로 일하는 것을 몹시 싫어했다.","title":"원죄","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:26":[{"t":"오후 여섯 시 이십육 분","q":"휴대폰으로 시간을 확인했다, 오후 여섯 시 이십육 분. \"피자 먹으러 갈래?\" 이십 분 뒤에 걸어 들어오며 카라가 물었다. 나는 그녀를 올려다보았다. 그녀는 미소 지으며 고개를 갸웃거렸다.","title":"나와 놀아줘","author":"아난스","ampm":"pm","kind":"역"}],"18:27":[{"t":"여섯 시 이십칠 분","q":"여섯 시 이십칠 분이었다. 프랜시스 페버렐의 아파트에서 전화벨이 울렸다. 제임스가 그녀의 이름을 부르는 순간, 그녀는 뭔가 잘못됐음을 알았다.","title":"원죄","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:28":[{"t":"여섯 시 이십팔 분","q":"오후 여섯 시 이십팔 분, 이그재미너지의 '속보' 알림이 시카고 전역의 휴대폰과 컴퓨터에 떴다. 한때 막강했던 일리노이 정치 명가의 막내 토머스 R. 오설리번 3세가 다이아몬드 포인트 강도 사건에서 살해된 두 명 중 하나로 확인됐다는 소식이었다.","title":"야망","author":"리 스트로벨","ampm":"pm","kind":"역"}],"18:29":[{"t":"여섯 시 이십구 분","q":"허셜 모트 경위는 웨슬리가 여섯 시 이십구 분에 전화를 걸어왔을 때, 목소리에서 히스테리에 가까운 떨림을 감추지 못했다. \"자네 지금 어딘가?\" 웨슬리가 스피커폰 너머로 다시 물었다.","title":"바디 팜","author":"퍼트리샤 콘웰","ampm":"pm","kind":"역"}],"18:30":[{"t":"여섯 시 반","q":"오후 여섯 시 반. 텔레비전이나 비디오를 본다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"18:31":[{"t":"여섯 시 삼십일 분","q":"\"전투는,\" 베리 함장이 전한다, \"해 질 무렵인 여섯 시 삼십일 분에 시작되어, 형언할 수 없는 기세와 위력으로 이어졌다.\"","title":"넬슨 이야기","author":"해럴드 F.B. 휠러","ampm":"pm","kind":"역"}],"18:32":[{"t":"여섯 시 삼십이 분","q":"그가 거대한 고딕 성당을 나서자 비가 내리기 시작했다. 셉티무스는 마지못해 곱게 말아둔 우산을 펼치고 웅덩이를 헤치며 달렸다, 여섯 시 삼십이 분 기차를 잡을 수 있기를 바라며.","title":"일상의 균열","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:33":[{"t":"여섯 시 삼십삼 분","q":"매일 저녁 미셸은 기차를 타고 집으로 돌아갔다, 에스브리에서 갈아탄 뒤 대개 여섯 시 삼십삼 분 기차로 크레시에 도착하면 안나벨이 역에서 기다리고 있었다.","title":"소립자","author":"미셸 우엘벡","ampm":"pm","kind":"역"}],"18:34":[{"t":"여섯 시 삼십사 분","q":"이제 그 낡은 차는 브리지보로 역 선로 위에 세워둔 채, 저녁 먹으러 아래층에 내려가야 한다. 아, 여섯 시 삼십사 분 급행열차가 밥 먹는 동안 와서 들이받지 않기를 바랄 뿐이다. 다들 조마조마하고 신났겠지, 안 그래?","title":"로이 블레이클리, 길을 잃다","author":"퍼시 키스 피츠휴","ampm":"pm","kind":"역"}],"18:35":[{"t":"여섯 시 삼십오 분","q":"그리고 여섯 시 삼십오 분이 되자 아버지가 밴을 몰고 집에 돌아오는 소리가 들려서 나는 침대를 문 앞으로 밀어 못 들어오게 막았는데, 아버지는 결국 집 안으로 들어왔고 아버지와 어머니는 서로에게 소리를 질렀다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"18:36":[{"t":"여섯 시 삼십육 분","q":"칼드런이 형광빛 그림자처럼 나를 쫓아다닌다. 그는 대문에 '96,688,365,498,702'라고 분필로 적어놓았다. 우편배달부를 헷갈리게 만들 만하다. 아홉 시 오 분에 깼다. 여섯 시 삼십육 분에 다시 잠들었다.","title":"시간의 목소리들","author":"J.G. 밸러드","ampm":"pm","kind":"역"}],"18:37":[{"t":"여섯 시 삼십칠 분","q":"\"그레이스 인 커피하우스로 오게,\" 핀토가 말했다, \"내가 그 도끼에 새겨진 흠집이 어떻게 생겼는지 말해주지.\" 그리고 우리는 여섯 시 삼십칠 분쯤 홀본 거리를 걸어 내려갔다.","title":"도끼의 흠집","author":"윌리엄 메이크피스 새커리","ampm":"pm","kind":"역"}],"18:38":[{"t":"여섯 시 삼십팔 분","q":"그는 매일 같은 길로 출근해 같은 경비원과 같은 시간만큼 이야기를 나누고, 같은 엘리베이터로 같은 층에 올라가 같은 자리에 코트를 걸고 점심때까지 같은 책상에 앉아 있었다. 매일 다섯 시 반이면 정확히 반대로 그 과정을 되짚어 집에 돌아왔는데, 운 좋은 날은 여섯 시 이십사 분, 나쁜 날은 여섯 시 삼십팔 분이었다.","title":"제멋대로인 교수 사건","author":"개러스 P. 존스","ampm":"pm","kind":"역"}],"18:39":[{"t":"일곱 시 이십일 분 전","q":"일곱 시 이십일 분 전, 유리는 당신의 테이블에, 혹은 그 옆 테이블에 앉을 것이다. 그건 물론 카페가 얼마나 붐비느냐에 달렸다.","title":"맨헌트","author":"제임스 배링턴","ampm":"pm","kind":"역"}],"18:40":[{"t":"여섯 시 사십 분","q":"같은 화요일, 여섯 시 사십 분이 되어서야 조지 챈들러파월은 세인트 앤절라 병원에서 개인 환자 진료 목록을 끝냈다. 수술복을 벗으며 그는 역설적이게도 지친 동시에 안절부절못하는 기분이었다.","title":"사적인 환자","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:41":[{"t":"여섯 시 사십일 분","q":"그는 여유 있게 그랜드 센트럴에 도착했다. 스틸먼의 기차는 여섯 시 사십일 분에나 도착할 예정이었지만, 퀸은 스틸먼이 자신을 따돌리지 못하도록 그곳 지형을 미리 파악할 시간이 필요했다.","title":"뉴욕 삼부작","author":"폴 오스터","ampm":"pm","kind":"역"}],"18:42":[{"t":"여섯 시 사십이 분","q":"여섯 시 사십이 분이었다. 주말을 다른 도시에서 보내는 게 아니라면 엠마는 아마 집에 있을 터였다.","title":"죽음의 맛","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"18:43":[{"t":"여섯 시 사십삼 분","q":"베브는 시계만 들여다보는 사람은 아니었지만, 여섯 시 사십삼 분이 되자 진력이 났다. 왼쪽 팔꿈치 옆에 쌓인 서류 더미는 마무리된 일들, 걸었던 전화, 끝낸 확인, 처리된 후속 조치를 뜻했다. 오른쪽에는 남은 일들이 놓여 있었다.","title":"나쁜 언론","author":"모린 카터","ampm":"pm","kind":"역"}],"18:45":[{"t":"여섯 시 사십오 분","q":"\"여섯 시 사십오 분이야,\" 루이가 외쳤다. \"들었어, 밍?\" 그가 물었다, \"들었냐고?\" \"응, 태디, 들었어.\" \"뭔데?\" 토미가 물었다. \"아기, 새 아기 말이야, 들어봐, 새 아기.\"","title":"아이들을 사랑한 남자","author":"크리스티나 스테드","ampm":"pm","kind":"역"}],"18:46":[{"t":"일곱 시 십사 분 전","q":"머리 위에서 쿵 소리가 났을 때 나는 굳이 올려다보지 않았다. 일곱 시 십사 분 전이라는 걸 이미 알고 있었으니까.","title":"티파니 스트리트","author":"제롬 와이드먼","ampm":"pm","kind":"역"}],"18:47":[{"t":"여섯 시 사십칠 분","q":"\"그가 나타나지 않는다면,\" 라몬트가 어조를 바꾸며 덧붙였다, \"호크의 명령은 더없이 분명했다. 중단하라. 포크너를 유죄로 몰 증거가 확실히 확보되지 않는 한 그의 집을 급습하지 않는다.\" \"부담 없네,\" 재키가 속삭였고, 윌리엄은 손목시계를 확인했다. 여섯 시 사십칠 분.","title":"누구나 보는 곳에 숨겨진","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:48":[{"t":"일곱 시 십이 분 전","q":"우리는 곧 거리를 질주하듯 나아갔다. 나는 리버풀을 잘 몰라서 그 남자가 어디로 가는지 정확히 알 수 없었다. 내가 이륜마차에 올랐을 때는 일곱 시 십이 분 전이었고, 그 분들은 빠르게 흘러갔지만 역은 여전히 보이지 않았다.","title":"미스터리의 대가","author":"로버트 유스터스","ampm":"pm","kind":"역"}],"18:49":[{"t":"여섯 시 사십구 분","q":"여섯 시 사십구 분. 탄츠 중장은 기계화 부대의 호위를 받으며 군단 사령부로 차를 몰았다.","title":"장군들의 밤","author":"한스 헬무트 키르스트","ampm":"pm","kind":"역"}],"18:50":[{"t":"여섯 시 오십 분","q":"마침내 목소리가 말했다, \"클리프턴 씨도 따님도 그 항공편에 없습니다, 구만 씨, 탑승구는 이미 마감됐고요. 여섯 시 오십 분 항공편을 확인해 드릴까요?\"","title":"때가 오면","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:51":[{"t":"여섯 시 오십일 분","q":"부엌 문간의 네모난 빛이 옅은 자주색으로 바래 있었다. 그의 시계는 여섯 시 오십일 분을 가리켰다.","title":"세일럼스 롯","author":"스티븐 킹","ampm":"pm","kind":"역"}],"18:52":[{"t":"일곱 시 팔 분 전","q":"\"기차를 놓쳤어! 일곱 시 팔 분 전이라고!\" 아서가 비난과 공포가 뒤섞인 목소리로 말했다. 그러고는 침대에서 벌떡 일어나 히스테릭한 기세로 옷가지를 챙기기 시작했다.","title":"기차를 잡아라","author":"아널드 베넷","ampm":"pm","kind":"역"}],"18:53":[{"t":"여섯 시 오십 분을 몇 분 지나서","q":"그는 여섯 시 오십 분을 몇 분 지나서 활주로를 가로질러 대기 중인 비행기로 걸어갔다. 그 아이콘을 태운 비행기는 두 시간쯤 뒤 워싱턴에 착륙할 예정이었다.","title":"명예의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:54":[{"t":"일곱 시 몇 분 전","q":"\"좀 어색하네요,\" 케이 랜들이 전화로 말했다, \"남자한테 이런 심부름을 시키는 게... 하지만 그건 제 문제지 당신 문제는 아니에요. 그냥 물품만 가져다가 일곱 시 몇 분 전까지 교회 모임실로 와주세요.\"","title":"다리 놓기","author":"맥스 애플","ampm":"pm","kind":"역"}],"18:55":[{"t":"일곱 시 오 분 전","q":"\"... 당신은 시각이 중요하다고 생각할 이유가 없었죠. 오히려 시각을 완벽하게 정확히 기억했다면 그게 더 의심스러웠을 겁니다.\" \"제가 정확하지 않았나요?\" \"거의 맞았지만요. 당신이 윌킨스와 이야기한 건 일곱 시 오 분 전이었어요.\" \"십 분 차이군요.\"","title":"조용한 미국인","author":"그레이엄 그린","ampm":"pm","kind":"역"}],"18:56":[{"t":"여섯 시 오십육 분","q":"그러다 여섯 시 오십육 분이 되었다. 검은색 로버, 로버 90, 번호판 PYX 520이 벙커 왼편으로 이어지는 거리로 들어섰다. 차가 멈춰 섰다. 운전석 문이 열렸다. 한 남자가 내렸다.","title":"떠나는 꿈","author":"루퍼트 톰슨","ampm":"pm","kind":"역"}],"18:57":[{"t":"일곱 시 삼 분 전","q":"이 삼중 선율에 감싸인 채 객석은 넋을 잃고 바라보았다. 마치 당연한 일인 양 아무 의문 없이, 초록 화분에 심긴 회양목이 부인들의 화장실 자리를 차지하는 광경을 순순히 지켜보았다. 그리고 벽처럼 보이는 곳에는 커다란 시계판이 걸려 있었는데, 바늘은 일곱 시 삼 분 전을 가리키고 있었다.","title":"막간","author":"버지니아 울프","ampm":"pm","kind":"역"}],"18:58":[{"t":"여섯 시 오십팔 분","q":"정확히 그 두 사람을 본 지점, 그들이 계속 산을 오르던 시각, 그리고 안개 속으로 사라지면서도 별 어려움이 없어 보였다는 사실을 적었다. 다 적고 나서 그는 손목시계를 확인했다, 여섯 시 오십팔 분.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"18:59":[{"t":"일곱 시 일 분 전","q":"일곱 시 일 분 전, 로버트슨 중령이 무대 위로 성큼 올라서자 방 안의 모든 사람이 순식간에 조용해지며 차렷 자세를 취했다.","title":"아버지의 죄","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:01":[{"t":"일곱 시 일 분","q":"묘지의 문은 해질녘에 닫혔는데, 그날 밤 해는 일곱 시 일 분에 졌고, 시내까지는 거리가 상당했다.","title":"필리그리 볼","author":"애나 캐서린 그린","ampm":"pm","kind":"역"}],"19:02":[{"t":"일곱 시 이 분","q":"테디 카렐라가 일곱 시 이 분에 형사실로 걸어 들어왔을 때, 피터 번스는 심장이 멎는 줄 알았다.","title":"살인자의 쐐기","author":"에드 맥베인","ampm":"pm","kind":"역"}],"19:03":[{"t":"일곱 시 삼 분","q":"선로에 문제가 있었다. 언제 복구될지 아무도 알지 못했다. 일곱 시 삼 분에 도착한 열차가 마지막이었다. 여행의 신들이 모두 그를 방해하려고 작당한 걸까.","title":"살인의 방","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:04":[{"t":"일곱 시 사 분","q":"일요일 저녁 거의 같은 시각(정확히 말하면 일곱 시 사 분쯤)에 그녀는 범죄국장 발터 뫼딩의 집 초인종을 눌렀는데, 그는 그때 사적인 이유가 아니라 직업상의 이유로 족장 복장으로 변장하는 중이었다.","title":"카타리나 블룸의 잃어버린 명예","author":"하인리히 뵐","ampm":"pm","kind":"역"}],"19:05":[{"t":"일곱 시 오 분","q":"휴버트가 이제는 집이라 불러야 할 그 아파트로 돌아온 것은 평소보다 조금 늦은 일곱 시 오 분이었지만, 그는 여전히 너무 오래 머무른 손님처럼 불편했다.","title":"어떤 정의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:06":[{"t":"일곱 시 육 분","q":"시계는 저녁 일곱 시 육 분을 가리키고 있었다. 그렇다고 샘 딜런이 정확히 일곱 시 육 분에 살해되었다고 단정할 순 없지만, 다른 모든 증거가 분명히 그 시각을 뒷받침했다.","title":"거짓말쟁이들과 함께","author":"데이비드 엘리스","ampm":"pm","kind":"역"}],"19:07":[{"t":"일곱 시 칠 분","q":"그녀는 의식을 잃고 이틀 하고도 다섯 시간을 그 상태로 지내다가, 화요일 저녁 일곱 시 칠 분이 되어서야 편안히 놓여났다. 그녀는 스물네 살하고 다섯 달이었다.","title":"나의 자서전에서","author":"마크 트웨인","ampm":"pm","kind":"역"}],"19:08":[{"t":"일곱 시 팔 분","q":"일곱 시 팔 분이 되었는데도 그 여자는 오지 않았다. 나는 초조하게 기다렸다. 또 한 무리의 사람들이 개찰구를 지나 계단을 서둘러 내려가는 것을 지켜보았다. 나는 낯익은 얼굴이 있는지 온 신경을 곤두세웠다.","title":"동베를린에서 온 소녀","author":"제임스 퍼너","ampm":"pm","kind":"역"}],"19:09":[{"t":"일곱 시 구 분","q":"발란데르는 운 좋게 바로 앞에서 택시를 잡았다. 로센가드에 도착했을 때는 일곱 시 구 분이었다. 그는 모나가 늦기를 바랐지만, 문에 붙은 쪽지를 읽고서 그렇지 않다는 걸 깨달았다.","title":"피라미드","author":"헨닝 만켈","ampm":"pm","kind":"역"}],"19:10":[{"t":"일곱 시 십 분","q":"택시 한 대가 일곱 시 십 분에 그녀의 옛 신혼집 앞에 멈춰 섰다. 잠시 후 알렉스가 나타났다. 그는 훈장 세 개를 단 턱시도를 입고 있었다.","title":"무엇을 바라든 조심하라","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:11":[{"t":"일곱 시 십일 분","q":"됐어, 네가 말했지. 뛰어, 안 그러면 자리 못 잡아. 곧 보자. 네 목소리는 안심시키듯 들렸다. 시계는 일곱 시 십일 분을 가리켰다. 나는 수화기를 내려놓고 뛰었다.","title":"온전한 이야기 외","author":"앨리 스미스","ampm":"pm","kind":"역"}],"19:12":[{"t":"일곱 시 십이 분","q":"일곱 시 십이 분, 부엌에서 킴벌리는 점점 초조해지고 있었다.","title":"사적인 환자","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:13":[{"t":"일곱 시 십삼 분","q":"기차는 카스피해에서 이백사십이 베르스타 떨어진 키질 아르바트에 일곱 시 정각이 아니라 일곱 시 십삼 분에 도착했다. 그 사소한 지연에 남작은 일 분마다 하나씩, 총 열세 번의 욕설을 퍼부었다.","title":"특파원의 모험","author":"쥘 베른","ampm":"pm","kind":"역"}],"19:14":[{"t":"일곱 시 십사 분","q":"그가 뉴욕에 살며 사무실에서 일했다면, 매일 밤 목에 립스틱 자국을 묻힌 채 일곱 시 십사 분 화이트플레인스행 열차를 타고, 다음 날까지 버틸 거짓말의 물결을 안고 떠나는 전형적인 바람둥이 남편으로 살아갔을지도 모른다.","title":"개 마프와 그의 친구 마릴린 먼로의 삶과 견해","author":"앤드루 오하건","ampm":"pm","kind":"역"}],"19:15":[{"t":"일곱 시 십오 분","q":"\"성하.\" 그가 불렀다. \"뭔가?\" \"말들이 준비됐습니다, 저녁 예배 시간입니다.\" \"지금 몇 시인가?\" \"일곱 시 십오 분입니다.\"","title":"주교","author":"안톤 체호프","ampm":"pm","kind":"역"}],"19:16":[{"t":"일곱 시 십육 분","q":"일곱 시 십육 분, 리프먼은 사무실 불을 끄고 복도로 나섰다. 문은 닫았지만 잠그지는 않았다. 그는 엘리베이터 쪽으로 걸어가며, 아직 불이 켜진 사무실이 회장실뿐이라는 걸 알아챘다.","title":"잘못된 인상","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:17":[{"t":"일곱 시 십칠 분","q":"푸트니스 대령은 일곱 시 십칠 분에 그의 방문을 두드렸다. 차는 호텔 앞에서 대기 중이었고, 두 사람은 어두운 거리를 지나 경찰 본부로 향했다. 저녁 들어 훨씬 더 추워졌고, 도시는 거의 텅 비어 있었다.","title":"리가의 개들","author":"헨닝 만켈","ampm":"pm","kind":"역"}],"19:18":[{"t":"일곱 시 십팔 분","q":"\"카르티에 시계로 지금 정확히 일곱 시 십팔 분입니다.\" 밖에는 여전히 비가 내리고 있었지만, 택시 한 대가 다가와 커플이 내렸고 도어맨은 큰 우산으로 그레첸을 가려주며 그녀가 택시로 뛰어가게 했다.","title":"부자와 빈자","author":"어윈 쇼","ampm":"pm","kind":"역"}],"19:19":[{"t":"일곱 시 십구 분","q":"오늘 오후 세 시간 가까이 계약서 하나를 두고 씨름한 것도 나였다. 아는 건 지금이 일곱 시 십구 분이고, 십일 분 후면 도시 반대편 맥심스에서 어머니와 오빠 다니엘과 저녁을 먹기로 되어 있다는 것뿐이다. 취소해야겠다, 내 생일 저녁인데.","title":"가정적이지 않은 여신","author":"소피 킨셀라","ampm":"pm","kind":"역"}],"19:20":[{"t":"일곱 시 이십 분","q":"다음 금요일 그는 그들이 또 오는지 지켜보았다. 그들은 왔고, 시간도 똑같았다. 여자가 먼저 일곱 시 이십 분에, 소년은 사십 분 뒤에.","title":"겨우살이 살인","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:21":[{"t":"일곱 시 이십일 분","q":"체육관 가방을 오른손에 꼭 쥔 채, 아오마메는 버즈컷처럼 뭔가 일어나기를 기다리고 있었다. 시계 표시는 일곱 시 이십일 분으로 바뀌었다가, 곧이어 이십이 분, 이십삼 분으로 넘어갔다.","title":"1Q84","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"19:22":[{"t":"일곱 시 이십이 분","q":"카발리는 시계를 확인했다, 일곱 시 이십이 분. 고개를 들자 조니가 얼굴이 빨개진 채 그를 향해 오는 게 보였다. 할리우드에서 일하지 않아도 되니 다행이라고 카발리는 생각했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:23":[{"t":"일곱 시 이십삼 분","q":"체육관 가방을 오른손에 꼭 쥔 채, 아오마메는 버즈컷처럼 뭔가 일어나기를 기다리고 있었다. 시계 표시는 이십일 분에서 이십이 분을 거쳐, 일곱 시 이십삼 분으로 바뀌었다.","title":"1Q84","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"19:24":[{"t":"일곱 시 이십사 분","q":"\"아마 대시우드 부인과 함께 돌아올 거예요.\" 그녀가 말했다. \"오늘 아침 일찍 그가 전보를 보내서 그녀가 시카고발 열 시 삼십오 분 기차를 타도록 했으니, 그 기차는 여기 일곱 시 이십사 분에 도착할 거예요. 대시우드 씨 소식은 없나요?\" 그녀가 덧붙였고, 어머니다운 얼굴에 깊은 근심이 어렸다.","title":"죽음의 그림자에서","author":"니컬러스 카터","ampm":"pm","kind":"역"}],"19:25":[{"t":"일곱 시 이십오 분","q":"\"아니요, 나리, 가정부뿐입니다. 딸을 만나러 뉴잉글랜드에 가 계셨거든요. 가을이면 늘 그리로 가십니다. 히스로에 BA 214편으로 일곱 시 이십오 분 도착 예정이었습니다.\"","title":"죽음의 맛","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:26":[{"t":"저녁 일곱 시 이십육 분","q":"뉴먼이 호텔 위쪽을 가리켰다. 처마 밑에는 한 자쯤 되는 고드름 조각들이 아래로 뻗어 있었다, 뒤집힌 얼음 울타리 같았다. 역은 사람 하나 없는 단층짜리 오두막에 불과했다. 계기판 시계는 저녁 일곱 시 이십육 분을 가리키고 있었다.","title":"터미널","author":"콜린 포브스","ampm":"pm","kind":"역"}],"19:27":[{"t":"일곱 시 이십칠 분","q":"조종사가 그들을 환영하며 약간의 지연이 있을지 모른다고 알렸다. 덱스터는 시계를 확인했다, 일곱 시 이십칠 분. 그는 스콧과 자신을 가르는 팔걸이를 손가락으로 두드리기 시작했다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:28":[{"t":"일곱 시 이십팔 분","q":"\"기록을 보니 오늘 저녁 일곱 시 이십팔 분에 어머니께 전화를 거셨더군요.\" \"뭔가 착오가 있는 겁니다. 저는 누구에게도 전화할 기회가 없었어요.\"","title":"슈피리어 저스티스","author":"톰 힐퍼트","ampm":"pm","kind":"역"}],"19:29":[{"t":"일곱 시 이십구 분","q":"옥타비아가 아버지를 불러들였다는 사실을, 계획이 다 세워지기 전까지는 알리고 싶지 않았을 것이다. 시간을 정한 것도 나였다. 열일곱 시 이십이 분 기차보다 먼저 탈 방법이 없었고, 그 기차는 워털루에 일곱 시 이십구 분에 도착한다.","title":"확실한 정의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:30":[{"t":"일곱 시 삼십 분","q":"버터 조각이 유리창을 타고 반짝이는 흔적을 남기며 벽 아래로 흘러내렸다. 아무도 말이 없었다. 버터를 보고, 시계를 보고, 다시 버터를 보았다. 버터는 일곱 시 삼십 분이 되기 삼십 초 전에야 바닥에 닿았고, 맥머피는 잃었던 돈을 모두 되찾았다.","title":"뻐꾸기 둥지 위로 날아간 새","author":"켄 키지","ampm":"pm","kind":"역"}],"19:31":[{"t":"일곱 시 삼십일 분","q":"일곱 시 삼십일 분, 또 한 번 돌풍이 몰아치자 밴스는 삭구가 버텨 주기를 바라며 위를 올려다보았다. 돛은 캔버스가 아니라 고대의 작은 베틀에서 짠 것처럼 아마포 조각을 이어 붙인 것이었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:32":[{"t":"일곱 시 삼십이 분","q":"일곱 시 삼십이 분, 마지는 취조실 탁자 한쪽에서 클레이 옆에 앉아 있다. 루크와 나는 맞은편에 앉았다. 서두는 이미 끝냈고, 면담은 녹화되고 있다.","title":"악마의 다리 아래","author":"로레스 앤 화이트","ampm":"pm","kind":"역"}],"19:33":[{"t":"일곱 시 삼십삼 분","q":"일곱 시 삼십삼 분, 그는 사우샘프턴 역 승강장에 서 있었다. 오언을 태운 기차가 도착하려면 아직 꼬박 한 시간이 남은 때였다. 그는 몇 마디 물어보았지만 참을성 있게 차근차근 조사할 여유가 없어 곧 시내로 들어갔다.","title":"필사적인 처방","author":"토머스 하디","ampm":"pm","kind":"역"}],"19:34":[{"t":"일곱 시 삼십사 분","q":"\"기다리지 않는 게 좋을걸, 사이먼. 실패하면 네 위로 뛰어들지도 모르니까.\" \"경고 고맙군, 마크. 버텨봐.\" 아름다운 저녁, 차에 올라타며 손목시계를 보니 일곱 시 삼십사 분이었다.","title":"대통령께 말씀드릴까요","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:35":[{"t":"일곱 시 삼십오 분","q":"조지는 손목시계를 확인했다. 일곱 시 삼십오 분. 지금쯤 제프리 영은 팀원들에게 내일 일정을 설명하며, 마지막 등정에 누구를 데려갈지 알려주고 있을 터였다. 물이 끓기 시작했다.","title":"영광의 길","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:36":[{"t":"일곱 시 삼십육 분","q":"뒷문이 쾅 닫히고 빅터가 형용하기 힘들 만큼 끔찍한 무언가를 손에 쥔 채 거실로 들어왔을 때, 비디오 녹화기에 찍힌 시각은 일곱 시 삼십육 분이었다.","title":"무덤에 한 발 걸치고","author":"데이비드 렌윅","ampm":"pm","kind":"역"}],"19:37":[{"t":"일곱 시 삼십칠 분","q":"\"오늘 밤 정확히 일곱 시 삼십칠 분, 주요 궤도 터미널에서 승인되지 않은 출항이 있을 겁니다. 우리는 궤도 방위군이 진짜 나포 사건에 대응하는 것처럼 보이는 반응을 이끌어내야 합니다.\"","title":"제국의 유물","author":"W. 마이클 기어","ampm":"pm","kind":"역"}],"19:38":[{"t":"일곱 시 삼십팔 분","q":"수요일 일곱 시 삼십팔 분. \"마이클! 에바까지! 이게 얼마 만이야! 세상에!\" 늙은 그리스인의 볕에 그을린 얼굴이 미소로 활짝 펴지며, 회색 콧수염 아래로 남은 이가 드러났다.","title":"프로젝트 다이달로스","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:39":[{"t":"여덟 시 이십일 분 전","q":"시간도 빠르게 흘러가고 있었다. 여덟 시 이십일 분 전이라니! 몇 분 안에 출발하지 않으면 기차를 놓치고 말 것이었다.","title":"오스카 브로드스키 사건","author":"오스틴 프리먼","ampm":"pm","kind":"역"}],"19:40":[{"t":"여덟 시 이십 분 전","q":"그들이 증언하기로는 여덟 시 이십 분 전이었다고 한다. 그때는 시신이 매달려 있지 않았고, 앞마당에는 아무도 없었다고 맹세할 수 있다는 것이다.","title":"본원적 죄악","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:41":[{"t":"일곱 시 사십일 분","q":"9월 25일, 점등 시각은 일곱 시 사십일 분이었다. 크란츠는 여덟 시가 넘어서야 웬트워스 외곽에 모습을 드러냈다.","title":"거짓 인상","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:42":[{"t":"일곱 시 사십이 분","q":"일곱 시 사십이 분, 프랜시스에게 전화를 건 지 한 시간이 조금 넘은 시각이었다. 지금쯤이면 도착했어야 했다.","title":"본원적 죄악","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:43":[{"t":"일곱 시 사십삼 분","q":"성벽 안쪽에서 신호가 오자 파수병 몇이 도르래로 달려가 격자문을 삐걱대며 끌어올렸고, 키 큰 기사가 말을 몰아 나올 때 맬러리의 회중시계는 일곱 시 사십삼 분을 가리키고 있었다.","title":"그런 기사가 있었네","author":"로버트 F. 영","ampm":"pm","kind":"역"}],"19:45":[{"t":"일곱 시 사십오 분","q":"\"그럴 겁니다. 그는 밤에 죽었거나, 아니면 일곱 시 사십오 분에 그레이스 윌슨이 마지막으로 그의 고해를 들었을 때가 산 채로 본 마지막 순간이겠지요. 아마 지루해서 죽었을 겁니다.\"","title":"검은 탑","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:46":[{"t":"일곱 시 사십육 분","q":"일곱 시 사십육 분. \"알겠습니다.\" 앨프리드 콘위츠가 차려 자세를 취했다. \"네, 알겠습니다.\" 그는 수화기를 내려놓고 잭 멀호니를 향해 돌아섰다. \"완전 부인입니다. 이스라엘 관제소는 에게해 그 구역에서 운항 중인 군용기가 전혀 없다고 합니다.\"","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:47":[{"t":"일곱 시 사십칠 분","q":"일곱 시 사십칠 분, 밴스는 프리깃함이 예광탄으로 경고 사격을 가하는 것을 지켜보았지만 아무 소용이 없었다. 헬기는 이를 무시한 채 57밀리 로켓탄을 퍼부었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:48":[{"t":"일곱 시 사십팔 분","q":"일곱 시 사십팔 분. 문이 열리고 닫히는 소리, 외계인의 쉿 소리 같은 속삭임이 들려왔다. 그녀는 자신이 강렬한 천장 조명 아래를 미끄러져 가는 침대 위에서 움직이고 있음을 느꼈다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:49":[{"t":"여덟 시 십일 분 전","q":"\"여덟 시 십일 분 전이군.\" \"넌 늘 정확해. 머릿속에 시계라도 있나 봐.\" \"오늘 밤은 틀릴 리 없어. 발사 일 초 전까지 정확히 말해줄 수 있다고. 봐, 십 분 경고야!\"","title":"시작의 끝","author":"레이 브래드버리","ampm":"pm","kind":"역"}],"19:50":[{"t":"여덟 시 십 분 전","q":"벽 한가운데 걸린 시계 바늘은 여덟 시 십 분 전을 가리키고 있었다. 카페는 여덟 시에 문을 닫는다.","title":"커피가 식기 전에: 카페에서의 이야기","author":"가와구치 도시카즈","ampm":"pm","kind":"역"}],"19:51":[{"t":"일곱 시 오십일 분","q":"비행기는 일곱 시 오십일 분에 이륙 활주로로 돌아 들어갔고, 엔진이 굉음을 내며 천천히 앞으로 나아가더니 속도를 높였다. 바퀴가 지면을 떠난 것은 일곱 시 오십삼 분이었다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:52":[{"t":"일곱 시 오십이 분","q":"일곱 시 오십이 분, 밴스는 갑판을 가로질러 몸을 뻗어 선미 아래 보관해 둔 장비 상자를 꺼냈다. 그 안에는 늘 지니고 다니는 크롬 손잡이 발터 9밀리 권총이 들어 있었다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"19:53":[{"t":"일곱 시 오십삼 분","q":"비행기는 일곱 시 오십일 분에 이륙 활주로로 돌아 들어갔고, 엔진이 굉음을 내며 천천히 앞으로 나아가더니 속도를 높였다. 바퀴가 지면을 떠난 것은 일곱 시 오십삼 분이었다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:54":[{"t":"여덟 시 육 분 전","q":"시신은 여덟 시 육 분 전에 발견되었다. 영 박사는 그로부터 삼십 분쯤 뒤에 도착했다. 확실히 해 두자면, 내 기억력이 형편없어서.","title":"쓰러진 남자","author":"나이오 마시","ampm":"pm","kind":"역"}],"19:55":[{"t":"일곱 시 오십오 분","q":"일곱 시 오십오 분, 케이트 미스킨 경위와 피어스 태런트 경위는 서더크 다리와 런던 다리 사이 강변 술집에서 함께 술을 마시고 있었다.","title":"살인의 방","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"19:56":[{"t":"여덟 시 사 분 전","q":"끝없이 몰려오는 폭풍 구름을 배경으로, 담배를 문 그의 굳은 얼굴이 떠오른다. 베르나르도가 불쑥 물었다. \"몇 시야, 이레노?\" 그는 하늘을 올려다보지도, 걸음을 멈추지도 않고 대답했다. \"여덟 시 사 분 전이야, 베르나르도.\" 목소리가 날카롭고 조롱하는 듯했다.","title":"기억의 천재 푸네스 (미궁들)","author":"호르헤 루이스 보르헤스","ampm":"pm","kind":"역"}],"19:57":[{"t":"여덟 시 삼 분 전","q":"여덟 시 삼 분 전, 라슬로와 그의 양키 후사르 악단이 무대에 자리를 잡았다. 밴드가 수자 메들리를 연주하는 동안 카터는 소품을 꼼꼼히 점검하며 카드 덱의 봉인을 확인했다.","title":"카터, 악마를 이기다","author":"글렌 데이비드 골드","ampm":"pm","kind":"역"}],"19:58":[{"t":"일곱 시 오십팔 분","q":"그는 공모자들을 산 채로 붙잡아 상원의원에게 불리한 증언을 하게 만들어야 했다. 국장은 워싱턴 지부 위 옛 우체국 탑 시계와 자신의 손목시계를 맞춰 보았다. 일곱 시 오십팔 분이었다.","title":"대통령께 말씀드릴까요","author":"제프리 아처","ampm":"pm","kind":"역"}],"19:59":[{"t":"여덟 시 일 분 전","q":"정확히 여덟 시 일 분 전이었어요. 광내는 통을 두고 왔나 확인하러 시연실에 들어갔는데, 수레 위에 우유병이 있길래 위쪽을 조금 마셨죠.","title":"나이팅게일을 위한 수의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:01":[{"t":"여덟 시 일 분","q":"레녹스 역에는 어렵지 않게 제시간에 도착했다. 사이러스가 들어섰을 때 큰 시계 바늘은 겨우 여덟 시 일 분을 가리키고 있었다.","title":"심문 법정","author":"그레이스 S. 리치먼드","ampm":"pm","kind":"역"}],"20:02":[{"t":"여덟 시 이 분","q":"\"그래, 역으로 가야 해. 거기 없으면 쫓아가서라도 붙잡아야지.\" 안나는 신문의 열차 시간표를 살폈다. 저녁 열차는 여덟 시 이 분에 출발한다. \"그래, 늦지 않겠어.\"","title":"안나 카레니나","author":"레프 톨스토이","ampm":"pm","kind":"역"}],"20:03":[{"t":"여덟 시 삼 분","q":"\"그래요, 죽은 지 얼마 안 됐다는 건 분명해요. 늦어도 두 시간 안이겠죠. 그런데 언제 발견했다고 했죠? 여덟 시 삼 분이었어요.\"","title":"전문가 증인의 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:04":[{"t":"여덟 시 사 분","q":"대지는 어둠을 하늘로 밀어 올리는 듯했다. 밤이 되면 농촌은 음산해진다. 랭커스터의 불빛이 흐릿한 전조등과 섞이자 그는 안도했다. 그는 식당 앞에 차를 세웠는데, 벽시계는 여덟 시 사 분을 가리키고 있었다.","title":"달려라 토끼","author":"존 업다이크","ampm":"pm","kind":"역"}],"20:05":[{"t":"여덟 시 오 분","q":"\"여덟 시 오 분쯤 데버루 코트 문으로 나갈 때, 폴렛 코트나 미들 템플로 들어가는 사람을 보셨나요?\" 캐서린이 답했다. \"아무도요. 데버루 코트도 스트랜드로 가는 통로도 텅 비어 있었어요.\"","title":"어떤 정의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:06":[{"t":"여덟 시 육 분","q":"\"등대에 도착한 건 여덟 시 육 분이었습니다. 안으로 들어갈 수가 없었어요. 문이 잠겨 있었거든요.\"","title":"등대","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:07":[{"t":"여덟 시 칠 분","q":"기차가 없으니 작은 역에 사람이 적다는 게 느껴져서 눈을 뜨고 손목시계를 보니 여덟 시 칠 분이었고, 나는 벤치에 다섯 시간쯤 앉아 있었던 셈이었지만 그렇게 느껴지지는 않았다. 엉덩이가 아프고 배도 고프고 목도 말랐을 뿐이었다.","title":"한밤중에 개에게 일어난 기이한 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"20:08":[{"t":"여덟 시 팔 분","q":"월요일, 여덟 시 팔 분. 그는 손목시계를 흘끗 보고는 얼룩진 호텔 창밖으로 스트랜드 거리를 내려다보았다. 이 분만 더 있으면 문에서 노크 소리가 날 터였다.","title":"다이달로스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"20:09":[{"t":"여덟 시가 넘도록","q":"내 평생 취한 적은 딱 두 번뿐인데, 그 두 번째가 바로 그날 오후였다. 그래서 그 뒤에 일어난 일은 모두 흐릿하고 뿌옇게만 느껴진다. 다만 여덟 시가 넘도록 아파트에는 명랑한 햇살이 가득했다.","title":"위대한 개츠비","author":"F. 스콧 피츠제럴드","ampm":"pm","kind":"역"}],"20:10":[{"t":"여덟 시 십 분","q":"여덟 시 십 분이다. 1918년 1월 27일 일요일 저녁 여덟 시 십 분, 내가 당신을 얼마나 사랑하는지 꼭 말해야겠다.","title":"존 미들턴 머리에게 보내는 편지","author":"캐서린 맨스필드","ampm":"pm","kind":"역"}],"20:11":[{"t":"여덟 시 십일 분","q":"헐리 부부는 정확히 여덟 시 십일 분에 도착했다. 내가 현관문을 열자 마틴이 임신 칠 개월이 다 되어 몸이 무거운 페이지를 현관 안으로 밀어 넣었다. \"일찍 지원군이 필요할 것 같아서 말이야,\" 네이선이 페이지의 코트를 벗겨 주는 동안 그가 중얼거렸다.","title":"두 번째 아내","author":"엘리자베스 뷰캔","ampm":"pm","kind":"역"}],"20:12":[{"t":"여덟 시 십이 분","q":"여덟 시 십이 분, 대사관 보안 게이트가 스르르 열리며 검은색 메르세데스 세단이 코를 들이밀었다. 차는 좌회전해 카메라 앞을 몇 센티미터 간격으로 지나갔는데, 어찌나 가까웠던지 가브리엘은 손을 뻗으면 뒷좌석의 단 한 명뿐인 승객을 잡아챌 수 있을 것만 같았다.","title":"타락한 천사","author":"대니얼 실바","ampm":"pm","kind":"역"}],"20:13":[{"t":"여덟 시 십삼 분","q":"여덟 시 십삼 분. 정말 힘든 하루였다! 니커스를 오래 산책시키고 돌아온 앨리는 소파에 몸을 던지듯 앉으며 완전히 지쳐 있었다. 그녀는 등을 기대고 구두를 벗어 던졌다. 가슴이 조이는 느낌이 몇 번 있었는데, 아마 심리적인 것, 불안 때문이었겠지만 지금은 다 가라앉았다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"20:14":[{"t":"여덟 시 십사 분","q":"여덟 시 십사 분, 딜워스의 집으로 전화가 걸려 왔을 때 올비어와 존스는 상황에 어울리지 않을 만큼 잔뜩 흥분했다. 그들은 무언가 벌어지기를 간절히 바라던 참이었기 때문이다.","title":"워처스","author":"딘 쿤츠","ampm":"pm","kind":"역"}],"20:15":[{"t":"여덟 시 십오 분","q":"여덟 시 십오 분. 흠. 사용 설명서를 도무지 찾을 수가 없다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"20:16":[{"t":"여덟 시 십육 분","q":"그는 그녀의 손에 입을 맞추고는 자리를 떠나 술 두 잔을 더 가지러 갔다. 그가 돌아왔을 때는 여덟 시 십육 분이었고, 로이스는 주크박스 소리에 맞춰 나직이 흥얼거리고 있었다.","title":"로터스 클럽","author":"조너선 코","ampm":"pm","kind":"역"}],"20:17":[{"t":"여덟 시 십칠 분","q":"여덟 시 십칠 분, 드라이브 룸의 경고등 하나가 켜지지 않았다. 이 사소한 사건이 이십삼 분 뒤 레드 드워프 승무원 전원을 몰살시키는 연쇄 참사의 시작이었다.","title":"레드 드워프","author":"그랜트 네일러","ampm":"pm","kind":"역"}],"20:18":[{"t":"여덟 시 십팔 분","q":"여덟 시 십팔 분, 카탸가 오데사 호텔에 도착했다. 바를리와 카탸는 구내식당에서 이야기를 나누고 있다. 위클로와 요원 한 명이 감시 중. 계속 지켜볼 것.","title":"러시아 하우스","author":"존 르카레","ampm":"pm","kind":"역"}],"20:19":[{"t":"여덟 시 십구 분","q":"여덟 시 십구 분, 그녀는 두 번째 전화를 받고 '화물'을 실은 비행기가 암만을 이륙했다는 사실을 알았다.","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"20:20":[{"t":"여덟 시 이십 분","q":"소년은 다시 문을 두드렸다. 다시 아무 응답이 없었다. 가브리엘은 지켜보며 함께 애를 태우다가, 여덟 시 이십 분이 되어서야 소년이 마침내 포기하고 돌아섰다.","title":"겨우살이 살인","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:21":[{"t":"여덟 시 이십일 분","q":"여덟 시 이십일 분이었다. 읍사무소는 아홉 시까지 문을 열어 둔다. 토요일이라 세금 납부하러 온 주민들이 드나들었다. 그날 밤 안으로 혼인 신고서를 받을 시간은 아직 있었다.","title":"안개","author":"윌리엄 더들리 펠리","ampm":"pm","kind":"역"}],"20:22":[{"t":"여덟 시 이십이 분","q":"여덟 시 이십이 분. 텍사스 스위트워터 출신의 에릭 햄블린은 지난 이 년 반 동안 샛컴의 경비원으로 일해 왔고 그 일을 좋아했다. 스물네 살, 흥청거리던 팔십 년대의 낙오자였던 그는 그리스에서 가장 아름다운 섬 중 하나에서 오후를 보낼 수 있었다.","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"20:23":[{"t":"여덟 시 이십삼 분","q":"여덟 시 이십삼 분. 몇 분 뒤면 아래층으로 내려가야 했다. 딸 샐리에게 마스카라를 빌릴 수도 있었지만 이미 늦었다. 노섬에 계신 어머니에게 전화를 걸 수도 있었지만 그것도 늦었다. 칠 분간의 혼자만의 시간이 남았고, 그다음엔 내려가야 했다.","title":"빛나는 길","author":"마거릿 드래블","ampm":"pm","kind":"역"}],"20:24":[{"t":"여덟 시 이십사 분","q":"피치는 손목시계를 확인했다. 여덟 시 이십사 분. 이십 분 안에 택시를 잡지 못하면 끝장이었다.","title":"떠나는 꿈","author":"루퍼트 톰슨","ampm":"pm","kind":"역"}],"20:25":[{"t":"여덟 시 이십오 분","q":"그녀는 늘 앉던 자리에 앉아 맞은편 의자에 몸을 묻는 남편을 향해 미소 지었다. 살았다. 겨우 여덟 시 이십오 분이었다.","title":"리스터데일 미스터리","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"20:26":[{"t":"여덟 시 이십육 분","q":"여덟 시 이십육 분이었다. 그는 망설임 없이 휴대품 보관소로 가서 표를 내밀고 커다란 여행 가방과 담요, 두꺼운 트위드 얼스터 코트를 건네받았다.","title":"요부","author":"윌리엄 르 쿠","ampm":"pm","kind":"역"}],"20:27":[{"t":"여덟 시 이십칠 분","q":"그녀의 언니는 한결같이 의리가 있었다. 사이렌이 울부짖는 와중에도 만나기로 한 자리를 떠날 사람이 아니었다. 그래서 여덟 시 이십칠 분, 군중의 머리 위로 또 다른 기이한 소리가 찢어지듯 울려 퍼졌을 때도 그녀는 그 자리를 지키고 있었다.","title":"작은 전시 도서관","author":"케이트 톰슨","ampm":"pm","kind":"역"}],"20:28":[{"t":"여덟 시 이십팔 분","q":"앉은 채로 하베르는 시계를 올려다보며 불쑥 말했다. \"우리 아버지는 정확히 이십오 년 전에 돌아가셨어.\" 린델이 고개를 들었다. \"정확히요?\" \"그래, 정확히. 정확히 이십오 년 전 오늘, 여덟 시 이십팔 분에.\"","title":"돌 관","author":"셸 에릭손","ampm":"pm","kind":"역"}],"20:29":[{"t":"여덟 시 이십구 분","q":"저녁 여덟 시 이십구 분, 나는 엘긴 크레센트의 현관 초인종을 눌렀다. 하얀 앞치마를 두른 자그마한 동양인 여성이 문을 열어 주었다. 그녀는 나를 벽난로와 커다란 유화 두 점이 걸린 텅 빈 넓은 거실로 안내했다.","title":"엥글비","author":"서배스천 폴크스","ampm":"pm","kind":"역"}],"20:30":[{"t":"여덟 시 반","q":"여덟 시 반이 되자 어스름이 밤과 거의 구별되지 않을 만큼 짙어졌고, 다섯 명이던 수색대는 어느새 열두 명으로 불어나 있었다.","title":"토미노커","author":"스티븐 킹","ampm":"pm","kind":"역"}],"20:31":[{"t":"여덟 시 삼십일 분","q":"그날 저녁 시계는 여덟 시 삼십일 분을 가리키고 있었다. 거의 땅거미가 질 무렵, 나뭇잎이 부드럽게 흔들리는 소리 말고는 정지된 풍경이었지만 자동차 엔진 소리와 자갈 위 타이어 마찰음이 녹화를 작동시킨 게 분명했다.","title":"이보다 눈먼 사람은 없다","author":"바버라 프래드킨","ampm":"pm","kind":"역"}],"20:32":[{"t":"여덟 시 삼십이 분","q":"앙크모포크 내전의 기원, 즉 그룬 3432년 저녁 여덟 시 삼십이 분부터 그룬 4432년 오전 열 시 사십오 분까지의 사건은 역사가들 사이에서 늘 뜨거운 논쟁거리였다.","title":"무빙 픽처스","author":"테리 프래쳇","ampm":"pm","kind":"역"}],"20:33":[{"t":"여덟 시 삼십삼 분","q":"여덟 시 삼십삼 분, 항법사 앙리 뒤부아는 설탕 네 스푼을 넣은 검은 코나 커피를 컴퓨터 콘솔 키보드 위에 쏟았다. 커피를 닦아내던 그는 모니터 화면에 뜬 붉은 경고등 세 개를 발견했지만 그저 자신이 흘린 커피 탓이라 착각했다.","title":"레드 드워프","author":"그랜트 네일러","ampm":"pm","kind":"역"}],"20:34":[{"t":"여덟 시 삼십사 분","q":"그는 이렇게 적었다. \"기침(발작성): 여덟 시 삼십사 분(지속 시간 24초)\"","title":"종소리","author":"리처드 하벨","ampm":"pm","kind":"역"}],"20:35":[{"t":"여덟 시 삼십오 분","q":"본 요리는 여덟 시 삼십오 분에 끝났고, 이어서 묽은 커스터드에 뭉그러진 자두가 나왔는데 프론 씨는 말없는 질책의 표시로 자두를 조금 덜 받았다.","title":"진실","author":"테리 프래쳇","ampm":"pm","kind":"역"}],"20:36":[{"t":"여덟 시 삼십육 분","q":"여덟 시 삼십육 분, 리머는 정체 갑판의 세면실에 서서 머리를 빗고 있었다.","title":"레드 드워프","author":"그랜트 네일러","ampm":"pm","kind":"역"}],"20:37":[{"t":"여덟 시 삼십칠 분","q":"피어스는 자리에서 일어나 조끼에서 회중시계를 꺼냈다. 검댕투성이 시곗줄 끝에 어울리지 않게 반짝이는 금빛 물건이었다. 뚜껑을 열자 여덟 시 삼십칠 분이었다.","title":"대열차 강도","author":"마이클 크라이튼","ampm":"pm","kind":"역"}],"20:38":[{"t":"여덟 시 삼십팔 분","q":"여덟 시 삼십팔 분, 3막이 시작될 무렵 그는 자리에서 일어나 되도록 소리를 내지 않으려 애쓰며 객석을 빠져나가 2층으로 올라갔다.","title":"여자들이 잠든 동안","author":"하비에르 마리아스","ampm":"pm","kind":"역"}],"20:39":[{"t":"여덟 시 삼십구 분","q":"여덟 시 삼십구 분. 캘리는 치즈와 이탈리아 소시지를 듬뿍 얹은 피자가 얼마나 먹고 싶은지 생각하고 있었다. 아니, 그냥 콜레스테롤을 듬뿍 얹은 거라고 해야 맞겠지. 맛있는 것들은 왜 하나같이 몸에 나쁘다고들 하는 걸까.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"20:40":[{"t":"여덟 시 사십 분","q":"\"십칠일이었죠, 맞아요. 그들은 여덟 시 사십 분에 자리에 앉았어요. 손님이 실제로 착석한 시각을 기록해두는 게 제 작은 버릇이거든요.\"","title":"죽음을 향한 취향","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"20:41":[{"t":"여덟 시 사십일 분","q":"지금은 여덟 시 사십일 분, 나는 침대에서 연습 중이다. 엄마는 비닐봉지에 아주 뜨거운 물을 채우고 새지 않게 꽉 묶은 다음, 그걸 또 다른 봉지에 넣고 다시 묶는다.","title":"룸","author":"엠마 도노휴","ampm":"pm","kind":"역"}],"20:42":[{"t":"여덟 시 사십이 분","q":"\"그래, 그냥 생각 좀...\" 샨은 추시계를 흘낏 훔쳐보았다. 여덟 시 사십이 분, 다시 끌려가기까지 십팔 분 남았다. \"관개 호스를 켜놓고 온 게 걸려서요. 레인저 로이가 일찍 오면 금방 돌아온다고 전해주세요.\"","title":"잃어버림의 끝자락","author":"크리스티나 맥모리스","ampm":"pm","kind":"역"}],"20:43":[{"t":"여덟 시 사십삼 분","q":"\"어느 쪽이든 그가 백악관으로 돌아가게 둬선 안 됩니다.\" 전화가 끊겼다. 카발리는 아버지 말이 두 가지 다 옳다는 걸 알고 있었다. 그는 다시 시계를 확인했다. 여덟 시 사십삼 분.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"20:44":[{"t":"여덟 시 사십사 분","q":"시계추는 정확한 규칙성으로 매초를 새겼고, 선수들은 그 소리가 귀에 부딪힐 때마다 육십분의 일 분씩 헤아릴 수 있었다. \"여덟 시 사십사 분!\" 존 설리번이 감정을 감추지 못한 목소리로 외쳤다. 이제 딱 일 분만 더 지나면 내기에서 이기는 것이었다.","title":"80일간의 세계일주","author":"쥘 베른","ampm":"pm","kind":"역"}],"20:45":[{"t":"여덟 시 사십오 분","q":"여덟 시 사십오 분, 나는 전화를 걸어 말했다. \"재정 조언이 좀 필요해. 정말이야, 지금 곤란한 상황이거든.\"","title":"내 휴식과 이완의 해","author":"오테사 모시페그","ampm":"pm","kind":"역"}],"20:46":[{"t":"여덟 시 사십육 분","q":"그때 그는 침실로 들어가 티나가 9월 11일 저녁 그 아파트에 있었음을 확인해주는 단서 하나를 발견했다. 애나의 침대 옆에 손목시계가 놓여 있었다. 잭은 시각을 확인했다. 여덟 시 사십육 분이었다.","title":"거짓 인상","author":"제프리 아처","ampm":"pm","kind":"역"}],"20:47":[{"t":"여덟 시 사십칠 분","q":"플리스가 문에서 벤의 열쇠 짤랑거리는 소리를 들었을 때, 조리대 시계는 여덟 시 사십칠 분을 가리키고 있었다. 어느샌가부터 남편은 더 이상 아무런 노력도 하지 않고 있었다.","title":"우리에게 남은 모든 것","author":"캐서린 밀러","ampm":"pm","kind":"역"}],"20:48":[{"t":"여덟 시 사십팔 분","q":"\"아직 여덟 시 사십팔 분밖에 안 됐어요.\" 콘스탄스가 지적했다. \"그래서 그게 어쨌다는 거야?\"","title":"늙은 아내들 이야기","author":"아널드 베넷","ampm":"pm","kind":"역"}],"20:49":[{"t":"여덟 시 사십구 분","q":"여덟 시 사십구 분, 문에서 요란한 노크 소리가 났고 데이비드 히스가 문을 열러 가자 해미시 경은 알아들을 수 없는 나무람을 중얼거렸다. 그가 발견한 것은 그의 연락책이었다.","title":"원칙의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"20:50":[{"t":"여덟 시 오십 분","q":"여덟 시 오십 분. 아, 도표라. \"IMC 기능용 버튼.\" 그런데 IMC 기능이 대체 뭐지?","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"20:51":[{"t":"여덟 시 오십일 분","q":"나는 여덟 시 오십일 분부터 아홉 시 십 분까지 북극성을 바라보고 있었다. 고개를 뒤로 젖혀 목이 아플 때까지, 현기증과 싸우며, 하늘에서 우리가 만나기로 한 저 멀고 반짝이는 빛에서 눈을 떼지 않은 채, 그 안에서 되비치는 당신의 얼굴을 보려 애썼다.","title":"영주의 연인","author":"알베르 코엔","ampm":"pm","kind":"역"}],"20:52":[{"t":"여덟 시 오십이 분","q":"\"여덟 시 오십이 분 기차일 겁니다, 돈캐스터와 피터버러에서 갈아타세요. 자정 직후면 케임브리지에 도착할 거예요.\"","title":"더기 모티머의 오른팔","author":"제프리 아처","ampm":"pm","kind":"역"}],"20:53":[{"t":"여덟 시 오십삼 분","q":"겨우 여덟 시 오십삼 분. 파트너들의 결정 회의는 칠 분 후에 시작된다. 이걸 견딜 수 있을지 모르겠다.","title":"가정적이지 않은 여신","author":"소피 킨셀라","ampm":"pm","kind":"역"}],"20:54":[{"t":"여덟 시 오십사 분","q":"IQ 테스트의 타당성에 관한 저녁 식탁 대화를 다시 이어가려 했지만 그는 또다시 침울해져 있었고, 나는 그를 달래줄 기분이 아니었다. 벨이 여덟 시 오십사 분에 울렸을 때 나는 안도했다. 이제 뭔가 진전이 있으려나.","title":"마감의 죽음","author":"로버트 골즈버러","ampm":"pm","kind":"역"}],"20:55":[{"t":"여덟 시 오십오 분","q":"격리병동의 티끌 하나 없는 흰 벽 방에서 침대에 앉아 있던 메랄 다바노스는 벽시계를 올려다보았다. 여덟 시 오십오 분이었다.","title":"어두운 토대","author":"크리스 월리","ampm":"pm","kind":"역"}],"20:56":[{"t":"여덟 시 오십육 분","q":"\"칠호 침대, 이등석입니다. 그 신사분은 아직 오지 않으셨고, 지금 여덟 시 오십육 분입니다.\"","title":"오리엔트 특급 살인","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"20:57":[{"t":"여덟 시 오십칠 분","q":"그녀는 여덟 시 오십칠 분을 가리키는 시계를 손가락으로 가리킨다, 아홉 시까지 딱 삼 분 남았다는 뜻이다. 그래서 나는 옷장으로 뛰어들어가 베개에 누워, 빨간 파이핑이 달린 온통 회색빛 보드라운 담요를 두른다.","title":"룸","author":"엠마 도노휴","ampm":"pm","kind":"역"}],"20:58":[{"t":"여덟 시 오십팔 분","q":"\"몇 시야?\" 그녀가 조용히, 단호하게, 절망적으로 물었다. \"여덟 시 오십팔 분이야,\" 그가 애써 사실대로 대답했다.","title":"아들과 연인","author":"D.H. 로렌스","ampm":"pm","kind":"역"}],"20:59":[{"t":"여덟 시 오십구 분","q":"다만 병영에서 이 마일 이상 벗어나지 말고, 로열 퓨질리어답게 처신하며, 여덟 시 오십구 분에는 판사처럼 멀쩡한 정신으로 위병소에 복귀해야 한다.","title":"까마귀가 나는 길로","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:01":[{"t":"아홉 시가 지났다","q":"아홉 시가 지났다. 윌리엄은 숙제와 저녁 식사를 마쳤다. 부모님과 필립스 부인에게 잘 자라는 인사를 하고 나서, 그는 손전등과 돋보기, 벌레 두 마리를 챙겨 다락방으로 몰래 올라갔다.","title":"다락방의 성","author":"엘리자베스 윈스럽","ampm":"pm","kind":"역"}],"21:02":[{"t":"아홉 시 이 분","q":"광장을 가로질러 서둘렀다. 시계를 확인했다. 아홉 시 이 분이었다. 그는 지난번에도 나를 기다리게 했었다.","title":"팝 고즈 더 위즐","author":"제임스 패터슨","ampm":"pm","kind":"역"}],"21:03":[{"t":"아홉 시 삼 분","q":"세바스찬은 자리에 앉은 채 전화기를 노려보며 벨이 울리기를 바랐다. 아홉 시 삼 분, 누군가 그의 뜻에 응답했다.","title":"무엇을 바라는지 조심하라","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:04":[{"t":"아홉 시 사 분","q":"아홉 시 사 분, 삼엽충들이 무대 위로 헤엄쳐 오고, 곧이어 버제스 셰일의 기묘한 생물들이 뒤따른다.","title":"거의 모든 것의 역사","author":"빌 브라이슨","ampm":"pm","kind":"역"}],"21:05":[{"t":"아홉 시 오 분","q":"아홉 시 오 분. 서재 천장에서 목소리가 흘러나왔다. '매클렐런 부인, 오늘 저녁엔 어떤 시를 원하시나요?' 집 안은 고요했다. 마침내 목소리가 말했다. '취향을 밝히지 않으셨으니, 제가 무작위로 시를 고르겠습니다.'","title":"부드러운 비가 내리리라","author":"레이 브래드버리","ampm":"pm","kind":"역"}],"21:06":[{"t":"아홉 시 육 분","q":"'파리 여자가 여기 온다고?' '그래, 아버지와 함께, 내일 아홉 시 육 분에 도착하는 기차로.'","title":"잉크 얼룩","author":"르네 바쟁","ampm":"pm","kind":"역"}],"21:07":[{"t":"아홉 시 칠 분","q":"그는 창문을 올리고 엔진을 끈 뒤 몸을 숙여 트렁크를 열었다. 시계를 확인했다. 아홉 시 칠 분이었다.","title":"이븐","author":"앤드루 그랜트","ampm":"pm","kind":"역"}],"21:08":[{"t":"아홉 시 팔 분","q":"아홉 시 팔 분 정각, 예비 진동으로 이미 약해져 있던 단층이 아무 예고 없이 격렬하게 어긋나며 백여 피트나 미끄러졌고, 수십억 톤의 바닷물을 함께 빨아들였다.","title":"포세이돈 어드벤처","author":"폴 갈리코","ampm":"pm","kind":"역"}],"21:09":[{"t":"아홉 시 구 분","q":"아홉 시 구 분. 이제 돌아서기엔 너무 늦었다. 너무 늦었고, 너무 위험했다.","title":"떠나는 꿈들","author":"루퍼트 톰슨","ampm":"pm","kind":"역"}],"21:10":[{"t":"아홉 시 십 분","q":"그녀는 거의 매일 밤 아홉 시 뉴스가 끝난 직후에 수영을 즐겼다. 그녀를 아는 사람이라면 다 아는 사실이었다. 그리고 일요일 뉴스는 아홉 시 십 분이었다.","title":"책략과 욕망","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:11":[{"t":"아홉 시 십일 분","q":"새 자물쇠는 에이거의 손길에 쉽게 굴복했다. 아홉 시 십일 분, 그들은 격자문을 열고 와인 저장고 안으로 들어섰다. 곧바로 열쇠를 찾기 시작했다.","title":"대열차 강도","author":"마이클 크라이튼","ampm":"pm","kind":"역"}],"21:12":[{"t":"아홉 시 십이 분","q":"그날 밤 하늘엔 유리처럼 맑은 보름달이 떠 있었고, 아홉 시 십이 분, 낡은 러시아 로켓이 대기권에 재진입하며 긴 불꼬리를 끄는 혜성처럼 하늘을 가로질러 폭발했다.","title":"악마의 다리 아래","author":"로레스 앤 화이트","ampm":"pm","kind":"역"}],"21:13":[{"t":"아홉 시 십삼 분","q":"오버해머 저택은 이제 썩어가고 있었다. 창문은 판자로 막혔고, 벽은 위층의 무게에 무너지지 않도록 사슬로 감겨 있었다. 시계탑은 언제나 아홉 시 십삼 분을 가리켰다, 쥐와 박쥐와 광인들의 시간, 딥게이트의 평민들이 상상한 온갖 악귀와 악마의 시간을.","title":"스카 나이트","author":"앨런 캠벨","ampm":"pm","kind":"역"}],"21:14":[{"t":"아홉 시 십사 분","q":"그는 밀리의 손가락에 반지를 끼우려 애쓰고 있다는 것을 어렴풋이 의식했다. 보석상에서만큼 잘 맞지 않았다. 에즈라는 에나멜 울타리 같은 이를 드러내며 씩 웃고 있었다. 아홉 시 십사 분이었다. 캐럴은 거실을 미션 양식으로 꾸미고 싶다고 말했었다.","title":"안개","author":"윌리엄 더들리 펠리","ampm":"pm","kind":"역"}],"21:15":[{"t":"아홉 시 십오 분","q":"내가 집을 나서 공원을 가로질러 옥스퍼드 거리를 지나 베이커 스트리트로 향한 것은 아홉 시 십오 분이었다.","title":"셜록 홈즈의 모험","author":"아서 코난 도일","ampm":"pm","kind":"역"}],"21:16":[{"t":"아홉 시 십육 분","q":"레너드는 시계를 확인했다, 아홉 시 십육 분. 그는 컴퓨터로 가서 AOL 계정에 접속했다. 이메일을 보내지 말라는 지시를 받았지만, 그는 존에게 메시지를 썼다. '전화할 거야?' 그러고는 로그아웃했다.","title":"레프리브","author":"제임스 한 매트슨","ampm":"pm","kind":"역"}],"21:17":[{"t":"아홉 시 십칠 분","q":"일요일 저녁 아홉 시 십칠 분, 앙비플란. 한 남자가 미용실 밖에서 목격된다. 그는 얼굴과 손을 유리에 바짝 붙이고 있으며, 몹시 취한 듯 보인다.","title":"렛 미 인","author":"욘 아이비데 린드크비스트","ampm":"pm","kind":"역"}],"21:18":[{"t":"아홉 시 십팔 분","q":"만약 그녀의 아파트에 누군가 있다면 마찬가지였다. 그럴 경우 그는 그저 지나가다가 그녀의 매력적인 집을 알아보고 들렀다고 말할 참이었다. 마틴 씨가 열두 번가로 접어든 것은 아홉 시 십팔 분이었다.","title":"유리한 자리","author":"제임스 서버","ampm":"pm","kind":"역"}],"21:19":[{"t":"아홉 시 십구 분","q":"멘델스존의 저주받은 바이올린 협주곡 1악장은 약 십이 분 삼십 초 길이였다. 그 유대인은 아홉 시 십구 분에 연주를 시작했었다.","title":"머니 머니 머니","author":"에드 맥베인","ampm":"pm","kind":"역"}],"21:20":[{"t":"아홉 시 이십 분","q":"아홉 시 이십 분, 그는 텔레비전을 끄고 몇 분간 쟁반을 무릎에 얹은 채 꼼짝 않고 앉아 있었다. 그는 자신이 어느 현대 회화 속의 인물, 쟁반을 든 남자처럼 보이리라 생각했다, 평범한 배경 속에서 뻣뻣하게 굳어버린, 어딘가 불길한 모습으로.","title":"책략과 욕망","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:21":[{"t":"아홉 시 이십일 분","q":"이 목격자들은 일 년도 더 전 구월 이십삼일 밤, 여덟 시 십칠 분부터 아홉 시 이십일 분 사이에 일어난 온갖 세세한 일을 놀라울 만큼 정확히 기억해냈다. 하지만 그로부터 십 분 전이나 십 분 후, 혹은 지난 금요일 저녁 아홉 시에 자신이 어디서 무얼 했는지는 도무지 떠올리지 못했다.","title":"머커","author":"에드거 라이스 버로스","ampm":"pm","kind":"역"}],"21:22":[{"t":"아홉 시 이십이 분","q":"이틀 후, 이월 이일 예루살렘 시각 아홉 시 이십이 분, 도미니언은 배너미어와 지구 사이의 세계 스물두 곳을 동시에 대대적으로 공격했다.","title":"무한한 날","author":"크리스 월리","ampm":"pm","kind":"역"}],"21:23":[{"t":"아홉 시 이십삼 분","q":"아버지가 역으로 마중 나오셨고, 개가 나를 반기려 뛰어올랐다가 놓치고는 아홉 시 이십삼 분발 버밍엄 급행열차 앞에 하마터면 넘어질 뻔했다.","title":"에이드리언 몰의 비밀일기","author":"수 타운센드","ampm":"pm","kind":"역"}],"21:24":[{"t":"아홉 시 이십사 분","q":"결혼의 사망 시각은 언제로 판정해야 할까? 남들에겐 어려운 질문이겠지만, 운 좋게도 내 것엔 시간이 찍혀 있다. 아홉 시 이십사 분.","title":"배스 하우스","author":"P.J. 버넌","ampm":"pm","kind":"역"}],"21:25":[{"t":"아홉 시 이십오 분","q":"책상 위 전화가 울려 그를 놀라게 했다. 아홉 시 이십오 분이었다. 자신이 그렇게 오랫동안 멍하니 앉아 있었는지 그는 깨닫지 못하고 있었다.","title":"등대","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:26":[{"t":"아홉 시 이십육 분","q":"'테러리스트들은,' 그가 말을 꺼냈다, '어젯밤 아홉 시 이십육 분에 국경을 넘었습니다. 여권 네 개가 출입국 관리에게 도장을 받으려 제출되었습니다. 셋은 스웨덴, 하나는 이라크 국적이었습니다.'","title":"도둑들 사이의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:27":[{"t":"아홉 시 이십칠 분","q":"전화가 걸려온 것은 아홉 시 이십칠 분, 어둠이 하늘 대부분을 뒤덮은 뒤였다. 서쪽 지평선을 따라 빛바랜 푸른 띠 하나만이 남아, 빛의 기억처럼 얼마 남지 않은 채 곧 사라질 참이었다.","title":"퍼가토리 리지","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"21:28":[{"t":"아홉 시 이십팔 분","q":"통화는 아홉 시 이십팔 분에 이루어졌다. 이는 또 하나의, 그것도 중요한 증거였다. 그것은 처음부터 그들이 의심했던 사실, 즉 살인자가 세인트 앤셀름 안에 있었다는 것을 입증했다.","title":"성직자의 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:29":[{"t":"아홉 시 이십구 분","q":"아홉 시 이십구 분, 가장 늦게 성구실에 들어선 라파엘의 눈에 들어온 것은 예배를 앞두고 겉옷을 벗고 있는 세바스천 신부뿐이었다.","title":"성직자의 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:30":[{"t":"아홉 시 반","q":"아홉 시 반, 잠자리에 들 것.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"21:31":[{"t":"아홉 시 삼십일 분","q":"아홉 시 삼십일 분에 전화벨이 울렸다. 팻은 얼른 수화기를 들었고, 반대편에서 들려온 레비 씨의 목소리에 안도했다.","title":"너는 후회할 틈도 없을 것이다","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:32":[{"t":"아홉 시 삼십이 분","q":"아홉 시 삼십이 분, 벤살렘 타운십 요양원으로 돌아가는 제럴딘의 버스가 출발할 예정이었다. 자존심 때문에 그녀는 삼십 분 넘게 걸리는 길인데도 아침까지 머무르길 거절했다.","title":"월요일에 팔리다","author":"크리스티나 맥모리스","ampm":"pm","kind":"역"}],"21:33":[{"t":"열 시 이십칠 분 전","q":"여름 별채에 도착했을 때는 열 시 이십칠 분 전쯤이었을 것이다. 랠프가 나를 기다리고 있었다.","title":"애크로이드 살인 사건","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"21:34":[{"t":"아홉 시 삼십사 분","q":"\"고맙네, 26일 아홉 시 삼십사 분에 도착할 예정\"이라는 답장을 보냈더니, 세 시간 뒤 \"환영하네, 3번 리핑길 난로를 가져오게\"라는 회신이 왔다. 내용과 달리 왠지 서늘한 느낌을 주는 당혹스러운 지시였다.","title":"모래사장의 수수께끼","author":"어스킨 차일더스","ampm":"pm","kind":"역"}],"21:35":[{"t":"아홉 시 삼십오 분","q":"대령은 그쪽으로 달려가 차에 올라타고는 로열 가든 호텔의 진입로를 재빨리 내려가 켄싱턴 팰리스 가든스로 좌회전했다. 애덤은 시계를 확인했다. 아홉 시 삼십오 분.","title":"명예의 문제","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:36":[{"t":"아홉 시 삼십육 분","q":"아홉 시 삼십육 분, 교통 흐름은 이제 순조로웠다. 그는 시 영화·방송국의 촬영을 지휘하는 경관에게 다가갔다.","title":"도둑들 사이의 의리","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:37":[{"t":"21시 37분","q":"\"어젯밤 몇 시에 일어난 일입니까?\" \"999 신고는 21시 37분에 접수되었습니다,\" 그가 수첩을 확인하며 대답했다.","title":"이탈의 혈통","author":"스티븐 코일","ampm":"pm","kind":"역"}],"21:38":[{"t":"아홉 시 삼십팔 분","q":"아홉 시 삼십팔 분, 웨이터가 돌아와 치즈와 살라미, 정어리를 한 접시 더 권했다. 파운드를 엔화로 환전하던 요시기 씨는 몹시 어리둥절한 표정으로 영국령 온두라스의 수출 규모가 그렇게 클 줄 몰랐다고 말했다.","title":"돼지와 후추","author":"데이비드 풋맨","ampm":"pm","kind":"역"}],"21:39":[{"t":"열 시 이십일 분 전","q":"플레치는 시계를 보았다. 열 시 이십일 분 전이었다. 그는 무의식적으로 경찰의 신속함을 가늠해 보았다.","title":"자백해, 플레치","author":"그레고리 맥도널드","ampm":"pm","kind":"역"}],"21:40":[{"t":"아홉 시 사십 분","q":"휘슬러의 네 번째 희생자는 열다섯 살 여덟 달 나흘 된 발레리 미첼로, 가장 어렸다. 그녀는 이스트헤이븐에서 콥스 마시로 가는 아홉 시 사십 분 버스를 놓쳐서 목숨을 잃었다.","title":"책략과 욕망","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:41":[{"t":"21시 41분","q":"\"다시 말해 보게, 경사,\" 워런이 물었다. 처음부터 정확히 들었다고 확신했지만. \"왕실 우편 배달 밴이 21시 41분에 스포츠센터 남서쪽 약 1.2킬로미터 지점의 교통 카메라를 지나쳤습니다.\"","title":"불 없이 연기 없다","author":"폴 깃샴","ampm":"pm","kind":"역"}],"21:42":[{"t":"아홉 시 사십이 분","q":"랭던은 미키마우스 손목시계를 들여다보았다. 밤 아홉 시 사십이 분.","title":"로스트 심벌","author":"댄 브라운","ampm":"pm","kind":"역"}],"21:43":[{"t":"아홉 시 사십삼 분","q":"아홉 시 사십삼 분. \"우린 함께 일하게 될 거야, 애송이,\" 도어 페레츠가 말했다. \"우린 한 팀이니까.\" 그는 희끗희끗한 갈기 같은 머리를 쓸어 넘기고는 조르주 르파르주 옆으로 다가갔다.","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"21:45":[{"t":"아홉 시 사십오 분","q":"그러나 출생과 죽음, 우주의 종말처럼 인간이 알 수 없는 어떤 이유로, 코디 멘호프의 가게는 목요일 아홉 시 사십오 분에 문을 닫혀 있었다.","title":"리븐 록","author":"T.C. 보일","ampm":"pm","kind":"역"}],"21:46":[{"t":"아홉 시 사십육 분","q":"아홉 시 사십육 분. \"하지만 아직 하기로 한 궤적 기본값 분석을 마무리하는 중이라서요,\" 르파르주가 시간을 끌어보려는 듯 도어 페레츠에게 말했다. \"절반밖에 아직-\"","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"21:47":[{"t":"아홉 시 사십칠 분","q":"\"맞아... 아홉 시 사십칠 분과 사십팔 분. 그들은 같은 시각에 죽었어.\" \"그건 같은 시각이 아니야, 해리.\" 나는 조바심을 내며 손을 내저었다.","title":"피의 의식","author":"짐 부처","ampm":"pm","kind":"역"}],"21:48":[{"t":"아홉 시 사십팔 분","q":"\"이건 금요일, 10월 15일 아홉 시 사십팔 분에 이노선트 하우스, 이노선트 워크, 와핑에서 제가 처음 본 시신입니다.\"","title":"원죄","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:49":[{"t":"열 시 십일 분 전","q":"\"TIMETRV가 언제 링크됐는지 봐.\" 나는 목록을 읽었다. \"5월 15일, 열 시 십일 분 전.\" \"그래서?\" \"이번엔 오브젝트 파일이 언제 생성됐는지 봐.\" 깁의 눈이 번뜩였다.","title":"해커","author":"맬로리 블랙먼","ampm":"pm","kind":"역"}],"21:50":[{"t":"아홉 시 오십 분","q":"그는 선실 문을 잠그고 안으로 들어서자마자 침대에 쓰러지듯 누웠다. 일은 끝났다. 시계를 확인했다. 아홉 시 오십 분. 앞으로 긴 기다림이 남아 있었다.","title":"바라는 것을 조심하라","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:51":[{"t":"아홉 시 오십일 분","q":"아홉 시 오십일 분. ...여보세요, 소호. 블루버드가 부탁이 있어. 서보를 켜줄 수 있겠나?","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"21:52":[{"t":"아홉 시 오십이 분","q":"아홉 시 오십이 분. \"조르주는 천재야,\" 그녀가 돌아서며 말했다. \"하지만 이건 실제로 불가능할지도 몰라. 지금까지 아무도 해낸 적 없거든.\"","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"21:53":[{"t":"열 시 칠 분 전","q":"사람들은 그녀에게 그런 식으로 말하지 않았다. 그녀의 아버지는 변호사였다. 열 시 칠 분 전이었다.","title":"캐리","author":"스티븐 킹","ampm":"pm","kind":"역"}],"21:54":[{"t":"아홉 시 오십사 분","q":"대니는 호텔을 지나 빠르게 걸으며 모든 교차로를 확인하다가, 마침내 머리 위 돌판에 큼지막하게 새겨진 아가일 스트리트라는 이름을 발견했다. 거리로 들어서며 시계를 확인했다. 아홉 시 오십사 분.","title":"출생의 죄수","author":"제프리 아처","ampm":"pm","kind":"역"}],"21:55":[{"t":"열 시 오 분 전","q":"열 시 오 분 전쯤, 마사는 스토브 옆에 우유 냄비를 올려 천천히 데우기 시작했다. 마틴게일에서는 일찍 잠자리에 들기 위해 거의 매일 밤 이렇게 했다.","title":"그녀의 얼굴을 덮어라","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"21:56":[{"t":"열 시 사 분 전","q":"그는 시계를 꺼내 리틀 빌리의 손이 외투를 열어젖힌 것을 알아챘다. 성냥을 켜보니 열 시 사 분 전, 다음 모퉁이까지 사 분이 남아 있었다. 이 분이면 갈 수 있었지만, 그래도 움직일 시간이었다.","title":"불의 산","author":"노먼 스프링어","ampm":"pm","kind":"역"}],"21:57":[{"t":"아홉 시 오십칠 분","q":"코크의 눈에 띈 목록 전체에서 유독 두드러진 것은 오로라 시장 윌프레드 리핀스키의 집에서 걸려온 두 통의 전화였다. 하나는 아홉 시 오십칠 분, 다른 하나는 밤 열 시 사십일 분이었다. 리핀스키에게 발할라 파티를 아는 십 대 자녀가 있었다면 이상할 것 없었겠지만, 그의 자녀들은 이미 오래전에 장성해 떠난 뒤라 코크는 의아했다.","title":"블러드 할로우","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"21:58":[{"t":"21시 58분","q":"끝에서 두 번째, 삽입된 시계가 21시 57분에서 21시 58분으로 바뀐다. 네이피어의 눈이 감기고, 갓 떠오른 햇살이 오래된 참나무 사이로 비스듬히 비쳐 사라진 강 위에 내려앉는다. 봐, 조, 왜가리야.","title":"클라우드 아틀라스","author":"데이비드 미첼","ampm":"pm","kind":"역"}],"21:59":[{"t":"열 시 일 분 전","q":"열 시 일 분 전, 하늘이 헬리콥터 로터 소리로 가득 찼다. 갈라 행사장에서처럼 세 대의 헬기가 요인들을 실어 왔다. 이번엔 에니그마 바빌론 대표는 없었고, 포르투나토와 마지막으로 카르파티아가 도착했다.","title":"암살자들","author":"팀 라헤이, 제리 B. 젠킨스","ampm":"pm","kind":"역"}],"22:01":[{"t":"열 시 일 분","q":"열 시 일 분, 자일스는 마지막 악수를 나누고 술이 간절해 부둣가 인부들과 어울리려 로드 넬슨으로 걸어갔다.","title":"칼보다 강한 펜","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:02":[{"t":"밤 열 시 이 분","q":"이제 밤 열 시 이 분이었다. 그에게 남은 시간은 두 시간이 채 되지 않았다.","title":"로스트 심벌","author":"댄 브라운","ampm":"pm","kind":"역"}],"22:03":[{"t":"밤 열 시 삼 분","q":"밤 열 시 삼 분, 안내원들이 문을 열어젖히고 나는 관객들이 흥분한 채 밤 속으로 쏟아져 나오는 익숙한 장면을 지켜본다.","title":"다크 레이크","author":"세라 베일리","ampm":"pm","kind":"역"}],"22:04":[{"t":"열 시 사 분","q":"1955년 11월 12일 토요일, 힐 밸리 법원 시계탑에 번개가 내리쳐 1.21기가와트의 에너지가 쏟아졌다. 그날 이후 시계 문자반은 열 시 사 분에 멈춰 있었다.","title":"백 투 더 퓨처: 시간을 가로질러","author":"마크 수머락","ampm":"pm","kind":"역"}],"22:05":[{"t":"열 시 오 분","q":"\"내일 밤 열 시 오 분까지 내가 알아야 할 모든 걸 말하지 않으면\" 그는 손목시계를 보며 말했다, \"너는 처형당할 것이다. 너와 그 세 배신자 전부.\"","title":"배신자들 사이에서","author":"마거릿 피터슨 해딕스","ampm":"pm","kind":"역"}],"22:06":[{"t":"열 시 육 분","q":"뭐든 알게 되면 바로 알려줘. 쿼일은 싸늘한 부엌에서 몸을 떨었다. 시계는 열 시 육 분을 가리켰다. 바다 소리는 들리지 않았다.","title":"시핑 뉴스","author":"애니 프루","ampm":"pm","kind":"역"}],"22:07":[{"t":"열 시 칠 분","q":"우회 표지판을 따라가라고 그는 그녀를 쳐다보지도 않은 채 말했다. 그녀는 계기판 시계를 흘끗 보았다. 열 시 칠 분이었다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:08":[{"t":"열 시 팔 분","q":"달글리시 총경은 죽은 소녀의 옷가지를 살피다 몸을 돌렸다. 침대 발치와 옷장 문 사이에 큰 키가 불편하게 끼었다. 그는 손목시계를 보았다. 열 시 팔 분이었다.","title":"나이팅게일의 수의","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"22:09":[{"t":"열 시 구 분","q":"시각은 열 시 구 분이었다. 순전한 흥분에 이가 딱딱 부딪히기 시작했다.","title":"조나 앤 컴퍼니","author":"돈포드 예이츠","ampm":"pm","kind":"역"}],"22:10":[{"t":"열 시 십 분","q":"열 시쯤 첫눈이 내리기 시작해 질의 팔에 내려앉았다. 열 시 십 분이 되자 눈은 제법 굵어져 있었다. 이십 분이 지나자 땅은 눈에 띄게 하얘졌다.","title":"은의자","author":"C.S. 루이스","ampm":"pm","kind":"역"}],"22:11":[{"t":"밤 열 시 십일 분","q":"그러나 호텔 방문을 두드리는 소리가 나자 그의 모든 감각이 곤두섰다. 그는 시계를 보았다. 밤 열 시 십일 분이었다.","title":"모든 악의 근원?","author":"레이 키팅","ampm":"pm","kind":"역"}],"22:12":[{"t":"열 시 십이 분","q":"전화가 열 시 십이 분에 울렸다. 그는 수화기를 잡았고, 즉시 지역 당 의장의 목소리임을 알아챘다. \"안녕하십니까, 피터.\"","title":"칼보다 강한 펜","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:13":[{"t":"열 시 십삼 분","q":"\"열 시 십삼 분이야.\" 클랜시가 알렸다. \"이 분만 더 있으면\" \"출발 시각이군.\" 내가 말했다.","title":"앤섬 스프린터스","author":"레이 브래드버리","ampm":"pm","kind":"역"}],"22:14":[{"t":"열 시 십사 분","q":"쇼핑백들은 무겁고 인상적이어서 중국 여자들이 그 무게에 서로에게 살짝 몸을 기울이게 만들었다. 열 시 십사 분쯤이라 해두자.","title":"인피니트 제스트","author":"데이비드 포스터 월리스","ampm":"pm","kind":"역"}],"22:15":[{"t":"열 시 십오 분","q":"아, 열 시 십오 분이다. 십오 분 후면 뉴스나이트다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:16":[{"t":"밤 열 시 십육 분","q":"텔레노르 기록에 따르면, 그러니까 문을 열고 들어가자마자 밤 열 시 십육 분에 나에게 메시지를 남겼을 때, 너는 뭔가의 단서를 잡았다는 사실에 꽤 흥분해 있던 게 분명했다.","title":"레드브레스트","author":"요 네스뵈","ampm":"pm","kind":"역"}],"22:17":[{"t":"밤 열 시 십칠 분","q":"밤 열 시 십칠 분. 카세트가 들어가지 않는다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:18":[{"t":"밤 열 시 십팔 분","q":"밤 열 시 십팔 분. 아. 델마와 루이스가 저 안에 들어 있다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:19":[{"t":"밤 열 시 십구 분","q":"밤 열 시 십구 분. 델마와 루이스가 나오지 않는다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:20":[{"t":"밤 열 시 이십 분","q":"연구소 사무실 벽시계가 밤 열 시 이십 분을 지나쳤다. 헬렌 포메로이와 에릭 마이어 목사는 책상 너머로 서로를 바라보았다. 그들은 오늘 벌어진 기이한 사건들을 막 이야기하던 참이었다.","title":"커시드럴","author":"레이 키팅","ampm":"pm","kind":"역"}],"22:21":[{"t":"밤 열 시 이십일 분","q":"밤 열 시 이십일 분. 미친 듯이 버튼을 모두 눌러본다. 카세트가 나왔다가 다시 들어간다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:22":[{"t":"열 시 이십이 분","q":"이제 겨우 열 시 이십이 분이었다. 소대를 떠난 지 삼십 분도 채 되지 않았지만, 중대 보급소에 불길이 치솟는 와중이라 두 사람 모두 지체 없이 부대로 돌아가야 한다는 걸 절실히 알고 있었다.","title":"다키스트 아워","author":"제임스 홀랜드","ampm":"pm","kind":"역"}],"22:23":[{"t":"밤 열 시 이십삼 분","q":"가면이 어두운 진열장 속에서 그를 노려보았다. 그는 서둘러 다음 관측소로 갔고, 그곳에서 상자의 열쇠를 돌렸다. 상자는 시각을 기록했다, 밤 열 시 이십삼 분.","title":"렐릭","author":"더글러스 프레스턴, 링컨 차일드","ampm":"pm","kind":"역"}],"22:24":[{"t":"열 시 이십사 분","q":"그럼에도 나는 그녀를 사랑한다. 메이페어의 저녁 파티에서 처음 그녀를 본 순간부터, 1862년 12월 24일 목요일 저녁 정확히 열 시 이십사 분부터 나는 그녀를 사랑했다.","title":"미스 커루","author":"아멜리아 B. 에드워즈","ampm":"pm","kind":"역"}],"22:25":[{"t":"열 시 이십오 분쯤","q":"벌티태프트 부인은 항상 열 시에 뜨거운 우유를 올려놓는다. 열 시 이십오 분쯤 우리는 샐리가 자기 방으로 머그잔을 들고 올라가는 걸 보았다.","title":"그녀의 얼굴을 덮어라","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"22:26":[{"t":"밤 열 시 이십육 분","q":"시돈스는 서류를 뒤적이다 찾던 문서를 발견했다. 그는 판사를 올려다보며 말했다. \"확인해 드리겠습니다, 판사님. 사망 증명서는 1951년 7월 26일 목요일 밤 열 시 이십육 분에 서명되었습니다.\"","title":"베스트 켑트 시크릿","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:27":[{"t":"열 시 이십칠 분","q":"하코트 씨는 열 시 이십칠 분에 이상하리만치 갑작스레 잠에서 깼는데, 묘하게도 바로 그 순간 집사가 위스키와 브랜디, 사이펀, 잔, 비스킷을 실은 쟁반을 든 하인 둘을 데리고 들어왔다.","title":"잉글랜드, 그들의 잉글랜드","author":"A.G. 맥도넬","ampm":"pm","kind":"역"}],"22:28":[{"t":"열 시 이십팔 분","q":"화요일 밤 열 시 이십팔 분, AP통신은 수십 년 만에 가장 치열했던 뉴욕시 시장 선거를 오맬리 시의원의 승리로 발표한다.","title":"상심한 채 사냥하기의 위험","author":"마리 파사난트","ampm":"pm","kind":"역"}],"22:29":[{"t":"열 시 이십구 분","q":"뭔가 말해야 할 때조차 적당한 말이 도무지 나오지 않았다. 머뭇거릴 때마다, 하려던 말을 삼킬 때마다, 사촌은 살짝 어리둥절한 표정으로 나를 바라보았다. 그의 왼쪽 귀가 살짝 내 쪽으로 기울었다. \"지금 몇 시야?\" 그가 물었다. \"열 시 이십구 분.\" 내가 대답했다.","title":"눈먼 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"22:30":[{"t":"열 시 반","q":"퀴름의 시계는 스물네 종의 꽃을 골라 심은 둥근 화단일 뿐이었다. 수전이 뛰어 지나칠 때 자주색 메꽃은 벌어지고 사랑앓이꽃은 오므라들고 있었으니, 대략 열 시 반이라는 뜻이었다.","title":"소울 뮤직","author":"테리 프래쳇","ampm":"pm","kind":"역"}],"22:31":[{"t":"오후 열 시 삼십일 분","q":"오후 열 시 삼십일 분. 좋아, 좋아. 침착하자. 페니 허즈번즈보스워스의 석면 백혈병 기사는 아직 안 나왔다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:32":[{"t":"열 시 삼십이 분","q":"버스가 마침내 모습을 드러낸 것은 열 시 삼십이 분이었다. 새로 나온 차종이라 예전에 고등학교 다닐 때 타던 버스와는 달랐다.","title":"눈먼 버드나무와 잠자는 여자","author":"무라카미 하루키","ampm":"pm","kind":"역"}],"22:33":[{"t":"열 시 삼십삼 분","q":"그는 손목시계를 보았다. 열 시 삼십삼 분. 그녀가 매일 밤 아홉 시가 조금 지나 수영을 하러 나간다는 이야기를 누구에게 언제 들었는지는 기억나지 않았다.","title":"수단과 욕망","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"22:34":[{"t":"열 시 반이 막 지나서","q":"\"실례지만 부인, 몇 시에 잠자리에 드셨습니까?\" \"열 시 반이 막 지나서였어요.\"","title":"나일 강의 죽음","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"22:35":[{"t":"열 시 삼십오 분","q":"\"연주회가 몇 시에 끝나죠?\" 그가 처음 눈에 띈 제복 차림의 직원에게 물었다. \"열 시 삼십오 분입니다, 선생님. 하지만 차를 거기 세워 두시면 안 됩니다.\"","title":"까마귀가 날아가듯","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:36":[{"t":"밤 열 시 삼십육 분","q":"우리의 이륙 시각은 밤 열 시 삼십육 분이었고, 별빛 쏟아지는 밤하늘로 무거운 비행기를 밀어 올리는 동안 손과 배 속은 얼음장처럼 차가웠다.","title":"에어 브리지","author":"해먼드 이네스","ampm":"pm","kind":"역"}],"22:37":[{"t":"오후 열 시 삼십칠 분","q":"그날 밤 오후 열 시 삼십칠 분, 어둠 속 오브스큐리티에서 화염이 크립스를 덮쳤다. 그는 죽기 직전 골디락스를 불러 '구멍투성이'라는 말을 남겼다.","title":"네 번째 곰","author":"재스퍼 포드","ampm":"pm","kind":"역"}],"22:38":[{"t":"열 시 삼십팔 분","q":"누군가 전화를 끊는 딸깍 소리뿐이었다. 통화는 전날 밤 열 시 삼십팔 분에 끊겼다. 잭은 그것이 자신이 집에 있는지 확인하려는 전화였으리라 의심치 않았다.","title":"킬 존","author":"크리스 라이언","ampm":"pm","kind":"역"}],"22:39":[{"t":"오후 열 시 삼십구 분","q":"4월 5일 일요일, 오후 열 시 삼십구 분. \"경호원을 데려왔어야 했나 싶었어요.\" 그는 가죽 재킷을 어깨에 걸친 채 문을 성큼 들어서며 말했다.","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"22:40":[{"t":"열 시 사십 분","q":"그녀는 열 시 사십 분에 침대에 들었지만 한 시간 이상 계속 잠들지 못했다. 이따금 텔레비전을 켜서 레바논어로 더빙된 스파게티 웨스턴을 보았다.","title":"도둑들의 명예","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:41":[{"t":"열 시 사십일 분","q":"윌리엄은 토니 블레어와 마이클 헤슬타인의 트라이던트 논쟁을 듣고 있었는데, 열 시 사십일 분 서머스의 거실 불이 꺼졌다. 그는 라디오를 끄고 수첩에 한 줄을 더 적었다.","title":"못 본 척","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:42":[{"t":"열한 시 십팔 분 전","q":"\"자니슨이 목에 칼이 꽂힌 채 무대에 쓰러진 정확한 시각을 확인했습니다. 열한 시 십팔 분 전이었습니다.\"","title":"괌의 서쪽","author":"라울 휘트필드","ampm":"pm","kind":"역"}],"22:43":[{"t":"오후 열 시 사십삼 분","q":"세바스천은 손목시계를 확인했다. 오후 열 시 사십삼 분. \"그럼 그가 아직 깨어 있는지 가서 알아보자.\"","title":"소원을 빌 때는 조심하라","author":"제프리 아처","ampm":"pm","kind":"역"}],"22:44":[{"t":"열 시 사십사 분","q":"\"레이디 휘슬다운의 정체를 밝히는 사람에게 천 파운드를 주겠다\"는 말이 나왔을 때, 시계는 열 시 사십사 분을 가리키고 있었다.","title":"브리저턴 씨와의 로맨스","author":"줄리아 퀸","ampm":"pm","kind":"역"}],"22:45":[{"t":"오후 열 시 사십오 분","q":"오후 열 시 사십오 분. 세상에. 내가 비디오를 프로그래밍할 줄 모른다고 하자 대니얼은 자지러지게 웃었다. 자기가 대신 해 주겠다고 했다. 그래도 엄마를 위해 최선을 다한 셈이다. 친구가 텔레비전에 나오다니 흥분되고 뿌듯한 일이다.","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"22:46":[{"t":"열한 시 십사 분 전","q":"올리브: [손목시계를 들여다보며] 열한 시 십사 분 전이야. 캐서린: 올리브, 올리브! 올리브: 그냥 몇 시인지 보고 싶었어. 억지로 자려 해도 도무지 잠이 안 와. 승전보 있어? [캐서린이 고개를 젓는다] 아, 저녁 신문에 실리게 해 달라고 특별히 기도했는데.","title":"군중","author":"존 골즈워디","ampm":"pm","kind":"역"}],"22:47":[{"t":"밤 열 시 사십칠 분","q":"화면 속에서 마지막 관객들이 하나둘 흩어지고, 시각 표시가 밤 열 시 사십칠 분으로 바뀌자 아무도 남아 있지 않았다.","title":"어두운 호수","author":"세라 베일리","ampm":"pm","kind":"역"}],"22:48":[{"t":"열 시 사십팔 분","q":"\"글쎄요, 그건 모르겠군요.\" 새터스웨이트 씨가 흥이 나서 말을 이었다. \"작년 여름에 잠깐 그곳에 내려가 있었죠. 시내와 오가기에 꽤 편리하더군요. 다만 기차가 한 시간에 한 대뿐이라, 워털루발 열차는 매시 사십팔 분에 있으니 열 시 사십팔 분 차가 되는 셈이죠.\"","title":"하늘의 징표","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"22:49":[{"t":"밤 열 시 사십오 분을 훌쩍 넘긴","q":"밤 열 시 사십오 분을 훌쩍 넘긴 시각이다. 개 목줄이 쉭 소리를 내며 형광빛 줄 끝까지 미끄러져 나가 문 안쪽에 서 있는 렌츠 앞 몇 걸음 거리에서 개를 멈춰 세운다. 렌츠는 개에게 옹알이하듯 말을 거는 자세로 살짝 몸을 기울이고 있다.","title":"인피니트 제스트","author":"데이비드 포스터 월리스","ampm":"pm","kind":"역"}],"22:50":[{"t":"오후 열 시 오십 분","q":"오후 열 시 오십 분. 이 일기를 쓰는 습관은 오늘 아침 적었던 그 과학적인 사고방식에서 비롯된 것이리라. 나는 인상이 생생할 때 그것을 기록해 두는 편을 좋아한다.","title":"기생체","author":"아서 코난 도일","ampm":"pm","kind":"역"}],"22:51":[{"t":"열한 시 구 분 전","q":"열한 시 구 분 전, 길 건너 집의 문이 열렸다. 나는 침대에 무릎을 세우고 앉아 창밖을 내다보았다. 구스타브센 부인이었다. 그녀는 쓰레기봉투를 손에 들고 진입로를 가로질러 걷고 있었다.","title":"나의 투쟁 1","author":"칼 오베 크나우스고르","ampm":"pm","kind":"역"}],"22:52":[{"t":"열한 시 팔 분 전","q":"이제 도박꾼의 열기가 롤리의 눈에 서렸다. 얼굴은 죽은 사람처럼 창백했지만 손은 태연하다 못해 무심할 만큼 침착하게 패를 던졌다. 열한 시 팔 분 전, 마침내 운이 그에게 돌아섰고 판돈은 다시 쌓여 갔다.","title":"북쪽의 빛","author":"길버트 파커","ampm":"pm","kind":"역"}],"22:53":[{"t":"열한 시 칠 분 전","q":"갈 때마다 당신은 바 끝자리에 혼자 앉아 커피 잔 위로 몸을 웅크리고 있었다. 그리고 매일 밤 정확히 열한 시 칠 분 전이면 바 위에 돈을 던져 놓고 코트를 움켜쥔 채 최대한 빨리 문을 나섰다.","title":"그게 전부야","author":"켈리 크리그시그먼, 데이브 아이세이","ampm":"pm","kind":"역"}],"22:54":[{"t":"열 시 오십사 분","q":"시내 전화번호부에 오즈가드, 램지 지 항목이 있었다. 콜로라도는 열 시 오십사 분이었지만, 이 시각이 오히려 통화를 더 다급하고 그럴듯하게 만들어 줄지도 몰랐다.","title":"벨로시티","author":"딘 쿤츠","ampm":"pm","kind":"역"}],"22:55":[{"t":"열한 시 오 분 전","q":"워그레이브 판사가 말했다. \"이제 열한 시 오 분 전이군요. 브렌트 양을 우리 모임에 불러야 할 것 같습니다.\"","title":"그리고 아무도 없었다","author":"애거사 크리스티","ampm":"pm","kind":"역"}],"22:56":[{"t":"오후 열 시 오십육 분","q":"손목시계는 오후 열 시 오십육 분을 가리켰다. 그렇다면 나는 이십 분 동안 정신을 잃었던 셈이다. 이십 분간의 잠, 딱 알맞은 낮잠이었다. 그사이 나는 조직 하나를 놓쳤고 팔천 달러를 잃었다.","title":"안녕 내 사랑","author":"레이먼드 챈들러","ampm":"pm","kind":"역"}],"22:57":[{"t":"밤 열 시 오십칠 분","q":"그들은 엔진을 끄고 어선단과 두아르느네 사이 어디쯤, 약 오 마일 떨어진 바다 위에 나란히 몇 분간 떠 있었다. 밤 열 시 오십칠 분에 그들은 주엔진을 다시 켜고 작업을 시작하려 방향을 틀었다.","title":"극비","author":"네빌 슈트","ampm":"pm","kind":"역"}],"22:58":[{"t":"열 시 오십팔 분","q":"\"그럼 언제 떠나는 거죠?\" \"일요일 밤에요. 제가 노리치까지 태워다 드리면 여덟 시 삼십 분 기차를 타고 열 시 오십팔 분에 리버풀 스트리트에 도착할 거예요. 딸이 마중 나올 거고요.\"","title":"수단과 욕망","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"22:59":[{"t":"열한 시 일 분 전","q":"그들은 정확히 열한 시 일 분 전 라우더스 앞에 차를 세웠다. 사람들이 빠져나오고 있었는데 저녁을 일찍 접어야 했던 것에 다들 흡족한 표정은 아니었다. 하지만 투덜거림은 조용했고, 그마저도 안전하게 거리로 나선 뒤에야 시작되었다.","title":"컴플레인츠","author":"이언 랜킨","ampm":"pm","kind":"역"}],"23:00":[{"t":"열한 시","q":"열한 시가 되자 개들은 디얼리 부인의 손에 마지막 입맞춤을 하고 디얼리 씨를 마지막 산책에 데리고 나갔다. 페르디타도 함께했다. 그날 저녁 그녀는 퐁고와 미시스가 자기 사람들과 단둘이 있고 싶어 할지도 모른다는 생각에 유모들과 시간을 보낸 터였다.","title":"101마리 달마시안","author":"도디 스미스","ampm":"pm","kind":"역"}],"23:01":[{"t":"열한 시 일 분","q":"그를 바라보았다. 그가 농담이 아니라는 걸 깨닫고서야 부엌 가전마다 달린 작은 시계들을 하나하나 살펴보았다. 모두 같은 시각을 가리켰다, 열한 시 일 분.","title":"다잉 포 밀리언스","author":"주디스 커틀러","ampm":"pm","kind":"역"}],"23:02":[{"t":"열한 시 이 분","q":"\"그래요.\" 페레나의 단호한 어조는 반박을 허용하지 않았다. \"11시 7분에 폭발했어요. 열한 시 이 분에 들어갔다면 그때는 정확히 두 문 사이 중간 지점에 있었을 거예요.\"","title":"섀도우 앤 나이트","author":"크리스 월리","ampm":"pm","kind":"역"}],"23:03":[{"t":"열한 시 삼 분","q":"\"진짜라고 생각하는 이유가 뭔데?\" \"그냥 감이지 뭐, 진짜처럼 들렸거든.\" 그녀는 부엌으로 돌아가며 소리쳤다. \"몇 시에 만나기로 했는데?\" \"열한 시 삼 분.\" 그가 답했다. 군인이나 정보요원들은 혼선을 없애려고 이렇게 정확한 시각을 정한다고 했다.","title":"리틀 그린 맨","author":"크리스토퍼 버클리","ampm":"pm","kind":"역"}],"23:04":[{"t":"열한 시 사 분","q":"그는 상념에서 깨어나 디지털시계를 보고는 벌써 열한 시 사 분이 되었음을 알아차렸다. 채널을 돌리며 그는 자신을, 자신의 나약함을, 이 저주받은 땅에 풀려난 사악한 힘들을 저주했다.","title":"라이온스 게임","author":"넬슨 드밀","ampm":"pm","kind":"역"}],"23:05":[{"t":"열한 시 오 분","q":"열한 시 오 분, 애머시스트의 성패가 갈리기까지 십오 분도 채 남지 않았다.","title":"인피니트 데이","author":"크리스 월리","ampm":"pm","kind":"역"}],"23:06":[{"t":"열한 시 육 분","q":"그는 벽에 걸린 큰 시계를 보고 현지 시각으로 열한 시 육 분임을 확인했다. 예정대로였다.","title":"라이트닝","author":"딘 쿤츠","ampm":"pm","kind":"역"}],"23:07":[{"t":"열한 시 칠 분","q":"밤 열한 시 칠 분, 새뮤얼 \"거너\" 윌슨은 모하비 사막 상공을 시속 645마일로 날고 있었다. 저 앞 달빛 속에서 후미등을 성난 듯 밝히며 나는 두 대의 선도기가 보였다.","title":"안드로메다 스트레인","author":"마이클 크라이튼","ampm":"pm","kind":"역"}],"23:08":[{"t":"열한 시 팔 분","q":"그는 헬멧 위쪽 데이터스트립에서 시각을 확인하려 고개를 들었다, 열한 시 팔 분 이십삼 초. 십 분 남았다. 그들은 비틀거리며 계속 걸었다.","title":"인피니트 데이","author":"크리스 월리","ampm":"pm","kind":"역"}],"23:09":[{"t":"열한 시 구 분","q":"\"그 지점의 시각은 열한 시 구 분입니다.\" 파월이 지방검사 직원들에게 말했다. \"모형 위쪽 시계를 보세요. 슬로모션과 동기화되어 있으니까요.\"","title":"파괴된 사나이","author":"알프레드 베스터","ampm":"pm","kind":"역"}],"23:10":[{"t":"열한 시 십 분","q":"그에게는 스스로를 도울 힘조차 남아 있지 않았고, 열한 시 십 분이 되자 이 세상 누구도 그를 도울 수 없었다.","title":"사마라의 약속","author":"존 오하라","ampm":"pm","kind":"역"}],"23:11":[{"t":"열한 시 십일 분","q":"피해자 휴대폰에 남은 마지막 통화 기록은 일요일 밤 열한 시 십일 분이었다. 그날 밤 이후로 그녀를 본 사람은 아무도 없다.","title":"버밀리언 드리프트","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"23:12":[{"t":"23시 12분","q":"위장 경찰관 6475호는 147번가와 암스테르담 대로가 만나는 모퉁이에서 23시 12분에 신원을 재확인했다.","title":"어 네이키드 싱귤래리티","author":"세르히오 데 라 파바","ampm":"pm","kind":"역"}],"23:13":[{"t":"열한 시 십삼 분","q":"베로가 미소 지었다. \"승인으로 받아들이죠. 정리하자면, 지금 궤도와 속도라면 블레이드 오브 나이트 호는 2월 17일 밤 예루살렘 시각으로 열한 시 십삼 분에서 열한 시 이십이 분 사이에 달 뒤를 지나갈 겁니다.\"","title":"인피니트 데이","author":"크리스 월리","ampm":"pm","kind":"역"}],"23:14":[{"t":"열한 시 십사 분","q":"\"열한 시 십사 분이네.\" 멜리사가 말했다. \"세상이 끝나기까지 아직 사십사 분이나 남았어.\"","title":"글래스 호텔","author":"에밀리 세인트존 맨델","ampm":"pm","kind":"역"}],"23:15":[{"t":"밤 열한 시 십오 분","q":"밤 열한 시 십오 분. 참 나. 엄마가 방금 전화했다. \"미안, 얘야. 내일은 뉴스나이트가 아니라 브렉퍼스트 뉴스란다. 내일 아침 일곱 시로 다시 녹화 예약해 줄래, BBC1로?\"","title":"브리짓 존스의 일기","author":"헬렌 필딩","ampm":"pm","kind":"역"}],"23:16":[{"t":"열한 시 십육 분","q":"마침내 열한 시 십육 분에 그가 나타나 바카라 테이블의 예약석에 앉았다. 스티븐은 토마토 주스를 홀짝이다 멈추었고, 장피에르는 하비 좌우에 앉은 사람이 자리를 뜨기를 참을성 있게 기다렸다.","title":"노 페니 모어, 노 페니 레스","author":"제프리 아처","ampm":"pm","kind":"역"}],"23:17":[{"t":"열한 시 십칠 분","q":"메랄은 머리를 빼내려 애쓰며 헬멧 데이터스트립에서 시각을 흘긋 보았다, 열한 시 십칠 분. 일 분도 채 남지 않았다. 이제 곧 태양 플레어 경보가 발령될 것이었다.","title":"인피니트 데이","author":"크리스 월리","ampm":"pm","kind":"역"}],"23:18":[{"t":"열한 시 십팔 분","q":"열한 시 십팔 분이다. 낙엽송 무리를 한가운데 둔 방갈로들이 둥글게 늘어서 있다.","title":"트럼펫","author":"재키 케이","ampm":"pm","kind":"역"}],"23:19":[{"t":"열한 시 십구 분","q":"날카로운 휘파람 소리가 그의 말을 끊었다. 피터가 창밖을 보려 무릎을 세우자 풀러 양이 그를 노려보았다. 폴리는 손목시계를 내려다보았다, 열한 시 십구 분. 기차 시간이었다. 하지만 역장은 늘 지연된다고 했었다.","title":"블랙아웃","author":"코니 윌리스","ampm":"pm","kind":"역"}],"23:20":[{"t":"열한 시 이십 분","q":"나중에 밝혀진 바로는 바로 그날 저녁 열한 시 이십 분에 그가 또 한 번 기이하고 뜻밖의 방문을 했다는 것이었다. 비는 여전히 그치지 않았다. 흠뻑 젖은 채로 그는 바실리옙스키 섬 세 번째 거리에 있는, 약혼녀 부모의 작은 집으로 걸어 들어갔다.","title":"죄와 벌","author":"표도르 도스토옙스키","ampm":"pm","kind":"역"}],"23:21":[{"t":"열한 시 이십일 분","q":"스웨덴 경찰은 결코 유능함을 보여주지 못했다. 팔메는 열한 시 이십일 분에 살해되었지만 도로 감시 지시는 열두 시 오십 분에야 떨어졌고, 그때조차 순찰차 경찰들은 무엇을 찾아야 하는지도 모른 채였으며, 공항 폐쇄는 새벽 한 시 오 분에야 이루어졌다.","title":"발칙한 유럽 산책","author":"빌 브라이슨","ampm":"pm","kind":"역"}],"23:22":[{"t":"열한 시 이십이 분","q":"열한 시 이십이 분, 그는 하품하는 검표원에게 표를 건네고 길게 이어진 나무 계단을 내려가 주차장으로 향했다. 바람이 불어 나뭇잎을 들었다 놓았고, 그는 금발 소녀를 떠올렸다. 자전거는 두었던 그 자리에 그대로 있었다.","title":"드림스 오브 리빙","author":"로버트 톰슨","ampm":"pm","kind":"역"}],"23:23":[{"t":"열한 시 이십삼 분","q":"두 번째 자물쇠마저 딸깍 소리와 함께 항복한 뒤에도 모든 일이 순조로웠다. 퀸턴은 손목시계를 보았다, 열한 시 이십삼 분.","title":"천국의 발견","author":"하리 뮐리스","ampm":"pm","kind":"역"}],"23:24":[{"t":"밤 열한 시 이십사 분","q":"밤 열한 시 이십사 분. 빌럼 보르스트는 세스나기 조종석에 앉아 에게해의 밤하늘을 가르며 안디키티라 섬을 향해 210도 항로로 빠르게 접근하고 있었다. 그는 고도를 오백 미터, 속도는 실속 직전인 시속 백 노트에 조금 못 미치게 유지했다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"23:25":[{"t":"열한 시 이십오 분","q":"\"좋아요, 에스텔. 토요일 밤 열한 시 이십오 분에 니스 공항에 도착할게요, BA편으로요. 운전기사 좀 보내 줄래요?\"","title":"아더 피플스 머니","author":"저스틴 카트라이트","ampm":"pm","kind":"역"}],"23:27":[{"t":"열한 시 이십칠 분","q":"열한 시 이십칠 분, 장피에르는 조용히 자리를 떠나 다음 날 오전 열한 시까지 머물 호텔 방의 고독 속으로 돌아갔다. 그는 누구에게도 전화하지 않았고 룸서비스도 이용하지 않았다.","title":"노 페니 모어, 노 페니 레스","author":"제프리 아처","ampm":"pm","kind":"역"}],"23:28":[{"t":"밤 열한 시 이십팔 분","q":"월요일 밤 열한 시 이십팔 분. 완벽했다. 그들은 19세기풍 여관 정원에 있는 담쟁이 덮인 고딕 온실에서 저녁을 먹었다. 웨이터들은 분주히 오갔고 지배인은 곁을 맴돌았으며, 소믈리에는 테이블을 지날 때마다 굽신거리듯 고개를 숙였다.","title":"프로젝트 다이달로스","author":"토머스 후버","ampm":"pm","kind":"역"}],"23:29":[{"t":"열한 시 이십구 분","q":"마감을 놓치지 않았다는 안도의 한숨을 내쉬며 그녀는 열한 시 이십구 분에 이불 속으로 기어들어가 곧바로 불을 껐다.","title":"벨 뒤 세뇌르","author":"알베르 코엔","ampm":"pm","kind":"역"}],"23:30":[{"t":"23시 30분","q":"그는 플레이어에 테이프를 넣고 뷰어를 켰다. 다시 무릎을 우두둑거리며 쭈그려 앉아 큐를 23시 30분에 맞췄다.","title":"인피니트 제스트","author":"데이비드 포스터 월리스","ampm":"pm","kind":"역"}],"23:31":[{"t":"자정 이십구 분 전","q":"자정 이십구 분 전이다. 날리카르 박사의 산부인과는 최소 인력으로 돌아가고 있다. 많은 직원들이 다가올 건국의 순간을 축하하기로 하고, 오늘 밤 아이들의 탄생을 돕지 않기로 했다.","title":"한밤의 아이들","author":"살만 루슈디","ampm":"pm","kind":"역"}],"23:32":[{"t":"밤 열한 시 삼십이 분","q":"그리고 비가 내리기 시작해 몸이 젖었고, 추위에 떨기 시작했다. 그러다 밤 열한 시 삼십이 분이 되었을 때, 거리를 걷는 사람들의 목소리가 들려왔다.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"pm","kind":"역"}],"23:33":[{"t":"밤 열한 시 삼십삼 분","q":"밤 열한 시 삼십삼 분. 폭풍우가 시야를 거의 앗아갔고, 저 아래 수상비행기는 여전히 응답이 없었다.","title":"사이클롭스 프로젝트","author":"토머스 후버","ampm":"pm","kind":"역"}],"23:34":[{"t":"열한 시 삼십사 분","q":"리처는 정확히 열한 시 삼십사 분에 술집 창문 아래에서 G36을 꺼내 들고 큰길을 따라 돌아가기로 했다. 그편이 더 빠를 것 같았다.","title":"하드 웨이","author":"리 차일드","ampm":"pm","kind":"역"}],"23:35":[{"t":"열한 시 삼십오 분","q":"그는 오토바이를 타고 몇 마일이나 그 차를 뒤따르다가 차가 돌 앞에 멈춰 서는 것을 보았다. 금요일 열한 시 삼십오 분 무렵의 일이었다.","title":"프라이빗 페이션트","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"23:36":[{"t":"밤 열한 시 삼십육 분","q":"그때 그린이 밤 열한 시 삼십육 분에 현관문을 두드린다. 게이틀리는 정확한 시각을 기록해야 하고, 문을 열어줄지는 그의 판단에 달렸다.","title":"인피니트 제스트","author":"데이비드 포스터 월리스","ampm":"pm","kind":"역"}],"23:37":[{"t":"밤 열한 시 삼십칠 분","q":"티즈데일호와의 마지막 교신은 밤 열한 시 삼십칠 분, 그러니까 거의 하루 반나절 전이었다. 선장은 덜루스 해안경비대에 폭풍을 피해 침로를 바꾸겠다고 보고했었다.","title":"연옥의 능선","author":"윌리엄 켄트 크루거","ampm":"pm","kind":"역"}],"23:38":[{"t":"열한 시 삼십오 분에서 사십 분 사이","q":"번호판 W341 UDG의 포드 포커스 한 대가 그녀가 죽던 날 밤 열한 시 삼십오 분에서 사십 분 사이에 집 근처에 주차된 것이 목격되었다.","title":"프라이빗 페이션트","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"23:39":[{"t":"열한 시 삼십구 분","q":"\"시각은?\" 레이스가 물었다. \"열한 시 삼십구 분입니다, 경.\" 경호원이 보고했다. \"아, 좋군. 아직 시간이 있어.\"","title":"피의 의식","author":"짐 부처","ampm":"pm","kind":"역"}],"23:40":[{"t":"자정 이십 분 전","q":"그랜트는 시간을 확인했다. \"자정 이십 분 전이군. 잔 나눠주고 샴페인 따라줄 사람?\"","title":"전사 수도승","author":"레이 키팅","ampm":"pm","kind":"역"}],"23:41":[{"t":"열한 시 사십일 분","q":"다시 운전석에 앉은 그는 손목시계를 확인했다. 열한 시 사십일 분. 두 시간이면 실링퍼드에 도착할 수 있을 것 같았지만, 아버지는 분명 그보다 훨씬 전부터 진입로를 서성이고 있을 터였다.","title":"가장 은밀한 비밀","author":"제프리 아처","ampm":"pm","kind":"역"}],"23:42":[{"t":"열한 시 사십이 분","q":"열한 시 사십이 분, 신호가 곧 떨어질 시각. 승객들은 하나같이 초조해하고, 이윽고 스킴블이 나타나 뒤쪽으로 어슬렁어슬렁 걸어갈 것이다.","title":"지혜로운 고양이가 되는 법","author":"T.S. 엘리엇","ampm":"pm","kind":"역"}],"23:43":[{"t":"열한 시 사십삼 분","q":"열한 시 사십삼 분. 앞으로 사 분 남짓이면 엠마는 죽을 것이었다.","title":"피의 의식","author":"짐 부처","ampm":"pm","kind":"역"}],"23:44":[{"t":"밤 열한 시 사십사 분","q":"\"어젯밤 밤 열한 시 사십사 분에 누군가 부엌칼로 이 소녀의 목을 찌르고, 곧이어 같은 칼을 두개골에 박아 넣어 그대로 두었습니다.\"","title":"죽어야 유명하다","author":"벤 엘튼","ampm":"pm","kind":"역"}],"23:45":[{"t":"자정 십오 분 전","q":"자정 십오 분 전이었다. 셀리아의 말에 따르면, 죽은 자들이 담요를 걷어내듯 관 뚜껑을 열어젖히는 시각이었다. 그만해, 매트는 스스로에게 말했다.","title":"전갈의 아이","author":"낸시 파머","ampm":"pm","kind":"역"}],"23:46":[{"t":"밤 열한 시 사십육 분","q":"키스멧 라운지에서 얼리 씨는 소스라치게 놀란다. 벌써 밤 열한 시 사십육 분이라니. 계획보다 훨씬 오래 이곳에 머물렀고, 마시려던 것보다 훨씬 많이 마셨다.","title":"돌: 미시시피의 로맨스","author":"조이스 캐롤 오츠","ampm":"pm","kind":"역"}],"23:47":[{"t":"자정 십삼 분 전","q":"손목시계를 보았다면 그는 자정 십삼 분 전이라는 걸 알았을 것이다. 그리고 주변에 관심을 두었다면 겁에 질린 사내들의 아우성을 들었을 것이다.","title":"죽은 병사는 노래하지 않는다","author":"루돌프 야시크","ampm":"pm","kind":"역"}],"23:48":[{"t":"자정 무렵","q":"자정 무렵이었다. 토르빅은 서재 소파에 놓여 있던 인형의 부러진 발을 고친 뒤, 다시 그것을 집어 들었다.","title":"신의 망치","author":"보 기에르츠","ampm":"pm","kind":"역"}],"23:49":[{"t":"자정 십일 분 전","q":"톰은 어깨를 으쓱했다. 분홍빛 주름 소매를 걷어 올리자 자정 십일 분 전이었다. 톰은 커피를 마저 마셨다.","title":"리플리를 따라간 소년","author":"퍼트리샤 하이스미스","ampm":"pm","kind":"역"}],"23:50":[{"t":"자정까지는 십 분","q":"\"오, 맥클리어 씨,\" 그가 장난스레 말했다. \"안식일을 어기지 않고 무사히 넘기셨군요! 아슬아슬했습니다! 그 무서운 자정까지는 십 분 남짓밖에 남지 않았거든요!\"","title":"불의 소금","author":"조지 맥도널드","ampm":"pm","kind":"역"}],"23:51":[{"t":"자정 구 분 전","q":"버지니아는 손목시계를 확인했다. 자정 구 분 전. 그녀는 약속을 지켰다. 초인종을 누르고 삼 층 불이 켜지는 것을 지켜보았다.","title":"이것이 한 남자였다","author":"제프리 아처","ampm":"pm","kind":"역"}],"23:52":[{"t":"자정 팔 분 전","q":"자정 팔 분 전이었다. 딱 좋은 시간이라고 나는 생각했다. 실내는 조용했고 어두웠다. 훌륭했다. 나는 바로 가서 잔과 소다수, 글렌 그랜트 한 병을 챙겨 약한 술 한 잔과 알약을 먹고 남은 이 분을 기다리며 자리에 앉았다.","title":"녹색의 사나이","author":"킹슬리 에이미스","ampm":"pm","kind":"역"}],"23:53":[{"t":"자정 칠 분 전","q":"\"물론이죠, 여보. 그냥 꽃병을 돌려주러 왔을 뿐이에요.\" 그녀는 다시 손목시계를 보았다. \"자정 칠 분 전이니, 저는 약속을 지킨 셈이네요.\"","title":"이것이 한 남자였다","author":"제프리 아처","ampm":"pm","kind":"역"}],"23:54":[{"t":"밤 열한 시 오십사 분","q":"그의 손목시계는 동부 표준시로 밤 열한 시 오십사 분을 가리키고 있었다. 로마는 벌써 새벽 여섯 시에 가까웠다. 그는 혹독한 1월 폭풍이 휩쓴 도시, 춥고 축축한 크리스마스 시즌을 뒤로하고 떠나온 참이었다.","title":"콘클라베","author":"그레그 토빈","ampm":"pm","kind":"역"}],"23:55":[{"t":"자정 오 분 전","q":"\"너를 가둬야겠구나. 지금은,\" 그가 시계를 확인했다, \"자정 오 분 전이다. 그레인저 양, 세 바퀴면 충분할 거예요. 행운을 빌어요.\"","title":"해리 포터와 아즈카반의 죄수","author":"J.K. 롤링","ampm":"pm","kind":"역"}],"23:56":[{"t":"자정 사 분 전","q":"인류는 종착점에 다다랐고, 최후 심판의 시계는 계속 돌아간다. 십 년째 자정 사 분 전에 멈춰 있지만, 바늘은 여전히 그 자리에 서 있다. 이제 곧 다시 움직이기 시작할 것이다.","title":"사악한 여자들","author":"페이 웰던","ampm":"pm","kind":"역"}],"23:57":[{"t":"자정 삼 분 전","q":"\"자정 삼 분 전이라고 적혀 있었다. 그때 내 기분으로는 그리 늦은 시간 같지 않았다. 나는 실내복을 걸치고 손전등을 챙겨 샐리의 방으로 갔다.\"","title":"얼굴을 가려라","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"23:58":[{"t":"자정 일 분 십칠 초 전","q":"인류는 자정 일 분 십칠 초 전에 등장한다. 이 척도로 보면 우리의 기록된 역사 전체는 고작 몇 초, 한 인간의 생애는 순간에 지나지 않을 것이다.","title":"거의 모든 것의 역사","author":"빌 브라이슨","ampm":"pm","kind":"역"}],"23:59":[{"t":"새로운 하루까지는 아직 일 분","q":"치거는 일어나 카펫에서 빈 탄피를 주워 안을 불어낸 뒤 주머니에 넣고 손목시계를 보았다. 새로운 하루까지는 아직 일 분 남아 있었다.","title":"노인을 위한 나라는 없다","author":"코맥 매카시","ampm":"pm","kind":"역"}],"01:28":[{"t":"1시 28분","q":"아버지가 경찰서에 도착한 건 새벽 1시 12분이었다. 나는 1시 28분이 되어서야 그를 알아챘지만 목소리로 이미 거기 있다는 걸 알고 있었다. 그는 소리치고 있었다, '내 아들을 만나게 해달라'고, '대체 왜 가둬놓은 거냐'고, '당연히 화가 나지 않겠냐'고.","title":"한밤중에 개에게 일어난 의문의 사건","author":"마크 해던","ampm":"am","kind":"역"}],"01:41":[{"t":"1시 41분","q":"래플스는 실오라기 하나 걸치지 않은 몸으로, 솜으로 막은 유리병을 이 사이에 물고 귀 뒤에는 작은 드라이버를 꽂은 채 침대 위 통풍구로 발부터 꿈틀거리며 들어갔다. 그가 머리부터 다시 나온 것은 1시 41분, 병은 여전히 이 사이에 물려 있었고 안에서 커다란 회색 콩처럼 덜그럭거리던 것을 잠재우려 솜을 꾹 눌러 채운 채였다.","title":"아마추어 금고털이","author":"E.W. 호넝","ampm":"am","kind":"역"}],"01:46":[{"t":"1시 46분","q":"그 이상한 현상 때문에 프레스토는 새벽 1시 46분에 일어나야 했다. 그는 조용히 얼굴과 벗은 몸에 위장 페인트를 칠했다. 방문을 열고 공동 복도로 나섰다.","title":"파드녹의 복수","author":"J.W. 스톡턴","ampm":"am","kind":"역"}],"02:51":[{"t":"2시 51분","q":"목요일 새벽 2시 51분. 흠뻑 젖은 채 잔뜩 짜증이 난 마이클 밴스가 제노 스탄토풀로스의 불 꺼진 카페 문을 두드렸다. 그는 어둠 속 외딴 길을 걸어 이라클리온으로 들어오며 빗줄기에 두들겨 맞은 플라타너스와 올리브, 야생 배나무 숲을 길잡이 삼았고, 대체 무슨 일이 벌어지고 있는 건지 알아내려 애썼다.","title":"프로젝트 다이달로스","author":"토머스 후버","ampm":"am","kind":"역"}],"04:26":[{"t":"4시 26분","q":"4시 26분, 그녀는 사망 판정을 받았다. 사인, 정확히는 사망 방식은 명백했다. 가슴에 총알이 뚫고 들어간 상처가 두 군데 있었다.","title":"네가 정말 날 사랑했다면","author":"앤 룰","ampm":"am","kind":"역"}],"04:28":[{"t":"4시 28분","q":"그는 유일한 생존자였다, 살아 돌아온 건 그 하나뿐이었다. 대체 무슨 일이 벌어지고 있는 걸까? 악몽 속의 이 낯선 인물은 누구인가? 그는 시계를 올려다보았고 이제 겨우 4시 28분이라는 사실에 맥이 빠졌다.","title":"솔플릿: 의무의 부름","author":"글렌 스미스","ampm":"am","kind":"역"}],"04:44":[{"t":"4시 44분","q":"'어제 아침 4시 44분, 착륙정 오르페우스호가 캐나다 토론토 출신의 스물일곱 살 천체물리학자 다이애나 챈들러 박사에 의해 무단으로 사용되었습니다. 챈들러 박사는 역시 토론토 출신이자 스타콜로니의 부두관리자인 스물일곱 살 남편 애런 로스먼과의 2년 결혼 계약 갱신이 무산된 데 낙담해, 자살한 것으로 추정됩니다.'","title":"황금 양털","author":"로버트 J. 소여","ampm":"am","kind":"역"}],"05:31":[{"t":"5시 31분","q":"5시 31분 - 맹크가 변호사와 통화하며: '이런, 우리가 가서 그 투표용지들을 확보해야 할 것 같은데! 압수해! 한 장도 남김없이!'","title":"공포와 혐오: 72년 대선 유세길에서","author":"헌터 S. 톰슨","ampm":"am","kind":"역"}],"05:47":[{"t":"5시 47분","q":"눈꺼풀이 억지로 떠졌다. 침대맡 등이 켜져 있었다. 루가 그의 귓불을 손가락으로 튕기며 위에서 내려다보고 있었다. 대체 무슨 일이지? 시계는 5시 47분을 가리키고 있었다. 일요일, 아직 동트기 전이었다.","title":"크리스마스의 은폐","author":"캐시 마일스","ampm":"am","kind":"역"}],"06:06":[{"t":"6시 6분","q":"6시 6분, 메리트 거리의 모든 변기가 갑자기 오물과 하수를 뿜어내며 폭발했다, 배린스 지역 새 폐수처리장의 저장 탱크로 이어지는 배관 안에서 상상도 못 할 역류가 일어난 것이다.","title":"그것","author":"스티븐 킹","ampm":"am","kind":"역"}],"07:22":[{"t":"7시 22분","q":"아침 7시 22분. '이거 다룰 줄 아나?' 밴스가 들고 있던 MP5를 캘리에게 건넸다. 그는 라미레즈를 제거하려고 그 총을 언덕 위까지 들고 올라왔지만, 섬광탄 작전이 엉망이 된 뒤로는 한 발도 쏘지 못한 채였다.","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"am","kind":"역"}],"08:46":[{"t":"8시 46분","q":"페트로프가 리모컨을 갖고 있는 게 틀림없었으니, 그 자식이 시간을 8시 46분에서... 지금으로 다시 맞춰놓았다는 데는 의심의 여지가 없었다.","title":"빛나는 천사","author":"넬슨 드밀","ampm":"am","kind":"역"}],"11:22":[{"t":"11시 22분","q":"16번 국도 시골배달함 12번지의 펠릭스 폴크는 어제 오전 11시 22분경 이곳에 나타나 자기 엄지손가락 끝을 주워간 사람이 없는지 물었다, 본인 말을 그대로 옮기면 '그걸 돌려받아서 열쇠고리로 만들고 싶다'고 했다.","title":"고물상의 개들","author":"크레이그 존슨","ampm":"am","kind":"역"}],"12:34":[{"t":"낮 12시 34분","q":"낮 12시 34분. 'W.B., 문제가 생겼습니다,' 칼 반 데 블리트가 마이크에 대고 말했다. 그는 개인 사무실에서 암호화된 화상전화를 하고 있었다. '크리스틴 어머니가 정오 직전에 권총을 들고 나타나 딸이 어디 있는지 대라고 하고 있습니다.'","title":"신드롬","author":"토머스 후버","ampm":"pm","kind":"역"}],"13:04":[{"t":"1시 4분","q":"'맙소사!' 그가 숨을 헐떡이며 말했다. '1시 4분이야!' 린든은 허둥지둥 사다리를 붙잡고 그것을 든 채 방 안을 이리저리 헤맸다.","title":"누더기 바지를 입은 박애주의자들","author":"로버트 트레셀","ampm":"pm","kind":"역"}],"13:37":[{"t":"오후 1시 37분","q":"그는 빌린 차 안에서 감히 잠들지 못했다, 헤수스 카스트로 밑에서 일할 때는 차 안에서 자면 안 됐으니까, 그리고 이제 헛것이 보이기 시작하고 있었다. 그래도 그는 임무 중이었고, 수첩에 이렇게 휘갈겨 적었다: 오후 1시 37분, 대상 누군가와 함께 있는 듯.","title":"라이트 하우스","author":"윌리엄 모나핸","ampm":"pm","kind":"역"}],"13:56":[{"t":"오후 1시 56분","q":"오후 1시 56분. 다행히 케이틀린은 기숙사 방에 없었다, 캠퍼스에서 뭘 하고 다니는지 몰라도 어쨌든 자리를 비운 덕에, 브라크는 그 성가신 룸메이트 눈치 볼 것 없이 에바를 위해 그녀의 컴퓨터 비밀번호를 타이핑할 수 있었다.","title":"위대한 중서부의 부엌들","author":"J. 라이언 스트라달","ampm":"pm","kind":"역"}],"17:34":[{"t":"5시 34분","q":"'5시 30분이었소. 나는 그로부터 4분쯤 뒤인 5시 34분에 여기 도착했소. 뺨 한쪽의 핏자국 상태와 시작된 사후경직으로 미루어, 그가 죽은 지 다섯 시간쯤 됐으리라 짐작했소.'","title":"성직에서의 죽음","author":"P.D. 제임스","ampm":"pm","kind":"역"}],"17:41":[{"t":"오후 5시 41분","q":"'좋아, 다들 서두르자, 일몰이 오후 5시 41분이고 우리는 23킬로미터를 더 가야 한다.' 베인 상사가 몸을 일으키자 소대원들이 뒤따랐다.","title":"용맹의 심장","author":"타냐 허프","ampm":"pm","kind":"역"}],"18:14":[{"t":"6시 14분","q":"'의식은 있나? 에테르는-' '그건 잘 모르겠는데,' 시미가 명랑하게 말했다. '5시부터 계속 자기 방에 있었어. 그러니까... 지금 몇 시지? 6시 14분. 거의 한 시간 15분째야. 다들 그러는데-'","title":"지붕 위에서","author":"조지 바 매커천","ampm":"pm","kind":"역"}],"19:44":[{"t":"저녁 7시 44분","q":"저녁 7시 44분. 밴스는 하인드 헬기가 구축함 우현으로 접근해 곧장 그쪽으로 향하며 고도를 낮추는 것을 지켜보았다. 대체 무슨 일이 벌어지고 있는 건가?","title":"프로젝트 사이클롭스","author":"토머스 후버","ampm":"pm","kind":"역"}],"21:44":[{"t":"9시 44분","q":"1671년 1월의 그날 밤, 9시 44분에 섬은 함락되었다, 고함과 비명, 공포탄과 화승총 소리가 요란했고, 약탈과 파손은 그리 심하지 않았다, 어느 정도는.","title":"돌피리","author":"찰스 스토","ampm":"pm","kind":"역"}],"23:26":[{"t":"밤 11시 26분","q":"로스앤젤레스. 밤 11시 26분. 생간 색깔에 가까운 어두운 붉은 방 안, 지나치게 딱 붙는 실크 반바지를 만화처럼 입은 키 큰 여자가 있다, 노란 블라우스에 묶여 위로 밀려 올라간 가슴이 앞으로 도드라져 있다.","title":"신들의 전쟁","author":"닐 게이먼","ampm":"pm","kind":"역"}],"06:07":[{"t":"여섯 시 칠 분","q":"힌턴은 여섯 시 칠 분에 정문을 통과한다. 고속도로에 정체가 있었거나 보안 브리핑이 지연됐을 것이다. 오늘 아침 그의 머리는 막 자른 듯 말끔해서, 높은 광대뼈와 반짝이는 굶주린 눈이 도드라져 보인다.","title":"드림 호텔","author":"라일라 랄라미","ampm":"am","kind":"역"}],"06:18":[{"t":"여섯 시 십팔 분","q":"처음 십오 분간은 아거스호가 유리한 위치를 점했고, 여섯 시 십팔 분에는 지근거리에서 펠리컨호에 포격을 가했지만 선체나 삭구에 큰 손상을 입히지 못했으며, 전사자는 많아야 한 명, 부상자는 다섯 명에 그쳤다.","title":"미합중국의 역사 7권","author":"헨리 애덤스","ampm":"am","kind":"역"}],"08:21":[{"t":"여덟 시 이십일 분","q":"오전 여덟 시 이십일 분. 발소리에 잠이 깼다. 위층에서 들려오는 소리였는데, 이상하게 낯설었다.","title":"한나를 지키며","author":"미하 마치니","ampm":"am","kind":"역"}],"10:28":[{"t":"열 시 이십팔 분","q":"열 시 이십팔 분, 크로우는 앰버의 인형이 반대편에 숨겨져 있던 지점의 방파제에 기대어 있었다. 빗줄기에 사방이 어슴푸레했다.","title":"낙원의 이방인","author":"로버트 B. 파커","ampm":"am","kind":"역"}],"11:46":[{"t":"열한 시 사십육 분","q":"시각은 오전 열한 시 사십육 분이었다. 마거릿의 점심시간까지 십오 분이 채 남지 않은 때였다. 시계가 정오를 가리키기까지, 그 십사 분은 고통스러울 만큼 더디게 흘렀다.","title":"디스오리엔테이션","author":"일레인 시에 초우","ampm":"am","kind":"역"}],"12:31":[{"t":"열두 시 삼십일 분","q":"낮 열두 시 삼십일 분, 헬스장은 패스, 사무실에서 먹을 점심을 사는 중. 저녁 여섯 시 삼십일 분, 아직 퇴근 못함, 오늘 안에 내일 할 일을 미리 시작한다. 밤 열 시 삼십일 분, 드디어 집에 와서 바로 침대로. 레이한테 부재중 전화가 와 있지만 너무 피곤해서 답장 못 하겠다.","title":"화요일, 세 시","author":"질리언 알렉스","ampm":"pm","kind":"역"}],"13:36":[{"t":"한 시 삼십육 분","q":"[오후 한 시 삼십육 분] 휴스턴: 다행이군요. 헤르메스호는 여전히 549솔 근접 통과 궤도를 유지 중입니다. 아시다시피 랑데부를 위해 MAV의 중량을 줄여야 합니다. 오늘 안으로 절차를 보내드리겠습니다. 물은 얼마나 남았습니까? 소변은 어떻게 처리했습니까?","title":"마션","author":"앤디 위어","ampm":"pm","kind":"역"}],"18:44":[{"t":"여섯 시 사십사 분","q":"사이먼은 혼자일 때는 기꺼이 이등석을 타고, 남들이 여섯 시 삼십팔 분 기차를 선호한다는 걸 알기에 일부러 여섯 시 이십오 분 기차를 노리기도 한다. 하지만 오늘은 크루역 신호 고장으로 그 기차가 여섯 시 사십사 분으로 지연되는 바람에, 조니 크로선이 플랫폼에서 그를 발견하고 만다.","title":"죽음들","author":"마크 로슨","ampm":"pm","kind":"역"}]},"buckets":{"자정":[{"t":"밤중","q":"아닌 밤중에 저게 무슨 소리야.”","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤중","q":"“아마 미쳤나보아, 밤중에 혼자 일어나서 왜 저리고 있을꾸.”","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤중","q":"이 밤중에 어디를 나가셔요.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤중","q":"“일은 밤중에 무슨 일.”","title":"감자","author":"김동인","kind":"원문"},{"t":"밤중","q":"밤중 복녀의 시체는 왕 서방의 집에서 남편의 집으로 옮겼다.","title":"감자","author":"김동인","kind":"원문"},{"t":"밤중","q":"그는 작곡과를 전공하였는데 때때로 스스로 작곡을 하여서는 밤중에 혼자서 피아노를 두드리고 하여서 우리들로 하여금 뜻하지 않고 일어나게 하고 하였습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤중","q":"그리고 우리는 그 밤중에 울리어 오는 야성적 선율에 몸을 소스라치고 하였습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤중","q":"그때 나는 조용한 밤중의 몇 시간씩을 ○○예배당에 가서 명상으로 시간을 보내는 것이 습관이 되어 있었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤중","q":"언덕 위에 홀로 서 있는 집으로서 조용한 밤중에 혼자 앉아 있노라면 때때로 들보에서 놀라 깬 비둘기의 날개 소리와 간간이 기둥에서 뚝뚝 하는 소리밖에는 아무 소리도 들리지 않는, 말하자면 나 같은 괴상한 성미를 가진 사람이 아니면 돈을 주면서 들어가래도 들어가지 않을 음침한 집이었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤중","q":"어떤 날 밤중, 가슴이 너무 무겁고 가슴속에 무엇이 가득 찬 것같이 거북하여서, 저는 산보를 나섰습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤중","q":"적적한 밤중에 쓸쓸한 마을에는 처참한 여자 목소리가 으스스하게 울리었다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"자정","q":"그날 밤 저녁을 먹고 자정 때나 되더니 삼돌이는 눈을 비비며 일어나서 문 밖으로 나갔다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤중","q":"잡히는 것보다도 안협집의 걱정은 보기도 싫은 삼돌이란 녀석하고 밤중에 무인지경에를 같이 가라니 그것이 딱한 일이다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤중","q":"아닌밤중에 혼자 자는데 와서 귀찮게 굽니다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤중","q":"\"이놈이 할 일이 없거든 자빠져 자기나 하지, 왜 아닌밤중에 남의 계집의 방에서 지랄이야?","title":"뽕","author":"나도향","kind":"원문"},{"t":"자정","q":"그러나 내 아내를 찾은 서너 사람의 내객들은 늘 비교적 점잖았다고 볼 수 있는 것이, 자정이 좀 지나면 으레 돌아들 갔다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"그것이 네 말마따나 자정 전인지는 정말이지 꿈에도 몰랐다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"내가 그 오 원 돈을 써 버릴 수가 있었던들 나는 자정 안에 집에 돌아올 수 없었을 것이다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"내 짐작 같아서는 밤이 어지간히 늦은 줄만 알았는데, 그것이 불행히도 자정 전이었다는 것은 참 안된 일이다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"나서면서 나는 제발 시간이 화살 단듯해서 자정이 어서 홱 지나 버렸으면 하고 조바심을 태웠다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"아내에게 돈을 주고 아내 방에서 자 보는 것은 어디까지든지 좋았지만 만일 잘못해서 자정 전에 집에 들어갔다가 아내의 눈총을 맞는 것은 그것은 여간 무서운 일이 아니었다.","title":"날개","author":"이상","kind":"원문"},{"t":"자정","q":"경성역(京城驛) 시계가 확실히 자정을 지난 것을 본 뒤에 나는 집을 향하였다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤중","q":"와서는 이 밤중에 평생 안 하던 쓰레질을 하는 것이었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤중","q":"밤중을 지난 무렵인지 죽은 듯이 고요한 속에서 짐승 같은 달의 숨소리가 손에 잡힐 듯이 들리며, 콩 포기와 옥수수 잎새가 한층 달에 푸르게 젖었다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤중","q":"밤중은 돼서 혼자 일어나 개울가에 목욕하러 나갔지.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"자정","q":"선술집에 가서 엔간히 취하도록 먹은 뒤에 C라는 카페에 가서 술 두 병을 놓고 자정이 되도록 노닥거렸다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤중","q":"그러나 동혁은 밤중에 길거리로 헤매게 된 젊은 여자를 내버려두고 저 혼자만 휘적휘적 친구의 집으로 자러 갈 수는 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"그러나 동혁은 밤중에 여기까지 여자의 뒤를 따라온 것이 새삼스러이 멋쩍은 것 같고, 또는 백씨까지도 초면에 저를 어떻게 볼는지 몰라서 모자를 훌떡 벗으며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"밤중에 동혁은 별안간 이불을 걷어차며 일어났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"자정","q":"열나흗날 달이 어지간히 기운 것을 보니 자정도 가까운 듯.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"이 밤중에 어디루 가셨나 허구, 빈방 속에서 한참이나 기다렸는데…….\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"하고 식전부터 오밤중까지도 동네 일과 집안 일로 몸을 얽어매었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"그것은 저의 집 산 울안에 선 참죽나무를 밤중에 몰래 베다가, 저의 아버지가 '도둑야!'","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"게다가 기만이에게 오백 원이나 급전을 도적맞아서 그 벌충을 대야만 되게 된 형편인데, 또 한편으로는 동혁이가 감정이 잔뜩 난 회원들을 선동해 가지고 밤중에 습격이라도 할 것 같아서 미상불 겁이 났던 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"회장이 된 첫번 행세를 하려고 제 동네서는 못 해도 저도 돈 십 원이나 기부를 한 읍내 소방조 출초식(消防組出初式)에 참례를 했다가, 술이 엉망진창으로 취해서 밤중에 자전거를 끌고 오다가 신작롯가에 있는 주막으로 비틀거리며 들어갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"자정","q":"밤은 자정이 넘은 지도 오래다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤중","q":"옛날 화적들은 밤중에나 들어와서 대문이나 짓부수고 하지요.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"한밤중","q":"푸욱푹 피어 오르는 담배 연기가 아직도 한밤중인 듯 전등불이 환히 켜져 있는 방 안으로 자욱이 찹니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"한밤중","q":"윤주사도 도합 사천오백 원을 마작으로 펐으나 오천 원도 채 못 되는 것, 술 사먹은 폭만 대면 그만이라고 새벽녘에야 든 잠이 시방 한밤중이요, 자고 있으니까 동경서 온 그 전보의 사단도 걱정을 잊었고…….","title":"태평천하","author":"채만식","kind":"원문"}],"새벽":[{"t":"새벽","q":"어느 날 새벽, 아내가 어렴폿이 잠을 깨어, 남편의 누웠던 자리를 더듬어보았다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"새벽","q":"쏠쏠한 새벽 바람이 싸늘하게 가슴에 부딪친다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"새벽","q":"그는 움쩍도 안하고 그 자리에 앉아서 밤을 새운 뒤에, 새벽 동터올 때 아내와 아우를 죽이려고 부엌에 가서 식칼을 가지고 들어와서 문을 벌컥 열었다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"새벽","q":"강가에 나가서 알아보니, 그의 배는 오늘 새벽에 떠났다 한다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"새벽","q":"그날 새벽에 안협집이 무사히 왔다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"새벽","q":"꼭두새벽부터 엣, 엣, 하며 괴로움을 모른다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"새벽","q":"이튿날 전에 없이 첫새벽에 일어난 P는 서투른 솜씨로 화롯밥을 지어 놓고 정거장으로 나갔다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"새벽","q":"새벽닭이 새날을 고한다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"새벽","q":"별별 생각이 다 나서 영신은 그날 밤 잠을 잘 자지 못하고, 이튿날 새벽밥을 지어 달래서 먹고는 길을 떠났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"창 밖에 새벽별이 차차 빛을 잃어 갈 때, 영신은 소세를 하고 나와서 예배당으로 올라갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"그러다가 새벽녘에는 동혁이와 첫날밤을 치르는 꿈을 꾸었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"기적은 동해변의 조그만 항구의 새벽 공기를 새되게 찢었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"새벽녘부터 철 아닌 궂은비가 오는 까닭인지, 회원은 물론 다른 조기회원도 올라오는 사람은 그전의 오분의 일도 못 된다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"기천은 아주 초죽음이 되었다가 새벽녘에야 간신히 저의 집으로 기어들었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"빠듯한 노자에서 사식이라도 차입할 생각을 하다가 새벽녘에야 간신히 눈을 좀 붙이려는데, 주정꾼들이 바로 옆방과 문간방으로 우르르 몰려들어왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"하고 어깨를 흔드는 것은 새벽 기도회에 참례하려고 잠이 깬, 곁에 누웠던 동급생이었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"꿈자리 산란한 이역의 서리 찬 새벽 하늘에―---","title":"상록수","author":"심훈","kind":"원문"},{"t":"새벽","q":"그러나 아무 소리도 들리지 아니하고 새벽 바람이 땀 흐르는 얼굴을 스쳐 지나갈 뿐이었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"아직 희미한 새벽빛이 언마는 그것이 아까 그 악한의 저고리 옷자락인 줄을 알았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"안주 박선생의 집을 떠날 때에 자기가 영채를 안고, ‘이제는 다시 못 보겠구나’ 하던 양도 보이고, 외가를 뛰어나와 개를 데리고 달밤에 혼자 도망하는 영채의 모양과 숙천 객점에서 어떤 악한에게 붙들려 가던 양이 얼른얼른 보이고, 남복을 입은 영채가 죽어 넘어진 개를 안고 새벽 외따른 길가에 앉아 우는 양도 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"“어젯저녁에 늦게 돌아오셔서 새벽이 되도록 앉아서 무슨 생각을 하시더니 아직도 주무십니다그려.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"어느덧 차창에는 새벽빛이 비치었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"어스름한 새벽빛에 대동강 물은 소리 없이 흐르고 기차는 평양역을 향하여 길게 고동을 핀다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"새벽 어스름에 아무것도 똑똑히 보이지는 아니하나, 평양 경치를 여러 번 본 형식의 눈에는 ‘저것이 능라도, 저것이 모란봉, 저기가 청류벽’ 하고 어렴풋하게 마음으로 지정하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"그런데 새벽부터 이렇게 배가 아프다고……”","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"그랬더니 어저께 물에 농사 지은 것은 말끔 물 속으로 들어가고 오늘 새벽에는 집까지 물에 들어가고 말았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"새벽","q":"이튿날 새벽같이 윤용규는 몸소 읍으로 달려들어가서, 당시 그 고을 원(수령)이요, 수차 토색질을 당한 덕에 안면(!)","title":"태평천하","author":"채만식","kind":"원문"},{"t":"새벽","q":"예를 들자면 드리없지만, 가령 밤늦게까지 건넌방에서 아무리 성냥 긋는 소리가 나도, 이튿날 새벽같이,","title":"태평천하","author":"채만식","kind":"원문"},{"t":"새벽","q":"얼마 전에 군의 같은 동료가 맡아 보는 돈 천 원을 둘러 쓴 일이 있는데, 그 돈 채워 놓아야 할 날짜가 이삼 일로 박두했고, 일변 술도 날씨 선선해진 판에 한바탕 먹어 제끼고 싶고, 이참 저참 올라왔던 것인데, 방위가 나빴던지 일수가 사나웠든지, 첫새벽 정거장에서 내리던 길로 일이 모두 꿀리기만 했습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"먼동","q":"그렇듯 반가운 새날이 시방 시작되느라고 먼동이 휘엿이 밝아 옵니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"새벽","q":"대단 부지런하고, 이 첫새벽(여섯점)에 일어나는 부지런은 춘하추동 구별이 없이, 오십 년 이짝 지켜 오는 절대의 습관입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"새벽","q":"그렇게 오줌 특약을 해두고는, 새벽이면 삼남이가 빨병을 둘러메고서 오줌을 걷어 오는 것이고, 시방도 바로 그 오줌입니다.","title":"태평천하","author":"채만식","kind":"원문"}],"아침":[{"t":"아침","q":"첫번에 삼십 전, 둘째 번에 오십 전 - 아침 댓바람에 그리 흔치 않은 일이었다.","title":"운수 좋은 날","author":"현진건","kind":"원문"},{"t":"아침","q":"지금 아내가 하나 남은 모본단 저고리를 찾는 것도 아침거리를 장만하려 함이라.","title":"빈처","author":"현진건","kind":"원문"},{"t":"아침","q":"나는 이런 일을 가슴에 그리며 그래도 내일 아침거리를 장만하려고 옷을 찾는 아내의 심중을 생각해 보니, 말할 수 없는 슬픈 생각이 가을 바람과 같이 설렁설렁 심골(心骨)을 분지르는 것 같다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"아침","q":"오늘 밤에 잘 주무시면 내일 아침에 아르켜 드리지요.”","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"아침","q":"그러게 내일 아침에 말을 하자니까…”","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"아침","q":"조금 좋은 땅은 먼저 간 이가 모조리 차지를 하였고 황무지는 비록 많다 하나 그곳 당도하던 날부터 아침거리 저녁거리 걱정이라 무슨 행세로 적어도 일년이란 장구한 세월을 먹고 입어 가며 거친 땅을 풀 수가 있으랴.","title":"고향","author":"현진건","kind":"원문"},{"t":"아침","q":"그날 밤, 집에 돌아와서도 그 배따라기와 그의 숙명적 경험담이 귀에 쟁쟁히 울리어서 잠을 못 이루고, 이튿날 아침 깨어서 조반도 안먹고 기자묘로 뛰어가서 또다시 그를 찾아보았다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"아침","q":"아침부터 저녁까지, 저녁부터 아침까지, 술잔이 그의 입에서 떠나지를 않았습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"아침","q":"변변치는 않으나마 오르간 하나를 준비하여 두고, 그가 잠자렬 때에는 슈베르트의 '자장가'로써 그의 잠을 도왔으며 아침에 깰 때는 하루 종일 유쾌히 지내게 하기 위하여 도 랜드의 '세컨드 왈츠'로써 그의 원기를 돋우었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"아침","q":"아침에는 새소리, 바람에 버석거리는 포플러잎, 어머니의 사랑, 부엌에서 국 끓는 소리, 이러한 모든 것이 이 소년에게는 신비스럽고도 다정스러워 그는 피아노에 향하여 앉아서 생각나는 대로 키를 두드리고 하였습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"아침","q":"그날 아침, 그는 위독한 어머니를 버려 두고 역시 공장에를 갔습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"아침","q":"아침결에 책보만한 해가 들었다가 오후에 손수건만 해지면서 나가 버린다.","title":"날개","author":"이상","kind":"원문"},{"t":"아침","q":"나는 오늘 아침에 네 개의 아스피린을 먹은 것을 기억하고 있었다.","title":"날개","author":"이상","kind":"원문"},{"t":"아침","q":"그래서 오늘 아침까지 끽소리 없이 왔다.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"아침","q":"실토이지 나는 점순이가 아침상을 가지고 나올 때까지는 오늘은 또 얼마나 밥을 담았나, 하고 이것만 생각했다.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"아침","q":"아버지가 볼까 봐서 얼른 홰에다 감추어 두었더니 오늘 아침에서야 겨우 정신이 든 모양 같다.","title":"동백꽃","author":"김유정","kind":"원문"},{"t":"아침","q":"하지만 오늘 아침만 해도 한 친구가 찾아와서 벼를 털 텐데 일 좀 와 해달라는 걸 마다하였다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"아침","q":"응칠이가 아침 일찍이 그 논께로 노닐자 이걸 발견하고 기가 막혔다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"아침","q":"마는, 아침에 아내에게 먹이고 남은 조죽밖에야.","title":"만무방","author":"김유정","kind":"원문"},{"t":"아침","q":"펄펄 뛰는 생선이 좋고, 아침 햇살이 빗기어 힘차게 출렁거리는 그 물결이 좋고.","title":"만무방","author":"김유정","kind":"원문"},{"t":"아침","q":"이렇게 몹시 춥고 두려운 날 아침에 문서방은 집을 나섰다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"아침","q":"\"오늘도 배고프겠구나, 아침도 변변히 못 먹고……","title":"탈출기","author":"최서해","kind":"원문"},{"t":"아침","q":"\"어제 아침에 사장더러 P군의 사정이 퍽 난처하니 어떻게 생각해 봐 주면 좋겠다고 여러 말을 했다가 코떼었소.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"아침","q":"그의 아들 창선이를 올려보낸다고 어제 편지가 왔고 오늘은 내일 아침에 경성역에 당도한다는 전보까지 왔다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"아침","q":"이튿날 아침 일찍 창선이를 데리고 ××인쇄소에 가서 A에게 맡기고 안 내키는 발길을 돌이켜 나오는 P는 혼자 중얼거렸다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"아침","q":"그러나 이 마님 입에서는 반드시 오늘 아침에 다녀가신 할머니의 말씀과 같은 “얘, 옛날에는 여편네가 배우지 않아도 수부다남(壽富多男)하고 잘만 살아 왔다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"아침","q":"아침에 경희가 할머니가 다녀가신 뒤에 마루에서 혼잣말로 “시집을 갈 때 가더라도 하도 여러 번 들으니까 인제 도무지 싫어 죽겠다.”","title":"경희","author":"나혜석","kind":"원문"},{"t":"아침","q":"아침이면 제일 먼저 일어납니다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"아침","q":"경희는 이렇게 아침부터 저녁까지 얻기 위하여 자라 갈 욕심으로 제 힘껏 일을 한다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"아침","q":"그러다가 어느 날 밤은 밤새도록 비가 퍼붓듯이 쏟아졌는데, 그 이튿날 아침에 가보니까 교실 속에 빗물이 웅덩이처럼 흥건하게 고였는데, 송판으로 엉성하게 만든 책상 걸상이 둥실둥실 떠다니는군요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"가면은 이 편지를 받으시는 다음다음 날(화요일) 아침 그곳에 도착할 예정입니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"저녁 뒤에 동혁은 가장 무관하게 지내고 또 영신을 오래 소개해 온 건배와 정득이, 갑산이, 칠룡이 같은 농우회원을 찾아다니며 '채영신이가 내일 아침에 온다'는 소식을 전하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"이른 아침, 동혁은 찢어진 지우산을 숙여 쓰고 큰덕미로 갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"이른 아침 물 속에서 낚여 나온 듯이 선명한 태양이 바다 저편에 붕긋이 솟아오를 때, 동리 한복판의 두 아름이나 되는 은행나무가 선 언덕 위에서 나팔 소리가 들린다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"이 노래는 동혁이와 건배의 합작으로, 청년들의 정신을 통일시키고 활기를 돋우기 위해서 아침마다 체조가 끝나면 부르는 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"날마다 한 번씩 부르는 노래건만, 이 노래를 지은 사람이나 받아서 합창을 하는 청년들은 아침마다 새로운 흥분을 느낀다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"오늘 아침에는 은행나무에 몸을 반쯤 가리고 서서 이 노래를 듣다가 감격에 흐느끼는 여자가 있었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"\"자, 아침 뒤에 우리 공동답 못자리를 만드세.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침볕을 눈이 부시도록 온몸에 받으며 눈물 흔적을 보이지 않으려고 바다 저편을 바라다보고 섰었기 때문이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"\"우린 아침마다 기도회가 있어요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"조반","q":"\"채선생, 조반은 우리집에 가서 잡수십시다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 동혁이와 나란히 서서 풀밭의 아침 이슬을 밟으며 내려온다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"두 사람은 아침 짓는 연기가 서리어 오르는 굴뚝 곁에서 서성거리며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"수란을 뜨고 닭고기를 볶고 하여서 세 사람은 아침을 맛있게 먹었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"허지만 아침마다 떨어지지 않는 눈을 억지루 부비면서 은행나무 밑으로 치닫는 것은 일이 있으나 없으나 하루 한 번씩 깨끗헌 정신으로 한장소에 모이자는 거지요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"가벼운 아침 바람에 주름이 잡히는 잔물결을 헤치며 칠룡이는 쟁기를 꼬느고 소를 몰아 갈기를 시작한다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"보자기를 열고 보니 아침에 먹다 남긴 것인지 미역을 넣고 끓인 닭국에는 노란 기름이 동동 떴다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침 일찍이 일어나 운동을 한바탕 허면 정신이 쇄락해지구, 첫째 소화가 잘 됩니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"오늘 아침에두 대판으루 싸웠는걸요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"영신이 자신도 동지들의 자별한 정의에 눈물이 날 만치나 고마워서, 아침 저녁으로 한곡리 청년들의 건강과 그네들의 사업을 위해서 정성껏 기도를 올렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"'내일 아침에야 일찌감치 오겠지.'","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"영신이가 이곳에 온 뒤로 하루도 거르지 않고 아침 저녁으로 거닐던 바닷가 백사장에는 하아얀 모래가 유리 가루처럼 반짝이는데, 그 모래를 밟으면 바삭바삭 소리가 난다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침 저녁 저의 손으로 치는 그 종소리는 저의 가슴뿐 아니라, 이곳 주민들의 어두운 귀와 혼몽히 든 잠을 깨워 주고 이 청석골의 산천초목까지도 울리겠지요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"그렇건만 아침에 벌떡 일어나서 냉수에 세수를 하고 나면 새로운 용기가 솟는다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침마다 제 시간이 되면 동혁이가 부는 나팔 소리가 바람결에 들려 오는 것 같아서 더 좀 누웠으려야 누워 있을 수가 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"\"주임이 당신을 보자는데, 내일 아침까지 주재소로 출두를 허시오.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"인전 아침두 안 먹구 오께 가라구 그러지 마세요, 네 네.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침부터 안 대청에서 자여질들이 헌수하는 술을 마시고 거나하게 취해 나온 한낭청은, 사방 삼십 센티미터나 됨직한 얼굴이 당호박처럼 시뻘겋게 익었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"학원을 지으려는 데만 열중한 그는, 그 전날도 기부금을 거두려고 삼십 리 밖 장거리까지 갔다가 날이 저물어서 그곳 교인의 집에서 묵고 아침에 떠나서 오는 길에 서너 집이나 들르느라고 점심때도 겨워서 흑석리 동구 앞까지 당도하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"새로운 회관에 들게 되는 날 아침에 동혁이가 부는 나팔 소리는 더한층 새되고 씩씩하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아무에게도 낙성식을 한다고 광고를 한 것도 아니요, 건배는 무슨 일이든지 크게 버르집고 뒤떠들려고만 든다고 동혁이와 의견 충돌까지 되었지만, 오늘 아침만은 누구나 은연중에 농우회관의 낙성식을 거행하는 기분으로 모인 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침 저녁으로 글 배우는 소리가 그칠 때가 없도록 해주십시오!","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"기천이는 면협 의원이 되던 날 아침에 행랑 사람과 머슴들을 불러 세우고,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"울다울다 지쳐서 잠이 들었다가 아침에 일어나 보니, 밤과 대추가 대소쿠리에 소복이 담겨서 머리맡에 놓여 있지 않았었던가.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"영신은 그 이튿날 아침 천만뜻밖에,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"그러나 영신은 아침볕이 벌겋게 물들어 오는 동녘 하늘을 빡빡한 눈으로 쳐다보면서도 이렇다할 감상이 일어날 마음의 여유가 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"정근은 여자의 날카로운 시선을 피하면서 지난봄에 결혼 문제를 해결지어 달라고 청석골까지 갔을 때보다도 더 여윈 얼굴에 아침볕을 모로 받으며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 집으로 뛰어들어가 보니, 어머니는 병들어 눕기는커녕 정지에서 아침 반찬을 할 것인지 생선을 다루고 섰지 않은가.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 반색을 하며 마당의 아침볕을 받으며 내닫는 어머니의 눈물이 글썽글썽해진 얼굴은 지난봄에 보았을 때와 조금도 다름이 없다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 어머니는 정지로 내려가서 수산조합에 다니는 동생의 댁과 아침상을 차린다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"방 안의 공기는 찢어질 듯이 빡빡한데, 어머니는 손수 딸의 아침상을 들고 들어왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"늦은 가을 서리 찬 아침은 정신이 번쩍 나도록 상쾌하다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"조반","q":"조반을 같이 먹으면서도 두 사람은 보통 연애를 하는 남녀와 같이 깨가 쏟아지는 듯한 이야기는 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"그 명랑한 종소리는 맑고 푸르게 갠 아침, 한없이 높은 하늘로 퍼지는데, 아이들은 와아 소리를 지르며 앞을 다투며 달려간다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침 저녁 내 손으로 울리는 그 종소리는 나의 가슴뿐 아니라, 이곳 주민들의 혼곤히 든 잠을 깨워 주고 청석골의 산천초목까지도 울리겠지요.'","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"오늘 아침의 그 종소리는 누구보다도 동혁의 가슴 한복판을 울렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아무튼 낙성식까지 하게 된 것이 덩달아 좋아서, 아침부터 주막에 가서 주렸던 막걸리를 잔뜩 마시고는 엉덩춤을 추며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"노형 말씀대루 급성 맹장염인데, 밤에는 설비 관계루 헐 수 없으니, 내일 아침에 수술을 헙시다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"동혁은 어느 날 아침, 아래와 같은 아우의 급한 편지를 받고 한곡리로 돌아왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"이튿날 이른 아침 동혁은 평일과 조금도 다름없이 일어나 회관으로 올라가서 기상나팔을 불었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"한참이나 자기가 살던 동리의 산천과 오막살이들을 넋을 잃고 내려다보다가, 남편에게 끌려서 그 고개를 넘으면서도 돌려다보고 돌려다보고 하는 것이 먼 광으로 보이더니, 그나마 아침 햇빛을 등지고 안계(眼界)에서 사라져 버렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"내일 아침에 뱃짐을 내시느냐구 헙니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"어려서부터 하나님을 불러 왔고, 그의 독생자에게서 희생과 봉사의 정신을 배웠고, 가장 어려울 때와 괴로울 때에 주를 부르며 아침저녁 기도를 올리지 않었느냐.'","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"아침 뒤에 영신은 동혁의 어머니를 위로해 주고 읍내를 향하여 떠났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"\"그럼, 면회는 내일 아침에 시켜 주지.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"숙직하는 교원에게 응급치료를 받은 후 교의가 올 때까지 기다리는 동안에, 영신은 몽유병 환자와 같이 눈을 멀거니 뜨고 누워서, 수술실처럼 흰 휘장을 친 유리창이 아침 햇발에 뿌옇게 물이 드는 것을 넋을 잃고 보고 있었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"구차한 살림에 얽매고, 어린것들이 매어달리고, 시부모의 시중을 들고, 집안 식구의 옷 뒤를 거두고, 다만 먹기를 위해서 이른 아침부터 밤늦도록 다른 농촌의 여자와 같이 집구석 ?","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"영신이가 떠나는 날 아침, 널따란 학교 마당에 전송하여 주는 사람은, 사감과 한방에 있던 학생 두엇뿐이었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"그러다가 하루 아침은 천만뜻밖에 동혁의 편지가 왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 아침에 종소리만 들리면 입술을 깨물며 문고리를 붙잡고 일어났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"기름이 졸아붙은 등잔불이 시름없이 꺼지자 뿌유스름한 아침 햇빛은 동창을 물들이기 시작하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"그러자 사흘 되는 날 아침에 뜻밖으로 동혁의 편지가 왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"동혁의 기념품인 학원의 종을 아침저녁으로 치던 사람의 상여머리에서 요령 소리가 땡그랑땡그랑 울린다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"이튿날 아침 동혁은 산소로 올라가서,","title":"상록수","author":"심훈","kind":"원문"},{"t":"아침","q":"하고 돈을 도로 가지고 가서 즉시 사죄를 하고 오라 하였더니, 중도에서 포박을 당하고 강도, 살인, 교사 급 공범 혐의로 박진사의 삼부자는 그날 아침으로 포박을 당하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"내가 밥값을 낼 것이니 저녁과 내일 아침 조반을 먹이고 재우시오’ 합데다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"또 팔월도 이십 일이 지났으니, 아침 저녁에는 찬바람이 솔솔 불어 무명고의 베적삼이 으스스하게 되었고, 또 밤에 덮을 것도 없이 자려면 사지가 가들어들어(옹송그려져) 잠을 이룰 수가 없었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"어젯저녁에도 칠성문 밖 어떤 집 윗목에서 밤새도록 추워서 한잠을 이루지 못하고 밤을 새웠더니, 아침부터 배가 아프기 시작하여 아버지를 만나기 전에 세 번이나 설사를 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"영채는 제가 입은 곱고 따뜻한 의복을 볼 때마다, 아침 저녁 먹는 맛나는 음식을 볼 때마다 아버지의 가엾은 모양이 눈에 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침 형식을 찾으려고 결심할 때에는 형식에게 그 동안 지내 온 말을 다 하려 하였더니, 이러한 생각이 나매 그만 그러한 결심도 다 풀어지고, 슬픈 생각과 원망스러운 생각만 가슴에 북받쳐 오를 뿐이다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그의 말소리도 정이 자아침을 따라 높았다 낮았다, 굵었다가 가늘었다, 마치 무슨 미묘한 음악을 듣는 듯하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"세수를 하고 영채의 일을 생각하며 조반을 먹을 제, 형식이가 가르치는 경성학교 학생 두 사람이 왔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러므로 여러 학생이 한꺼번에 배학감에게 ‘너희도 사람이냐’ 하는 책망을 받은 때에는 일동이 한곳에 모여앉아, 마치 큰절에서 아침에 중들이 모여앉아 염불하듯이 배학감의 별명을 있는 대로 부른다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침에도 뾰족해서 오지 않았습디까”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"형식은 아침부터 괴로움으로 지내 오던 마음속에 일점 향기롭고 서늘한 바람이 불어들어 옴을 깨달았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그를 봄철, 따뜻한 아침에 핀 꽃에 비길진대, 그는 아직 바람도 모르고 비도 모르고 늙음도 모르고 시들어 떨어짐도 모르는 바로 핀 꽃이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러다가 그날 아침에 ‘오늘은 기필코 형식을 찾아보리라’ 하고 오후에 형식을 찾아왔다가 만나지 못하고 저녁에 또 찾아왔던 것이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"영채도 점점 미인이라는 이름과 노래 잘하고 단율 잘 짓는다는 이름이 나서, 영채라는 오늘 아침에 핀 꽃을 제가 꺾으리라 하는 사람이 많게 되었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"이튿날 아침에 일어나 몇 친구에게 돈 오 원을 취하려 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러므로 그네가 만일 이 자리를 벗어나기만 하면 내일 아침부터는 자기네는 아무 죄도 없는 사람인 줄로 알 것이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"나는 이렇게 형사에게 포박을 당하더라도 내일 아침이면 놓여 나올 수도 있건마는, 너는 한번 옥에 들어가기가 바쁘게 일생을 그 속에서 썩으리라 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"내일 아침에는 식전에 김현수가 오렷다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그 이튿날 아침에 형식은 주인 노파가 너무 정직한 것을 한하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"노파는 벌써 조반을 차려 놓고 사오 차나 형식의 방을 엿보았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"저렇게 조반이 다 식는데”","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"“어서 세수를 하고 조반을 먹어!","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"“아씨께서 오늘 아침 차로 평양을 내려가셨어요!”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"“아침에 누구 오든 않았던가?”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"형식의 오늘 아침에 새로 입은 모시 두루마기 등에는 땀이 두어 군데 내어비친다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침 월향은, 어젯저녁의 슬퍼하던 빛이 없어지고 일찍 일어나 세수하고, 분을 바르고, 향수를 뿌리고, 모시 치마 저고리에 여학생 모양으로 차리고 아직 자리에서 일어나지도 아니한 노파의 방에 와서 아주 유쾌한 듯이 방글방글 웃으며,","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"‘참 어여쁜 계집애로다’ 하고 형식도 부끄러운 생각이 나면서, “녜, 내일 아침에 써드리지요”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그것을 써서 책 사이에 끼워 두고 ‘어서 아침이 왔으면’ 하고 잠을 이루지 못하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그 이튿날 아침에 형식은 더욱 양치와 세수를 잘하고 두루마기를 방정히 입고 그 종이―이 종이로다―를 접어 품에 품고 대문에 서서 영채가 나오기를 기다리던 생각은 마치 사랑을 하는 남자가 사람 없는 곳에서 그 사랑하는 처녀를 기다리는 생각과 같았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러나 아침에 영채가 분을 바르고 향수를 뿌리고 방글방글 웃으며 들어오는 양을 보매 노파의 영혼의 눈은 다시 감기어, 어젯저녁에 보던 영채의 ‘속사람’을 보지 못하고 다만 영채의 육체만 보았을 뿐이다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"노파는 오늘 아침 영채에게 ‘잘 생각하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러므로 칠 년 동안이나 아침저녁 ‘참사람’인 영채를 보면서도, 다만 월향이라는 살과 뼈로 생긴 기생을 보았을 뿐이요, 그 속에 있는 영채라는 ‘참사람’을 보지 못하였었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"영채는 어제 아침에 자기의 방에 와서 하던 모양으로 방글방글 웃으며 ‘생각하여 보니깐 우스운 일이야요’ 한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"머리는 아직 깎지 아니하여 부모상으로 흰 댕기를 드리고, 감발을 하고, 어느 봄날 아침에 칠성문으로 들어왔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"“어디 들어가서 조반을 사먹고 찾아봅시다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"자, 어디 가서 조반이나 먹읍시다”","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"조반을 먹거든 이리로 오지요”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그런데 아침차로 오셨어요?”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"영채가 청량사에서 어떤 사람에게 강간을 당할 뻔한 일과, 그날 저녁에 집에 돌아와 입술을 물어뜯고 울던 일과, 그 이튿날 아침에 자기가 자는 데 들어와서 평양에 갈 말을 하던 것과, 차를 탈 때에 자기에게 편지 한 장을 주었고 그 편지에는 이러이러한 말을 썼던 것과, 오늘 아침에 평양경찰서에 와서 물어 보던 일을 말하고 나중에,","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"형식은 그 집에서 조반을 먹고 대문 밖에 나섰다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"“오늘 아침차에 왔네”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침에는 분도 바르지 아니하였건마는, 귀밑에는 어저께 발랐던 분이 조곰 남았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"형식은 숙소에 돌아와 조반을 먹고는 곧 학교에 갔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러나 오늘 아침 첫 시간에는 사년급 영어가 있다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"형식은 아침마다 학교 문을 들어서서 학생들이 노니는 양을 보면 기쁘고, 시간마다 강단에 서서 학생들이 자기를 보고 자기의 말을 듣는 양을 보면 기쁘고, 밤에 혼자 자리에 누워 학생들의 놀던 모양과 배우던 모양을 생각하면 기뻤다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"내일이나 내년에 무슨 새로운 낙이 오기를 기다리는지도 모르지마는 그는 밤이 새고 아침이 되면, 또 자리에서 일어나서 밥을 짓고 빨래를 한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"또 나는 왜 그 이튿날 아침에 일찍이 영채를 찾지 아니하였던고.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침에야 비로소 장로가 웃는 말 모양으로,","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"차라리 어찌 생각하면 정다운 듯한 생각도 있었고, 더구나 아침에 부친의 말을 듣고는 전보다 좀더 정다운 생각도 나게 되었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"그러나 오늘 아침에 던지던 것과는 뜻이 다르다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"아침에 일어나서는 혼자 웃었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"오늘 아침부터 경상남북도, 전라남북도 일경에 비가 오기 시작하여 금강 낙동강은 십여 척의 증수가 되었다고.”","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"이것은 어저께 아침 곁에 병국의 부인과 셋이 그 목화밭에 가서 송별연삼아 수박을 따먹으면서 따모은 것이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"하고 아침 인사를 잊어버린 것을 생각하고 웃는다.","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"“아마, 내일 아침까지는 갈걸요”","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"눈앞에 늘어 있는 집들에서는 조반 짓는 연기가 나온다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"이때에 저편으로서 지금 바로 조반을 먹은 형식의 일행이 나와서 차차 이편을 향하고 온다.","title":"무정","author":"이광수","kind":"원문"},{"t":"조반","q":"하고, 저 수재를 당한 사람들 중에는 병인도 있고, 태모도 있고, 젖먹이 가진 부인도 있는데, 조반도 못 먹고 비를 맞고 떠는 정경이 가련하며, 더구나 어머니가 무엇을 먹지 못하였으므로 젖이 아니 나서 어린아이들의 우는 양은 차마 못 보겠다는 말을 한 뒤에,","title":"무정","author":"이광수","kind":"원문"},{"t":"아침","q":"간밤에 꿈을 잘못 꾸었던지, 오늘 아침에 마누라하고 다툼질을 하고 나왔던지, 아무튼 엔간히 일수 좋지 못한 인력거꾼입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"때가 아침저녁의 러시아워도 아닌데 웬일인지 만원 된 차가 두 대나 그냥 지나가 버립니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"이천 냥 돈을 그렇게 들이고서야, 어제 아침 달포 만에 말대가리 윤용규는 장독(杖毒)으로 꼼짝못하는 몸을 보교에 실려 옥으로부터 집으로 놓여 나왔던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"한 것이, 맏손자며느리는, 그렇다면 내일 아침부터 꼭꼭 보리밥을 먹어야 하겠다고 좋아했고, 둘째손자며느리는 아무려나 나도 먹어는 보겠다고 유념을 했고, 서울아씨는 나도 먹었으면 좋겠는데, 하는 생각을 했으니 말입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"그래도 작년 정월 시어머니 오씨가 살아 있을 때까지는 삼십 년 눌려서 살아온 타성으로, 고양이 앞에 쥐같이 찍소리도 못 하고 마음으로만 앓고 살았지만, 이제는 그 폭군이 하루 아침에 없고 보매 기는 탁 펴지는데, 그러나 세상은 여전히 뜻과 같지 않으니, 불평은 할 수 없이 악으로 변해 버리게만 되었던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"\"그러구저러구 간으, 그건 아침에 말헌 대루 이화리〔二割引〕아니구넌 안 되니 그렇게 알소잉?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"그리구 언제 왔느냐니깐 아침차루 왔다구, 그 말꺼정 했는데!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"조반","q":"××여관에서 종수는 조반을 먹고 드러누워 늘어지게 한잠을 잤습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"매일 아침 소변으로 눈을 씻으면 안력이 쇠하지 않는다는 것은 전부터 일러 오던 말인데, 윤직원 영감은 시방 그 보안법(保眼法)을 행하고 있는 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"아침마다 하는 일과라, 삼남이는 들고 들어온 빨병을 말없이 내바치고, 윤직원 영감 또한 말없이 그걸 받아 놓더니, 물었던 담뱃대를 뽑고 연상 서랍에서 소라껍데기로 만든 잔을 꺼냅니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"이웃의 가난한 집으로 어린애가 있는 데를 물색해서 그 어린애들의 아침 자고 일어난 오줌을 받아 오기로 특약을 해두었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"오줌이란 본시 찝찔한 것이지만 사람의 신경의 세련이란 무서운 것이어서, 삼십 년이나 두고 매일 아침 먹어 온 윤직원 영감은 그것이 조금 더 짜고, 덜 짜고 한 것까지도 알아맞힙니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"어제 아침 치는 약이 너머 졸았더라!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"후줄근하게 땀이 배고 약간 숨이 가쁜 것을, 앞 미닫이를 열어 놓고 앉아서 서늑서늑한 아침 바람을 쏘입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"아침","q":"혼자 걱정을 하는데, 마침 대복이가 아침 문안삼아, 오늘 하루의 일을 협의할 겸 건너왔습니다.","title":"태평천하","author":"채만식","kind":"원문"}],"오전":[{"t":"오전","q":"선형은 어서 미국에 갈 생각으로, 순애는 아무에게나 남에게 지지 않게 많이 배울 생각으로 어제 종일과 오늘 오전에 별로 쉬일 틈 없이 에이, 비, 시를 외우고 썼다.","title":"무정","author":"이광수","kind":"원문"}],"정오":[{"t":"낮","q":"그리고 그 낮은 하늘보다는 오히려 더 높이 있는 듯한 분홍빛 구름은, 뭉글뭉글 엉기면서 이리저리 날아다닌다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"낮","q":"\"그래 영감은 밤낮 나돌아다니니 혼자 지내기 쓸쓸치도 않소.\"","title":"뽕","author":"나도향","kind":"원문"},{"t":"낮","q":"나는 밤이나 낮이나 잠만 자느라고 그런 것을 알 길이 없다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"33번지 18가구의 낮은 참 조용하다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"아내는 낮에 보다도 밤에 더 좋고 깨끗한 옷을 입는다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"그리고 낮에도 외출하고 밤에도 외출하였다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"아랫방에서 아내와 그 남자의 내 귀에도 들리지 않을 만큼 낮은 목소리로 소곤거리는 기척이 장지 틈으로 전하여 왔던 것이다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"나는 날마다 이불을 뒤집어쓰고 밤이나 낮이나 잤다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"유난스럽게 밤이나 낮이나 졸려서 견딜 수가 없는 것이다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"무슨 목적으로 아내는 나를 밤이나 낮이나 재웠어야 됐나?","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"나를 밤이나 낮이나 재워 놓고, 그리고 아내는 내가 자는 동안에 무슨 짓을 했나?","title":"날개","author":"이상","kind":"원문"},{"t":"대낮","q":"다만 몇 시간 후에 내가 미쓰꼬시 옥상에 있는 것을 깨달았을 때는 거의 대낮이었다.","title":"날개","author":"이상","kind":"원문"},{"t":"정오","q":"이때 뚜우 하고 정오 사이렌이 울었다.","title":"날개","author":"이상","kind":"원문"},{"t":"정오","q":"그야말로 현란을 극한 정오다.","title":"날개","author":"이상","kind":"원문"},{"t":"낮","q":"아무리 잘 봐야 내 겨드랑(다른 사람보다 좀 크긴 하지만) 밑에서 넘을락 말락 밤낮 요 모양이다.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"낮","q":"밤낮 부려만 먹구 해준다, 해준다……”","title":"봄봄","author":"김유정","kind":"원문"},{"t":"낮","q":"\"밤낮 일만 하다 말 텐가!\"","title":"봄봄","author":"김유정","kind":"원문"},{"t":"낮","q":"낮에 구장님 앞에서 장인님과 내가 싸운 것을 어떻게 알았는지 대구 빈정거리는 것이 아닌가.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"낮","q":"\"밤낮 일만 해주구 있을 테냐?\"","title":"봄봄","author":"김유정","kind":"원문"},{"t":"낮","q":"낮은 하늘로 외면하여 못 본 척하고 닭을 향하여 저켠으로 널찍이 돌아 내린다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"낮","q":"하고 그게 옳지, 여기서 뭘 하느냐, 대장간이라구 일이나 많으면 모르거니와 밤낮 파리만 날리는데 그보다는 즈 형이 크게 농사를 짓는다니 그 뒤나 거들어 주고 국으로 얻어먹는게 신상에 편하겠지.","title":"만무방","author":"김유정","kind":"원문"},{"t":"낮","q":"나는 밤이나 낮이나, 비 오나 바람이 치나 헤아리지 않고 삯김, 삯심부름, 삯나무, 무엇이든지 가리지 않았다.","title":"탈출기","author":"최서해","kind":"원문"},{"t":"낮","q":"이 사상이 드디어 나로 하여금 집을 탈출케 하였으며, ××단에 가입하게 하였으며, 비바람 밤낮을 헤아리지 않고 벼랑 끝보다 더 험한 ×선에 서게 한 것이다.","title":"탈출기","author":"최서해","kind":"원문"},{"t":"낮","q":"떡장수가 아무 때나 아침에도 다녀가고 낮에도 다녀가고 저녁때도 다녀가지 학교에 다니는 학생같이 시간을 맞춰서 다니나요!","title":"경희","author":"나혜석","kind":"원문"},{"t":"낮","q":"“아이 무엇이 그리 우순지 그 애가 오면 밤낮 셋이 몰켜다니며 웃는 소리에 도무지 산란해 못 견디겠어요.","title":"경희","author":"나혜석","kind":"원문"},{"t":"낮","q":"밤낮 몰려댕기며 역적 모의허듯 쑥덕공론만 허니 밥이 생기나 옷이 생기나.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"대낮","q":"수동이네 주막에서 대낮버텀 술을 처먹는다더니 여태 게 있는 게지.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"밤낮 그 잘나 빠진 공동답이나 주무르구 콧물 흘리는 아이들을 뫄놓구서 언문 뒷다리나 가르치면 제일의 강산이란 말이요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"대낮","q":"아들은 젓잡이를 하러 나가고, 늙은 마누라와 며느리만 집을 지키고 있어서, 대낮에도 노 젓는 소리와 간간이 뱃노래 소리밖에는 들리는 것이 없어 여간 조용하지가 않다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"\"아아뇨, 인제 죽가래루 판판허게스리 번대를 친 뒤에 새내끼를 다시 띄워 놓구서 하루 밤 하루 낮을 뒀다가, 수확이 많다는 은방주(銀坊主)든지 요새 새루 장려하는 팔단(八段) 같은 걸 뿌리지요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"그러다가 하루는 낮이 훨씬 겨워서 기만은 자회색 봄 양복을 말쑥하게 거들고 도금으로 장식을 한 단장을 휘두르며 바닷가 영신이가 유숙하는 집으로 찾아갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"대낮","q":"그 말에 대낮 같으면 영신의 얼굴이 석류처럼 빨개진 것을 볼 수 있었으리라.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"그러나 그 반면으로 건강은 아주 회복이 되어서, 먼동이 훤하게 틀 때 일어나 기도회에 참례를 하고 낮에는 학원을 지을 기부금을 모집하러 몇십 리 밖까지 다니거나, 그렇지 않으면 부인 친목계의 계회원들과 같이 발을 벗고 들어서서 원두밭을 매고 풀을 뽑고 하다가 저녁을 먹고 나면, 그 자리에 쓰러지고 싶은 것을 간신히 참고 예배당으로 가야 한다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"조금 있자, 풍물 소리를 듣고 성벽이 난 작은 마을과 구엉 마을에서도, 낮에 두레로 논을 매던 야학의 학부형들이 잡이를 차려 가지고 와서는 큰마을 두레와 어울렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"금분이나 창례만할 때에, 그때도 추석 전날 오늘처럼 달이 초롱같이 밝은데, 낮에 동산에서 주워다 둔 밤과 풋대추를 가지고 마루에서 사촌동생과 공기를 놀던 생각이 났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"\"저 녀석들은 처먹구 헐 짓들이 없어서 밤낮 몰려만 댕기는 게여.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"낮에는 편을 갈라 윷놀이를 하게 되었는데, 그때까지도 갑산이와 동화는 회관의 열쇠를 내놓지 않았다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"부모의 상사를 당한 것만치나 섧게들 울며 밤낮을 계속하는데, 그 중에도 금분이는 사흘씩이나 절곡을 하고 참새 같은 가슴을 쥐어짜며 울다가, 지금은 선생이 입던 헌 재킷을 끌어안은 채 관머리에 지쳐 늘어졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"낮","q":"하나는 부모 갖고, 집 있고, 재산 있어 편안하게 학교에도 다니고, 명년에는 미국까지 간다 하는데, 하나는 부모도 없고, 형제도 없고, 집도 없고, 어디 의지할 곳이 없이 밤낮을 눈물로 보내는고.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"옷은 집에서 서너 벌 가지고 갔었으나, 밤낮 물 긷고 불 때기에 다 더럽고, 더러워도 빨아 주는 사람이 없어서 제 손으로 빨아서 풀도 아니 먹이고 다리지도 아니하고 입었습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"이튿날 조반도 굶고 낮이 기울어지도록 가다가 시장증도 나고 다리도 아프기로 길가 어느 촌중에 들어갔습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"밤낮 소동만 일어나고.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"하고 자기보다 훨씬 낮은 사람 모양으로 말하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"아아, 영채의 원혼(怨魂)이 밤낮 내 몸에 붙어서 낮에는 병이 되고 밤에는 꿈이 되어 나를 괴롭게 하지나 아니하겠는가 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"게다가 처음부터 월화와 친해서 밤낮 월화의 말만 들었으니까, 꼭 마음이 월화와 같이 되었습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"예쁜 학생들이 낮에 그 나무 그늘에 앉아서 즐겁게 이야기하는 것을 볼 때에 형식은 매양 기쁨을 깨달았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"낮에는 잠자고 있던 사람들도 차차 기운을 내어 말도 하고 웃기도 하게 된다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"높은 소리로부터 낮은 소리까지, 또는 낮은 소리로부터 높은 소리까지 맑은 소리가 황혼의 공기를 가볍게 떤다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"영채의 눈에는 여름낮 볕을 받은 푸른 산이 보이고 밀과 보리의 누른 물결과, 조와 피의 푸른 물결도 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"그래도 아내는 밤낮 남편의 옷을 빨고 다리고 한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"어쨌든 칠팔 년 동안이나 밤낮 생각하던 사람을 그렇게 어떻게 쉽게 잊겠니?","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"세상 사람들이 입으로 말은 아니 하지마는 속으로 밤낮 구하는 것은 이러한 사랑이다.","title":"무정","author":"이광수","kind":"원문"},{"t":"낮","q":"아, 그년은 글씨 무엇 하러 밤낮 그렇기 싸댕긴다냐?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"대낮","q":"그런데 그게 귀신이 곡을 할 일이라고, 윤두꺼비는 두고두고 기막혀하였었지마는, 그걸 어떻게 염탐했는지 벌건 대낮에 쏙 빠진 양복쟁이 둘이 들이덤벼 가지고는 그 돈 사천 원을 몽땅 뺏어 가던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"대낮","q":"한데 이건, 바로 대낮에 귀한 손님 행차하듯이 어엿이 찾아와서는, 한다는 짓이 그 짓이니 꼼짝인들 할 수가 있었나요.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"\"밤낮 그렇게 사탕만 사먹어?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"그런디 그놈덜이, 내가 뫼야 준 돈은 각구서 즈덜만 밤낮 그 지랄을 허지, 나넌 통히 모른 체를 허네그려!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"그래, 느놈덜은 이놈덜, 밤낮 지집 둘셋 읃어 놓구……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"돈이나 뜯어 낼라구 허구, 검방지기나 허구, 밤낮 샛밥이나 처먹구……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"밤낮 다리만 치라구 허구…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"말동무 하나 없이 밤이나 낮이나 텅 빈 삼 칸 장방에 담뱃대를 물고 혼자 달랑 누웠다 앉았다 하자니, 어떤 때에는 마구 다리가 비비 꼬이게시리 심심해 살 수가 없습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"이리 궁금해하면서 기다리노라니까, 아닌게아니라, 훨씬 낮이 겨운 뒤에 그 애 동기아이가 찰래찰래 오지를 않겠습니까.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"윤직원 영감은, 에― 거 애여 어린 계집애년들 이뻐하고 데리고 놀고 할 게 아니라고, 얼마 동안을 다시 전대로 소일거리 없이 심심한 밤과 낮을 보냈습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"아까 낮에 명창대회서 영감님이 연신 조오타!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"내일 낮에 가서 사주마.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"공분 밤낮 꼴찌만 하는 녀석이, 놀 속은 남보담 더 바치구…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"번번이 마주 앉으면 노래 부르듯 육장 두고서 하는 꼭 같은 푸념이요 팔자 탄식인 걸, 그러니 인제는 듣기도 헤먹거니와 이편의 위로엣 말도 밤낮 되풀이하던 그 소리라 말하는 나부터가 헤먹습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"\"아, 고 병신이, 밤낮 절더러, 대고모 말을 하겠지!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"머, 내가 누구 때문에 밤낮 여길 오는데 그래……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"그리구 내일 낮에 올라냐?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"그러니까 방금 창식이 윤주사의 둘째첩 옥화가 계동 큰댁에 들렀다가 며느리뻘 되는 뒤채의 두 새댁들과 말말 끝에, 집에는 얼굴도 들여놓지 않은 종수를, 아까 낮에 우미관 앞에서 만났다는 그 이야기를 하고 있는 그 시각과 거진 같은 시각입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"낮","q":"역시 병호는 집에 없고 그의 아낙의 말이, 어제 낮에 잠깐 다녀온다고 나간 채 여태 안 들어왔다는 것입니다.","title":"태평천하","author":"채만식","kind":"원문"}],"오후":[{"t":"오후","q":"도회와 교외의 경계에 달린 K씨의 집에까지 두 노인이 이른 때는 오후 너덧시가 된 때였었다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"오후","q":"“아까 오후에 청량리 나갔소.","title":"무정","author":"이광수","kind":"원문"},{"t":"오후","q":"오후에 나가서 여섯점엔 온다던 것이 아직 아니 들어와!’","title":"무정","author":"이광수","kind":"원문"},{"t":"오후","q":"그러고 오늘 오후에 나하고 김장로 댁에 가시지요.","title":"무정","author":"이광수","kind":"원문"},{"t":"오후","q":"동네 사람들에게 ‘잘 가거라’ ‘잘 있으오’ 하는 인사를 필하고 일행이 동구를 나설 때는 정히 오후 일시경, 내리쬐는 팔월 볕이 모닥불을 퍼붓는 듯하다.","title":"무정","author":"이광수","kind":"원문"},{"t":"오후","q":"그래서 마침 부산 가는 기차가 비에 걸려서 오후까지 머물게 되었으니, 음악회를 열어 거기서 수입된 돈으로 불쌍한 사람들에게 따뜻한 국밥이라도 만들어 먹이고 싶다는 뜻을 말하고 허가와 원조하여 주기를 청하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"오후","q":"오후쯤 해서는 올챙이와 말이 얼린 수형 조건으로 오천구백오십 원을 주고서 칠천 원짜리 수형을 받아, 일천오십 원의 이익을 볼 테니, 그 중 일백오 원은 구문으로 올챙이를 주더라도 구백사십오 원이고 본즉, 오늘도 벌이가 쑬쑬하여 기쁘고.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"오후","q":"어제 오후 부민관의 명창대회에 가던 때처럼, 탕건 받쳐 통영갓에, 윤이 치르르 흐르는 안팎 모시 진솔것에, 하얀 큰 버선에다가 운두 새까마니 간드러진 가죽신에, 은으로 개대가리를 한 개화장에, 합죽선에 이렇게 차리고 처억 나섭니다.","title":"태평천하","author":"채만식","kind":"원문"}],"저녁":[{"t":"저녁","q":"마음은 급하고 불길은 닿지 않아 채 익지도 않은 것을 그 오라질 년이 숟가락은 고만두고 손으로 움켜서 두 뺨에 주먹덩이 같은 혹이 불거지도록 누가 빼앗을 듯이 처박질 하더니만 그날 저녁부터 가슴이 땅긴다, 배가 켕긴다고 눈을 홉뜨고 지랄병을 하였다.","title":"운수 좋은 날","author":"현진건","kind":"원문"},{"t":"황혼","q":"흐리고 비오는 하늘은 어둠침침하게 벌써 황혼에 가까운 듯하다.","title":"운수 좋은 날","author":"현진건","kind":"원문"},{"t":"해질","q":"처음에는 그럭저럭 지내었지마는 한푼 나는 데 없는 살림이라 한 달 가고 두 달 갈수록 점점 곤란해질 따름이었다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"어스름","q":"창경(窓鏡)으로 비치는 어스름한 햇빛에 나는 흔히 그의 눈물 머금은 근심 있는 눈을 발견하였다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"어스름","q":"이틀 뒤 해 어스름에 처형은 우리집에 놀러 왔었다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"저녁","q":"모처럼 오셨다가 반찬은 없어도 저녁이나 잡수셔요.\"","title":"빈처","author":"현진건","kind":"원문"},{"t":"저녁","q":"오늘 저녁 차로 떠날 것이니까 가서 짐을 매어야지.","title":"빈처","author":"현진건","kind":"원문"},{"t":"저녁","q":"벌써 오늘 저녁 차로 간다고 편지까지 했는데…….\"","title":"빈처","author":"현진건","kind":"원문"},{"t":"저녁","q":"초저녁부터 아내는 별별 생각을 다하면서 남편을 고대고대하고 있었다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"저녁","q":"영유, 이름은 모르지만 산에 올라가서 내려다보면 앞은 망망한 황해이니, 그곳 저녁때의 경치는 한번 본 사람은 영구히 잊을 수가 없으리라.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"그날 저녁, 얼근히 취한 그는 아내를 위하여 떡을 한 돈어치 사 가지고 집으로 돌아왔다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"거울을 사 가지고 장을 본 뒤에 그는 이 거울을 아내에게 주면 그 기뻐할 모양을 생각하며, 새빨간 저녁 햇빛을 받는, 넘치는 듯한 바다를 안고 자기 집으로, 늘 들러오던 탁주 집에도 안 들러서 돌아왔다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"그래서 알아보니까, 꼭 그의 아우같이 생긴 사람이 오륙 일 전에 멧산자 보따리를 하여 진 뒤에, 시뻘건 저녁 해를 등으로 받고 더벅더벅 동쪽으로 가더라 한다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"말을 끝낸 그의 눈에는 저녁 해에 반사하여 몇 방울의 눈물이 반짝인다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"노래를 끝낸 다음에 그는 일어서서 시뻘건 저녁 해를 잔뜩 등으로 받고, 을밀대로 향하여 더벅더벅 걸어간다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"저녁","q":"어떤 여름날 저녁이었었다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"저녁","q":"새빨간 저녁 해에 비치어서 그의 늙은 눈에는 눈물이 반득였다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"저녁","q":"그날 저녁을 먹은 뒤에, 혼자서 신간 치료보고서를 읽고 있을 때에 M이 찾아왔습니다.","title":"발가락이 닮았다","author":"김동인","kind":"원문"},{"t":"저녁","q":"이리하여 작별을 하였는데, 지금에 이르러 생각하면 그 저녁의 그 문답이 오늘날의 그의 혼약을 이루게 하지 않았는가 합니다.","title":"발가락이 닮았다","author":"김동인","kind":"원문"},{"t":"저녁","q":"M이 결혼한 지 일년이 거의 된 어떤 날 저녁이었습니다.","title":"발가락이 닮았다","author":"김동인","kind":"원문"},{"t":"저녁","q":"그와 나는 어떤 곳에서 저녁을 같이 하고 있었습니다.","title":"발가락이 닮았다","author":"김동인","kind":"원문"},{"t":"저녁","q":"그날 저녁에 방원이는 술이 얼근하여 돌아왔다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"저녁","q":"\"여보, 이번에는 임자가 하루 저녁 가보구려.","title":"뽕","author":"나도향","kind":"원문"},{"t":"저녁","q":"놈이 신이 나서 저녁 먹고, 마당 쓸고, 소 여물 주고, 도야지, 병아리새끼 다 몰아넣고, 앞뒤로 돌아다니며 씻은 듯 부신 듯 다 해놓고, 목물하고 발 씻고, 등거리 잠뱅이까지 갈아입은 후 곰방대에 담배를 꾹꾹 눌러 듬뿍 한모금 빨아 휘― 내뿜으며 시간 오기만 기다린다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"저물","q":"저물도록 미닫이 여닫는 소리가 잦다.","title":"날개","author":"이상","kind":"원문"},{"t":"저녁","q":"아내는 엊저녁 내가 의식을 잃은 동안에 외출한 것인지도 모른다.","title":"날개","author":"이상","kind":"원문"},{"t":"저녁","q":"나는 또 엊저녁에 그 돈 오 원을 한꺼번에 아내에게 주어 버린 것을 후회하였다.","title":"날개","author":"이상","kind":"원문"},{"t":"저물","q":"나는 저물도록 길가 시계를 들여다보고 들여다보고 하면서 또 지향 없이 거리를 방황하였다.","title":"날개","author":"이상","kind":"원문"},{"t":"저녁","q":"아내 방에는 저녁 밥상이 조촐하게 차려져 있는 것이다.","title":"날개","author":"이상","kind":"원문"},{"t":"저녁","q":"나는 마음을 턱 놓고 조용히 아내와 마주 이 해괴한 저녁밥을 먹었다.","title":"날개","author":"이상","kind":"원문"},{"t":"해 질","q":"장인님은 헷손질을 하며 솔개미에 챈 닭의 소리를 연해 질렀다.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"저녁","q":"눈물을 흘리고 간 담날 저녁나절이었다.","title":"동백꽃","author":"김유정","kind":"원문"},{"t":"저녁","q":"생각해 보니 어젯저녁부터 여태껏 창자가 곯렸던 것이다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"저녁","q":"저녁거리를 기다리는 아내를 생각하며 좁쌀 서너 되를 손에 사들고 어두운 고개를 터덜터덜 올라오는 건 좋으나 이 신세를 뭐에 쓰나 하고 보면 을프냥궂기가 짝이 없겠고―---이까짓 걸 못 먹어 그래 홧김에 또 한 놈을 뽑아 들고 이번엔 물에 흙도 씻을 새 없이 그대로 텁석거린다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"저물","q":"그러나 저물면은 그대로 쓰러진다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"저녁","q":"약이라야 어젯저녁 울 뒤에서 옭 아들인 구렁이지만.","title":"만무방","author":"김유정","kind":"원문"},{"t":"저녁","q":"장날 저녁은 정해놓고 계집의 고함소리로 시작되는 것이다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"저녁","q":"반날 동안이나 뚜벅뚜벅 걷고 장터 있는 마을에 거지 반 가까왔을 때, 거친 나귀가 한바탕 우렁차게 울면, 더구나 그것이 저녁녘이어서 등불들이 어둠 속에 깜박거릴 무렵이면, 늘 당하는 것이건만 허 생원은 변치 않고 언제든지 가슴이 뛰놀았다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"황혼","q":"눈옷 입은 산봉우리 나뭇가지 끝에 남았던 붉은 석양볕이 스르르 자취를 감추고 먼 동쪽 하늘가에 차디찬 연자줏빛이 싸르르 돌더니 그마저 스러지고 쌀쌀한 하늘에 찬 별들이 내려다보게 되면서부터 어둑한 황혼빛이 빼허의 좁은 골에 흘러들어서 게딱지 같은 집 속까지 흐리기 시작하였다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"황혼","q":"그러므로 우리는 황혼이면 산에 가서 도적 나무를 하여 지고 밤이 깊어서 돌아온다.","title":"탈출기","author":"최서해","kind":"원문"},{"t":"저녁","q":"\"저이가 나더러 당신하고 오늘 저녁……","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"저녁","q":"어제 저녁에 꿈이 괜찮더니 이런 땡을 잡을 양으로 그랬구나……","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"해질","q":"P와 같은 인생이 이 세상에 하나도 없이 싹 치운다면 근로하는 사람이 조금은 편해질는지도 모른다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"저녁","q":"김 부인은 아무 뜻 없이 어제 저녁에 자리 속에서 딸에게 들은 이야기를 한다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"아마 오늘 저녁 꼭은 올 터이지.”","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"경희는 쇠귀에 경을 읽지 하고 제 입만 아프고 저만 오늘 저녁에 또 이 생각으로 잠을 못 자게 될 것을 생각하였다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"그러고 어느 날 저녁에 경희가 “공부를 하면 많이 해야겠어요.","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"시월이는 속으로 ‘저녁 진지에는 작은아씨의 즐기시는 옥수수를 어디 가서 맛있는 것을 얻어다가 쪄서 드려야겠다.’","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"“그러면 저녁때 늦지?”","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"그러면 건넌방 아씨하고 저녁 해 놓을 터이니 늦게 돌아와서 잡수어라.","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"그러므로 오늘 저녁에 부부가 앉아서 혼처에 대한 걱정이라든지 그 애 버릴까 보아 염려하던 것을 안심하는 부모의 애정은 그 두 얼굴에 띠운 웃음 속에 가득하다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"저녁","q":"오늘 저녁은 각처에서 모여든 대원들을 위로하는 다과회가 그 신문사 누상에서 열린 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"오늘 저녁에 항상 그리워하던 여러분 동지와 한자리에 모여서 흉금을 터놓고 서로 얘기할 기회를 얻은 것을 무한히 기뻐합니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"더구나 오늘 저녁은 간단한 경과만 보고하기를 약속헌 까닭에, 정작 이 가슴속에 첩첩이 쌓인 그 무엇을 여러분 앞에 시원스럽게 부르짖지 못하는 것을 크게 유감으로 생각합니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"오늘 저녁 이 자리에 모인 바루 여러분의 손으로 시작해야겠습니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"비록 오늘 저녁 공석에서 처음 대면을 하였건만, 여러 해 사귀어 온 지기(知己)와 같이 피차에 반가웠던 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"토요일 저녁마다 농촌운동에 뜻을 둔 청년 남녀들이 모여서 토론도 하고 간담도 하는 모임이 백선생 댁에서 열리는데, 돌아오는 토요일에 올러오셔서 참석하시면 백선생은 물론이고요, 여러 회원들이 여간 환영을 하지 않겠습니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그날 저녁에 실례한 것은 이 사람이었소이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"황혼","q":"마당은 그다지 넓지 못하나 각색 화초가 어울려 피었는데, 그 중에도 이름과 같이 청초한 옥잠화 두어 분은 황혼에 그윽한 향기를 놓는다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"자, 이것들이나 들으면서 우리 저녁을 먹읍시다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"아 이건 별식을 헌다구 저녁을 굶길 작정야?\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그랬다가 해가 설핏헐 때 그눔을 끄내설랑 쩍 뻐개 놓구는 삑 둘러앉어서 어적어적 먹어 가며 얘기를 했으면 아마 오늘 저녁의 백선생이 허신 말씀이 턱 어울릴 겝니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"어째 오늘 저녁엔 서양으루 유람이나 온 것 같은걸요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"땅거미","q":"박첨지는 혀를 끌끌 차며 젊은 사람들을 꾸짖고 마누라는 아들의 두둔을 하느라고 어느덧 땅거미 지는 줄을 모른다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"하고 다시 안으로 들어가, 전번 일요일에 모였을 때의 회록과 오늘 저녁에 여러 사람에게 들려 줄 이야기를 초잡아 놓은 공책을 꺼내 가지고 나와서 작은마을 건배네 집 편으로 걸었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그저 저녁도 안 먹고 자는 동화의 거친 숨소리에 섞여, 누에가 뽕잎을 써는 것처럼 부시럭부시럭하는 소리가 간간이 머리맡에서 들렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"지금 임시로 빌려 쓰는 예배당은 워낙 협착헌데다가 주일날허구 삼일날 저녁은 쓰지 못허니까, 여간 불편치가 않어서 이번에 좀 쉬었다가 가선, 억지루라도 집 한 채를 얽어 볼 작정이야요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"허더니 웬걸, 작심 삼 일은커녕 그날 저녁두 못 참구 주막으루 간 사람들이 있었어요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"우리 동지들끼리 저녁이나 같이 먹으면서 좋은 얘기나 듣구 싶은데…….\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그는 영신이가 먼 데서 찾아온 귀한 손님이라고 대접을 하려는 것보다도, 몸이 비비 틀리도록 심심한 판에 동리에 처음으로 떠들어온 신여성을 불러다 놓고 하루 저녁 소견이나 하고 싶은 눈치다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"오늘 저녁은 저 동혁 씨 댁으루 가기로 먼저 약속을 했습니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"으뭉스레 굴지 말구 저녁엔 꼭 데리구 오너라.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"어제 저녁에는 동화도 형과 겸상을 해서 밥을 푹푹 퍼넣다가,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"박첨지와 동화는 자리를 내어 주느라고 마실을 갔는데, 윗간에서 저녁을 기다리는 동안 세 사람은 농촌 문제를 토론하고, 요새 한참 떠드는 중에 있는 자력갱생(自力更生) 운동을 비판하는데, 건배의 아낙이 밥상을 들고 들어온다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"온 지 나흘 되는 날 저녁에 영신은 건배의 아낙을 앞장 세우고, 동네에 말귀 알아들을 만한 여인네들을 그 집 마당에 모아 놓고 또 한 번 일장연설을 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"아, 엊저녁엔 공직자 부스럭지들을 대접헌다구 주막의 갈보까지 불러다가 밤새두룩 술상을 벌여 놓구 뚱땅거려서 잠두 못 자게 굴길래 그래서 한바탕 야단을 쳤지요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"그럼 내일 저녁에래두 놀러 와 줍시오.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그 중에도 눈에 암암한 것은 저녁마다 손목과 치마꼬리에 매어달리던 어린이들이요, 귀에 쟁쟁한 것은,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"다른 사람들은 초저녁에 다 와서 작별을 하고 갔고, 건배의 아낙은 영신이가 친정에나 왔다가 가는 것처럼 수수엿을 다 고아 가지고 와서 눈물로 작별을 하고 갔건만, 동혁이만은 기다려도 기다려도 오지 않았다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그러던 것이 오늘 저녁은 즉흥적으로 드리고나 슈베르트 같은 작곡가의 애련한 영탄적(詠嘆的)인 노래가 줄달아 불러졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"처음에는 입 속으로만 군소리하듯 불러 보던 것이 차츰차츰 그 소리가 높아져서, 무섭도록 고요한 깊은 밤 해변의 적막을 깨트리다가는 가느다랗게 뽑아내리는 피아니시모에 영신은 '내가 성악가나 될 걸 그랬어' 하리만치, 제 목소리가 오늘 저녁만은 은실같이 곱고 꾀꼬리 소리만치나 청아한 듯이 제 귀에 들렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"그럼 여태 저녁두 안 잡쉈게요?\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"아무리 고집이 세고, 무슨 일에나 앞장을 서고 누구에게나 지지 않으려는 성벽이 대단한 영신이건만, 오늘 저녁 이 자리에서만은 꽃을 부끄리는 처녀의 속탈을 벗지 못한다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그러다가 어느 날 저녁때였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그는 아픈 다리를 간신히 끌고 돌아와서 저녁도 아니 먹고 그날 밤을 꼬박이 새우다시피 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"해질","q":"그런 소문이 미리 나면 일이 더 복잡해질 것을 염려하였기 때문이었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"주학과 야학으로 가르고는 싶으나 저녁에는 부인 야학이 있어서 번차례로 가르칠 수도 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그러다가는 저녁까지 굶고 눈이 하가마가 되어서 캄캄한 밤에 하늘의 별만 대중해서 방향을 잡고 오는 날도 겅성드뭇하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그 돈은 저녁 안으루 꼭 보내 드리리다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그날 저녁부터 일주일 동안이나 영신은 경찰서 유치장 마루방에서 새우잠을 잤다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"여러 해 별러 오던 농우회의 회관을 지으려고 오늘 저녁에 그 지경을 닦는 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"고요한 바닷가의 저녁 공기를 헤치는 달구질 소리는 점점 더 커지는데, 큰 마을 편에서 징, 장구, 꽹과리를 두드리는 소리가 가까이 들려 온다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그럭저럭 언덕 아래는 머슴 설날이라는 이월 초하루나 추석날 저녁보다도 더 풍성풍성해졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"땅을 다지는 동네 사람들은 목이 쉬어 가는 줄도 모르는데, 그날 저녁 동혁은 젊은 사람과 조금도 다름이 없이 싱싱하고 씩씩한 아버지의 목소리를 생후 처음으로 들었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"저 강도사 댁 작은사랑 나으리가 저녁때 잠깐 만나자구 허시는데요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"저녁 먹구 건너간다구, 가서 그러게.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁 뒤에 그는 말대답할 것을 생각하면서 큰마을로 발길을 옮겼다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"아 이 사람아, 난 여태 저녁두 안 먹구 기다렸네.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"오늘 저녁은 학예회에 출연할 아이들을 마직막으로 연습을 시켜서 돌려보내고, 유희하는 데 나오는 여왕에게 씌워 줄 종이 면류관을, 마분지로 오리고 금지로 배접을 해서는 그것을 꿰매고 앉은 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"낼 저녁에 너희 반에서 헐 거 말야.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"얘, 오늘 저녁엔 우리 선생님이 여간 이뻐 뵈지 않는구나.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"아닌게아니라, 오늘 저녁의 영신은 달빛에 보아 그런지 담 밖을 넘겨다보는 한 송이 목련화처럼 탐스러워 보였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"오늘 저녁에 아무것도 준비한 것이 없는데, 이처럼 여러분께서 많이 와주셔서 감사합니다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"영신의 덕택으로 호미와 절굿공이와 오줌동이밖에 모르고 지내던 자기네부터 글눈을 떴거니와, 오늘 저녁에 자기네가 금지옥엽같이 기르는 자녀들이 그처럼 신통하게 재주가 있을 줄은 꿈에도 몰랐었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"일년 중에도 가장 밝고 맑고 서늘한 추석날 저녁의 달빛은 예배당 마당으로 쏟아져 내린다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"늙으신 어머니를 그리워할 겨를도 없고, 토요일 저녁이면 무슨 일이 있든지 동혁에게 꼭꼭 써 부치던 편지도 두 번씩이나 거르기까지 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"자동차가 떠날 때 차창을 스치는 저녁 바람에 한가닥 두가닥 휘날리던 서릿발 같은 머리털!","title":"상록수","author":"심훈","kind":"원문"},{"t":"황혼","q":"그는 마악 전깃불이 나가서 황혼 때와 같이 으스레한 정거장 넓은 마당에서 머리를 들었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"아무튼 내가 없인 낙성식을 못 헐 테니깐 저녁차루 떠나야겠수.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"'저녁차에는 꼭 오겠지.'","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"하고 저녁때 또다시 나갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"두 사람이 점심 저녁을 굶어서 몹시 시장할 것을 생각하고 영신은,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"곡식이 무럭무럭 자라는 시퍼런 벌판을 바라보는 게 내 눈을 시원허게 해주는 그림이구요, 저녁마다 야학당에서 아이들이 글을 배우는 소리가 내 귀를 즐겁게 해주는 음악이에요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁때에 들어온 사람이 밥상은 윗목에다 물려 놓고,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그저께 저녁버텀 죽기 작정허구 막 들이켰네.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"아무리 비밀을 지키라고 당부를 해도 저녁 안으로 그 말이 새어서 기천의 귀에까지 들어갈 것을 동혁이가 모를 리는 없다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"하면서도 동혁은 더 기다릴 수가 없어서 저녁을 든든히 먹은 뒤에 큰마을로 기천이를 찾아갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁상을 내보낼까 물어 보려고 불러들이는 눈치다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"전 저녁을 먹구 왔지만, 세잔갱작(洗盞更酌)이라는데 자 이번엔 반주루 한잔 더 드시지요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁때에야 회관문은 열렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그날 저녁 동네의 육십 이상 된 노인이 있는 집에는 죽은 지 이틀이나 되어서 검푸르게 빛 변한 돼지고기가 두 근, 혹은 세 근씩이나 세찬이란 명목으로 배달되었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"해질","q":"그의 곁에 쪼그리고 앉은 기천의 존재가 납작해질 만치나 동혁의 윤곽은 큼직하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁때가 되니까 창 밖에는 바람이 일어 불김이 없는 회관 안은 냉기가 돌건만, 누구 하나 추워하는 눈치가 보이지 않는다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저물","q":"기천은 날도 저물고 하니 말을 간단히 하라고 주의를 시키려다가, 동혁에게 우박을 맞을까 보아 내밀었던 고개가 옴씰 하고 들어갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"초저녁에는 여기저기 머슴사랑에서,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"날은 초저녁보다도 강강한데 싸래기눈이 쌀쌀하게 뿌리기 시작한다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"초저녁에는 강도사 집 마당에서 젊은 사람들이 편윷을 놀았었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"기천이가 새로 선거된 임원들을 불러 저녁을 먹이는데, 동화가 술이 취해 가지고 달려들었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"황혼","q":"황혼은 자취 없이 토담집 속까지 스며드는데, 주인을 잃은 도야지가 우릿간에서 꾸울꾸울거리는 소리만 들린다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"저녁때에 중대 사건이나 난 듯이 자동차를 몰아 온 경관대는, 추녀가 불에 끄슬린 회관을 임검한 뒤에, 동혁과 농우회원들의 집을 엄밀히 뒤졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"해질","q":"정양할 겸 온 것이라서 수토가 달라 몸은 점점 쇠약해질 뿐.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"원재 어머니는 저녁상을 들고 들어오며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"너희들두 이젠 고만 가서 저녁들 먹어라.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"이튿날 저녁때에야 공의의 진찰을 받게 되었을 때 영신은 혼수상태에 빠져 있었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"엇저녁까지 기동을 했었으니까……","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"오늘은 초저녁부터 영신의 숨소리가 더 거칠어졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"그날 저녁 동혁은 거의 실신이 된 사람처럼 청석골을 향하여 길을 떠났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"황혼","q":"장사가 끝난 뒤에, 백현경과 장래의 일을 의논하며 산에서 내려왔던 동혁은 황혼에 몸을 숨기고 홀로 영신의 무덤으로 올라갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"이른 봄 산기슭으로 스며드는 저녁 바람은 소름이 끼칠 만치 쌀쌀하다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"\"엊저녁에 한곡리꺼정 다녀올 일이 있다구 자전거를 타구 가서 여태 안 들어왔어요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"동혁이가 동리 어귀로 들어서자 맨 먼저 눈에 띄는 것은 불그스름하게 물든 저녁 하늘을 배경삼고 언덕 위에 우뚝우뚝 서 있는 전나무와 소나무와 향나무들이었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"저녁","q":"주인 노파가 저녁상을 차리다가 치마로 손을 씻으면서,","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"“이따가 저녁에 또 온다고 하고 매우 섭섭해서 갑데다.”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"자 들어가셔서 저녁이나 잡수시고 기다리십시오.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 밥상을 앞에 놓고 아무리 생각하여도 알 수 없어 좀 지나면 온다 하였으니 그때가 되면 알리라 하고 저녁을 먹었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"저녁을 먹고 나서 신문을 볼 즈음에 대문 밖에 찾는 사람이 있다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"아무리 옥에 계시다 하기로 자식이야 같이 있게 아니하랴 하고 그날 밤에 도망하여 평양으로 가려고 작정하고 저녁밥을 많이 먹고 식구들이 잠들기를 기다렸습니다.”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하고 웃으며, “마침 저녁에 옷을 다려서 대청에 놓은 줄을 알므로 가만가만히 대청에 가서 제 옷을 벗어 놓고 조카의 옷을 갈아입었습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저물","q":"몸은 더할 수 없이 곤하고 해도 저물었습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에 고생한 생각을 하면 지금도 치가 떨립니다”","title":"무정","author":"이광수","kind":"원문"},{"t":"저물","q":"주인이 아랫목에 앉았다가 저를 보고 ‘너 어떤 아이냐’ 하기로 길 가던 아인데 날이 저물어 하룻밤 자고 가려노라 하였습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러면 저녁을 먹어야 하겠구나 하기에, 돈이 한푼도 없어서 밥을 사먹을 수 없으니 자고나 가게 하여 달라고 하였습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그래 저녁을 먹고 나서 여러 손님들이 이야기하는 것을 듣다가 어느 틈에 윗목에 누워 잠이 들었습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에 한자리에 누워 서로 꼭 쓸어안고, 지나간 칠팔 년간의 고생하던 것과 서로 생각하고 그리워하던 말을 하리라.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"내가 저녁때에 일을 마치고 집에 돌아오면 영채는 나를 기다리고 기다리다가 내가 오는 것을 보고 뛰어나오며 내게 안기리라.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"또 영채의 생각에는 평양에 와서 아버지만 만나면 평생 아버지를 모시고 있을 줄로 알고 갔던 것이 정작 와본즉, 모시고 있기는커녕 한 달에 한 번씩밖에 더 뵈올 수가 없고, 또 손에 돈이 없고 평양에 아는 사람이 없으니 오늘 저녁부터라도 먹고 잘 일이 걱정이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에 영채는 생각하던 바와 같이 오래간만에 고깃국에 맛나는 밥을 먹었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"혹 어떤 유야랑(遊冶郞)과 오늘 저녁에 만나기를 약속하고 그 약속한 시간이 오기 전에 잠깐 나를 찾은 것이 아닌가.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하고 머리를 훔치며, “그게 어젯저녁에도 월향이한테 발길로 채인 표야요.”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"만일 오늘 저녁에 어떤 사람이 ‘천 원’을 가지고 가서 영채를 손에 넣으면 어찌할까.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"혹 어젯저녁에 벌써 누가 ‘천 원’을 가지고 가서 영채를 자기 집으로 데려가지나 아니하였는가.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러면 어젯저녁에 벌써 십구 년 동안 지켜 오던 몸을 어떤 짐승 같은 더러운 놈에게 허하지나 아니하였을까.","title":"무정","author":"이광수","kind":"원문"},{"t":"황혼","q":"황혼의 형식의 얼굴은 하얗게 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"여기저기 수십 명 사람이 모여선 것은 아마 무슨 값싸고 쓰기 좋은 물건을 파는 것인 듯, 사람들은 저녁의 서늘한 맛에 취하여 아무 목적 없이 왔다갔다한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"또 외가에 가서 내종형댁의 학대와 조카네의 학대를 당하고, 거기서 도망할 때에 어느 촌중 아이들의 핍박을 당하고, 그날 저녁 죽천 땅 어느 객주에서 그 변을 당하고, 마침내 평양에서 자기의 몸이 기생으로 팔리게 되매, 어린 영채는 세상이 자기의 가정과 다르고 세상 사람들이 자기와 및 자기의 주위에 있던 사람들과 다름을 깨달았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하루 저녁에는 월화가 영채를 찾아와서 연설 구경을 가자고 한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"평양 사람들은, 혹은 새로운 말을 들으리라는 정성으로, 혹은 다만 구경이나 하리라는 호기심으로 저녁 후면 패성학교 대강당이 터지도록 모여들었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러고 오늘 저녁 그의 풍채와 말을 또 들으니, 내 마음은 온통 그이게로 가고 말았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"왜 오늘 저녁에는 그런 말씀을 하셔요?”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁때에 대동강에서 낚시질하던 배가 시체 하나를 얻었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"묻은 날 저녁때에 옥가락지 끼인 손이 꽃 한줌과, 눈물 한줌을 그 무덤 위에 뿌렸다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"이날 저녁에 영채를 찾아온 형식은 영채를 만났는가.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어젯저녁에 내 집에서 돌아오는 길로 팔려 가지나 아니하였는가.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하고 영채가 어젯저녁에 자기를 찾아왔단 말과 자기를 찾아와서 신세 타령을 하던 말과, 자기가 방금 다방골 월향의 집으로 다녀온다는 말을 하고 다시,","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"“참, 오늘 저녁 힘을 써주게”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"우선은 경성학교 교주 김남작의 아들 김현수와 배명식 양인이 월향을 청량리로 데리고 갔단 말을 월향의 집에서 듣고, 월향은 오늘 저녁에는 김현수의 손에 들어가는 줄을 짐작하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러므로 그가 오늘 저녁에 한 일이 결코 도덕이나 양심에 거슬리는 행위인 줄로는 생각지 아니한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"를 ‘좋소’로 들어 주어, 어느 날 저녁에 그 여자를 데려다가 형식의 방에 넣어 주었더면 형식은 그 노파를 ‘괘씸하다’ 하고 원망하였을까.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그 후에 하루 저녁은 그 여자가 주인 노파의 방에 와서 잤다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식의 눈앞에는 어젯저녁 바로 이 방에 앉았던 영채의 모양이 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 지금, 어젯저녁에 영채가 앉았던 자리를 보고 그때의 광경과 그때의 상상하던 바를 생각한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"설혹 어저께까지는 처녀라 하더라도 오늘 저녁에는 이미 처녀가 아니로다’ 하고 청량사의 광경을 한번 다시 그렸다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어젯저녁에는 행여나 영채가 어떠한 귀한 가정의 거둠이 되어 마치 선형이나 순애 모양으로 번뜻하게 여학교를 졸업하고 순결한 처녀로 있으려니 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러나 노파는 어젯저녁 형식이가 늦게 잔 줄을 알므로 깨우려도 아니하고 모처럼 만들어 놓은 장찌개가 식는 것을 근심하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"한번 신우선이가 형식으로 더불어 저녁을 같이 먹을 때에도 노파의 자랑하는 된장찌개가 있었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 우선이가 ‘어서 옷 입고―’ 하는 말을 듣고 비로소 어젯저녁 생각을 하고 영채의 생각을 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러고 어젯저녁 자기 혼자 잠을 못 이루고 생각하던 일을 생각하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러고 어젯저녁에 영채와 선형이가 하얀 옷을 입고 웃으면서 각각 한편 손을 내어밀며 ‘제 손을 잡아 줍시오.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"“흥 오늘 저녁에도 누가 계월향을 찾아서 놀러 올 테지.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어젯저녁 열한점이 친 다음에야 들어오시더니만……","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 어젯저녁 이 마당에 서서 그 노파에게 멸시당하던 일을 생각하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 어젯저녁에 섰던 모양으로 서서 어젯저녁에 보던 모양으로 영채의 방을 보았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러나 어젯저녁 모양으로 마음이 번민하지는 아니하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어젯 저녁에 와서 ‘월향 씨 있소’ 하던 사람이로구나 하고, 그러면 그가 ‘신주사의, 심부름꾼이던가’ 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어젯저녁에는 실례하였습니다……","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"모기장의 주름이 어제와 같으니, 영채가 어젯저녁에는 모기장을 아니 치고 잤구나 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"노파는 이 두 사람이 어젯저녁 사건을 모르려니 한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"저 새로운 친구도 아마 월향의 이름을 듣고 한번 만나 볼 양으로 어젯저녁에 왔다가 헛길이 되고, 아마 자기의 초라한 모양을 보고 월향을 내어놓지 아니하는가 보아서 오늘은 월향과 친한 우선을 데리고 온 것이어니 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"“어머니, 어젯저녁에는 제가 잘못하였습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"노파는 그 슬퍼하고 고집하던 마음을 고친 것이 반갑고, 어젯저녁에 월향을 안고 울 때에 얼마큼 애정도 생겼고―자고 나서는 사분의 삼이나 식었건마는―또 조고마한 일이면 제 소원대로 하여 주는 것이 좋으리라 하여,","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"노파는 불현듯 오 년 전 월화의 생각을 하고, 월향이가 항상 월화가 준 누런 옥지환을 끼고 있던 것을 생각하고, 어젯저녁 청량리 일을 생각하고 눈이 둥그래지며,","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"“어젯저녁에 칠 년 동안이나 그리고 그리던 선생을 (뵈오매, 마치 이미 세상을) 버리신 어버이를 대한 듯하여 기쁘기 그지없었나이다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"노파는 어젯저녁에 진정으로 영채를 안고 울던 생각을 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그때에 어젯저녁의 기억은 마치 수십 년 전에 지나간 일과 같았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러나 영채의 편지를 보매 갑자기 그러한 생각이 스러지고 칼과, 지환과, 형식의 눈물을 볼 때에 어젯저녁 떴던 노파의 영혼의 눈이 뜨였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러므로 여자 된 영채가 어젯저녁 청량사 사건에 대하여 잡을 길은 이 길밖에는 없다 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"혹 어젯저녁에 어떤 사나이의 희롱을 받지나 아니하였는가 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그 사람은 형식의 행색이 수상하다 하면서, “그러면 저녁에는 내 집으로 오게.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은, 영채는 죽은 사람으로 작정하고 계향의 집에 돌아와, 노파는 이삼 일 평양에 있는다 하므로 자기 혼자 그날 저녁차로 서울에 올라왔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"어스름","q":"형식은 너무 신경이 흥분하여, 거의 잠을 이루지 못하고 차창을 열어 놓고 시원한 바람을 쐬면서 어스름한 달빛을 어렴풋하게 보이는 황해도 연산(黃海道 連山)을 보았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"같이 저녁을 먹자고 그러시던데.”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하다가 그런 생각을 하는 것이 슬프기도 하고 또 형식을 자기의 아들에 비기는 것이 버릇없는 듯도 하여, “오늘 저녁에 가시거든 확실하게 허락을 합시오.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"딴소리 말고 오늘 저녁 김장로 집에 가게.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"하는 소리도 이제는 아니 들리게 되고 집집에는 앞뒷문을 활짝 열어 놓고 한 손으로 땀을 씻어 가며 저녁밥을 먹는다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"북악의 황토가 가로쏘는 햇볕을 받아 빨간빛을 발하고 경복궁 어원 늙은 나무 수풀에서는 저녁 까치 소리가 시끄럽게 들린다.","title":"무정","author":"이광수","kind":"원문"},{"t":"황혼","q":"남산 솔수풀 위에 살짝 덮였던 석양도 무엇으로 지우는 듯이 점점 스러지고, 그 무성한 가지와 잎사귀 속으로 자줏빛 띤 황혼이 거미줄 모양으로 아슬랑아슬랑 기어나온다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"세 사람은 맛나게 또 유쾌하게 저녁을 먹었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"다른 방에서는 부인과 선형과 순애와 계집 하인이 이 역시 맛나게 유쾌하게 저녁을 바치고 말없이 서로 보고 웃는다.","title":"무정","author":"이광수","kind":"원문"},{"t":"황혼","q":"그것이 방에서 넘쳐나서 황혼의 바람에 풍겨 마당을 건너 담을 넘어 마치 물결 모양으로 사방으로 퍼진다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"저녁 서늘한 바람이 하얀 레이스 문장을 가만가만히 흔들고 그러할 때마다 바로 창 밑에 놓인 화분의 월계의 연한 잎새가 한들한들한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"오늘 저녁이면 나는 죽는다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"오늘 저녁이면 죽어 버리는 몸이요, 또 이 부인이 이처럼 친절하게 하여 주니 자초지종을 있는 대로 이야기하고 싶기도 하나 그래도 말을 내기가 부끄럽기도 하고 또 어디서부터 어떻게 시작할 것인지를 몰라 떡을 든 채로 고개를 숙이고 잠자코 앉았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그래서 그날 저녁에 집에 돌아와서는 어떻게 마음이 섭섭한지 울었습니다.”","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에는 부친을 빼어 놓고 온 가족이 모여앉아서 밀국수를 먹으며 즐겁게 이야기하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에는 셋이 한자리에서 가지런히 누워 잤다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"죽으러 가던 몸이, 어젯저녁에 죽었을 몸이, 아직도 살아 있는 것을 생각하니 우습다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"어떤 날 저녁에 둘이 마주앉아서 우선이가 영채를 달랠 때에 영채의 마음도 아니 움직임도 아니었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그날 저녁에 선형은 ‘녜’ 하고 대답은 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"병국도 사리원까지 갈 일이 있다 하여 같이 올랐으나, 자기는 오늘 저녁에 돌아올 길인 고로 걸상에 앉은 대로 바깥을 내다보지도 아니한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"이렇게 강한 인상을 얻은 그날 저녁에 다시 영채를 보았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"황혼","q":"황혼이라 자세히 알 수는 없으되, 하늘은 온통 검은 구름으로 덮이고 선득선득한 바람에 이따금 굵은 빗방울이 섞여 떨어진다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"형식은 오늘 저녁에 이것을 깨달았다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"선형은 형식의 입을 보고 어젯저녁 자기의 손등에 대던 생각을 하고 속으로 우스워하면서,","title":"무정","author":"이광수","kind":"원문"},{"t":"저녁","q":"그러고는 어젯저녁에 자기가 병욱에게 위로를 받던 생각이 나서 속으로 우스워진다.","title":"무정","author":"이광수","kind":"원문"},{"t":"저물","q":"추석을 지나 이윽고, 짙어 가는 가을 해가 저물기 쉬운 어느 날 석양.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"안 받어 간다먼 나 이놈으루 괴기 사다가 야긋야긋 다져서 저녁 반찬이나 히여 먹을라네.\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"글씨 어떤 놈의 소리가 금방 엊저녁까지 들리던 소리가 오널사 말구 시급스럽게 안 들리넝고?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"오늘 저녁에 우리가 네 집에를 온 것은…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"아랫목으로 펴놓은 돗자리 위에 방 안이 온통 그들먹하게시리 발을 개키고 앉아 있는 윤직원 영감 앞에다가, 올망졸망 사기 반상기가 그득 박힌 저녁상을 조심스레 가져다 놓는 게 둘째손자며느리 조씹니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"윤직원 영감은 밥을 먹어도 꼭 태식이를 데리고 같이 먹곤 하는데, 오늘 저녁에는 마침 눈에 뜨이지 않으니까 숟갈을 들려고 않고서 그애를 먼저 찾던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"시방 오늘 저녁만 하더라도, 아까 쪽대문을 열어 놓았다고 윤직원 영감이 군욕질을 했대서 그 원혐으로다가 기어코 한바탕 화룡도를 내고라야 말 작정으로 그렇게 벼르고 있는 참입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"집 안은 안방에서 윤직원 영감이 태식을 데리고 앉아서 저녁을 먹으면서 잔소리를 씹느라고 웅얼거리는 소리, 태식이 딸그락딸그락 째금째금 하는 소리, 그 외에는 누구 하나 기침 한 번 크게 하는 사람 없고, 모두 조심을 하느라 죽은 듯 조용합니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"황혼","q":"바깥은 황혼이 또한 소리 없이 짙어 가고, 으슴푸레하던 방 안에는 깜박 생각이 난 듯이 전등이 반짝 켜집니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저물","q":"\"너는 학교서 파하거던 일찍일찍 오지는 않구서 무슨 해망을 허느라구 이렇게 저물구……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"이놈, 오널 저녁으루 담박 제 지집을 이혼을 안 히였다 부아라!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"저허구 나허구 애비자식 천륜을 끊든지, 지집을 이혼을 허든지 좌우양단간 오널 저녁 안으루 요정을 내구래야 말 티닝개루……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"계집종인 삼월이는 부엌에서 행랑어멈과 같이서 얼추 설거지를 하고 있고, 행랑아범은 안팎 아궁이를 찾아다니면서 군불을 조금씩 지피고, 그 나머지 식구들은 고씨만 빼놓고 다 안방으로 모여 저녁밥을 시작합니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"그들은 아무도 방금 일어났던 풍파를 심려한다든가 윤직원 영감이 저녁밥을 중판멘 것을 걱정한다든가, 고씨가 밥상을 도로 쫓은 걸 민망히 여긴다든가 할 사람은 하나도 없고, 따라서 아무도 입맛이 없어 밥 생각이 안 날 사람도 없습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"윤직원 영감은 속으로야, 이 사람이 저녁에 다시 온 것이 반가울 일이 있어서 느긋하기는 해도, 짐짓,","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"정녕 저녁 진질 아니 잡수셨어요?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"오늘 저녁으 온댔으닝개 오기넌 올 것이구, 오머넌 내일 아무 때라두 돈이사 주겄지만……","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"그런데, 정녕 저녁 진질 아니 잡수셨습니까?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"해질","q":"또 역정을 낼 줄 알았더니, 그런 게 아니고 방금, 아무 근심기 없던 얼굴이 졸지에 해질 무렵같이 흐려들면서 음성은 풀기 없이 가라앉습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"허기야 따님까지 와서 기시구 허니깐 머어 범연하겠습니까마는, 그래두 잘 하나 못 하나 마나님이라구 이름 지어 두구 지내시면, 시중 드는 것두 훨씬 맘에 드실 것이구, 또오 아직 저엉정하시겠다 밤저녁으루 적적하시면 내려가서 위로두 더러 받으시구, 헤헤!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"실상은 말씀이야 오늘 저녁에 첨으루 냈지만, 그새두 늘 그런 유념을 하구설랑 눈여겨보기두 허구, 그럴 만한 자리에 연통두 해보구 그래 왔더랍니다!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"춘심이년이나 어서 왔으면 하겠는데, 저녁 먹고 곧 오마고 했으니까 오기는 올 테지만, 그년이 이내 뽀로로 오는 게 아니라 까불고 초라니짓을 하느라고 이렇게 더디거니 싶어 얄밉습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"저녁을 몇 술 뜨다가 말아서 속도 출출합니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"그럼 어서 건너가서 저녁 먹소.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"아―니 그만두구, 어서 건너가서 저녁 먹소.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"가령 두부를 오늘 저녁에는 세 모만 사들여 보낼 예정이라면, 사는 마당에서는 두 모하고 반만 사고 싶습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"\"전서방님 오싰넌디 저녁 진지상 주어기라우…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"가 대단히 심했고, 그뿐 아니라 밤저녁으로 말동무가 없게 되어 여간만 심심치가 않았습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"그럭저럭 날이 저무니까 간다고 일어서는 것을 달래서, 전에 없이 맞상을 내다가 같이 저녁을 먹었고, 저녁을 마친 뒤에는 시급히 춘향전을 사들여 그 애더러 읽으라고 하고는 자기는 버얼떡 드러누워서 이야기책 읽는 입을 바라다보고, 하느라고 그야말로 천금 같은 봄밤의 한 식경을 또한 즐겁게 보낼 수가 있었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"보내면서, 내일도 오너라 했더니 과연 이튿날 저녁에, 저녁을 일찌감치 먹곤 올라왔습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"윤직원 영감은 어제 저녁처럼 옆에다가 앉혀 놓고는, 이야기도 시키고 이야책도 읽히고, 내시가 이 앓는 소리 같은 노래도 듣고, 오늘 저녁 개시로 다리도 치라 하고, 그러면서 삼남이를 시켜 말눈깔사탕 십 전 어치도 사다가 먹이고, 머리는 물론 여러 번 쓰다듬어 주었고, 그러구러 밤이 이슥한 뒤에 돌려보냈습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"대접상으로는 역시 인력거를 태워 주었어야 할 것이지만, 인제 앞으로 자주 다닐 텐데 그렇게 번번이 탈 수야 있느냐고, 그러니 오늘 저녁부터는 이 애더러 바래다 달래라고, 그 알뜰한 삼남이를 안동해 보냈습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"밤은 아직 초저녁이었고, 그들먹하게 뻗고 누웠는 다리를 조막만한 계집애가 밤만한 주먹으로 토닥토닥 무심히 치고 있는데, 문득 윤직원 영감이,","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"윤직원 영감은 그런데, 저녁밥을 설치기까지 한 판이라 속이 다뿍 허출해서 우동 한 그릇을 탕수육으로 반찬삼아 걸게 먹었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"경손이가 아까 안방에서 열다섯 살 동갑짜리 대부 태식이와 같이 싸우며 놀리며 저녁을 먹고 나서는 아랫목에 가 버얼떡 드러누워 뒹굴고 있었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"또 오뉴월에도 이야기책을 차고 누웠다고 비웃음을 하거나 말거나 아무것도 상관할 바 없고 사시장철 밤낮없이 손에서『추월색』을 놓지 않는 서울아씨요, 그래 오늘 저녁에도 일찌감치 시작을 했던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"전서방, 저녁 다아 먹었나……?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"서울아씨는 아까 대복이의 저녁 밥상을 차리러 나서느라고 저도 모르게 일으킨 이변을 비로소 깨달았으나, 그래서 속이 뜨끔했던 것이나, 경손이가 막상 눈치를 채지는 못한 것 같아서 적이 마음이 놓였습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"\"저어, 저녁이라 말하기가 안돼서 그러는데요!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"오늘 저녁처럼 경손이가 서울아씨를 존경(?)","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"간밤에 침대차가 만원이 되어 잠을 못 잔 것이 피곤도 하거니와, 이따가 저녁에 한바탕 놀자면 정력을 길러 두는 것도 해롭진 않았습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저물","q":"이럴 줄 알았으면 진작 아까 저물기 전에 집으루나 가서 할아버지께라두 말씀을 했지!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"자네 거 기생 고만두고서 오늘 저녁일라컨 여학생 오입 하나 해볼려나?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"아 오늘 저녁 일만 두구 생각해 보게?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"자아, 오늘 저녁일라컨 위선 산뜻한 여학생 오입을 속짜루 한바탕 한 뒤에, 어디 별장으루 나가서 밤새두룩, 응?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"\"그렇게 뒷심을 보실 테거들랑 돈을 애끼지 말구서, 우선 오늘 저녁버틈이라두 척 돈을 좀 몇십 환 듬뿍 쓰세야죠!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"\"그년의 자식이 엊저녁으 짜게 처먹었넝개비다!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"저어 이따가 저녁에― 에…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"저녁","q":"다시 그리고, 이따가 저녁에 춘심이를 사랑하게 될 행복에 이르러서는 침이 흥건히 괴어 방금 뚜―우 오정 소리를 듣고도 이어 점심을 먹으러 들어갈 여념이 없이, 술에 취하듯 푹신 취해 버렸습니다.","title":"태평천하","author":"채만식","kind":"원문"}],"밤":[{"t":"밤","q":"오늘 밤에 옆집 할멈을 시켜 잡히려 하는 것이다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"밤","q":"봄은 벌써 반이나 지났건마는 이슬을 실은 듯한 밤기운이 방구석으로부터 슬금슬금 기어나와 사람에게 안기고 비가 오는 까닭인지 밤은 아직 깊지 않건만 인적조차 끊어지고 온 천지가 빈 듯이 고요한데 투닥투닥 떨어지는 빗소리가 한없는 구슬픈 생각을 자아낸다.","title":"빈처","author":"현진건","kind":"원문"},{"t":"밤","q":"밤이 깊도록 다듬이를 하다가 그만 옷 입은 채로 쓰러져 곤하게 자는 그의 파리한 얼굴을 들여다보며,","title":"빈처","author":"현진건","kind":"원문"},{"t":"밤","q":"어제 일로 심신이 피곤하였던지 그 이튿날 늦게야 잠을 깨니 간밤에 오던 비는 어느결에 그치었고 명랑한 햇발이 미닫이에 높았더라.","title":"빈처","author":"현진건","kind":"원문"},{"t":"밤","q":"그것은 다른 일이 아니라, 밤이 깊어서 새로 한 점이 되어 모든 기숙생들이 달고 곤한 잠에 떨어졌을 때 난데없는 깔깔대는 웃음과 속살속살대는 말낱이 새어 흐르는 일이었다.","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤","q":"하루 밤이 아니고 이틀 밤이 아닌 다음에야 그런 소리가 잠귀 밝은 기숙생의 귀에 들리기도 하였지만 잠결이라 뒷동산에 구르는 마른 잎의 노래로나, 달빛에 날개를 번뜩이며 울고 가는 기러기의 소리로나 흘러들었다.","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤","q":"“어젯밤에 나도 저 소리에 놀랬었어.","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤","q":"적적한 밤 가운데 다른 파동 없는 공기는 그 수상한 말 마디를 곁에서 나는 듯이 또렷또렷이 전해 주었다.","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤","q":"이 안에 있는 여자 애인을 보려고 학교 근처를 뒤돌고 곰돌던 사내 애인이, 타는 듯한 가슴을 걷잡다 못하여 밤이 이슥하기를 기다려 담을 뛰어 넘었는지 모르리라.","title":"B사감과 러브레터","author":"현진건","kind":"원문"},{"t":"밤","q":"집에 들면 정신없이 무슨 책을 보기도 하고 또는 밤새도록 무엇을 쓰기도 하였다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤","q":"오늘 밤에도 지금까지 돌아오지 않았다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤","q":"검푸른 밤 빛이 허연 길 위에 그물그물 깃들었을 뿐이었다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤","q":"다시금 밤은 적적히 깊어간다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤","q":"그의 눈은 하염없이 검은 밤 안개를 물끄러미 바라보고 있다.","title":"술 권하는 사회","author":"현진건","kind":"원문"},{"t":"밤","q":"극단으로 나가서는 밤에 돈벌이 나갔던 사람은 그날 밤 사 백 여 원을 벌어 가지고 와서 그 근처에서 담배장사를 시작한 사람까지 있었다.","title":"감자","author":"김동인","kind":"원문"},{"t":"밤","q":"칠성문 밖 빈민굴의 여인들은 가을이 되면 칠성문 밖에 있는 중국인의 채마 밭에 감자(고구마)며 배추를 도둑질하러, 밤에 바구니를 가지고 간다.","title":"감자","author":"김동인","kind":"원문"},{"t":"밤","q":"어떤 날 밤, 그는 고구마를 한 바구니 잘 도둑질하여가지고, 이젠 돌아오려고 일어설 때에, 그의 뒤에 시꺼먼 그림자가 서서 그를 꽉 붙들었다.","title":"감자","author":"김동인","kind":"원문"},{"t":"밤","q":"밤이 깊도록, 왕 서방의 집에는 중국인들이 모여서 별한 악기를 뜯으며 별한 곡조로 노래하며 야단하였다.","title":"감자","author":"김동인","kind":"원문"},{"t":"밤","q":"“우리, 오늘 밤 일이 있어 못 가.”","title":"감자","author":"김동인","kind":"원문"},{"t":"밤","q":"그러나 그의 아내의 참 기쁜 듯이 웃는 소리가 그의 아우의 집에서 밤새도록 울리었다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"밤","q":"그러나 아내는 밤이 가고 날이 밝기는커녕, 해가 중천에 올라도 돌아오지를 않았다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"밤","q":"그가 정신을 차린 때는 밤이었다.","title":"배따라기","author":"김동인","kind":"원문"},{"t":"밤","q":"나는 그날 밤 그 백성수를 데리고 집으로 돌아왔습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그날 밤이 새도록, 그는 흥분이 되어서 자기의 과거를 일일이 다 이야기하였습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"(중략) 그리하여 그날도 또한 이제 밤을 지낼 집을 구하느라고 돌아다니던 저는 우연히 그 집, 제가 전에 돈 오십여 전을 훔친 집 앞에까지 이르렀습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"깊은 밤 사면은 고요한데 그 집 앞에서 잘 곳을 구하느라고 헤매던 저는 문득 마음속에 무서운 복수의 생각이 일어났습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"널따란 북향 방에 동남쪽 귀에 든든한 참나무 침대가 하나, 서북쪽 귀에 아무 장식 없는 참나무 책상과 의자, 피아노가 하나씩, 그 밖에는 방 안에 장식이라고는 서남쪽 벽에 커다란 거울이 하나 있을 뿐, 덩더렇게 넓은 방은 사실 밤에 전등 아래 앉아 있노라면 저절로 소름이 끼치도록 무시무시한 방이었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그날 밤에 된 것이 '성난 파도'이었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그리고 그러한 날은 한 가지의 방화사건이 생겨나며 그날 밤에는 한 곡의 음악이 생겨났습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그런데, 그 어떤 날 밤이구려.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그날 밤에 된 것이 '피의 선율'이었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"저는, 그날 밤 혼자 몰래 그 여자의 무덤을 찾아갔습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"그날 밤에 된 것이 '사령(死靈)'이었습니다.","title":"광염 소나타","author":"김동인","kind":"원문"},{"t":"밤","q":"어떠한 가을밤 유난히 밝은 달이 고요한 이 촌을 한적하게 비칠 때 그 물레방앗간 옆에 어떠한 여자 하나와 어떤 남자 하나가 서서 이야기를 하는 소리가 들리었다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"그는 하는 수 없이 밤이 될 때까지 그 근처 산 속으로 돌아다녔다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"그래서 깊은 밤에 촌으로 내려왔다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"캄캄한 그믐밤에 얼굴을 바짝 계집의 코앞에 들이대었다.","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"임자와 나와 이년 전에 이곳으로 도망해올 적에도 전 남편이 나를 죽이겠다고 허리를 찔러 그 흠이 있는 것을 날마다 밤에 당신이 어루만지었지요?","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"광채가 어두운 밤에 번개같이 번쩍거리며,","title":"물레방아","author":"나도향","kind":"원문"},{"t":"밤","q":"\"어젯밤에는 어디 갔었습던교?\"","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"어젯밤 안쥔 심바람으로 님자 집을 갔었으니깐두루 말이지.\"","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"\"어젯밤에도 김참봉 아들네 사랑방에서 자고 왔습네그려.\"","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"\"그 녀석이 밤에 도둑질을 해온 게지?","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"오늘 밤에는 꼭 내 것이던 걸 그랬지.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"밤새도록 놈하고 승강이를 하다가 그대로 왔지.\"","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"그날 밤에 삼돌이란 놈은 혼자 앉아서 생각하기를, '복 없는 놈은 하는 수가 없거든.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"그리고 밤새도록 서로 말이 없었다.","title":"뽕","author":"나도향","kind":"원문"},{"t":"밤","q":"그들은 밤에는 잠을 자지 않나?","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"달이 밝은 밤에는 한참씩 마당에 우두커니 섰다가 들어오곤 한다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"하룻밤 사이에도 수십 차를 돌쳐 눕지 않고는 여기저기가 배겨서 나는 배겨낼 수가 없었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"나는 아내의 밤 외출 틈을 타서 밖으로 나왔다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"그리고 밤이 이슥하도록 까닭을 잃어버린 채 이 거리 저 거리로 지향 없이 헤매었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"나는 사실 밤이 퍽 이슥한 줄만 알았던 것이다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"하룻밤을 비었던 내 이부자리는 여전히 반갑게 나를 맞아 준다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"따라서 나는 또 오늘 밤에도 외출하고 싶었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"조금 있다가 아내가 눕는 기척을 엿보자마자 나는 또 장지를 열고 아내 방으로 가서 그 돈 이 원을 아내 손에 덥석 쥐어 주고 그리고— 하여간 그 이 원을 오늘 밤에도 쓰지 않고 도로 가져온 것이 참 이상하다는 듯이 아내는 내 얼굴을 몇 번이고 엿보고— 아내는 드디어 아무 말도 없이 나를 자기 방에 재워 주었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"나는 어느덧 오늘 밤에도 외출할 것을 생각하고 있었다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"아내는 무슨 근심되는 일이 있어서 밤이면 잠이 잘 오지 않아서 정작 아내가 아달린을 사용한 것이나 아닌지?","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"아내는 너 밤새워 가면서 도둑질하러 다니느냐, 계집질하러 다니느냐고 발악이다.","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"아내가 대체 그럴 까닭이 없을 것이니, 그러면 나는 날밤을 새면서 도둑질을 계집질을 하였나?","title":"날개","author":"이상","kind":"원문"},{"t":"밤","q":"이렇게 말하자면 결국 어젯밤 뭉태네 집에 마슬간 것이 썩 나빴다.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"밤","q":"꼭 곧이들었다면 간밤에 와서 장인님과 싸웠지 무사히 있었을 리가 없지 않은가.","title":"봄봄","author":"김유정","kind":"원문"},{"t":"밤","q":"간밤 쓸데 없는 노름에 밤을 팬 것이 몹시 나른하였다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"물론 수가 좋으면 괴때기 위에서 밤을 편히 잘 적도 있었다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"하루는 밤이 깊어서 코를 골며 자는 아내를 깨웠다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"그러자 어느 날 밤 아내의 얼굴이 썩 슬픈 빛이었다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"아내의 말대로 개가를 해가서 젖먹이나 잘 키우고 몸 성히 있으면 혹 연분이 닿아 다시 만날지도 모르니깐, 마지막으로 아내와 같이 땅바닥에서 나란히 누워 하룻밤을 새고 나서 날이 훤해지자 그는 툭툭 털고 일어섰다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"오늘 밤에는 요놈을 지켰다 꼭 붙들어 가지고 정강이를 분질러 노리라.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"이렇게 보면 재작년 가을 어느 밤 산중에서 낫으로 사람을 찍어 죽인 강도가 문득 머리에 떠오른다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"오늘 밤에는 이놈을 다리를 꺾어 놓고 내일쯤은 봐서 설렁설렁 뜨는 것이 옳은 일이겠다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"밤이 내리니 만물은 고요히 잠이 든다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"친구는 웬 영문을 몰라서 뻔히 쳐다보다 밤이 이렇게 늦었으니 나갈 생각 말고 어여 이리 들어와 자라 하였다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"여기에서 밤 새울 생각을 하니 기가 찼다.","title":"만무방","author":"김유정","kind":"원문"},{"t":"밤","q":"“오늘 밤은 밤을 새서 걸어야 될걸?”","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"축들은 그 어느 쪽으로든지 밤을 새며 육칠십 리 밤길을 타박거리지 않으면 안 된다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"“달밤이었으나 어떻게 해서 그렇게 됐는지 지금 생각해두 도무지 알 수 없어.”","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"“달밤에는 그런 이야기가 격에 맞거든.”","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"대화까지는 팔십 리의 밤길, 고개를 둘이나 넘고 개울을 하나 건너고 벌판과 산길을 걸어야 된다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"“장 선 꼭 이런 날 밤이었네.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"구수한 자주빛 연기가 밤 기운 속에 흘러서는 녹았다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"생각하면 무섭고도 기막힌 밤이었어.”","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"첫날밤이 마지막 밤이었지.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"금방 땀을 흘린 뒤였으나 밤 물은 뼈를 찔렀다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"걸음도 해깝고 방울소리가 밤 벌판에 한층 청청하게 울렸다.","title":"메밀꽃 필 무렵","author":"이효석","kind":"원문"},{"t":"밤","q":"문서방 내외는 그 밤을 인가의 집 울타리 밖에서 새었다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"밤","q":"문서방의 아내가 죽던 그 이튿날 밤이었다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"밤","q":"그날 밤에도 바람이 몹시 불었다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"밤","q":"이날 밤에도 그 모양으로, 달리소에는 회오리바람이 일어서 낟가리가 날리고 지붕이 날리고 산천이 울려서 혼돈이 배판할 때 빙세계나 트는 듯한 판이라 사람은커녕 개와 도야지도 굴 속에서 꿈쩍 못 하였다.","title":"홍염","author":"최서해","kind":"원문"},{"t":"밤","q":"아이는 젖을 달라고 밤새껏 빽빽거린다.","title":"탈출기","author":"최서해","kind":"원문"},{"t":"밤","q":"아내는 이고 나는 지고 캄캄한 밤에 산비탈로 내려오다가 발이 미끄러지거나 돌에 채면 곤두박질을 하여 나뭇짐 속에 든다.","title":"탈출기","author":"최서해","kind":"원문"},{"t":"밤","q":"이날 밤에도 그는 그 계집애를 조금도 어떻게 하겠다는 생각은 나지 아니하였다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"다분의 가면 밑에서 꿈틀거리는 인도주의에 몹시 증오를 느끼는 P는 이날 밤 자기의 행동을 어떻게 해석할지 몰라 괴로워하였다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"밤은 어느 때나 되었는지 짐작할 수가 없다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"밤이 깊지 아니했으면 잠긴 안대문을 두드려 주인 노인에게라도 물을 청하겠지만 이 깊은 밤에 그리하기도 미안하다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"그러나 이 어두운 밤에 어디가 어딘지 보이지 아니할 테고 또 우물에는 두레박도 없을 것이다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"그러면서 어젯밤 일이 머리에 떠오른다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"하룻밤 몸값을 '이십 전도 좋소' 하는 여자, 그에게는 다른 사람이 갖는 성도덕도 없고 따라서 자신을 타락이라서 슬퍼하지도 아니한다.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"창선이가 도착한 날 밤.","title":"레디메이드 인생","author":"채만식","kind":"원문"},{"t":"밤","q":"겨울이면 추울까, 여름이면 더울까, 밤에 자다가도 곤히 자는 수남의 투덕투덕한 볼기짝을 몇 번씩 뚜덕뚜덕하던 세상에 둘도 없는 귀한 아들은 어느덧 나이 십륙 세에 이르러 사방에서 혼인하자는 말이 끊일 새 없었다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"밤","q":"까맣던 밤이 백색으로 활짝 열린다.","title":"경희","author":"나혜석","kind":"원문"},{"t":"밤","q":"남양의 달밤을 상상케 하는 애련하고도 청아한 선율에, 회장은 다시 조용해졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"첫해에는 아이들을 잔뜩 모아는 놨어두 가르칠 장소가 없어서 큰 은행나무 밑에다 널판대기에 먹칠을 한 걸 칠판이라고 기대어 놓구 공석이나 가마니를 깔구는 밤 깊도록 이슬을 맞아 가면서 가르치기를 시작했었는데, 마침 장마 때라 비가 자꾸만 와서 견딜 수가 있어야지요.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"\"밤을 새우는 한이 있드래두 이런 기회에 우리는 충분히 의견을 교환허고 싶습니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"깊은 밤 후미진 구석으로 여학생의 뒤를 따라다니는 것부터 부질없는 노릇인데, 더구나 아는 사람의 눈에 띄든지 해서 재미 없는 소문이 퍼지는 날이면 영신에게 미안할 것도 모르는 것은 아니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그날 밤은 여간 실례를 하지 않었습니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그날 밤 백선생도 늦게야 한강에서 들어오셔서 같이 자면서 간접으로나마 동혁 씨를 소개하였더니, 좋은 동지라고 꼭 한 번 만나기를 원하십니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신은 그날 밤 그가 숭배하는 백씨에게 백 퍼센트로 동혁을 소개하였었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"\"정신을 잃으신 동안에 어느 몹쓸놈이 푼푼이 모아 넣으신 돈주머니를 끌러 가서 그게 원통해 밤새두룩 우시는데……!\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"\"우리 둘이 이렇게 만나서 한 십 년이나 사귄 동지처럼 가슴을 터놓구 하룻밤을 새운 기념을 우리 영원히 남기십시다.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"밤새도록 울고도 지칠 줄을 몰라서, 대합조개 껍데기를 마주 부비는 듯이 와글와글하는 소리가 시끄러울 지경이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"비는 그치고 바닷가의 밤은 깊어 갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"어느 눈 내리던 날 밤 야학을 파하고 사숙으로 돌아가는 길인데, 아버지도 어머니도 잃어버리고 일갓집에 붙어서 사는 금분이란 계집애가 숨이 턱에 닿아서 쫓아오더니, 선생님의 재킷 주머니에다가 꽁꽁 언 손에 쥐고 있던 것을 넌지시 넣어 주고 달아났다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신이가 떠나기로 작정한 전날 밤은 달이 유난히 밝았다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"바닷가의 밤은 점점 깊어만 가는데 해감내를 머금은 바람이 솔솔 불어오기 시작해서, 이슬에 촉촉히 젖은 몸이 감기나 들지 않을까 하고 동혁은 염려가 되었던 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그 말 한마디에 이태 전 ××일보사 주최의 간친회 석상에서 처음 보았을 때의 인상과, 악박골서 밤을 새우던 때의 정경이 바로 어제런 듯 주마등과 같이 두 사람의 눈앞을 달렸다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"제에발 고만 시집을 가라구 이틀 밤이나 꼬박이 새워 가며 빌다시피 허시는 걸 끝끝내 시원헌 대답을 못 해드렸어요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"지새려는 봄 밤, 잠 깊이 든 바다의 얼굴을 휩쓰는 쌀쌀한 바람이 쏴― 하고 또 쏴― 하고 타는 듯한 두 사람의 가슴에 벅차게 안긴다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"몇 번이나 다시 돌려보내려고 하였으나, 한창 어려운 고비를 넘는 농촌에서 십 원이란 큰 돈을 변통하기가 얼마나 어려우셨을 것을 알고, 또는 제가 떠나기 전날 밤에, 이 돈을 남에게 취하려고 몇십 리 밖까지 가셨다가 늦게야 돌아오셨던 것이 이제야 짐작되어서 차마 도로 부치지를 못하였습니다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그 바닷가의 기울어 가는 달밤, 모래 위에 그 육중한 몸뚱이를 몸부림치며 사랑을 고백하던 동혁이, 온 몸뚱이가 액체로 녹을 듯이 힘차게 끌어안던 두 팔의 힘, 숨이 턱턱 막히던 불 같은 키스.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그날 밤 그 하늘에 떴던 달이나 별들밖에는 그 장면을 본 사람이 없으니 아무도 두 사람의 마음속의 비밀을 알 리 없건만, 그래도 동혁의 생각이 불현듯이 나서 멀리 남녘 하늘의 구름을 바라다보고 섰을 때에는, 곁에 있는 사람이 제 속을 뚫고 들여다보는 것 같아서 머리가 저절로 수그러들기도 여러 번 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"'오냐, 예배당이 터지도록 모여 오너라, 여름만 되면 나무 그늘도 좋고, 달밤이면 등불두 일없다.'","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"아무리 곰곰 생각해 보아도 묘책이 나서지를 않아서 그는 하룻밤을 하얗게 밝혔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"첫째, 남자 친구를 찾아가는 것과 달라서 하룻밤이나마 묵을 데도 만만치 않을 듯하고, 둘이 함께 얼려 다니고 마주 붙어앉아 이야기라도 하면 노처녀인 영신이가 제가 당한 것보다도 곱절이나 부질없는 놀리움을 받을 것도 상상되었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그래서 어떠한 수단이든지 써서, 젊은 사람들이 하는 일을 헤살을 놓을 계책을 생각하느라고 밤이면 잠을 못 자는 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"마루 끝에 걸터앉아서 송편을 빚던 두 소녀는 팔월 열나흗날 밤 구름 한 점 없는 중천에 둥두렷이 떠오른 달을, 눈 하나를 째굿 하고 손가락으로 재보다가 서로 호호거리며 웃는다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그날 입힐 복색까지도 영신이와 원재 어머니가 며칠씩 밤을 새우며 꿰매 놓았다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"제 손으로 고요히 반주를 해가며 그 처량한 노래를 나직이 부르는 영신의 눈에는 고향의 산천과 한곡리 바닷가의 달밤이 번차례로 지나간다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그날 밤 영신은 어머니를 꿈속에 만나서 마주 붙들고 느껴느껴 울었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신은 아이들의 옷과 유희하던 제구를 챙겨 넣은 뒤에, 어젯밤 밤늦도록 빚은 송편과 시루떡을 아이들과 함께 나누어 먹었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"달밤을 이용해서 영신은 모래를 날랐다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"하고 어느 날 밤은 속눈썹이 쩍쩍 들러붙는 것을 참으면서 그 동안의 경과를 소상히 적고 인제는 만날 날이 가까워 온다는 기쁜 소식을 전해 주었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"김정근과의 혼인 일로 청석골까지 오셨을 때 이틀 밤을 울며 밝히시다가,","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"밤새도록 차창에 들부빈 머리를 빗어 올릴 사이도 없이 뛰어내렸건만, 플랫폼은 기차가 떠난 뒤처럼 휘덩그렇게 비었는데, 마중을 나온 몇 사람 중에서 영신을 맞아 주는 사람은 하나도 없다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"밤새도록 기차 속에서 시달리면서 불안과 초조에 지지리 졸아붙은 듯하던 영신의 신경은 다시금 불쾌한 흥분으로 옥죄어 드는 것 같다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"동혁이도 한곡리 바닷가의 오막살이에서 영신이가 오던 날 밤에 제가 한 말이 생각이 나서 빙긋이 웃으며,","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"어떤 계집애는 추석놀이를 하던 날 밤에 꽂았던 풀이 죽은 리본을 꽂고 자랑스러이 고개를 갸우뚱거리며 다닌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"가을 밤이라 꽤 지루헌데요.\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"시계의 초침이 돌아가는 소린 듯 창 틈에서 재깍거리는 버러지 소리에 가을 밤은 쓸쓸히 깊어 갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그것은 동혁이가 제 곁에 있지 않으면 긴긴 밤에 잠을 이루지 못하는 것이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그래서 동혁은 그 사정을 건배에게 편지로 알리고, 밤이 들면 꼭 환자의 침상머리에 앉아서 신문이나 잡지를 얻어다가 읽어 주고, 어느 때는 흑인종으로 무지한 동족을 위해서 갖은 고생과 백인의 학대를 받으면서 큰 사업을 성취한 푸커 티 워싱톤 같은 사람의 분투한 역사를 이야기해서 들려 주었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그러다가 밤이 깊어 영신이가 잠이 드는 것을 보고야 동혁은 벽 하나를 격한 대합실로 가서 의자를 모아 놓고 그 위에 담요 한 자락을 덮고는, 다시 갈피를 잡을 수 없는 공상에 잠겼다가 잠이 드는 것이었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그래서 그런 끝에는 처음으로 악박골 샘물터에서 밤을 새울 때에 뿌리만 따다가 둔 종교 문제를 끄집어내어 가지고 서로 얼굴에 핏대를 올려 가며 토론을 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"하고 두 사람은 밤 깊도록 그 구체적인 방법을 토론할 때도 있었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"하고 미친놈이 생침을 맞는 듯한 소리를 지르며 장작윷을 노느라고 떠들썩하더니, 밤이 이슥해지며 한집 두집 불이 꺼지고 지금은 큰 마을 편짝에서 개 짖는 소리만 이따금 컹컹컹 들릴 뿐…….","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"대보름달은 구름 속에 잠겨 언저리만이 흐릿한데, 그 사이로 유난히 붉은빛이 도는 별 서넛은 보초병의 눈초리처럼 날카로이 땅 위에 깊이 든 눈밤을 감시하는 듯.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그 동안 혼자서 곡기도 끊고 며칠 밤을 울며 밝힌 모양이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"가뜩이나 파리한 몸의 피가 졸아붙는 듯한 고민의 하룻밤은 밝았다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"기름이 졸아붙은 남폿불을 돋워 가며 잠을 이루지 못하는 겨울 밤은 길기도 길었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"\"떠나기 전에 뵙구 가려구 왔다가 한곡리서 하룻밤 자구 왔는데, 차마 나 혼자 어떻게…….\"","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"소녀 시절에 부르던 '홈 스위트 홈'을 그나마 남몰래 불러 보려면, 떠나올 때에도 찾아가 뵙지 못하고 온 홀어머니 생각에 저도 모르게 베개를 적시는 밤이 계속되었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그러나 밤이면 밤, 꿈이면 꿈마다 보이는 것은 청석골이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신은 비로소 마음을 놓고, 그날 밤은 일찍 자리에 누웠다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"청석골의 환경이 머릿속에 환하게 나타나고, 학원과 아이들의 얼굴이 핀트가 어그러진 활동사진처럼 어른어른하다가는 한곡리의 달밤, 그 바닷가에서 동혁에게 사랑의 고백을 받던 때의 정경!","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신은 기도회에 참례를 하려고 밤 사이에 더 부어오른 다리를 간신히 짚고 일어서 세숫간으로 나가다가 머릿속이 핑 내둘리고 다리의 힘이 풀려 문지방에 허리를 걸치고 쓰러졌다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"'왜 곧잘 참어 오던 내가 내 발로 걸어서 한곡리를 찾었고, 달 밝은 그날 밤 바닷가에서 경솔히 마음을 허락했던가.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"기숙사의 밤이 깊어 가는 대로 영신의 고민도 깊어 가고, 마음이 괴로울수록 안절부절을 못 하는 육신도 어느 한군데 괴롭지 않은 데가 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"밤에는 고통이 더 심해서 뜬눈으로 밝히는 날까지 있으면서도, 그는 이를 악물고 하루도 빼어놓지 않고 교단에 서기를 거진 한 달 동안이나 하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그러다가 어느 날 밤에는 학부형회에 참례를 하고 늦도록 학원의 유지 방침을 의논하다가, 별안간 심장의 고동이 뚝 그치는 것 같아서 원재에게 업혀 내려왔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"그들이 집증하는 것은 다 각각이나, 화타(華陀) 편작(扁鵲)이가 와도 오늘 밤을 넘기지 못하리라는 데는 의견이 일치하였다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"창 밖은 별빛조차 무색한 그믐밤이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"지새려는 봄 밤, 한곡리 앞바다에 뜬 새우잡이배의 등불처럼 의식이 깜박깜박하면서도, 악박골 약물터 우거진 숲속의 반딧불과 같이 반짝 하다가 꺼지려는 저의 일생을, 혼몽중에 추억의 날개로 더듬어 보는 듯.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신의 손때가 묻은 손풍금은 원재가 가져가고, 바람 차고 눈 뿌리는 밤이면 저를 품어 주던 재킷은 금분의 차지인데, 부인네들은 요 이불 베개 하다못해 구두, 고무신까지 다투어 가며 짝짝이로 치맛자락에 싸가지고 갔다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"뻐국새는 무엇이 서러워서 밤 깊도록 저다지 청승맞게 우느냐.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"애인의 무덤을 홀로 앉아 지키는 밤, 그 밤도 깊어 가서 저의 숨소리조차 듣기에 무서우리만치나 온누리는 괴괴한데, 추위와 함께 등허리에 오싹오싹 소름이 끼치게 하는 것은 형용할 수 없는 고독감이다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"영신이가 거처하던 원재네 집 텅 비인 건넌방에서 하룻밤을 드새자니, 동혁은 참으로 무량한 감개에 몸둘 바가 없었다.","title":"상록수","author":"심훈","kind":"원문"},{"t":"밤","q":"혼자 어디 있는지, 죽었는지 살았는지도 모르는 형식을 생각하고 울면서 밤을 새운 적도 있었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"저도 외로운 밤길에 동무나 될까, 하고 구태 때려 쫓지도 아니하였습니다.”","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러나 나는 나이 어리고 밤새도록 걸음을 걸어 다리가 아파서 뛰지 못할 줄을 알고 우뚝 섰습니다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그 몹쓸놈들이 밤새도록 잠은 아니 자고 그런 토론만 하였구먼”","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러나 영채를 등에 업고 캄캄한 밤에 사람 없는 데로 걸어가니, 등과 손에 감각되는 영채의 따뜻한 살이 금할 수 없이 그의 육욕의(육욕을) 자극하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"밤이 깊은 뒤에 그 사람이 돌아와서 부인께 영채의 말을 듣고 깜짝 놀랐다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"하니까 명망과 정성으로나 얼러 볼 양으로 매일 밤 월향 아씨게 참배 기도를 하는 모양인데 엊그저께 어떤 장난꾼 학생이 뒤를 따랐던가 봅데다”","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"또 생각하면 영채가 어떤 사람에게 팔린 줄을 알고 밤에 남모르게 도망하지나 아니하였는가.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"마치 봄철 곡식의 씨가 땅 속에서 불을 대로 불었다가 안개비만 조곰 와도 하룻밤에 쑥 움이 나오는 모양으로, 형식의 ‘속 사람’도 남보다 풍부한 실사회의 경험과 종교와 문학이라는 수분으로 흠뻑 불었다가 선형이라는 처녀와 영채라는 처녀의 봄바람 봄비에 갑자기 껍질을 깨트리고 뛰어난 것이라.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"월화는 어느 요리점 같은 데 불려 갔다가 밤이 깊어 돌아오는 길에 영채를 찾아와서는 흔히 눈물을 흘리며,","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"못 보던 남자를 대할 때에는 얼굴도 후끈후끈하고, 밤에 혼자 자리에 누워 잘 때에는 품어 줄 누구가 있었으면 하는 생각이 나게 되었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"학생들도 만일 월화를 본다 하면 ‘어여쁘다’ 하는 생각이 날는지도 모르고, ‘한번 더 보자’ 하는 생각이 날는지도 모르거니와, 그네는 결코 다른 사람들과 같이, ‘저것을 하룻밤 데리고 놀았으면 좋겠다’ 하는 생각을 두지 아니한다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"짧은 여름밤이 새었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"아아, 이것이 무슨 팔자인고 하고 그날 밤이 새도록 잠을 이루지 못하고 캄캄한 방에서 혼자 울었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"“밤이 깊었으니까 삼십 분에 한 번씩이나 다니는지”","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러고 지나간 사오 년 동안 영채가 밤에 ‘손님을 치렀더면, 일년에 백 명씩을 치르더라도 한번에 오 원 치고 오백 명에 이천오백 원쯤은 더 벌었을 것을, 내가 약하여 저년의 미련한 고집을 들어주었구나’ 하고 영채를 발길로 차고도 싶었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러고 더욱 기특한 것은, 밤에 잘 때에는 반드시 노파가 자기의 손으로 자리를 깔고, 이 ‘영감쟁이’를 아랫목에 누이더라.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"이제는 밤에 손님도 치르게 되려니 하고 두 겹으로 기뻤었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그래서 영채를 평양에 보낸 후로부터 지금 영채의 편지를 볼 때까지 노파는 영채로 하여금 밤에 ‘손을 보’게 할 생각과, 김현수에게 이천 원에 팔아먹을 생각만 하였었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"‘그러나 지금은 여름이니까’ 하고, 영채는 경찰서에서 지난밤을 지냈더라도 자기와 같이 떨지는 아니하였으리라 하고 얼마큼 안심을 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러나 밤에 자려 할 때에 같이 있던 이삼 인이 서로 다투어 형식의 곁에서 자려 하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그래서 지금 어젯밤 차로 내려왔는데요……","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"계향은 ‘어젯밤 차에서 구겨졌고나.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"하룻밤 이야기나 하세”","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러나 갑오년 을밀대 대포 한 방에 그가 꿈꾸던 태평시대는 어느덧 깨어지고 마치 캄캄한 밤에 번개가 번쩍하는 모양으로 새 시대가 돌아왔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러고 밤에 차를 타고 올 때에도 남모르게 가슴을 아프고 남모르게 눈물을 씻었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"메와 들에 풀과 나무가 밤 동안에 자라노라고 바삭바삭 하는 소리와, 자기의 몸에 피 돌아가는 것과, 그 피를 받아 즐거워하는 세포들의 소곤거리는 소리도 들린다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"어머니는 아직 젊었으나 아버지는 오십이 넘었으므로, 자기가 조곰이라도 병이 나면 그 병이 낫기까지 목욕재계하고 자기의 곁에서 밤을 새우던 것과, 자기가 혹 눈을 뜨면 아버지는 자기의 눈을 보고 그 아들이 눈을 뜨는 것이 무한히 기쁜 듯이 빙그레 웃으며 자기의 손을 잡던 것과, 아직 삼십이 다 못 된 자기의 어머니는 곤함을 이기지 못하여 앉은 대로 졸던 것이 생각이 난다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"한번은 형식이가 그 족제의 집에서 놀다가 밤이 깊었다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"밤새도록 차 속에서도 영채는 생각도 아니하고 왔다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"가게에 앉았던 사람들은 ‘이제는 서늘한 밤이 온다’ 하는 듯이 피곤한 얼굴에 땀을 씻으면서 행길에 나서 거닌다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"수증기 많은 여름밤 공기가 땀난 형식의 몸에 불같이 지나간다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"그러고 병욱과 영채는 무명밭에 가서 참외와 수박을 따다가 혹은 꿀을 두고, 혹은 사탕을 두어서, 혹은 하룻밤을 재우기도 하고, 혹은 우물에 넣어 식히기도 하여 내어놓는다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"휘황하던 전등은 밤새도록 이 두 괴로워하는 사람의 얼굴을 비추었고 커다란 눈을 부릅뜬 시커먼 기관차는 캄캄한 밤과 내려쏟는 비를 뚫고 별로 태우고 내리우는 사람도 없이 산굽이를 돌고 굴을 통하여 여러 가지 꿈을 꾸는 여러 가지 사람을 싣고 남으로 남으로 향하였다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"장차 누렇게 열매를 맺어 가을밤 골안개에 무거운 고개를 숙이려 하던 벼의 꽃도 다 말이 못 되고 말았을 것이다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"일생에 뼈가 휘도록 애써서 쌓아 놓은 생활의 근거를 하룻밤 비에 다 씻겨 내려 보내고 말리만큼 그네는 힘이 없다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"하룻밤 비에 모든 것을 잃어버리고 발발 떠는 그네들이 어찌 보면 가련하기도 하지마는 또 어찌 보면 너무 약하고 어리석어 보인다.","title":"무정","author":"이광수","kind":"원문"},{"t":"밤","q":"이놈으루 군밤이나 사먹구, 귀경(구경)은 공으루 들여 달라구 히여, 응……?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"부지깽이 같은 그 화승총을 가지고, 더구나 호미와 쇠스랑을 다루던 솜씨로, 으심치무레한 달밤에 보리밭 사이로 죽자사자 내빼는 사람을 쏜다고 쏘았댔자 제법 똑바로 가서 맞을 이치도 없기도 하지만.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"이날 밤 윤두꺼비도 그리하여 일변 몸져 누운 부친이 마음에 걸려, 선뜻 망설이기는 하면서도 사리가 그러했기 때문에, 이내 제 몸을 우선 피해 놓고 보던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"이 밤에 이 집을 쳐들어온 이 패들만 보아도, 패랭이 쓴 놈, 테머리 한 놈, 머리 땋은 총각, 늙은이 해서 차림새나 생김새가 가지각색이듯이, 모두 무질서하고 무지한 잡색 인물들이기는 하나, 일반으로 그들은 어느 때 어디를 쳐서 갖은 참상을 다 저지르곤 할 값에, 좀체로 부녀와 어린아이들한테만은 손을 대는 법이 없습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"밤이 어둡다구, 백년 가두 날이 안 샐 줄 아느냐?","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"달포 전인데 이 패에게 노략질을 당하던 날 밤, 그 중에 한 놈, 잘 알 수 있는 자가 섞여 있는 것을 윤용규는 보아 두었었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"\"밤새두룩 댐배질만 허니라구 성냥 열일곱 번 그신(그은) 년이 어떤 년이냐?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"하고 야단을 치는 사람이 없어, 잠 못 이루는 밤을 담배로 동무삼아 밝히기도 무척 임의로웠습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"물론 첩질이나 하고, 마작이나 하고, 요정으로 밤을 도와 드나드는 걸 보면 갈데없는 불량자고요.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"거상에 손자놈이 학교를 잘 다니건 말건, 공부를 착실히 하건 말건, 통히 알은체도 안 해오던 터에, 오늘 밤이야 말고서 갑작스레 그런 소리를 하는 게 다 속 앗길 짓이기는 하지만, 다급한 판이니 옹색한 대로 둘러댈 수밖에 없던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"그저 날 같언 사람은 말이네, 그저 도둑놈이 노적(露積)가리 짊어져 가까 버서, 밤새두룩 짖구 댕기는 개, 개 신세여!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"와서 날 이얘기책두 읽어 주구, 더러 다리두 쳐주구 허머넌, 내 군밤 사먹으라구 돈 주지…….\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"그런데 그게 옹근 기생이 아니요 동기고 볼 양이면, 이런 체면 저런 대접 여부 없이 가끔가다가 돈 장이나 집어주곤 하면 제야 군밤을 사먹거나 봉지쌀을 사들고 가거나 이편의 아랑곳이 아니요, 내가 할 도리는 넉넉 차리게 될 테니까 두루 좋습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"그 뒤로부터 그 애는 윤직원 영감의 뜻을 곧잘 받아, 이틀에 한 번, 또 어느 때는 매일같이 올라와선 놀곤 했고, 그렇게 하기를 한 이십여 일 해오던 어느 날 밤이었습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"\"무얼 핥어먹느라구 밤새두룩 주둥일 끌구 다녔수?\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"간밤에 변소에 가서 휴지가 없어서 고만!\"","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"종수는 사람이 밤에 불(光線)을 가진 것이 참으로 고맙고 다행스럽다는 것을 절절히 느끼면서, 자동차를 몰아 동소문 밖 ××원 별장으로 나왔습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"그러나 암만해도 괄세할 수 없는 개평꾼은 역시 괄세를 못 하는 법이라 한 육칠 인이나 그 중 서넛은 판 뒤에서 넘겨다보고 있고, 서넛은 밤새도록 온종일 지키느라 지쳤는지, 머리방인 서사의 방에 가서 곯아떨어졌습니다.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"경손이는 간밤에 춘심이로 더불어 랑데부를 하면서, 이 원 돈을 유흥하던 추억에 싸여 시방 학과에도 여념이 없는 중이고.","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"밤새두룩 잠두 아니 잔걸!","title":"태평천하","author":"채만식","kind":"원문"},{"t":"밤","q":"창식이 윤주사가 조금 아까야 일어나서, 간밤에 동경서 온 전보 때문에 억지로 억지로 큰댁 행보를 하던 것입니다.","title":"태평천하","author":"채만식","kind":"원문"}]},"bucketMeta":{"자정":{"rep":"00:00","start":"23:30","end":"00:29"},"새벽":{"rep":"04:30","start":"03:00","end":"05:59"},"아침":{"rep":"07:30","start":"06:00","end":"08:59"},"오전":{"rep":"10:00","start":"09:00","end":"11:29"},"정오":{"rep":"12:00","start":"11:30","end":"13:29"},"오후":{"rep":"15:00","start":"13:30","end":"16:59"},"저녁":{"rep":"18:30","start":"17:00","end":"19:29"},"밤":{"rep":"21:30","start":"19:30","end":"23:29"}}};
